impl FileArtifactOwnershipPolicy {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let policy: FileArtifactOwnershipPolicy = serde_json::from_str(input)
            .context("failed to parse File/Artifact Ownership Policy JSON")?;
        policy.validate_schema()?;
        Ok(policy)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != FILE_ARTIFACT_OWNERSHIP_POLICY_SCHEMA_VERSION {
            return Err(anyhow!(
                "file/artifact ownership policy schemaVersion must be {FILE_ARTIFACT_OWNERSHIP_POLICY_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("file/artifact ownership policy policyId", &self.policy_id)?;
        require_text("file/artifact ownership policy milestone", &self.milestone)?;
        if self.entries.is_empty() {
            return Err(anyhow!(
                "file/artifact ownership policy entries must not be empty"
            ));
        }
        for (index, entry) in self.entries.iter().enumerate() {
            entry.validate_schema(index)?;
        }
        self.generated_state.validate()?;
        self.validate_conflict_policy()?;
        validate_nonempty_text_list(
            "file/artifact ownership policy guardrails",
            &self.guardrails,
        )?;
        validate_nonempty_text_list(
            "file/artifact ownership policy forbiddenActions",
            &self.forbidden_actions,
        )?;
        require_text("file/artifact ownership policy boundary", &self.boundary)?;
        let forbidden_text = self.forbidden_actions.join(" ").to_ascii_lowercase();
        for required_forbidden in [
            "silent overwrite",
            "auto-apply",
            "hidden background agents",
            "browser command bridge",
        ] {
            if !forbidden_text.contains(required_forbidden) {
                return Err(anyhow!(
                    "file/artifact ownership policy forbiddenActions must include {required_forbidden} boundary"
                ));
            }
        }
        if !self
            .boundary
            .to_ascii_lowercase()
            .contains("does not lock files")
        {
            return Err(anyhow!(
                "file/artifact ownership policy boundary must state that the policy does not lock files"
            ));
        }
        Ok(())
    }

    fn validate_conflict_policy(&self) -> Result<()> {
        let mut entry_ids = BTreeSet::new();
        let mut work_package_owners = BTreeMap::<&str, &str>::new();
        for (index, entry) in self.entries.iter().enumerate() {
            if !entry_ids.insert(entry.id.as_str()) {
                return Err(anyhow!(
                    "file/artifact ownership policy duplicate entry id: {}",
                    entry.id
                ));
            }
            entry.validate_mode_target_pair(index)?;
            entry.validate_generated_root_scope(index, &self.generated_state.roots)?;
            for work_package_ref in &entry.work_package_refs {
                if let Some(existing_owner) = work_package_owners.get(work_package_ref.as_str()) {
                    if *existing_owner != entry.owner_agent {
                        return Err(anyhow!(
                            "file/artifact ownership policy conflicting work package {work_package_ref}: owner {existing_owner} conflicts with owner {}",
                            entry.owner_agent
                        ));
                    }
                } else {
                    work_package_owners
                        .insert(work_package_ref.as_str(), entry.owner_agent.as_str());
                }
            }
        }

        for left_index in 0..self.entries.len() {
            let left = &self.entries[left_index];
            if left.releases_ownership() {
                continue;
            }
            for right_index in (left_index + 1)..self.entries.len() {
                let right = &self.entries[right_index];
                if right.releases_ownership() || !left.targets_overlap(right) {
                    continue;
                }
                let conflict_kind = ownership_conflict_kind(left, right);
                if let Some(conflict_kind) = conflict_kind {
                    if left.conflict_is_resolved() && right.conflict_is_resolved() {
                        continue;
                    }
                    return Err(anyhow!(
                        "file/artifact ownership policy {conflict_kind} conflict between entries {} owned by {} and {} owned by {}; conflicting entries must be blocked, deferred, or escalated",
                        left.id,
                        left.owner_agent,
                        right.id,
                        right.owner_agent
                    ));
                }
            }
        }
        Ok(())
    }
}

impl OwnershipPolicyEntry {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(&format!("ownership policy entries[{index}].id"), &self.id)?;
        validate_path_component(
            &format!("ownership policy entries[{index}].ownerAgent"),
            &self.owner_agent,
        )?;
        validate_path_component(
            &format!("ownership policy entries[{index}].role"),
            &self.role,
        )?;
        if !SUPPORTED_AGENT_ROLES.contains(&self.role.as_str()) {
            return Err(anyhow!(
                "ownership policy entries[{index}].role '{}' is unsupported",
                self.role
            ));
        }
        self.target
            .validate_schema(&format!("ownership policy entries[{index}].target"))?;
        validate_nonempty_text_list(
            &format!("ownership policy entries[{index}].workPackageRefs"),
            &self.work_package_refs,
        )?;
        for evidence in &self.evidence_refs {
            evidence.validate(&format!("ownership policy entries[{index}].evidenceRefs"))?;
        }
        if self.evidence_refs.is_empty() {
            return Err(anyhow!(
                "ownership policy entries[{index}].evidenceRefs must not be empty"
            ));
        }
        if matches!(
            self.state,
            OwnershipState::Blocked | OwnershipState::Escalated
        ) && self.blocked_reasons.is_empty()
        {
            return Err(anyhow!(
                "ownership policy entries[{index}] blocked or escalated state requires blockedReasons"
            ));
        }
        if self.mode == OwnershipMode::EscalationHold && self.escalation.is_none() {
            return Err(anyhow!(
                "ownership policy entries[{index}] escalation-hold mode requires escalation"
            ));
        }
        if let Some(escalation) = &self.escalation {
            escalation.validate_schema(index)?;
        }
        Ok(())
    }

    fn validate_mode_target_pair(&self, index: usize) -> Result<()> {
        match self.mode {
            OwnershipMode::SharedReadOnly => {
                if self.target.kind != OwnershipTargetKind::SharedReadOnlyRef {
                    return Err(anyhow!(
                        "ownership policy entries[{index}] shared-read-only mode requires shared-read-only-ref target"
                    ));
                }
            }
            OwnershipMode::ExclusiveWrite => {
                if !matches!(
                    self.target.kind,
                    OwnershipTargetKind::FilePath | OwnershipTargetKind::Artifact
                ) {
                    return Err(anyhow!(
                        "ownership policy entries[{index}] exclusive-write mode requires file-path or artifact target"
                    ));
                }
            }
            OwnershipMode::GeneratedWrite => {
                if self.target.kind != OwnershipTargetKind::GeneratedOutputRoot {
                    return Err(anyhow!(
                        "ownership policy entries[{index}] generated-write mode requires generated-output-root target"
                    ));
                }
            }
            OwnershipMode::EscalationHold => {}
        }
        Ok(())
    }

    fn validate_generated_root_scope(
        &self,
        index: usize,
        generated_roots: &[String],
    ) -> Result<()> {
        if self.target.kind == OwnershipTargetKind::GeneratedOutputRoot {
            let is_declared_root = generated_roots
                .iter()
                .any(|root| project_manifest_path_contains(root, &self.target.path));
            if !is_declared_root {
                return Err(anyhow!(
                    "ownership policy entries[{index}].target generated-output-root path {} must be within generatedState.roots",
                    self.target.path
                ));
            }
        }
        Ok(())
    }

    fn releases_ownership(&self) -> bool {
        self.state == OwnershipState::Released
    }

    fn conflict_is_resolved(&self) -> bool {
        matches!(
            self.state,
            OwnershipState::Blocked | OwnershipState::Deferred | OwnershipState::Escalated
        )
    }

    fn targets_overlap(&self, other: &OwnershipPolicyEntry) -> bool {
        self.target.kind == other.target.kind && self.target.id == other.target.id
            || project_manifest_paths_overlap(&self.target.path, &other.target.path)
    }
}

fn ownership_conflict_kind(
    left: &OwnershipPolicyEntry,
    right: &OwnershipPolicyEntry,
) -> Option<&'static str> {
    let left_writes = left.mode.writes_target();
    let right_writes = right.mode.writes_target();
    let left_reads = left.mode == OwnershipMode::SharedReadOnly;
    let right_reads = right.mode == OwnershipMode::SharedReadOnly;

    if left_writes && right_writes && left.owner_agent != right.owner_agent {
        Some("write/write")
    } else if (left_reads && right_writes) || (left_writes && right_reads) {
        Some("read/write ambiguity")
    } else {
        None
    }
}

impl OwnershipMode {
    fn writes_target(self) -> bool {
        matches!(
            self,
            OwnershipMode::ExclusiveWrite | OwnershipMode::GeneratedWrite
        )
    }
}

pub const FILE_ARTIFACT_OWNERSHIP_POLICY_READ_MODEL_SCHEMA_VERSION: &str =
    "file-artifact-ownership-policy-read-model-v1";

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct FileArtifactOwnershipPolicyReadModel {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    #[serde(rename = "policyId")]
    pub policy_id: String,
    pub status: String,
    #[serde(rename = "entryCount")]
    pub entry_count: usize,
    #[serde(rename = "conflictCount")]
    pub conflict_count: usize,
    pub blockers: Vec<String>,
    #[serde(rename = "deferredEntries")]
    pub deferred_entries: Vec<String>,
    pub escalations: Vec<String>,
    #[serde(rename = "generatedRoots")]
    pub generated_roots: Vec<String>,
    #[serde(rename = "malformedReasons")]
    pub malformed_reasons: Vec<String>,
    pub boundary: String,
}

pub fn file_artifact_ownership_policy_read_model_from_json_str(
    input: &str,
) -> FileArtifactOwnershipPolicyReadModel {
    match FileArtifactOwnershipPolicy::from_json_str(input) {
        Ok(policy) => FileArtifactOwnershipPolicyReadModel::from_policy(&policy),
        Err(error) => FileArtifactOwnershipPolicyReadModel::malformed(format!("{error:#}")),
    }
}

impl FileArtifactOwnershipPolicyReadModel {
    pub fn from_policy(policy: &FileArtifactOwnershipPolicy) -> Self {
        let mut blockers = Vec::new();
        let mut deferred_entries = Vec::new();
        let mut escalations = Vec::new();
        for entry in &policy.entries {
            for reason in &entry.blocked_reasons {
                blockers.push(format!("{}: {reason}", entry.id));
            }
            if entry.state == OwnershipState::Deferred {
                deferred_entries.push(entry.id.clone());
            }
            if entry.state == OwnershipState::Escalated {
                let decision = entry
                    .escalation
                    .as_ref()
                    .map(|escalation| escalation.required_decision.as_str())
                    .unwrap_or("decision required");
                escalations.push(format!("{}: {decision}", entry.id));
            }
        }

        let conflict_count = ownership_policy_conflict_count(&policy.entries);
        let status = if !escalations.is_empty() {
            "escalated"
        } else if conflict_count > 0
            || policy
                .entries
                .iter()
                .any(|entry| entry.state == OwnershipState::Blocked)
        {
            "blocked"
        } else if !deferred_entries.is_empty() {
            "deferred"
        } else {
            "active"
        };

        Self {
            schema_version: FILE_ARTIFACT_OWNERSHIP_POLICY_READ_MODEL_SCHEMA_VERSION.to_string(),
            policy_id: policy.policy_id.clone(),
            status: status.to_string(),
            entry_count: policy.entries.len(),
            conflict_count,
            blockers,
            deferred_entries,
            escalations,
            generated_roots: policy.generated_state.roots.clone(),
            malformed_reasons: Vec::new(),
            boundary: "Read-only ownership policy summary; it reports conflicts, blockers, deferred entries, and escalation requirements without locking files, spawning agents, executing commands, applying changes, writing trusted browser state, or merging PRs.".to_string(),
        }
    }

    fn malformed(reason: String) -> Self {
        Self {
            schema_version: FILE_ARTIFACT_OWNERSHIP_POLICY_READ_MODEL_SCHEMA_VERSION.to_string(),
            policy_id: "malformed-ownership-policy".to_string(),
            status: "malformed".to_string(),
            entry_count: 0,
            conflict_count: 0,
            blockers: Vec::new(),
            deferred_entries: Vec::new(),
            escalations: Vec::new(),
            generated_roots: Vec::new(),
            malformed_reasons: vec![reason],
            boundary: "Read-only malformed ownership policy summary; it reports validation errors without locking files, spawning agents, executing commands, applying changes, writing trusted state, or merging PRs.".to_string(),
        }
    }
}

fn ownership_policy_conflict_count(entries: &[OwnershipPolicyEntry]) -> usize {
    let mut count = 0;
    for left_index in 0..entries.len() {
        let left = &entries[left_index];
        if left.releases_ownership() {
            continue;
        }
        for right in entries.iter().skip(left_index + 1) {
            if right.releases_ownership() || !left.targets_overlap(right) {
                continue;
            }
            if ownership_conflict_kind(left, right).is_some() {
                count += 1;
            }
        }
    }
    count
}

impl OwnershipTargetRef {
    fn validate_schema(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.id"), &self.id)?;
        validate_project_manifest_path(&format!("{field}.path"), &self.path)?;
        if self.kind == OwnershipTargetKind::GeneratedOutputRoot && !self.generated_root {
            return Err(anyhow!(
                "{field}.generatedRoot must be true for generated-output-root targets"
            ));
        }
        Ok(())
    }
}

impl OwnershipEscalation {
    fn validate_schema(&self, index: usize) -> Result<()> {
        require_text(
            &format!("ownership policy entries[{index}].escalation.reason"),
            &self.reason,
        )?;
        require_text(
            &format!("ownership policy entries[{index}].escalation.requiredDecision"),
            &self.required_decision,
        )?;
        require_text(
            &format!("ownership policy entries[{index}].escalation.safeNextAction"),
            &self.safe_next_action,
        )
    }
}

