impl AgentSharedStateSnapshot {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let snapshot: AgentSharedStateSnapshot = serde_json::from_str(input)
            .context("failed to parse Agent Shared State Snapshot JSON")?;
        snapshot.validate_schema()?;
        Ok(snapshot)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != AGENT_SHARED_STATE_SNAPSHOT_SCHEMA_VERSION {
            return Err(anyhow!(
                "agent shared state snapshot schemaVersion must be {AGENT_SHARED_STATE_SNAPSHOT_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("agent shared state snapshot snapshotId", &self.snapshot_id)?;
        require_text("agent shared state snapshot milestone", &self.milestone)?;
        require_text("agent shared state snapshot observedAt", &self.observed_at)?;
        if !self.observed_at.contains('T') || !self.observed_at.ends_with('Z') {
            return Err(anyhow!(
                "agent shared state snapshot observedAt must be UTC RFC3339-like text"
            ));
        }
        validate_snapshot_hash(
            "agent shared state snapshot projectManifestHash",
            &self.project_manifest_hash,
        )?;
        validate_snapshot_hash(
            "agent shared state snapshot assetManifestHash",
            &self.asset_manifest_hash,
        )?;
        validate_snapshot_hash(
            "agent shared state snapshot scenarioPackHash",
            &self.scenario_pack_hash,
        )?;
        validate_nonempty_snapshot_hash_refs(
            "agent shared state snapshot sceneHashes",
            &self.scene_hashes,
        )?;
        validate_snapshot_hash_refs(
            "agent shared state snapshot tilemapHashes",
            &self.tilemap_hashes,
        )?;
        validate_snapshot_hash_refs(
            "agent shared state snapshot behaviorVersionHashes",
            &self.behavior_version_hashes,
        )?;
        validate_nonempty_text_list(
            "agent shared state snapshot recentRunIds",
            &self.recent_run_ids,
        )?;
        validate_nonempty_text_list("agent shared state snapshot openTasks", &self.open_tasks)?;
        if self.ownership_map.is_empty() {
            return Err(anyhow!(
                "agent shared state snapshot ownershipMap must not be empty"
            ));
        }
        for (index, ownership) in self.ownership_map.iter().enumerate() {
            ownership.validate(index)?;
        }
        validate_optional_text_list(
            "agent shared state snapshot pendingReviews",
            &self.pending_reviews,
        )?;
        if let Some(context) = &self.before_context {
            context.validate("agent shared state snapshot beforeContext")?;
        }
        if let Some(context) = &self.after_context {
            context.validate("agent shared state snapshot afterContext")?;
        }
        validate_optional_text_list("agent shared state snapshot staleRefs", &self.stale_refs)?;
        validate_optional_text_list(
            "agent shared state snapshot missingRefs",
            &self.missing_refs,
        )?;
        validate_optional_text_list(
            "agent shared state snapshot malformedReasons",
            &self.malformed_reasons,
        )?;
        validate_optional_text_list(
            "agent shared state snapshot conflictingRefs",
            &self.conflicting_refs,
        )?;
        self.generated_state.validate()?;
        validate_nonempty_text_list("agent shared state snapshot guardrails", &self.guardrails)?;
        validate_nonempty_text_list(
            "agent shared state snapshot forbiddenActions",
            &self.forbidden_actions,
        )?;
        require_text("agent shared state snapshot boundary", &self.boundary)?;
        self.validate_status_shape()?;
        self.validate_guardrails()
    }

    fn validate_status_shape(&self) -> Result<()> {
        match self.status {
            AgentSharedStateSnapshotStatus::Fresh => {
                if !self.stale_refs.is_empty()
                    || !self.missing_refs.is_empty()
                    || !self.malformed_reasons.is_empty()
                    || !self.conflicting_refs.is_empty()
                {
                    return Err(anyhow!(
                        "fresh agent shared state snapshot must not include stale, missing, malformed, or conflicting refs"
                    ));
                }
            }
            AgentSharedStateSnapshotStatus::Stale => {
                if self.stale_refs.is_empty() {
                    return Err(anyhow!(
                        "stale agent shared state snapshot requires staleRefs"
                    ));
                }
            }
            AgentSharedStateSnapshotStatus::Partial | AgentSharedStateSnapshotStatus::Missing => {
                if self.missing_refs.is_empty() {
                    return Err(anyhow!(
                        "partial or missing agent shared state snapshot requires missingRefs"
                    ));
                }
            }
            AgentSharedStateSnapshotStatus::Malformed => {
                if self.malformed_reasons.is_empty() {
                    return Err(anyhow!(
                        "malformed agent shared state snapshot requires malformedReasons"
                    ));
                }
            }
            AgentSharedStateSnapshotStatus::Conflicting => {
                if self.conflicting_refs.is_empty() {
                    return Err(anyhow!(
                        "conflicting agent shared state snapshot requires conflictingRefs"
                    ));
                }
            }
        }
        Ok(())
    }

    fn validate_guardrails(&self) -> Result<()> {
        let forbidden = self.forbidden_actions.join(" ").to_ascii_lowercase();
        for phrase in [
            "hidden background agents",
            "auto-apply",
            "auto-merge",
            "self-approval",
            "browser command bridge",
            "trusted browser writes",
        ] {
            if !forbidden.contains(phrase) {
                return Err(anyhow!(
                    "agent shared state snapshot forbiddenActions must include {phrase} boundary"
                ));
            }
        }
        let boundary = self.boundary.to_ascii_lowercase();
        for phrase in [
            "read-only",
            "does not execute commands",
            "does not mutate",
            "does not write trusted browser state",
            "does not repair stale state",
            "does not claim production readiness",
            "does not claim godot replacement",
        ] {
            if !boundary.contains(phrase) {
                return Err(anyhow!(
                    "agent shared state snapshot boundary must state {phrase}"
                ));
            }
        }
        Ok(())
    }

    pub fn detect_staleness_against(
        &self,
        current: &AgentSharedStateSnapshotCurrentState,
    ) -> AgentSharedStateSnapshotStalenessReport {
        let mut stale_refs = Vec::new();
        let mut missing_refs = Vec::new();
        let mut conflicting_refs = Vec::new();

        compare_snapshot_hash(
            "projectManifestHash",
            &self.project_manifest_hash,
            &current.project_manifest_hash,
            &mut stale_refs,
        );
        compare_snapshot_hash(
            "assetManifestHash",
            &self.asset_manifest_hash,
            &current.asset_manifest_hash,
            &mut stale_refs,
        );
        compare_snapshot_hash(
            "scenarioPackHash",
            &self.scenario_pack_hash,
            &current.scenario_pack_hash,
            &mut stale_refs,
        );
        compare_snapshot_hash_refs(
            "sceneHashes",
            &self.scene_hashes,
            &current.scene_hashes,
            &mut stale_refs,
            &mut missing_refs,
        );
        compare_snapshot_hash_refs(
            "tilemapHashes",
            &self.tilemap_hashes,
            &current.tilemap_hashes,
            &mut stale_refs,
            &mut missing_refs,
        );
        compare_snapshot_hash_refs(
            "behaviorVersionHashes",
            &self.behavior_version_hashes,
            &current.behavior_version_hashes,
            &mut stale_refs,
            &mut missing_refs,
        );
        compare_text_set(
            "openTasks",
            &self.open_tasks,
            &current.open_tasks,
            &mut stale_refs,
            &mut missing_refs,
        );
        compare_text_set(
            "pendingReviews",
            &self.pending_reviews,
            &current.pending_reviews,
            &mut stale_refs,
            &mut missing_refs,
        );
        compare_snapshot_ownership(
            &self.ownership_map,
            &current.ownership_map,
            &mut stale_refs,
            &mut missing_refs,
            &mut conflicting_refs,
        );

        let status = if !conflicting_refs.is_empty() {
            AgentSharedStateSnapshotStatus::Conflicting
        } else if !missing_refs.is_empty() {
            AgentSharedStateSnapshotStatus::Partial
        } else if !stale_refs.is_empty() {
            AgentSharedStateSnapshotStatus::Stale
        } else {
            AgentSharedStateSnapshotStatus::Fresh
        };

        AgentSharedStateSnapshotStalenessReport {
            schema_version: "agent-shared-state-snapshot-staleness-report-v1".to_string(),
            snapshot_id: self.snapshot_id.clone(),
            status,
            stale_refs,
            missing_refs,
            conflicting_refs,
            malformed_reasons: Vec::new(),
            boundary: "Read-only agent shared state snapshot staleness report; it compares current local manifest, scene, tilemap, asset, behavior, scenario, task, ownership, and review evidence without executing commands, spawning agents, repairing stale state, mutating task boards, writing trusted browser state, applying changes, or merging PRs.".to_string(),
        }
    }
}

pub fn agent_shared_state_snapshot_read_model_from_json_str(
    input: &str,
) -> AgentSharedStateSnapshotReadModel {
    match AgentSharedStateSnapshot::from_json_str(input) {
        Ok(snapshot) => AgentSharedStateSnapshotReadModel::from_snapshot(&snapshot),
        Err(error) => AgentSharedStateSnapshotReadModel::malformed(format!("{error:#}")),
    }
}

impl AgentSharedStateSnapshotReadModel {
    pub fn from_snapshot(snapshot: &AgentSharedStateSnapshot) -> Self {
        let blockers = snapshot
            .stale_refs
            .iter()
            .chain(snapshot.missing_refs.iter())
            .chain(snapshot.conflicting_refs.iter())
            .chain(snapshot.malformed_reasons.iter())
            .cloned()
            .collect();
        Self {
            schema_version: AGENT_SHARED_STATE_SNAPSHOT_READ_MODEL_SCHEMA_VERSION.to_string(),
            snapshot_id: snapshot.snapshot_id.clone(),
            milestone: snapshot.milestone.clone(),
            status: snapshot.status.as_str().to_string(),
            observed_at: snapshot.observed_at.clone(),
            scene_hash_count: snapshot.scene_hashes.len(),
            tilemap_hash_count: snapshot.tilemap_hashes.len(),
            behavior_version_hash_count: snapshot.behavior_version_hashes.len(),
            recent_run_count: snapshot.recent_run_ids.len(),
            open_task_count: snapshot.open_tasks.len(),
            ownership_count: snapshot.ownership_map.len(),
            pending_review_count: snapshot.pending_reviews.len(),
            before_context_label: snapshot
                .before_context
                .as_ref()
                .map(|context| context.label.clone()),
            after_context_label: snapshot
                .after_context
                .as_ref()
                .map(|context| context.label.clone()),
            blockers,
            generated_roots: snapshot.generated_state.roots.clone(),
            malformed_reasons: Vec::new(),
            boundary: "Read-only agent shared state snapshot display model; it summarizes hashes, tasks, ownership, reviews, generated roots, stale/missing/malformed/conflicting evidence, and before/after context without executing commands, spawning agents, repairing stale state, mutating task boards, writing trusted browser state, applying changes, or merging PRs.".to_string(),
        }
    }

    fn malformed(reason: String) -> Self {
        Self {
            schema_version: AGENT_SHARED_STATE_SNAPSHOT_READ_MODEL_SCHEMA_VERSION.to_string(),
            snapshot_id: "malformed-agent-shared-state-snapshot".to_string(),
            milestone: "unknown".to_string(),
            status: "malformed".to_string(),
            observed_at: String::new(),
            scene_hash_count: 0,
            tilemap_hash_count: 0,
            behavior_version_hash_count: 0,
            recent_run_count: 0,
            open_task_count: 0,
            ownership_count: 0,
            pending_review_count: 0,
            before_context_label: None,
            after_context_label: None,
            blockers: Vec::new(),
            generated_roots: Vec::new(),
            malformed_reasons: vec![reason],
            boundary: "Read-only malformed agent shared state snapshot display model; it reports validation errors without executing commands, spawning agents, repairing stale state, mutating state, writing trusted browser state, applying changes, or merging PRs.".to_string(),
        }
    }
}

