#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct AgentDecisionLedgerAppendOnly {
    pub sequence: u64,
    #[serde(rename = "previousLedgerHash", skip_serializing_if = "Option::is_none")]
    pub previous_ledger_hash: Option<String>,
    #[serde(rename = "entryOrderHash")]
    pub entry_order_hash: String,
    pub note: String,
}

impl AgentDecisionLedger {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let ledger: AgentDecisionLedger =
            serde_json::from_str(input).context("failed to parse Agent Decision Ledger JSON")?;
        ledger.validate_schema()?;
        Ok(ledger)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != AGENT_DECISION_LEDGER_SCHEMA_VERSION {
            return Err(anyhow!(
                "agent decision ledger schemaVersion must be {AGENT_DECISION_LEDGER_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("agent decision ledger ledgerId", &self.ledger_id)?;
        require_text("agent decision ledger milestone", &self.milestone)?;
        if self.decisions.is_empty() {
            return Err(anyhow!("agent decision ledger decisions must not be empty"));
        }
        for (index, decision) in self.decisions.iter().enumerate() {
            decision.validate_schema(index)?;
        }
        self.validate_unique_decision_ids()?;
        self.pipeline_refs.validate_schema()?;
        self.validate_decision_evidence_refs()?;
        self.validate_stale_ref_targets()?;
        self.append_only.validate_schema()?;
        self.validate_append_only_consistency()?;
        validate_optional_text_list("agent decision ledger staleRefs", &self.stale_refs)?;
        validate_optional_text_list(
            "agent decision ledger malformedReasons",
            &self.malformed_reasons,
        )?;
        self.generated_state.validate()?;
        validate_nonempty_text_list("agent decision ledger guardrails", &self.guardrails)?;
        validate_nonempty_text_list(
            "agent decision ledger forbiddenActions",
            &self.forbidden_actions,
        )?;
        require_text("agent decision ledger boundary", &self.boundary)?;
        self.validate_status_shape()?;
        self.validate_guardrails()
    }

    fn validate_status_shape(&self) -> Result<()> {
        match self.status {
            AgentDecisionLedgerStatus::Active => {
                if !self.stale_refs.is_empty() || !self.malformed_reasons.is_empty() {
                    return Err(anyhow!(
                        "active agent decision ledger must not include staleRefs or malformedReasons"
                    ));
                }
            }
            AgentDecisionLedgerStatus::Stale => {
                if self.stale_refs.is_empty() {
                    return Err(anyhow!("stale agent decision ledger requires staleRefs"));
                }
            }
            AgentDecisionLedgerStatus::Malformed => {
                if self.malformed_reasons.is_empty() {
                    return Err(anyhow!(
                        "malformed agent decision ledger requires malformedReasons"
                    ));
                }
            }
            AgentDecisionLedgerStatus::AppendOnlyViolation => {
                if self
                    .malformed_reasons
                    .iter()
                    .chain(self.stale_refs.iter())
                    .all(|reason| !reason.to_ascii_lowercase().contains("append"))
                {
                    return Err(anyhow!(
                        "append-only-violation agent decision ledger requires append-only evidence in staleRefs or malformedReasons"
                    ));
                }
            }
        }
        Ok(())
    }

    fn validate_unique_decision_ids(&self) -> Result<()> {
        let mut ids = BTreeSet::new();
        for decision in &self.decisions {
            if !ids.insert(decision.decision_id.as_str()) {
                return Err(anyhow!(
                    "agent decision ledger duplicate decisionId: {}",
                    decision.decision_id
                ));
            }
            let mut alternative_ids = BTreeSet::new();
            for alternative in &decision.alternatives_rejected {
                if !alternative_ids.insert(alternative.id.as_str()) {
                    return Err(anyhow!(
                        "agent decision ledger decision {} duplicate alternativesRejected id: {}",
                        decision.decision_id,
                        alternative.id
                    ));
                }
            }
        }
        Ok(())
    }

    fn validate_decision_evidence_refs(&self) -> Result<()> {
        let known = self.known_artifact_refs();
        for decision in &self.decisions {
            for evidence_ref in &decision.evidence_refs {
                if !known
                    .iter()
                    .any(|candidate| artifact_refs_match(candidate, evidence_ref))
                {
                    return Err(anyhow!(
                        "agent decision ledger decision {} evidenceRefs target is unknown: {}",
                        decision.decision_id,
                        evidence_ref.id
                    ));
                }
            }
        }
        Ok(())
    }

    fn validate_stale_ref_targets(&self) -> Result<()> {
        let known = self.known_artifact_refs();
        for stale_ref in &self.stale_refs {
            let anchored_to_decision = self
                .decisions
                .iter()
                .any(|decision| stale_ref.contains(&decision.decision_id));
            let anchored_to_artifact = known.iter().any(|reference| {
                stale_ref.contains(&reference.id) || stale_ref.contains(&reference.path)
            });
            if !anchored_to_decision && !anchored_to_artifact {
                return Err(anyhow!(
                    "agent decision ledger staleRefs target is unknown: {stale_ref}"
                ));
            }
        }
        Ok(())
    }

    fn validate_append_only_consistency(&self) -> Result<()> {
        if self.status != AgentDecisionLedgerStatus::AppendOnlyViolation
            && self.append_only.sequence as usize != self.decisions.len()
        {
            return Err(anyhow!(
                "agent decision ledger appendOnly.sequence must match decisions length for non-violation ledgers"
            ));
        }
        Ok(())
    }

    fn known_artifact_refs(&self) -> Vec<&AuthoringLoopArtifactRef> {
        let mut refs = vec![&self.pipeline_refs.task_board_ref];
        refs.extend(self.pipeline_refs.work_package_refs.iter());
        refs.extend(self.pipeline_refs.handoff_refs.iter());
        refs.extend(self.pipeline_refs.review_gate_refs.iter());
        refs.extend(self.pipeline_refs.qa_result_refs.iter());
        refs.extend(self.pipeline_refs.performance_regression_refs.iter());
        refs.extend(self.pipeline_refs.evidence_bundle_refs.iter());
        refs
    }

    fn validate_guardrails(&self) -> Result<()> {
        let forbidden = self.forbidden_actions.join(" ").to_ascii_lowercase();
        for phrase in [
            "hidden background agents",
            "auto-apply",
            "auto-merge",
            "self-approval",
            "browser command bridge",
            "trusted browser state",
            "production readiness",
            "Godot replacement",
        ] {
            if !forbidden.contains(&phrase.to_ascii_lowercase()) {
                return Err(anyhow!(
                    "agent decision ledger forbiddenActions must include {phrase} boundary"
                ));
            }
        }
        for phrase in [
            "does not execute commands",
            "does not spawn agents",
            "does not apply",
            "does not merge",
            "does not write trusted browser state",
        ] {
            if !self
                .boundary
                .to_ascii_lowercase()
                .contains(&phrase.to_ascii_lowercase())
            {
                return Err(anyhow!(
                    "agent decision ledger boundary must state it {phrase}"
                ));
            }
        }
        Ok(())
    }
}

impl AgentDecisionRecord {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("agent decision ledger decisions[{index}].decisionId"),
            &self.decision_id,
        )?;
        validate_path_component(
            &format!("agent decision ledger decisions[{index}].taskId"),
            &self.task_id,
        )?;
        validate_path_component(
            &format!("agent decision ledger decisions[{index}].role"),
            &self.role,
        )?;
        validate_path_component(
            &format!("agent decision ledger decisions[{index}].actorId"),
            &self.actor_id,
        )?;
        require_text(
            &format!("agent decision ledger decisions[{index}].rationale"),
            &self.rationale,
        )?;
        validate_nonempty_refs(
            &format!("agent decision ledger decisions[{index}].evidenceRefs"),
            &self.evidence_refs,
        )?;
        if self.alternatives_rejected.is_empty() {
            return Err(anyhow!(
                "agent decision ledger decisions[{index}].alternativesRejected must not be empty"
            ));
        }
        for (alternative_index, alternative) in self.alternatives_rejected.iter().enumerate() {
            alternative.validate_schema(index, alternative_index)?;
        }
        require_text(
            &format!("agent decision ledger decisions[{index}].timestamp"),
            &self.timestamp,
        )?;
        if !self.timestamp.contains('T') || !self.timestamp.ends_with('Z') {
            return Err(anyhow!(
                "agent decision ledger decisions[{index}].timestamp must be UTC RFC3339-like text"
            ));
        }
        validate_optional_text_list(
            &format!("agent decision ledger decisions[{index}].blockedReasons"),
            &self.blocked_reasons,
        )?;
        if matches!(self.outcome, AgentDecisionOutcome::Blocked) && self.blocked_reasons.is_empty()
        {
            return Err(anyhow!(
                "blocked agent decision ledger decisions[{index}] requires blockedReasons"
            ));
        }
        Ok(())
    }
}

impl AgentDecisionRejectedAlternative {
    fn validate_schema(&self, decision_index: usize, alternative_index: usize) -> Result<()> {
        validate_path_component(
            &format!(
                "agent decision ledger decisions[{decision_index}].alternativesRejected[{alternative_index}].id"
            ),
            &self.id,
        )?;
        require_text(
            &format!(
                "agent decision ledger decisions[{decision_index}].alternativesRejected[{alternative_index}].summary"
            ),
            &self.summary,
        )?;
        require_text(
            &format!(
                "agent decision ledger decisions[{decision_index}].alternativesRejected[{alternative_index}].rejectionReason"
            ),
            &self.rejection_reason,
        )
    }
}

impl AgentDecisionLedgerPipelineRefs {
    fn validate_schema(&self) -> Result<()> {
        self.task_board_ref
            .validate("agent decision ledger pipelineRefs.taskBoardRef")?;
        validate_nonempty_refs(
            "agent decision ledger pipelineRefs.workPackageRefs",
            &self.work_package_refs,
        )?;
        validate_nonempty_refs(
            "agent decision ledger pipelineRefs.handoffRefs",
            &self.handoff_refs,
        )?;
        validate_nonempty_refs(
            "agent decision ledger pipelineRefs.reviewGateRefs",
            &self.review_gate_refs,
        )?;
        validate_nonempty_refs(
            "agent decision ledger pipelineRefs.qaResultRefs",
            &self.qa_result_refs,
        )?;
        validate_nonempty_refs(
            "agent decision ledger pipelineRefs.performanceRegressionRefs",
            &self.performance_regression_refs,
        )?;
        validate_nonempty_refs(
            "agent decision ledger pipelineRefs.evidenceBundleRefs",
            &self.evidence_bundle_refs,
        )
    }
}

impl AgentDecisionLedgerReadModel {
    pub fn from_ledger(ledger: &AgentDecisionLedger) -> Self {
        let mut linked_task_ids = ledger
            .decisions
            .iter()
            .map(|decision| decision.task_id.clone())
            .collect::<Vec<_>>();
        linked_task_ids.sort();
        linked_task_ids.dedup();

        let mut blockers = Vec::new();
        blockers.extend(ledger.stale_refs.iter().cloned());
        for decision in &ledger.decisions {
            blockers.extend(
                decision
                    .blocked_reasons
                    .iter()
                    .map(|reason| format!("{}: {reason}", decision.decision_id)),
            );
        }
        if ledger.status == AgentDecisionLedgerStatus::AppendOnlyViolation {
            blockers.extend(ledger.malformed_reasons.iter().cloned());
        }

        Self {
            schema_version: AGENT_DECISION_LEDGER_READ_MODEL_SCHEMA_VERSION.to_string(),
            ledger_id: ledger.ledger_id.clone(),
            milestone: ledger.milestone.clone(),
            status: ledger.status.as_str().to_string(),
            decision_count: ledger.decisions.len(),
            accepted_count: ledger
                .decisions
                .iter()
                .filter(|decision| decision.outcome == AgentDecisionOutcome::Accepted)
                .count(),
            rejected_count: ledger
                .decisions
                .iter()
                .filter(|decision| decision.outcome == AgentDecisionOutcome::Rejected)
                .count(),
            deferred_count: ledger
                .decisions
                .iter()
                .filter(|decision| decision.outcome == AgentDecisionOutcome::Deferred)
                .count(),
            blocked_count: ledger
                .decisions
                .iter()
                .filter(|decision| decision.outcome == AgentDecisionOutcome::Blocked)
                .count(),
            superseded_count: ledger
                .decisions
                .iter()
                .filter(|decision| decision.outcome == AgentDecisionOutcome::Superseded)
                .count(),
            evidence_ref_count: ledger
                .decisions
                .iter()
                .map(|decision| decision.evidence_refs.len())
                .sum(),
            rejected_alternative_count: ledger
                .decisions
                .iter()
                .map(|decision| decision.alternatives_rejected.len())
                .sum(),
            linked_task_ids,
            work_package_ref_paths: artifact_ref_paths(&ledger.pipeline_refs.work_package_refs),
            handoff_ref_paths: artifact_ref_paths(&ledger.pipeline_refs.handoff_refs),
            review_gate_ref_paths: artifact_ref_paths(&ledger.pipeline_refs.review_gate_refs),
            qa_result_ref_paths: artifact_ref_paths(&ledger.pipeline_refs.qa_result_refs),
            performance_regression_ref_paths: artifact_ref_paths(
                &ledger.pipeline_refs.performance_regression_refs,
            ),
            evidence_bundle_ref_paths: artifact_ref_paths(&ledger.pipeline_refs.evidence_bundle_refs),
            append_only_sequence: ledger.append_only.sequence,
            append_only_hash: ledger.append_only.entry_order_hash.clone(),
            stale_refs: ledger.stale_refs.clone(),
            blockers,
            malformed_reasons: ledger.malformed_reasons.clone(),
            boundary: "Read-only agent decision ledger summary; it links decisions to task, work package, handoff, review, QA, regression, and evidence-bundle refs without executing commands, spawning agents, applying changes, writing trusted browser state, auto-merging, self-approving, or repairing append-only drift.".to_string(),
        }
    }

    fn malformed(reason: String) -> Self {
        Self {
            schema_version: AGENT_DECISION_LEDGER_READ_MODEL_SCHEMA_VERSION.to_string(),
            ledger_id: "malformed-agent-decision-ledger".to_string(),
            milestone: "malformed-agent-decision-ledger".to_string(),
            status: "malformed".to_string(),
            decision_count: 0,
            accepted_count: 0,
            rejected_count: 0,
            deferred_count: 0,
            blocked_count: 0,
            superseded_count: 0,
            evidence_ref_count: 0,
            rejected_alternative_count: 0,
            linked_task_ids: Vec::new(),
            work_package_ref_paths: Vec::new(),
            handoff_ref_paths: Vec::new(),
            review_gate_ref_paths: Vec::new(),
            qa_result_ref_paths: Vec::new(),
            performance_regression_ref_paths: Vec::new(),
            evidence_bundle_ref_paths: Vec::new(),
            append_only_sequence: 0,
            append_only_hash: String::new(),
            stale_refs: Vec::new(),
            blockers: Vec::new(),
            malformed_reasons: vec![reason],
            boundary: "Read-only malformed agent decision ledger summary; it reports validation errors without executing commands, spawning agents, applying changes, writing trusted state, auto-merging, or self-approving.".to_string(),
        }
    }
}

impl AgentDecisionLedgerStatus {
    pub fn as_str(self) -> &'static str {
        match self {
            AgentDecisionLedgerStatus::Active => "active",
            AgentDecisionLedgerStatus::Stale => "stale",
            AgentDecisionLedgerStatus::Malformed => "malformed",
            AgentDecisionLedgerStatus::AppendOnlyViolation => "append-only-violation",
        }
    }
}

fn artifact_ref_paths(refs: &[AuthoringLoopArtifactRef]) -> Vec<String> {
    refs.iter()
        .map(|reference| reference.path.clone())
        .collect()
}

impl AgentDecisionLedgerAppendOnly {
    fn validate_schema(&self) -> Result<()> {
        require_text(
            "agent decision ledger appendOnly.entryOrderHash",
            &self.entry_order_hash,
        )?;
        validate_ledger_hash_text(
            "agent decision ledger appendOnly.entryOrderHash",
            &self.entry_order_hash,
        )?;
        if let Some(previous) = &self.previous_ledger_hash {
            require_text(
                "agent decision ledger appendOnly.previousLedgerHash",
                previous,
            )?;
            validate_ledger_hash_text(
                "agent decision ledger appendOnly.previousLedgerHash",
                previous,
            )?;
        }
        require_text("agent decision ledger appendOnly.note", &self.note)?;
        if !self.note.to_ascii_lowercase().contains("append-only") {
            return Err(anyhow!(
                "agent decision ledger appendOnly.note must describe append-only semantics"
            ));
        }
        Ok(())
    }
}

fn artifact_refs_match(left: &AuthoringLoopArtifactRef, right: &AuthoringLoopArtifactRef) -> bool {
    left.id == right.id && left.path == right.path
}

fn validate_ledger_hash_text(field: &str, value: &str) -> Result<()> {
    let Some(hex) = value.strip_prefix("fnv1a64-ledger-v1:") else {
        return Err(anyhow!(
            "{field} must use fnv1a64-ledger-v1:<16-hex> format"
        ));
    };
    if hex.len() != 16 || !hex.chars().all(|ch| ch.is_ascii_hexdigit()) {
        return Err(anyhow!(
            "{field} must use fnv1a64-ledger-v1:<16-hex> format"
        ));
    }
    Ok(())
}

