impl ProductionEvidenceBundleConflict {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("production evidence bundle unresolvedConflicts[{index}].id"),
            &self.id,
        )?;
        require_text(
            &format!("production evidence bundle unresolvedConflicts[{index}].summary"),
            &self.summary,
        )?;
        validate_nonempty_refs(
            &format!("production evidence bundle unresolvedConflicts[{index}].ownershipRefs"),
            &self.ownership_refs,
        )?;
        require_text(
            &format!("production evidence bundle unresolvedConflicts[{index}].safeNextAction"),
            &self.safe_next_action,
        )
    }
}

impl ProductionEvidenceBundleMissingReview {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("production evidence bundle missingReviews[{index}].id"),
            &self.id,
        )?;
        self.work_package_ref.validate(&format!(
            "production evidence bundle missingReviews[{index}].workPackageRef"
        ))?;
        validate_path_component(
            &format!("production evidence bundle missingReviews[{index}].requiredReviewerRole"),
            &self.required_reviewer_role,
        )
    }
}

impl ProductionEvidenceBundleLaneOutput {
    fn validate_schema(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("production evidence bundle laneOutputs[{index}].id"),
            &self.id,
        )?;
        validate_nonempty_refs(
            &format!("production evidence bundle laneOutputs[{index}].evidenceRefs"),
            &self.evidence_refs,
        )?;
        validate_optional_text_list(
            &format!("production evidence bundle laneOutputs[{index}].blockedReasons"),
            &self.blocked_reasons,
        )?;
        if self.status == ProductionEvidenceBundleLaneStatus::Blocked
            && self.blocked_reasons.is_empty()
        {
            return Err(anyhow!(
                "production evidence bundle laneOutputs[{index}] blocked status requires blockedReasons"
            ));
        }
        Ok(())
    }
}

fn validate_nonempty_refs(field: &str, refs: &[AuthoringLoopArtifactRef]) -> Result<()> {
    if refs.is_empty() {
        return Err(anyhow!("{field} must not be empty"));
    }
    for (index, reference) in refs.iter().enumerate() {
        reference.validate(&format!("{field}[{index}]"))?;
    }
    Ok(())
}

fn validate_optional_refs(field: &str, refs: &[AuthoringLoopArtifactRef]) -> Result<()> {
    for (index, reference) in refs.iter().enumerate() {
        reference.validate(&format!("{field}[{index}]"))?;
    }
    Ok(())
}

fn validate_unique_bundle_ref_id(
    field: &str,
    reference: &AuthoringLoopArtifactRef,
    ids: &mut BTreeSet<String>,
) -> Result<()> {
    if !ids.insert(reference.id.clone()) {
        return Err(anyhow!(
            "production evidence bundle duplicate artifact ref id at {field}: {}",
            reference.id
        ));
    }
    Ok(())
}

fn validate_optional_text_list(field: &str, values: &[String]) -> Result<()> {
    for (index, value) in values.iter().enumerate() {
        require_text(&format!("{field}[{index}]"), value)?;
    }
    Ok(())
}

impl AgentWorkPackageReadModel {
    pub fn from_package(package: &AgentWorkPackage) -> Self {
        let blockers = if package.blocked_reasons.is_empty() {
            Vec::new()
        } else {
            package
                .blocked_reasons
                .iter()
                .map(|reason| format!("{}: {reason}", package.work_package_id))
                .collect()
        };
        Self {
            schema_version: AGENT_WORK_PACKAGE_READ_MODEL_SCHEMA_VERSION.to_string(),
            work_package_id: package.work_package_id.clone(),
            task_id: package.task_id.clone(),
            role: package.role.clone(),
            status: package.status.as_str().to_string(),
            allowed_artifact_count: package.allowed_artifacts.len(),
            acceptance_criterion_count: package.acceptance_criteria.len(),
            expected_evidence_count: package.expected_evidence.len(),
            verification_command_count: package.verification_commands.len(),
            blockers,
            ownership_refs: package
                .ownership_refs
                .iter()
                .map(|reference| reference.path.clone())
                .collect(),
            handoff_target_path: package.handoff_target.path.clone(),
            state_snapshot_path: package
                .state_snapshot_ref
                .as_ref()
                .map(|reference| reference.path.clone()),
            malformed_reasons: Vec::new(),
            boundary: "Read-only agent work package summary; it reports status, blockers, evidence counts, ownership refs, and handoff target without executing commands, spawning hidden agents, applying changes, writing trusted browser state, auto-merging, or self-approving.".to_string(),
        }
    }

    fn malformed(reason: String) -> Self {
        Self {
            schema_version: AGENT_WORK_PACKAGE_READ_MODEL_SCHEMA_VERSION.to_string(),
            work_package_id: "malformed-agent-work-package".to_string(),
            task_id: "malformed-agent-work-package".to_string(),
            role: "unknown".to_string(),
            status: "malformed".to_string(),
            allowed_artifact_count: 0,
            acceptance_criterion_count: 0,
            expected_evidence_count: 0,
            verification_command_count: 0,
            blockers: Vec::new(),
            ownership_refs: Vec::new(),
            handoff_target_path: String::new(),
            state_snapshot_path: None,
            malformed_reasons: vec![reason],
            boundary: "Read-only malformed agent work package summary; it reports validation errors without executing commands, spawning agents, applying changes, writing trusted state, auto-merging, or self-approving.".to_string(),
        }
    }
}

impl AgentWorkPackageStatus {
    pub fn as_str(self) -> &'static str {
        match self {
            AgentWorkPackageStatus::Assigned => "assigned",
            AgentWorkPackageStatus::Blocked => "blocked",
            AgentWorkPackageStatus::Stale => "stale",
            AgentWorkPackageStatus::ReadyForReview => "ready-for-review",
            AgentWorkPackageStatus::Completed => "completed",
        }
    }
}

pub const STUDIO_MULTI_AGENT_PIPELINE_INSPECTION_READ_MODEL_SCHEMA_VERSION: &str =
    "studio-multi-agent-pipeline-inspection-read-model-v1";

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct StudioMultiAgentPipelineInspectionReadModel {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub status: String,
    pub sections: Vec<StudioMultiAgentPipelineInspectionSection>,
    #[serde(rename = "malformedReasons")]
    pub malformed_reasons: Vec<String>,
    pub boundary: String,
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct StudioMultiAgentPipelineInspectionSection {
    pub id: String,
    pub label: String,
    pub status: String,
    #[serde(rename = "itemCount")]
    pub item_count: usize,
    pub blockers: Vec<String>,
    #[serde(rename = "malformedReasons")]
    pub malformed_reasons: Vec<String>,
}

pub fn studio_multi_agent_pipeline_inspection_read_model_from_json_str(
    input: &str,
) -> StudioMultiAgentPipelineInspectionReadModel {
    match serde_json::from_str::<serde_json::Value>(input) {
        Ok(value) => StudioMultiAgentPipelineInspectionReadModel::from_value(&value),
        Err(error) => StudioMultiAgentPipelineInspectionReadModel::malformed(format!(
            "pipeline inspection input must be JSON: {error:#}"
        )),
    }
}

