impl AgentHandoffContract {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let handoff: AgentHandoffContract =
            serde_json::from_str(input).context("failed to parse Agent Handoff Contract JSON")?;
        handoff.validate_schema()?;
        Ok(handoff)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != AGENT_HANDOFF_CONTRACT_SCHEMA_VERSION {
            return Err(anyhow!(
                "agent handoff schemaVersion must be {AGENT_HANDOFF_CONTRACT_SCHEMA_VERSION}"
            ));
        }
        // `stale` is an agent-handoff-v2-only status. The AgentHandoffStatus enum
        // is shared with v2, so reject it here to preserve the v1 accepted set
        // (ready, blocked, failed, completed) and keep v1 compatibility intact.
        if self.status == AgentHandoffStatus::Stale {
            return Err(anyhow!(
                "agent handoff status 'stale' is not valid for {AGENT_HANDOFF_CONTRACT_SCHEMA_VERSION}; it is an agent-handoff-v2 status"
            ));
        }
        validate_path_component("agent handoff loopId", &self.loop_id)?;
        if let Some(step) = &self.current_step {
            step.validate()?;
        }
        validate_safe_handoff_text("agent handoff nextSafeAction", &self.next_safe_action)?;
        if matches!(
            self.status,
            AgentHandoffStatus::Blocked | AgentHandoffStatus::Failed
        ) && self.blockers.is_empty()
        {
            return Err(anyhow!(
                "blocked or failed agent handoff must list blockers"
            ));
        }
        for (index, decision) in self.required_decisions.iter().enumerate() {
            decision.validate(&format!("agent handoff requiredDecisions[{index}]"))?;
        }
        for (index, blocker) in self.blockers.iter().enumerate() {
            require_text(&format!("agent handoff blockers[{index}]"), blocker)?;
        }
        for (index, command) in self.allowed_commands.iter().enumerate() {
            command.validate(&format!("agent handoff allowedCommands[{index}]"))?;
            let boundary = command.boundary.to_ascii_lowercase();
            if !(boundary.contains("inert") || boundary.contains("does not execute")) {
                return Err(anyhow!(
                    "agent handoff allowedCommands[{index}].boundary must state commands are inert or do not execute"
                ));
            }
        }
        validate_nonempty_text_list("agent handoff forbiddenActions", &self.forbidden_actions)?;
        validate_nonempty_text_list("agent handoff driftGuardrails", &self.drift_guardrails)?;
        for (index, evidence_ref) in self.evidence_refs.iter().enumerate() {
            evidence_ref.validate(&format!("agent handoff evidenceRefs[{index}]"))?;
        }
        self.generated_state.validate()?;
        require_text("agent handoff boundary", &self.boundary)?;
        let boundary = self.boundary.to_ascii_lowercase();
        if !(boundary.contains("advisory") && boundary.contains("does not execute")) {
            return Err(anyhow!(
                "agent handoff boundary must state advisory evidence and does not execute"
            ));
        }
        Ok(())
    }
}

impl AgentHandoffV2 {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let handoff: AgentHandoffV2 =
            serde_json::from_str(input).context("failed to parse Agent Handoff v2 JSON")?;
        handoff.validate_schema()?;
        Ok(handoff)
    }

    pub fn validate_schema(&self) -> Result<()> {
        if self.schema_version != AGENT_HANDOFF_V2_SCHEMA_VERSION {
            return Err(anyhow!(
                "agent handoff v2 schemaVersion must be {AGENT_HANDOFF_V2_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("agent handoff v2 handoffId", &self.handoff_id)?;
        validate_path_component("agent handoff v2 fromRole", &self.from_role)?;
        validate_path_component("agent handoff v2 toRole", &self.to_role)?;
        if !SUPPORTED_AGENT_ROLES.contains(&self.from_role.as_str()) {
            return Err(anyhow!(
                "agent handoff v2 fromRole '{}' is unsupported",
                self.from_role
            ));
        }
        if !SUPPORTED_AGENT_ROLES.contains(&self.to_role.as_str()) {
            return Err(anyhow!(
                "agent handoff v2 toRole '{}' is unsupported",
                self.to_role
            ));
        }
        validate_path_component("agent handoff v2 taskId", &self.task_id)?;
        validate_nonempty_path_component_list(
            "agent handoff v2 knownTaskIds",
            &self.known_task_ids,
        )?;
        if !self
            .known_task_ids
            .iter()
            .any(|task_id| task_id == &self.task_id)
        {
            return Err(anyhow!(
                "agent handoff v2 taskId {} is not listed in knownTaskIds",
                self.task_id
            ));
        }
        validate_agent_handoff_v2_role_transition(&self.from_role, &self.to_role)?;

        let mut artifact_ids = BTreeSet::new();
        let mut artifact_paths = BTreeSet::new();
        for (index, artifact_ref) in self.artifact_refs.iter().enumerate() {
            if !artifact_ids.insert(artifact_ref.id.as_str()) {
                return Err(anyhow!(
                    "agent handoff v2 duplicate artifactRefs id: {}",
                    artifact_ref.id
                ));
            }
            if !artifact_paths.insert(artifact_ref.path.as_str()) {
                return Err(anyhow!(
                    "agent handoff v2 duplicate artifactRefs path: {}",
                    artifact_ref.path
                ));
            }
            artifact_ref.validate(&format!("agent handoff v2 artifactRefs[{index}]"))?;
        }
        if self.artifact_refs.is_empty() {
            return Err(anyhow!("agent handoff v2 artifactRefs must not be empty"));
        }
        validate_nonempty_text_list("agent handoff v2 assumptions", &self.assumptions)?;
        for (index, decision) in self.decisions.iter().enumerate() {
            decision.validate(&format!("agent handoff v2 decisions[{index}]"))?;
        }
        let mut evidence_ids = BTreeSet::new();
        let mut evidence_paths = BTreeSet::new();
        for (index, evidence_ref) in self.evidence_links.iter().enumerate() {
            evidence_ref.validate(&format!("agent handoff v2 evidenceLinks[{index}]"))?;
            if !evidence_ids.insert(evidence_ref.id.as_str()) {
                return Err(anyhow!(
                    "agent handoff v2 duplicate evidenceLinks id: {}",
                    evidence_ref.id
                ));
            }
            if !evidence_paths.insert(evidence_ref.path.as_str()) {
                return Err(anyhow!(
                    "agent handoff v2 duplicate evidenceLinks path: {}",
                    evidence_ref.path
                ));
            }
        }
        if self.evidence_links.is_empty() {
            return Err(anyhow!("agent handoff v2 evidenceLinks must not be empty"));
        }
        for (index, risk) in self.open_risks.iter().enumerate() {
            risk.validate(index)?;
        }
        for (index, item) in self.acceptance_checklist.iter().enumerate() {
            item.validate(index)?;
        }
        if self.acceptance_checklist.is_empty() {
            return Err(anyhow!(
                "agent handoff v2 acceptanceChecklist must not be empty"
            ));
        }
        let mut stale_ids = BTreeSet::new();
        for (index, indicator) in self.stale_state_indicators.iter().enumerate() {
            indicator.validate(index)?;
            if !stale_ids.insert(indicator.id.as_str()) {
                return Err(anyhow!(
                    "agent handoff v2 duplicate staleStateIndicators id: {}",
                    indicator.id
                ));
            }
            if !(artifact_paths.contains(indicator.artifact_ref.path.as_str())
                || evidence_paths.contains(indicator.artifact_ref.path.as_str()))
            {
                return Err(anyhow!(
                    "agent handoff v2 stale artifact ref {} must be listed in artifactRefs or evidenceLinks",
                    indicator.artifact_ref.path
                ));
            }
        }
        if self.status == AgentHandoffStatus::Stale && self.stale_state_indicators.is_empty() {
            return Err(anyhow!(
                "stale agent handoff v2 must list staleStateIndicators"
            ));
        }
        if self.status == AgentHandoffStatus::Blocked && self.open_risks.is_empty() {
            return Err(anyhow!("blocked agent handoff v2 must list openRisks"));
        }
        validate_safe_handoff_text(
            "agent handoff v2 nextRecommendedAction",
            &self.next_recommended_action,
        )?;
        validate_nonempty_text_list("agent handoff v2 forbiddenActions", &self.forbidden_actions)?;
        self.generated_state.validate()?;
        if let Some(compatibility) = &self.v1_compatibility {
            compatibility.validate()?;
        }
        require_text("agent handoff v2 boundary", &self.boundary)?;
        let boundary = self.boundary.to_ascii_lowercase();
        if !(boundary.contains("advisory") && boundary.contains("does not execute")) {
            return Err(anyhow!(
                "agent handoff v2 boundary must state advisory evidence and does not execute"
            ));
        }
        Ok(())
    }
}

fn validate_nonempty_path_component_list(field: &str, values: &[String]) -> Result<()> {
    if values.is_empty() {
        return Err(anyhow!("{field} must not be empty"));
    }
    let mut seen = BTreeSet::new();
    for value in values {
        validate_path_component(field, value)?;
        if !seen.insert(value) {
            return Err(anyhow!("duplicate {field}: {value}"));
        }
    }
    Ok(())
}

fn validate_agent_handoff_v2_role_transition(from_role: &str, to_role: &str) -> Result<()> {
    let allowed = matches!(
        (from_role, to_role),
        ("designer", "reviewer")
            | ("level-designer", "reviewer")
            | ("gameplay-engineer", "reviewer")
            | ("asset-import-planner", "reviewer")
            | ("reviewer", "critic")
            | ("critic", "reviewer")
            | ("reviewer", "qa-agent")
            | ("qa-agent", "performance-regression-agent")
            | (
                "performance-regression-agent",
                "build-release-candidate-agent"
            )
            | ("build-release-candidate-agent", "reviewer")
    );
    if !allowed {
        return Err(anyhow!(
            "agent handoff v2 unsupported role transition from {from_role} to {to_role}"
        ));
    }
    Ok(())
}

impl AgentHandoffRisk {
    fn validate(&self, index: usize) -> Result<()> {
        validate_path_component(&format!("agent handoff v2 openRisks[{index}].id"), &self.id)?;
        validate_path_component(
            &format!("agent handoff v2 openRisks[{index}].severity"),
            &self.severity,
        )?;
        require_text(
            &format!("agent handoff v2 openRisks[{index}].description"),
            &self.description,
        )?;
        require_text(
            &format!("agent handoff v2 openRisks[{index}].mitigation"),
            &self.mitigation,
        )
    }
}

