impl QaAgentWorkQueueArtifact {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let artifact: QaAgentWorkQueueArtifact =
            serde_json::from_str(input).context("failed to parse QA Agent Work Queue JSON")?;
        artifact.validate()?;
        Ok(artifact)
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != QA_AGENT_WORK_QUEUE_SCHEMA_VERSION {
            return Err(anyhow!(
                "qa agent work queue schemaVersion must be {QA_AGENT_WORK_QUEUE_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("qa agent work queue queueId", &self.queue_id)?;
        require_text("qa agent work queue milestone", &self.milestone)?;
        if self.items.is_empty() {
            return Err(anyhow!("qa agent work queue items must not be empty"));
        }
        let mut item_ids = BTreeSet::new();
        self.generated_state.validate()?;
        for (index, item) in self.items.iter().enumerate() {
            item.validate(index, &self.generated_state)?;
            if !item_ids.insert(item.queue_item_id.as_str()) {
                return Err(anyhow!(
                    "duplicate qa agent work queue queueItemId: {}",
                    item.queue_item_id
                ));
            }
        }
        validate_nonempty_text_list("qa agent work queue guardrails", &self.guardrails)?;
        validate_nonempty_text_list(
            "qa agent work queue forbiddenActions",
            &self.forbidden_actions,
        )?;
        require_text("qa agent work queue boundary", &self.boundary)?;
        self.validate_guardrails()
    }

    fn validate_guardrails(&self) -> Result<()> {
        let forbidden = self.forbidden_actions.join(" ").to_ascii_lowercase();
        for phrase in [
            "hidden background agents",
            "unbounded spawning",
            "auto-apply",
            "auto-merge",
            "self-approval",
            "reviewer bypass",
            "browser command bridge",
            "trusted browser writes",
            "remote worker pool",
            "production readiness",
            "Godot replacement",
        ] {
            if !forbidden.contains(&phrase.to_ascii_lowercase()) {
                return Err(anyhow!(
                    "qa agent work queue forbiddenActions must include {phrase} boundary"
                ));
            }
        }
        let boundary = self.boundary.to_ascii_lowercase();
        for phrase in [
            "does not execute commands",
            "does not spawn agents",
            "does not mutate trusted files",
            "does not write trusted browser state",
            "does not auto-apply",
            "does not auto-merge",
            "does not self-approve",
            "does not claim production readiness",
            "does not claim godot replacement",
        ] {
            if !boundary.contains(phrase) {
                return Err(anyhow!(
                    "qa agent work queue boundary must state it {phrase}"
                ));
            }
        }
        Ok(())
    }
}

impl QaAgentWorkQueueItem {
    fn validate(
        &self,
        index: usize,
        generated_state: &AuthoringLoopGeneratedStatePolicy,
    ) -> Result<()> {
        validate_path_component(
            &format!("qa agent work queue items[{index}].queueItemId"),
            &self.queue_item_id,
        )?;
        self.scenario_target.validate(&format!(
            "qa agent work queue items[{index}].scenarioTarget"
        ))?;
        self.risk_area
            .validate(&format!("qa agent work queue items[{index}].riskArea"))?;
        self.run_command_context.validate(&format!(
            "qa agent work queue items[{index}].runCommandContext"
        ))?;
        validate_nonempty_refs(
            &format!("qa agent work queue items[{index}].expectedEvidence"),
            &self.expected_evidence,
        )?;
        self.validate_expected_evidence(index, generated_state)?;
        validate_path_component(
            &format!("qa agent work queue items[{index}].assignedRole"),
            &self.assigned_role,
        )?;
        validate_path_component(
            &format!("qa agent work queue items[{index}].assignedAgent"),
            &self.assigned_agent,
        )?;
        self.task_ref
            .validate(&format!("qa agent work queue items[{index}].taskRef"))?;
        self.work_package_ref.validate(&format!(
            "qa agent work queue items[{index}].workPackageRef"
        ))?;
        if let Some(reference) = &self.review_gate_ref {
            reference.validate(&format!("qa agent work queue items[{index}].reviewGateRef"))?;
        }
        validate_optional_refs(
            &format!("qa agent work queue items[{index}].runEvidenceRefs"),
            &self.run_evidence_refs,
        )?;
        validate_optional_refs(
            &format!("qa agent work queue items[{index}].evaluatorEvidenceRefs"),
            &self.evaluator_evidence_refs,
        )?;
        validate_optional_text_list(
            &format!("qa agent work queue items[{index}].blockedReasons"),
            &self.blocked_reasons,
        )?;
        self.validate_stale_run_refs(index, generated_state)?;
        if let Some(transition) = &self.status_transition {
            transition.validate(index, self.status)?;
        }
        self.validate_status_shape()
    }

    fn validate_expected_evidence(
        &self,
        index: usize,
        generated_state: &AuthoringLoopGeneratedStatePolicy,
    ) -> Result<()> {
        let mut expected_ids = BTreeSet::new();
        let mut expected_paths = BTreeSet::new();
        for (evidence_index, reference) in self.expected_evidence.iter().enumerate() {
            if !expected_ids.insert(reference.id.as_str()) {
                return Err(anyhow!(
                    "duplicate qa agent work queue items[{index}].expectedEvidence id: {}",
                    reference.id
                ));
            }
            if !expected_paths.insert(reference.path.as_str()) {
                return Err(anyhow!(
                    "duplicate qa agent work queue items[{index}].expectedEvidence path: {}",
                    reference.path
                ));
            }
            if !generated_state.roots.iter().any(|root| {
                reference.path == *root || reference.path.starts_with(&format!("{root}/"))
            }) {
                return Err(anyhow!(
                    "qa agent work queue items[{index}].expectedEvidence[{evidence_index}] must stay under generated QA roots"
                ));
            }
        }
        let expected_text = self
            .expected_evidence
            .iter()
            .map(|reference| {
                format!(
                    "{} {} {}",
                    reference.id,
                    reference.path,
                    reference.description.clone().unwrap_or_default()
                )
            })
            .collect::<Vec<_>>()
            .join(" ")
            .to_ascii_lowercase();
        if !expected_text.contains("scenario") || !expected_text.contains("evaluator") {
            return Err(anyhow!(
                "qa agent work queue items[{index}].expectedEvidence must include scenario and evaluator evidence expectations"
            ));
        }
        for (field, refs) in [
            ("runEvidenceRefs", self.run_evidence_refs.as_slice()),
            (
                "evaluatorEvidenceRefs",
                self.evaluator_evidence_refs.as_slice(),
            ),
        ] {
            for (ref_index, reference) in refs.iter().enumerate() {
                if !generated_state.roots.iter().any(|root| {
                    reference.path == *root || reference.path.starts_with(&format!("{root}/"))
                }) {
                    return Err(anyhow!(
                        "qa agent work queue items[{index}].{field}[{ref_index}] must stay under generated QA roots"
                    ));
                }
            }
        }
        Ok(())
    }

    fn validate_stale_run_refs(
        &self,
        index: usize,
        generated_state: &AuthoringLoopGeneratedStatePolicy,
    ) -> Result<()> {
        validate_optional_text_list(
            &format!("qa agent work queue items[{index}].staleRunRefs"),
            &self.stale_run_refs,
        )?;
        let live_run_paths = self
            .run_evidence_refs
            .iter()
            .map(|reference| reference.path.as_str())
            .chain(
                self.evaluator_evidence_refs
                    .iter()
                    .map(|reference| reference.path.as_str()),
            )
            .collect::<BTreeSet<_>>();
        let mut stale_paths = BTreeSet::new();
        for (stale_index, stale_ref) in self.stale_run_refs.iter().enumerate() {
            validate_project_manifest_path(
                &format!("qa agent work queue items[{index}].staleRunRefs[{stale_index}]"),
                stale_ref,
            )?;
            if !generated_state
                .roots
                .iter()
                .any(|root| stale_ref == root || stale_ref.starts_with(&format!("{root}/")))
            {
                return Err(anyhow!(
                    "qa agent work queue items[{index}].staleRunRefs[{stale_index}] must stay under generated QA roots"
                ));
            }
            if !stale_paths.insert(stale_ref.as_str()) {
                return Err(anyhow!(
                    "duplicate qa agent work queue items[{index}].staleRunRefs path: {stale_ref}"
                ));
            }
            if live_run_paths.contains(stale_ref.as_str()) {
                return Err(anyhow!(
                    "qa agent work queue items[{index}].staleRunRefs[{stale_index}] must not duplicate current evidence refs"
                ));
            }
        }
        Ok(())
    }

    fn validate_status_shape(&self) -> Result<()> {
        match self.status {
            QaAgentQueueStatus::Pass => {
                if self.failure_classification.is_some()
                    || !self.blocked_reasons.is_empty()
                    || !self.stale_run_refs.is_empty()
                {
                    return Err(anyhow!(
                        "pass qa agent work queue item must not include failureClassification, blockedReasons, or staleRunRefs"
                    ));
                }
                if self.run_evidence_refs.is_empty() || self.evaluator_evidence_refs.is_empty() {
                    return Err(anyhow!(
                        "pass qa agent work queue item requires runEvidenceRefs and evaluatorEvidenceRefs"
                    ));
                }
            }
            QaAgentQueueStatus::Fail => {
                if self.failure_classification.is_none() {
                    return Err(anyhow!(
                        "fail qa agent work queue item requires failureClassification"
                    ));
                }
                if self.run_evidence_refs.is_empty() || self.evaluator_evidence_refs.is_empty() {
                    return Err(anyhow!(
                        "fail qa agent work queue item requires runEvidenceRefs and evaluatorEvidenceRefs"
                    ));
                }
            }
            QaAgentQueueStatus::Deferred | QaAgentQueueStatus::Blocked => {
                if self.blocked_reasons.is_empty() {
                    return Err(anyhow!(
                        "deferred or blocked qa agent work queue item requires blockedReasons"
                    ));
                }
            }
            QaAgentQueueStatus::Flaky => {
                if self.failure_classification != Some(QaAgentFailureClassification::Flaky) {
                    return Err(anyhow!(
                        "flaky qa agent work queue item requires flaky failureClassification"
                    ));
                }
                if self.run_evidence_refs.len() < 2 {
                    return Err(anyhow!(
                        "flaky qa agent work queue item requires multiple runEvidenceRefs"
                    ));
                }
            }
            QaAgentQueueStatus::NeedsRerun => {
                if self.failure_classification != Some(QaAgentFailureClassification::StaleRunRef) {
                    return Err(anyhow!(
                        "needs-rerun qa agent work queue item requires stale-run-ref failureClassification"
                    ));
                }
                if self.stale_run_refs.is_empty() && self.blocked_reasons.is_empty() {
                    return Err(anyhow!(
                        "needs-rerun qa agent work queue item requires staleRunRefs or blockedReasons"
                    ));
                }
            }
        }
        Ok(())
    }
}

impl QaAgentScenarioTarget {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.scenarioId"), &self.scenario_id)?;
        self.scenario_pack_ref
            .validate(&format!("{field}.scenarioPackRef"))?;
        let pack_path = self.scenario_pack_ref.path.to_ascii_lowercase();
        let pack_text = format!(
            "{} {} {}",
            self.scenario_pack_ref.id,
            self.scenario_pack_ref.path,
            self.scenario_pack_ref
                .description
                .clone()
                .unwrap_or_default()
        )
        .to_ascii_lowercase();
        if !pack_text.contains("scenario") {
            return Err(anyhow!(
                "{field}.scenarioPackRef must identify a scenario pack target"
            ));
        }
        if !(pack_path.ends_with(".json") || pack_path.ends_with(".scenarios.json")) {
            return Err(anyhow!(
                "{field}.scenarioPackRef path must point to a JSON scenario pack"
            ));
        }
        if pack_path.starts_with("runs/") || pack_path.starts_with("dashboard-data/") {
            return Err(anyhow!(
                "{field}.scenarioPackRef must not point at generated run or dashboard state"
            ));
        }
        Ok(())
    }
}

impl QaAgentRiskArea {
    fn validate(&self, field: &str) -> Result<()> {
        validate_path_component(&format!("{field}.riskId"), &self.risk_id)?;
        validate_path_component(&format!("{field}.category"), &self.category)?;
        require_bounded_display_text(&format!("{field}.summary"), &self.summary)
    }
}

impl QaAgentQueueStatus {
    pub fn as_str(self) -> &'static str {
        match self {
            QaAgentQueueStatus::Pass => "pass",
            QaAgentQueueStatus::Fail => "fail",
            QaAgentQueueStatus::Deferred => "deferred",
            QaAgentQueueStatus::Blocked => "blocked",
            QaAgentQueueStatus::Flaky => "flaky",
            QaAgentQueueStatus::NeedsRerun => "needs-rerun",
        }
    }

    fn can_transition_to(self, next: Self) -> bool {
        match (self, next) {
            (current, next) if current == next => true,
            (QaAgentQueueStatus::Deferred, QaAgentQueueStatus::NeedsRerun)
            | (QaAgentQueueStatus::Deferred, QaAgentQueueStatus::Blocked)
            | (QaAgentQueueStatus::Blocked, QaAgentQueueStatus::Deferred)
            | (QaAgentQueueStatus::Blocked, QaAgentQueueStatus::NeedsRerun)
            | (QaAgentQueueStatus::NeedsRerun, QaAgentQueueStatus::Pass)
            | (QaAgentQueueStatus::NeedsRerun, QaAgentQueueStatus::Fail)
            | (QaAgentQueueStatus::NeedsRerun, QaAgentQueueStatus::Flaky)
            | (QaAgentQueueStatus::NeedsRerun, QaAgentQueueStatus::Blocked)
            | (QaAgentQueueStatus::Fail, QaAgentQueueStatus::NeedsRerun)
            | (QaAgentQueueStatus::Flaky, QaAgentQueueStatus::NeedsRerun)
            | (QaAgentQueueStatus::Flaky, QaAgentQueueStatus::Fail)
            | (QaAgentQueueStatus::Flaky, QaAgentQueueStatus::Pass) => true,
            _ => false,
        }
    }
}

impl QaAgentQueueStatusTransition {
    fn validate(&self, index: usize, status: QaAgentQueueStatus) -> Result<()> {
        if self.to != status {
            return Err(anyhow!(
                "qa agent work queue items[{index}].statusTransition.to must match status"
            ));
        }
        if !self.from.can_transition_to(self.to) {
            return Err(anyhow!(
                "qa agent work queue items[{index}] invalid status transition {:?} -> {:?}",
                self.from,
                self.to
            ));
        }
        Ok(())
    }
}

impl QaAgentRunCommandContext {
    fn validate(&self, field: &str) -> Result<()> {
        require_text(&format!("{field}.command"), &self.command)?;
        if self.argv.is_empty() {
            return Err(anyhow!("{field}.argv must not be empty"));
        }
        for (index, arg) in self.argv.iter().enumerate() {
            require_text(&format!("{field}.argv[{index}]"), arg)?;
        }
        require_text(&format!("{field}.boundary"), &self.boundary)?;
        let combined = std::iter::once(self.command.as_str())
            .chain(self.argv.iter().map(String::as_str))
            .collect::<Vec<_>>()
            .join(" ")
            .to_ascii_lowercase();
        let command_tokens = combined
            .split(|ch: char| !(ch.is_ascii_alphanumeric() || ch == '-'))
            .filter(|token| !token.is_empty())
            .collect::<BTreeSet<_>>();
        for forbidden in [
            "apply",
            "apply-scene",
            "merge",
            "publish",
            "deploy",
            "install",
            "mutation",
            "add",
            "remove",
            "rm",
            "mv",
            "push",
            "commit",
            "workflow",
            "release",
            "chmod",
            "curl",
            "wget",
            "ssh",
            "scp",
            "sudo",
        ] {
            if command_tokens.contains(forbidden) {
                return Err(anyhow!(
                    "qa agent work queue runCommandContext must not request mutation, apply, merge, publish, deploy, install, credentialed, release, or file-mutating commands"
                ));
            }
        }
        for forbidden_phrase in [
            "gh pr merge",
            "gh workflow",
            "git push",
            "git commit",
            "npm install",
            "pnpm install",
            "yarn install",
            "cargo add",
            "cargo install",
        ] {
            if combined.contains(forbidden_phrase) {
                return Err(anyhow!(
                    "qa agent work queue runCommandContext must not request mutation, apply, merge, publish, deploy, install, credentialed, release, or file-mutating commands"
                ));
            }
        }
        let boundary = self.boundary.to_ascii_lowercase();
        if !(boundary.contains("inert")
            && boundary.contains("does not execute")
            && boundary.contains("does not mutate"))
        {
            return Err(anyhow!(
                "qa agent work queue runCommandContext boundary must state inert command text that does not execute or mutate"
            ));
        }
        Ok(())
    }
}

