#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "kebab-case")]
pub enum PerformanceRegressionClassification {
    Improved,
    Unchanged,
    Regressed,
    Inconclusive,
    MissingBaseline,
    Unsupported,
    Stale,
}

impl PerformanceRegressionClassification {
    pub fn as_str(self) -> &'static str {
        match self {
            PerformanceRegressionClassification::Improved => "improved",
            PerformanceRegressionClassification::Unchanged => "unchanged",
            PerformanceRegressionClassification::Regressed => "regressed",
            PerformanceRegressionClassification::Inconclusive => "inconclusive",
            PerformanceRegressionClassification::MissingBaseline => "missing-baseline",
            PerformanceRegressionClassification::Unsupported => "unsupported",
            PerformanceRegressionClassification::Stale => "stale",
        }
    }
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "kebab-case")]
pub enum PerformanceRegressionThresholdOperator {
    LessThanOrEqual,
    GreaterThanOrEqual,
    DeltaLessThanOrEqual,
    DeltaGreaterThanOrEqual,
}

#[derive(Debug, Clone, Copy, Default, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "kebab-case")]
pub enum PerformanceRegressionMetricSource {
    #[default]
    LocalRust,
    ScenarioEvaluator,
    BrowserAdvisory,
    Unsupported,
}

impl PerformanceRegressionLaneArtifact {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let artifact: PerformanceRegressionLaneArtifact = serde_json::from_str(input)
            .context("failed to parse Performance Regression Lane JSON")?;
        artifact.validate()?;
        Ok(artifact)
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != PERFORMANCE_REGRESSION_LANE_SCHEMA_VERSION {
            return Err(anyhow!(
                "performance regression lane schemaVersion must be {PERFORMANCE_REGRESSION_LANE_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("performance regression lane laneId", &self.lane_id)?;
        require_text("performance regression lane milestone", &self.milestone)?;
        self.risk_area
            .validate("performance regression lane riskArea")?;
        validate_path_component(
            "performance regression lane assignedRole",
            &self.assigned_role,
        )?;
        validate_path_component(
            "performance regression lane assignedAgent",
            &self.assigned_agent,
        )?;
        if self.classification == PerformanceRegressionClassification::MissingBaseline {
            validate_optional_refs(
                "performance regression lane baselineRuns",
                &self.baseline_runs,
            )?;
        } else {
            validate_nonempty_refs(
                "performance regression lane baselineRuns",
                &self.baseline_runs,
            )?;
        }
        validate_nonempty_refs(
            "performance regression lane comparisonRuns",
            &self.comparison_runs,
        )?;
        self.validate_stale_run_refs()?;
        if self.metrics.is_empty() {
            return Err(anyhow!(
                "performance regression lane metrics must not be empty"
            ));
        }
        let mut metric_ids = BTreeSet::new();
        for (index, metric) in self.metrics.iter().enumerate() {
            metric.validate(index)?;
            if !metric_ids.insert(metric.id.as_str()) {
                return Err(anyhow!(
                    "duplicate performance regression lane metric id: {}",
                    metric.id
                ));
            }
        }
        if self.thresholds.is_empty() {
            return Err(anyhow!(
                "performance regression lane thresholds must not be empty"
            ));
        }
        for (index, threshold) in self.thresholds.iter().enumerate() {
            threshold.validate(index, &metric_ids)?;
        }
        self.evidence_links.validate()?;
        self.validate_browser_metric_warnings()?;
        validate_optional_text_list(
            "performance regression lane blockedReasons",
            &self.blocked_reasons,
        )?;
        self.generated_state.validate()?;
        validate_nonempty_text_list("performance regression lane guardrails", &self.guardrails)?;
        validate_nonempty_text_list(
            "performance regression lane forbiddenActions",
            &self.forbidden_actions,
        )?;
        require_text("performance regression lane boundary", &self.boundary)?;
        self.validate_classification_shape()?;
        self.validate_guardrails()
    }

    fn validate_classification_shape(&self) -> Result<()> {
        match self.classification {
            PerformanceRegressionClassification::Regressed
            | PerformanceRegressionClassification::Inconclusive
            | PerformanceRegressionClassification::MissingBaseline
            | PerformanceRegressionClassification::Unsupported
            | PerformanceRegressionClassification::Stale => {
                if self.blocked_reasons.is_empty() {
                    return Err(anyhow!(
                        "performance regression lane {:?} classification requires blockedReasons",
                        self.classification
                    ));
                }
            }
            PerformanceRegressionClassification::Improved
            | PerformanceRegressionClassification::Unchanged => {}
        }
        if self.classification == PerformanceRegressionClassification::MissingBaseline
            && !self.baseline_runs.is_empty()
        {
            return Err(anyhow!(
                "performance regression lane missing-baseline classification must not include trusted baselineRuns"
            ));
        }
        if self.classification == PerformanceRegressionClassification::Stale
            && self.stale_run_refs.is_empty()
        {
            return Err(anyhow!(
                "performance regression lane stale classification requires staleRunRefs"
            ));
        }
        if self.classification != PerformanceRegressionClassification::Stale
            && !self.stale_run_refs.is_empty()
        {
            return Err(anyhow!(
                "performance regression lane staleRunRefs require stale classification"
            ));
        }
        if self.classification != PerformanceRegressionClassification::Unsupported
            && self.metrics.iter().any(|metric| {
                metric.metric_source == PerformanceRegressionMetricSource::Unsupported
            })
        {
            return Err(anyhow!(
                "performance regression lane unsupported metric sources require unsupported classification"
            ));
        }
        Ok(())
    }

    fn validate_stale_run_refs(&self) -> Result<()> {
        validate_optional_text_list(
            "performance regression lane staleRunRefs",
            &self.stale_run_refs,
        )?;
        let live_run_paths = self
            .baseline_runs
            .iter()
            .map(|reference| reference.path.as_str())
            .chain(
                self.comparison_runs
                    .iter()
                    .map(|reference| reference.path.as_str()),
            )
            .chain(
                self.evidence_links
                    .run_comparison_refs
                    .iter()
                    .map(|reference| reference.path.as_str()),
            )
            .collect::<BTreeSet<_>>();
        let mut stale_paths = BTreeSet::new();
        for (index, stale_ref) in self.stale_run_refs.iter().enumerate() {
            validate_project_manifest_path(
                &format!("performance regression lane staleRunRefs[{index}]"),
                stale_ref,
            )?;
            if !self
                .generated_state
                .roots
                .iter()
                .any(|root| stale_ref == root || stale_ref.starts_with(&format!("{root}/")))
            {
                return Err(anyhow!(
                    "performance regression lane staleRunRefs[{index}] must stay under generated performance roots"
                ));
            }
            if !stale_paths.insert(stale_ref.as_str()) {
                return Err(anyhow!(
                    "duplicate performance regression lane staleRunRefs path: {stale_ref}"
                ));
            }
            if live_run_paths.contains(stale_ref.as_str()) {
                return Err(anyhow!(
                    "performance regression lane staleRunRefs[{index}] must not duplicate current run or comparison evidence refs"
                ));
            }
        }
        Ok(())
    }

    fn validate_browser_metric_warnings(&self) -> Result<()> {
        let has_browser_metrics = self.metrics.iter().any(|metric| {
            metric.metric_source == PerformanceRegressionMetricSource::BrowserAdvisory
        });
        if !has_browser_metrics {
            return Ok(());
        }
        let warning_text = self
            .evidence_links
            .browser_metric_warnings
            .join(" ")
            .to_ascii_lowercase();
        if !(warning_text.contains("advisory")
            && warning_text.contains("rust/local validation")
            && warning_text.contains("trusted"))
        {
            return Err(anyhow!(
                "performance regression lane browser metric warnings must state browser metrics are advisory and Rust/local validation owns trusted classification"
            ));
        }
        Ok(())
    }

    fn validate_guardrails(&self) -> Result<()> {
        let forbidden = self.forbidden_actions.join(" ").to_ascii_lowercase();
        for phrase in [
            "hidden background agents",
            "unbounded spawning",
            "auto-apply",
            "auto-merge",
            "self-approval",
            "reviewer bypass",
            "browser command bridge",
            "trusted browser writes",
            "remote worker pool",
            "production readiness",
            "Godot replacement",
        ] {
            if !forbidden.contains(&phrase.to_ascii_lowercase()) {
                return Err(anyhow!(
                    "performance regression lane forbiddenActions must include {phrase} boundary"
                ));
            }
        }
        let boundary = self.boundary.to_ascii_lowercase();
        for phrase in [
            "does not execute commands",
            "does not spawn agents",
            "does not mutate trusted files",
            "does not write trusted browser state",
            "does not auto-apply",
            "does not auto-merge",
            "does not self-approve",
            "does not claim production readiness",
            "does not claim godot replacement",
        ] {
            if !boundary.contains(phrase) {
                return Err(anyhow!(
                    "performance regression lane boundary must state it {phrase}"
                ));
            }
        }
        Ok(())
    }
}

impl PerformanceRegressionMetric {
    fn validate(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("performance regression lane metrics[{index}].id"),
            &self.id,
        )?;
        validate_path_component(
            &format!("performance regression lane metrics[{index}].name"),
            &self.name,
        )?;
        require_text(
            &format!("performance regression lane metrics[{index}].unit"),
            &self.unit,
        )?;
        for (field, value) in [
            ("baselineValue", &self.baseline_value),
            ("comparisonValue", &self.comparison_value),
            ("deltaValue", &self.delta_value),
        ] {
            if !(value.is_number() || value.is_string()) {
                return Err(anyhow!(
                    "performance regression lane metrics[{index}].{field} must be a number or explicit textual value"
                ));
            }
            if self.metric_source != PerformanceRegressionMetricSource::Unsupported
                && !value.is_number()
            {
                return Err(anyhow!(
                    "performance regression lane metrics[{index}].{field} must be numeric unless metricSource is unsupported"
                ));
            }
        }
        if let Some(notes) = &self.notes {
            require_bounded_display_text(
                &format!("performance regression lane metrics[{index}].notes"),
                notes,
            )?;
        }
        Ok(())
    }
}

impl PerformanceRegressionThreshold {
    fn validate(&self, index: usize, metric_ids: &BTreeSet<&str>) -> Result<()> {
        validate_path_component(
            &format!("performance regression lane thresholds[{index}].id"),
            &self.id,
        )?;
        validate_path_component(
            &format!("performance regression lane thresholds[{index}].metricId"),
            &self.metric_id,
        )?;
        if !metric_ids.contains(self.metric_id.as_str()) {
            return Err(anyhow!(
                "performance regression lane thresholds[{index}].metricId must reference an existing metric"
            ));
        }
        if !(self.value.is_number() || self.value.is_string()) {
            return Err(anyhow!(
                "performance regression lane thresholds[{index}].value must be a number or explicit textual value"
            ));
        }
        if !self.value.is_number()
            && self.classification_if_exceeded != PerformanceRegressionClassification::Unsupported
        {
            return Err(anyhow!(
                "performance regression lane thresholds[{index}].value must be numeric unless classificationIfExceeded is unsupported"
            ));
        }
        if matches!(
            self.classification_if_exceeded,
            PerformanceRegressionClassification::Improved
                | PerformanceRegressionClassification::Unchanged
                | PerformanceRegressionClassification::MissingBaseline
        ) {
            return Err(anyhow!(
                "performance regression lane thresholds[{index}].classificationIfExceeded must be a blocking classification"
            ));
        }
        require_bounded_display_text(
            &format!("performance regression lane thresholds[{index}].rationale"),
            &self.rationale,
        )
    }
}

impl PerformanceRegressionEvidenceLinks {
    fn validate(&self) -> Result<()> {
        validate_nonempty_refs(
            "performance regression lane evidenceLinks.runComparisonRefs",
            &self.run_comparison_refs,
        )?;
        validate_nonempty_refs(
            "performance regression lane evidenceLinks.frameBudgetRefs",
            &self.frame_budget_refs,
        )?;
        validate_nonempty_refs(
            "performance regression lane evidenceLinks.scenarioMatrixRefs",
            &self.scenario_matrix_refs,
        )?;
        validate_nonempty_refs(
            "performance regression lane evidenceLinks.qaQueueRefs",
            &self.qa_queue_refs,
        )?;
        validate_nonempty_refs(
            "performance regression lane evidenceLinks.reviewGateRefs",
            &self.review_gate_refs,
        )?;
        validate_optional_text_list(
            "performance regression lane evidenceLinks.browserMetricWarnings",
            &self.browser_metric_warnings,
        )
    }
}

const QA_WORKER_ASSIGNMENT_SCHEMA_VERSION: &str = "qa-worker-assignment-v1";

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct QaWorkerAssignmentArtifact {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    #[serde(rename = "planId")]
    pub plan_id: String,
    #[serde(rename = "runId")]
    pub run_id: String,
    pub assignments: Vec<QaWorkerAssignment>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub guardrails: Vec<String>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct QaWorkerAssignment {
    #[serde(rename = "assignmentId")]
    pub assignment_id: String,
    #[serde(rename = "workerId")]
    pub worker_id: String,
    #[serde(rename = "assignedLane")]
    pub assigned_lane: String,
    pub target: QaWorkerAssignmentTarget,
    pub budget: QaWorkerAssignmentBudget,
    #[serde(rename = "timeoutMs")]
    pub timeout_ms: u64,
    #[serde(rename = "runCount")]
    pub run_count: u32,
    #[serde(rename = "outputRoot")]
    pub output_root: String,
    #[serde(rename = "cleanupPolicy")]
    pub cleanup_policy: QaWorkerCleanupPolicy,
    pub status: QaWorkerAssignmentStatus,
    #[serde(
        rename = "blockedReasons",
        default,
        skip_serializing_if = "Vec::is_empty"
    )]
    pub blocked_reasons: Vec<String>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct QaWorkerAssignmentTarget {
    #[serde(rename = "targetType")]
    pub target_type: QaWorkerAssignmentTargetType,
    #[serde(rename = "targetId")]
    pub target_id: String,
    #[serde(rename = "evidenceRef")]
    pub evidence_ref: String,
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "snake_case")]
pub enum QaWorkerAssignmentTargetType {
    ScenarioCandidate,
    FuzzTarget,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct QaWorkerAssignmentBudget {
    #[serde(rename = "maxRuns")]
    pub max_runs: u32,
    #[serde(rename = "maxDurationMs")]
    pub max_duration_ms: u64,
    #[serde(rename = "maxArtifacts")]
    pub max_artifacts: u32,
    #[serde(rename = "maxOutputBytes")]
    pub max_output_bytes: u64,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct QaWorkerCleanupPolicy {
    pub mode: QaWorkerCleanupMode,
    #[serde(rename = "maxRetentionMs", skip_serializing_if = "Option::is_none")]
    pub max_retention_ms: Option<u64>,
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "snake_case")]
pub enum QaWorkerCleanupMode {
    DeleteOnSuccess,
    RetainOnFailure,
    RetainForReview,
}

#[derive(Debug, Clone, Copy, Deserialize, Serialize, PartialEq, Eq, PartialOrd, Ord)]
#[serde(rename_all = "snake_case")]
pub enum QaWorkerAssignmentStatus {
    Assigned,
    Passed,
    Failed,
    Deferred,
    Blocked,
    Exhausted,
}

impl QaWorkerAssignmentArtifact {
    pub fn from_json_str(input: &str) -> Result<Self> {
        let artifact: QaWorkerAssignmentArtifact =
            serde_json::from_str(input).context("failed to parse QA Worker Assignment JSON")?;
        artifact.validate()?;
        Ok(artifact)
    }

    pub fn validate(&self) -> Result<()> {
        if self.schema_version != QA_WORKER_ASSIGNMENT_SCHEMA_VERSION {
            return Err(anyhow!(
                "qa worker assignment schemaVersion must be {QA_WORKER_ASSIGNMENT_SCHEMA_VERSION}"
            ));
        }
        validate_path_component("qa worker assignment planId", &self.plan_id)?;
        validate_path_component("qa worker assignment runId", &self.run_id)?;
        if self.assignments.is_empty() {
            return Err(anyhow!(
                "qa worker assignment assignments must not be empty"
            ));
        }
        let mut assignment_ids = BTreeSet::new();
        let mut output_roots = BTreeSet::new();
        for (index, assignment) in self.assignments.iter().enumerate() {
            assignment.validate(index)?;
            if !assignment_ids.insert(assignment.assignment_id.as_str()) {
                return Err(anyhow!(
                    "duplicate qa worker assignment assignmentId: {}",
                    assignment.assignment_id
                ));
            }
            if !output_roots.insert(assignment.output_root.as_str()) {
                return Err(anyhow!(
                    "duplicate qa worker assignment outputRoot: {}",
                    assignment.output_root
                ));
            }
        }
        for (left_index, left) in self.assignments.iter().enumerate() {
            for (right_index, right) in self.assignments.iter().enumerate().skip(left_index + 1) {
                if qa_worker_output_roots_overlap(&left.output_root, &right.output_root) {
                    return Err(anyhow!(
                        "qa worker assignment outputRoot overlap between assignments[{left_index}] and assignments[{right_index}]"
                    ));
                }
            }
        }
        for guardrail in &self.guardrails {
            require_bounded_display_text("qa worker assignment guardrail", guardrail)?;
        }
        Ok(())
    }
}

impl QaWorkerAssignment {
    fn validate(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("qa worker assignments[{index}].assignmentId"),
            &self.assignment_id,
        )?;
        validate_path_component(
            &format!("qa worker assignments[{index}].workerId"),
            &self.worker_id,
        )?;
        validate_path_component(
            &format!("qa worker assignments[{index}].assignedLane"),
            &self.assigned_lane,
        )?;
        self.target.validate(index)?;
        self.budget.validate(index)?;
        if self.timeout_ms == 0 {
            return Err(anyhow!(
                "qa worker assignments[{index}].timeoutMs must be bounded and greater than zero"
            ));
        }
        if self.run_count > self.budget.max_runs {
            return Err(anyhow!(
                "qa worker assignments[{index}].runCount must not exceed budget.maxRuns"
            ));
        }
        validate_qa_worker_output_root(&self.output_root, &self.worker_id)
            .with_context(|| format!("qa worker assignments[{index}].outputRoot is invalid"))?;
        self.cleanup_policy.validate(index)?;
        for reason in &self.blocked_reasons {
            require_bounded_display_text(
                &format!("qa worker assignments[{index}].blockedReasons"),
                reason,
            )?;
        }
        match self.status {
            QaWorkerAssignmentStatus::Blocked if self.blocked_reasons.is_empty() => Err(anyhow!(
                "qa worker assignments[{index}] blocked status requires blockedReasons"
            )),
            QaWorkerAssignmentStatus::Assigned | QaWorkerAssignmentStatus::Passed
                if !self.blocked_reasons.is_empty() =>
            {
                Err(anyhow!(
                    "qa worker assignments[{index}] assigned/passed status must not include blockedReasons"
                ))
            }
            _ => Ok(()),
        }
    }
}

impl QaWorkerAssignmentTarget {
    fn validate(&self, index: usize) -> Result<()> {
        validate_path_component(
            &format!("qa worker assignments[{index}].target.targetId"),
            &self.target_id,
        )?;
        validate_qa_worker_target_ref(&self.evidence_ref, self.target_type).with_context(|| {
            format!("qa worker assignments[{index}].target.evidenceRef is invalid")
        })
    }
}

impl QaWorkerAssignmentBudget {
    fn validate(&self, index: usize) -> Result<()> {
        if self.max_runs == 0 {
            return Err(anyhow!(
                "qa worker assignments[{index}].budget.maxRuns must be greater than zero"
            ));
        }
        if self.max_duration_ms == 0 {
            return Err(anyhow!(
                "qa worker assignments[{index}].budget.maxDurationMs must be greater than zero"
            ));
        }
        if self.max_artifacts == 0 {
            return Err(anyhow!(
                "qa worker assignments[{index}].budget.maxArtifacts must be greater than zero"
            ));
        }
        if self.max_output_bytes == 0 {
            return Err(anyhow!(
                "qa worker assignments[{index}].budget.maxOutputBytes must be greater than zero"
            ));
        }
        Ok(())
    }
}

impl QaWorkerCleanupPolicy {
    fn validate(&self, index: usize) -> Result<()> {
        if matches!(self.mode, QaWorkerCleanupMode::RetainForReview)
            && self.max_retention_ms.unwrap_or_default() == 0
        {
            return Err(anyhow!(
                "qa worker assignments[{index}].cleanupPolicy retain_for_review requires maxRetentionMs"
            ));
        }
        Ok(())
    }
}

fn validate_qa_worker_target_ref(
    reference: &str,
    target_type: QaWorkerAssignmentTargetType,
) -> Result<()> {
    validate_evidence_artifact_path(reference)?;
    if !reference.ends_with(".json") {
        return Err(anyhow!(
            "qa worker assignment target evidenceRef must be JSON"
        ));
    }
    let allowed_prefix = match target_type {
        QaWorkerAssignmentTargetType::ScenarioCandidate => "evidence/scenarios/",
        QaWorkerAssignmentTargetType::FuzzTarget => "evidence/fuzz/",
    };
    if !reference.starts_with(allowed_prefix) {
        return Err(anyhow!(
            "qa worker assignment target evidenceRef must match targetType output root {allowed_prefix}"
        ));
    }
    Ok(())
}

fn validate_qa_worker_output_root(output_root: &str, worker_id: &str) -> Result<()> {
    validate_evidence_artifact_path(output_root)?;
    let expected_prefix = format!("evidence/qa-workers/{worker_id}/");
    if !output_root.starts_with(&expected_prefix) {
        return Err(anyhow!(
            "qa worker assignment outputRoot must stay under {expected_prefix}"
        ));
    }
    Ok(())
}

fn qa_worker_output_roots_overlap(left: &str, right: &str) -> bool {
    let normalize = |value: &str| {
        if value.ends_with('/') {
            value.to_string()
        } else {
            format!("{value}/")
        }
    };
    let left = normalize(left);
    let right = normalize(right);
    left.starts_with(&right) || right.starts_with(&left)
}

pub fn validate_qa_worker_assignment_refs(
    run_dir: impl AsRef<Path>,
    artifact: &QaWorkerAssignmentArtifact,
) -> Result<()> {
    let run_dir = run_dir.as_ref();
    artifact.validate()?;
    let index = read_evidence_index(run_dir)?;
    let indexed_paths = index
        .artifacts
        .iter()
        .map(|artifact| artifact.path.as_str())
        .collect::<BTreeSet<_>>();
    for (index, assignment) in artifact.assignments.iter().enumerate() {
        if !indexed_paths.contains(assignment.target.evidence_ref.as_str()) {
            return Err(anyhow!(
                "qa worker assignments[{index}].target.evidenceRef is missing from evidence index: {}",
                assignment.target.evidence_ref
            ));
        }
        let value =
            read_json_value(run_dir.join(&assignment.target.evidence_ref)).with_context(|| {
                format!(
                    "failed to read qa worker assignments[{index}].target.evidenceRef {}",
                    assignment.target.evidence_ref
                )
            })?;
        // Fail closed: target evidence must carry a run identity so freshness can
        // actually be proven. Accepting an artifact with no runId/run_id would let
        // an unversioned or stale target pass as current-run planning evidence.
        let run_id = json_string(&value, "runId")
            .or_else(|| json_string(&value, "run_id"))
            .ok_or_else(|| {
                anyhow!(
                    "qa worker assignments[{index}].target.evidenceRef is missing a runId/run_id needed to prove freshness"
                )
            })?;
        if run_id != artifact.run_id {
            return Err(anyhow!(
                "qa worker assignments[{index}].target.evidenceRef is stale for runId {} (expected {})",
                run_id,
                artifact.run_id
            ));
        }
        // Fail closed: target evidence must carry a target identity so target-id
        // drift can be rejected. Accepting an artifact with no recognized identity
        // field would let it validate against any assignment targetId.
        let target_id = json_string(&value, "targetId")
            .or_else(|| json_string(&value, "target_id"))
            .or_else(|| json_string(&value, "scenarioId"))
            .or_else(|| json_string(&value, "scenario_id"))
            .or_else(|| json_string(&value, "id"))
            .ok_or_else(|| {
                anyhow!(
                    "qa worker assignments[{index}].target.evidenceRef is missing a target identity field needed to reject target-id drift"
                )
            })?;
        if target_id != assignment.target.target_id {
            return Err(anyhow!(
                "qa worker assignments[{index}].target.evidenceRef target id {target_id} does not match assignment targetId {}",
                assignment.target.target_id
            ));
        }
    }
    Ok(())
}

