impl SourcePatchApplyTransactionValidation {
    pub fn is_blocked(&self) -> bool {
        self.status == "blocked"
    }
}

pub fn inspect_source_patch_apply_transaction_artifact(
    artifact: &SourcePatchApplyTransactionArtifact,
) -> SourcePatchApplyTransactionValidation {
    let mut blocked_reasons = Vec::<String>::new();

    if artifact.schema_version != SOURCE_PATCH_APPLY_TRANSACTION_SCHEMA_VERSION {
        blocked_reasons.push(format!(
            "schemaVersion must be {SOURCE_PATCH_APPLY_TRANSACTION_SCHEMA_VERSION}"
        ));
    }
    push_if_blank(
        &mut blocked_reasons,
        "transactionId",
        &artifact.transaction_id,
    );
    push_if_blank(&mut blocked_reasons, "createdAt", &artifact.created_at);
    inspect_source_patch_apply_transaction_evidence(&artifact.evidence, &mut blocked_reasons);
    inspect_source_patch_apply_transaction_base_ref(&artifact.base_ref, &mut blocked_reasons);
    inspect_source_patch_apply_transaction_targets(artifact, &mut blocked_reasons);
    inspect_source_patch_apply_transaction_diff_summary(artifact, &mut blocked_reasons);
    inspect_source_patch_apply_transaction_rollback_ref(artifact, &mut blocked_reasons);
    inspect_source_patch_apply_transaction_verification_commands(artifact, &mut blocked_reasons);
    inspect_source_patch_apply_transaction_post_apply_refs(artifact, &mut blocked_reasons);
    inspect_source_patch_apply_transaction_guardrails(artifact, &mut blocked_reasons);

    match artifact.status {
        SourcePatchApplyTransactionStatus::Blocked => {
            if artifact.blocked_reasons.is_empty() {
                blocked_reasons.push("blocked status requires blockedReasons".to_string());
            }
            blocked_reasons.push(
                "transaction status is blocked; trusted apply readiness is not satisfied"
                    .to_string(),
            );
        }
        SourcePatchApplyTransactionStatus::ReadyForTrustedApply => {
            if !artifact.blocked_reasons.is_empty() {
                blocked_reasons.push(
                    "ready_for_trusted_apply transaction must not carry blockedReasons".to_string(),
                );
            }
        }
    }

    blocked_reasons.sort();
    blocked_reasons.dedup();

    SourcePatchApplyTransactionValidation {
        schema_version: "source-patch-apply-transaction-validation-v1".to_string(),
        status: if blocked_reasons.is_empty() {
            "shape_valid_pending_linked_evidence".to_string()
        } else {
            "blocked".to_string()
        },
        transaction_id: artifact.transaction_id.clone(),
        target_count: artifact.targets.len(),
        verification_command_count: artifact.verification_commands.len(),
        blocked_reasons,
        guardrails: vec![
            "shape validation checks transaction metadata only; it does not apply patches"
                .to_string(),
            "linked evidence readiness requires inspect_source_patch_apply_transaction_artifact_with_evidence_root before any future trusted apply"
                .to_string(),
            "validated transactions still require a separate trusted apply implementation before writes"
                .to_string(),
            "verification commands are allowlist-checked metadata, not executed by validation"
                .to_string(),
            "browser/dashboard/Studio surfaces remain read-only and command-inert".to_string(),
        ],
    }
}

pub fn validate_source_patch_apply_transaction_artifact(
    artifact: &SourcePatchApplyTransactionArtifact,
) -> Result<SourcePatchApplyTransactionValidation> {
    let validation = inspect_source_patch_apply_transaction_artifact(artifact);
    if validation.is_blocked() {
        return Err(anyhow!(
            "source patch apply transaction blocked: {}",
            validation.blocked_reasons.join("; ")
        ));
    }
    Ok(validation)
}

pub fn inspect_source_patch_apply_transaction_artifact_with_evidence_root(
    artifact: &SourcePatchApplyTransactionArtifact,
    evidence_root: impl AsRef<Path>,
) -> SourcePatchApplyTransactionValidation {
    let mut validation = inspect_source_patch_apply_transaction_artifact(artifact);
    let root = evidence_root.as_ref();
    inspect_source_patch_apply_transaction_linked_evidence(
        artifact,
        root,
        &mut validation.blocked_reasons,
    );
    validation.blocked_reasons.sort();
    validation.blocked_reasons.dedup();
    validation.status = if validation.blocked_reasons.is_empty() {
        "linked_evidence_ready_no_apply_authority".to_string()
    } else {
        "blocked".to_string()
    };
    validation
}

pub fn source_patch_apply_transaction_read_model(
    artifact: &SourcePatchApplyTransactionArtifact,
) -> SourcePatchApplyTransactionReadModel {
    let validation = inspect_source_patch_apply_transaction_artifact(artifact);
    let mut evidence_summary = vec![
        format!("preview:{}", artifact.evidence.patch_preview_ref),
        format!("sandbox:{}", artifact.evidence.sandbox_report_ref),
        format!("review:{}", artifact.evidence.review_decision_ref),
        format!("file-class:{}", artifact.evidence.file_class_report_ref),
        format!(
            "diff-integrity:{}",
            artifact.evidence.diff_integrity_report_ref
        ),
        format!("rollback:{}", artifact.rollback_ref.rollback_plan_ref),
    ];
    evidence_summary.extend(
        artifact
            .post_apply_scenario_refs
            .iter()
            .map(|artifact_ref| format!("post-apply:{}:{}", artifact_ref.kind, artifact_ref.path)),
    );
    SourcePatchApplyTransactionReadModel {
        schema_version: "source-patch-apply-transaction-read-model-v1".to_string(),
        transaction_id: artifact.transaction_id.clone(),
        status: validation.status.clone(),
        readiness_label: if validation.is_blocked() {
            "blocked_before_trusted_apply".to_string()
        } else {
            "shape_valid_pending_linked_evidence_no_apply_authority".to_string()
        },
        target_count: artifact.targets.len(),
        verification_command_count: artifact.verification_commands.len(),
        target_summaries: artifact
            .targets
            .iter()
            .map(|target| {
                format!(
                    "{}: {}/{}",
                    target.path, target.file_class, target.review_level
                )
            })
            .collect(),
        evidence_summary,
        blocked_reasons: validation.blocked_reasons,
        allowed_actions: vec![
            "inspect_transaction_evidence".to_string(),
            "copy_verification_commands".to_string(),
            "record_manual_follow_up".to_string(),
        ],
        forbidden_actions: vec![
            "apply_patch".to_string(),
            "merge_branch".to_string(),
            "execute_command".to_string(),
            "write_trusted_file".to_string(),
            "browser_command_bridge".to_string(),
            "bypass_review_gate".to_string(),
        ],
        guardrails: vec![
            "read model is display-only and command-inert".to_string(),
            "ready metadata does not apply source patches or merge branches".to_string(),
            "dashboard and Studio surfaces may not write trusted files".to_string(),
            "trusted apply remains separately scoped from transaction readiness".to_string(),
        ],
    }
}

fn inspect_source_patch_apply_transaction_linked_evidence(
    artifact: &SourcePatchApplyTransactionArtifact,
    evidence_root: &Path,
    blocked_reasons: &mut Vec<String>,
) {
    for contract in [
        SourcePatchApplyLinkedEvidenceContract {
            field: "evidence.patchPreviewRef",
            path: artifact.evidence.patch_preview_ref.as_str(),
            expected_id: artifact.evidence.patch_preview_id.as_str(),
            id_keys: &["patchPreviewId", "patch_preview_id", "id"],
            status_keys: &["status", "validationStatus", "validation_status"],
            required_statuses: &["passed", "ready", "complete", "valid"],
        },
        SourcePatchApplyLinkedEvidenceContract {
            field: "evidence.sandboxReportRef",
            path: artifact.evidence.sandbox_report_ref.as_str(),
            expected_id: artifact.evidence.sandbox_report_id.as_str(),
            id_keys: &["sandboxReportId", "sandbox_report_id", "id"],
            status_keys: &["status", "result", "validationStatus", "validation_status"],
            required_statuses: &["passed", "success", "succeeded", "complete"],
        },
        SourcePatchApplyLinkedEvidenceContract {
            field: "evidence.reviewDecisionRef",
            path: artifact.evidence.review_decision_ref.as_str(),
            expected_id: artifact.evidence.review_decision_id.as_str(),
            id_keys: &["reviewDecisionId", "review_decision_id", "id"],
            status_keys: &["status", "reviewStatus", "review_status", "decision"],
            required_statuses: &["accepted", "approved", "passed"],
        },
        SourcePatchApplyLinkedEvidenceContract {
            field: "evidence.fileClassReportRef",
            path: artifact.evidence.file_class_report_ref.as_str(),
            expected_id: artifact.evidence.file_class_report_id.as_str(),
            id_keys: &["fileClassReportId", "file_class_report_id", "id"],
            status_keys: &["status", "validationStatus", "validation_status"],
            required_statuses: &["passed", "valid", "complete"],
        },
        SourcePatchApplyLinkedEvidenceContract {
            field: "evidence.diffIntegrityReportRef",
            path: artifact.evidence.diff_integrity_report_ref.as_str(),
            expected_id: artifact.evidence.diff_integrity_report_id.as_str(),
            id_keys: &["diffIntegrityReportId", "diff_integrity_report_id", "id"],
            status_keys: &["status", "validationStatus", "validation_status"],
            required_statuses: &["passed", "valid", "complete"],
        },
    ] {
        inspect_source_patch_apply_transaction_linked_json(
            evidence_root,
            contract,
            blocked_reasons,
        );
    }
}

#[derive(Clone, Copy)]
struct SourcePatchApplyLinkedEvidenceContract<'a> {
    field: &'a str,
    path: &'a str,
    expected_id: &'a str,
    id_keys: &'a [&'a str],
    status_keys: &'a [&'a str],
    required_statuses: &'a [&'a str],
}

fn inspect_source_patch_apply_transaction_linked_json(
    evidence_root: &Path,
    contract: SourcePatchApplyLinkedEvidenceContract<'_>,
    blocked_reasons: &mut Vec<String>,
) {
    if let Err(error) = validate_relative_artifact_path(contract.field, contract.path) {
        blocked_reasons.push(error.to_string());
        return;
    }
    let evidence_path = evidence_root.join(contract.path);
    let value = match read_json_value(&evidence_path) {
        Ok(value) => value,
        Err(error) => {
            blocked_reasons.push(format!(
                "{} linked evidence {} must exist and be readable JSON: {error}",
                contract.field,
                evidence_path.display()
            ));
            return;
        }
    };
    if !json_object_has_any_string_field(&value, contract.id_keys, contract.expected_id) {
        blocked_reasons.push(format!(
            "{} linked evidence must record expected id {} in one of fields: {}",
            contract.field,
            contract.expected_id,
            contract.id_keys.join(", ")
        ));
    }
    if !json_object_has_any_string_field_ci(
        &value,
        contract.status_keys,
        contract.required_statuses,
    ) {
        blocked_reasons.push(format!(
            "{} linked evidence must record one of statuses in fields {}: {}",
            contract.field,
            contract.status_keys.join(", "),
            contract.required_statuses.join(", ")
        ));
    }
}

fn json_object_has_any_string_field(
    value: &serde_json::Value,
    keys: &[&str],
    expected: &str,
) -> bool {
    let Some(map) = value.as_object() else {
        return false;
    };
    keys.iter()
        .filter_map(|key| map.get(*key))
        .any(|value| value.as_str() == Some(expected))
}

fn json_object_has_any_string_field_ci(
    value: &serde_json::Value,
    keys: &[&str],
    expected: &[&str],
) -> bool {
    let Some(map) = value.as_object() else {
        return false;
    };
    keys.iter().filter_map(|key| map.get(*key)).any(|value| {
        value.as_str().is_some_and(|actual| {
            expected
                .iter()
                .any(|expected| actual.eq_ignore_ascii_case(expected))
        })
    })
}

fn inspect_source_patch_apply_transaction_evidence(
    evidence: &SourcePatchApplyTransactionEvidenceLinks,
    blocked_reasons: &mut Vec<String>,
) {
    for (field, value) in [
        (
            "evidence.patchPreviewId",
            evidence.patch_preview_id.as_str(),
        ),
        (
            "evidence.sandboxReportId",
            evidence.sandbox_report_id.as_str(),
        ),
        (
            "evidence.reviewDecisionId",
            evidence.review_decision_id.as_str(),
        ),
        (
            "evidence.fileClassReportId",
            evidence.file_class_report_id.as_str(),
        ),
        (
            "evidence.diffIntegrityReportId",
            evidence.diff_integrity_report_id.as_str(),
        ),
    ] {
        push_if_blank(blocked_reasons, field, value);
    }
    for (field, path) in [
        (
            "evidence.patchPreviewRef",
            evidence.patch_preview_ref.as_str(),
        ),
        (
            "evidence.sandboxReportRef",
            evidence.sandbox_report_ref.as_str(),
        ),
        (
            "evidence.reviewDecisionRef",
            evidence.review_decision_ref.as_str(),
        ),
        (
            "evidence.fileClassReportRef",
            evidence.file_class_report_ref.as_str(),
        ),
        (
            "evidence.diffIntegrityReportRef",
            evidence.diff_integrity_report_ref.as_str(),
        ),
    ] {
        if let Err(error) = validate_relative_artifact_path(field, path) {
            blocked_reasons.push(error.to_string());
        }
    }
}

fn inspect_source_patch_apply_transaction_base_ref(
    base_ref: &SourcePatchApplyTransactionBaseRef,
    blocked_reasons: &mut Vec<String>,
) {
    for (field, value) in [
        ("baseRef.branch", base_ref.branch.as_str()),
        ("baseRef.previewCommit", base_ref.preview_commit.as_str()),
        (
            "baseRef.trustedApplyCommit",
            base_ref.trusted_apply_commit.as_str(),
        ),
        (
            "baseRef.staleTargetPolicy",
            base_ref.stale_target_policy.as_str(),
        ),
    ] {
        push_if_blank(blocked_reasons, field, value);
    }
    if !base_ref
        .stale_target_policy
        .to_ascii_lowercase()
        .contains("re-read")
        && !base_ref
            .stale_target_policy
            .to_ascii_lowercase()
            .contains("stale")
    {
        blocked_reasons
            .push("baseRef.staleTargetPolicy must describe stale/re-read protection".to_string());
    }
}

fn inspect_source_patch_apply_transaction_targets(
    artifact: &SourcePatchApplyTransactionArtifact,
    blocked_reasons: &mut Vec<String>,
) {
    if artifact.targets.is_empty() {
        blocked_reasons.push("targets must not be empty".to_string());
    }
    let mut seen_targets = BTreeSet::<String>::new();
    for (index, target) in artifact.targets.iter().enumerate() {
        let field = format!("targets[{index}]");
        push_if_blank(blocked_reasons, &format!("{field}.path"), &target.path);
        if !target.path.trim().is_empty() && !seen_targets.insert(target.path.clone()) {
            blocked_reasons.push(format!("duplicate target path {}", target.path));
        }
        if let Err(error) = validate_relative_artifact_path(&format!("{field}.path"), &target.path)
        {
            blocked_reasons.push(error.to_string());
        }
        require_sha256_like(
            blocked_reasons,
            &format!("{field}.beforeHash"),
            &target.before_hash,
        );
        require_sha256_like(
            blocked_reasons,
            &format!("{field}.expectedAfterHash"),
            &target.expected_after_hash,
        );
        require_sha256_like(
            blocked_reasons,
            &format!("{field}.sandboxAfterHash"),
            &target.sandbox_after_hash,
        );
        if target.expected_after_hash != target.sandbox_after_hash {
            blocked_reasons.push(format!(
                "{field}.expectedAfterHash must match sandboxAfterHash before trusted apply readiness"
            ));
        }
        let class_report = classify_source_file_path_str(&target.path);
        let expected_file_class = source_file_class_label_value(&class_report.class);
        if target.file_class != expected_file_class {
            blocked_reasons.push(format!(
                "{field}.fileClass expected {expected_file_class} from current file-class policy for {}",
                target.path
            ));
        }
        if class_report.decision != SourceFileClassDecision::Allowed {
            blocked_reasons.push(format!(
                "{field}.path {} has unsupported file class decision {:?}; apply transactions are limited to explicitly allowed source-like classes",
                target.path, class_report.decision
            ));
        }
        if target.review_level.trim().is_empty() {
            blocked_reasons.push(format!("{field}.reviewLevel must not be empty"));
        }
    }
}

fn inspect_source_patch_apply_transaction_diff_summary(
    artifact: &SourcePatchApplyTransactionArtifact,
    blocked_reasons: &mut Vec<String>,
) {
    push_if_blank(
        blocked_reasons,
        "diffSummary.summary",
        &artifact.diff_summary.summary,
    );
    if artifact.diff_summary.files_changed != artifact.targets.len() {
        blocked_reasons.push(format!(
            "diffSummary.filesChanged {} must match target count {}",
            artifact.diff_summary.files_changed,
            artifact.targets.len()
        ));
    }
    if artifact.diff_summary.additions + artifact.diff_summary.deletions == 0 {
        blocked_reasons.push("diffSummary must record additions or deletions".to_string());
    }
    if artifact.diff_summary.diff_integrity_report_ref
        != artifact.evidence.diff_integrity_report_ref
    {
        blocked_reasons.push(
            "diffSummary.diffIntegrityReportRef must match evidence.diffIntegrityReportRef"
                .to_string(),
        );
    }
}

fn inspect_source_patch_apply_transaction_rollback_ref(
    artifact: &SourcePatchApplyTransactionArtifact,
    blocked_reasons: &mut Vec<String>,
) {
    for (field, path) in [
        (
            "rollbackRef.rollbackPlanRef",
            artifact.rollback_ref.rollback_plan_ref.as_str(),
        ),
        (
            "rollbackRef.cleanupPolicyRef",
            artifact.rollback_ref.cleanup_policy_ref.as_str(),
        ),
    ] {
        if let Err(error) = validate_relative_artifact_path(field, path) {
            blocked_reasons.push(error.to_string());
        }
    }
    push_if_blank(
        blocked_reasons,
        "rollbackRef.preApplyBranch",
        &artifact.rollback_ref.pre_apply_branch,
    );
    push_if_blank(
        blocked_reasons,
        "rollbackRef.preApplyCommit",
        &artifact.rollback_ref.pre_apply_commit,
    );
    if artifact.rollback_ref.pre_apply_commit != artifact.base_ref.trusted_apply_commit {
        blocked_reasons
            .push("rollbackRef.preApplyCommit must match baseRef.trustedApplyCommit".to_string());
    }

    let mut rollback_hashes = BTreeMap::<String, String>::new();
    for (index, hash) in artifact
        .rollback_ref
        .target_before_hashes
        .iter()
        .enumerate()
    {
        let field = format!("rollbackRef.targetBeforeHashes[{index}]");
        if let Err(error) = validate_relative_artifact_path(&format!("{field}.path"), &hash.path) {
            blocked_reasons.push(error.to_string());
        }
        require_sha256_like(
            blocked_reasons,
            &format!("{field}.beforeHash"),
            &hash.before_hash,
        );
        if rollback_hashes
            .insert(hash.path.clone(), hash.before_hash.clone())
            .is_some()
        {
            blocked_reasons.push(format!("duplicate rollback before hash for {}", hash.path));
        }
    }
    for target in &artifact.targets {
        match rollback_hashes.get(&target.path) {
            Some(before_hash) if before_hash == &target.before_hash => {}
            Some(_) => blocked_reasons.push(format!(
                "rollbackRef.targetBeforeHashes for {} must match target beforeHash",
                target.path
            )),
            None => blocked_reasons.push(format!(
                "rollbackRef.targetBeforeHashes missing target {}",
                target.path
            )),
        }
    }
}

fn inspect_source_patch_apply_transaction_verification_commands(
    artifact: &SourcePatchApplyTransactionArtifact,
    blocked_reasons: &mut Vec<String>,
) {
    if artifact.verification_commands.is_empty() {
        blocked_reasons.push("verificationCommands must not be empty".to_string());
    }
    for (index, command) in artifact.verification_commands.iter().enumerate() {
        let field = format!("verificationCommands[{index}]");
        push_if_blank(
            blocked_reasons,
            &format!("{field}.command"),
            &command.command,
        );
        if command.argv.is_empty() {
            blocked_reasons.push(format!("{field}.argv must not be empty"));
            continue;
        }
        let normalized = normalize_source_patch_test_command(&command.argv);
        if command.command != normalized {
            blocked_reasons.push(format!(
                "{field}.command must match normalized argv `{normalized}`"
            ));
        }
        if command.allowlist_policy_id != "source-patch-preview-safe-local-checks-v1" {
            blocked_reasons.push(format!(
                "{field}.allowlistPolicyId must be source-patch-preview-safe-local-checks-v1"
            ));
        }
        if !command.execution_authority.contains("copyable")
            || !command.execution_authority.contains("not_executed")
        {
            blocked_reasons.push(format!(
                "{field}.executionAuthority must remain copyable/not_executed metadata"
            ));
        }
        if command.expected_status.trim().is_empty() {
            blocked_reasons.push(format!("{field}.expectedStatus must not be empty"));
        }
        let test_command = SourcePatchTestCommand {
            command: command.command.clone(),
            argv: command.argv.clone(),
        };
        if let Some(forbidden) = classify_source_patch_forbidden_test_command(&test_command) {
            blocked_reasons.push(format!("{field}.argv forbidden: {}", forbidden.reason));
        } else if default_source_patch_test_command_allowlist()
            .match_command(&test_command)
            .is_none()
        {
            blocked_reasons.push(format!(
                "{field}.argv is not in the source patch test command allowlist"
            ));
        }
    }
}

fn inspect_source_patch_apply_transaction_post_apply_refs(
    artifact: &SourcePatchApplyTransactionArtifact,
    blocked_reasons: &mut Vec<String>,
) {
    if artifact.post_apply_scenario_refs.is_empty() {
        blocked_reasons.push("postApplyScenarioRefs must not be empty".to_string());
    }
    for (index, artifact_ref) in artifact.post_apply_scenario_refs.iter().enumerate() {
        let field = format!("postApplyScenarioRefs[{index}]");
        push_if_blank(
            blocked_reasons,
            &format!("{field}.kind"),
            &artifact_ref.kind,
        );
        if let Err(error) =
            validate_relative_artifact_path(&format!("{field}.path"), &artifact_ref.path)
        {
            blocked_reasons.push(error.to_string());
        }
        if !artifact_ref.required {
            blocked_reasons.push(format!("{field}.required must be true for readiness"));
        }
    }
}

fn inspect_source_patch_apply_transaction_guardrails(
    artifact: &SourcePatchApplyTransactionArtifact,
    blocked_reasons: &mut Vec<String>,
) {
    if !artifact.guardrails.iter().any(|guardrail| {
        let guardrail = guardrail.to_ascii_lowercase();
        guardrail.contains("do not apply") || guardrail.contains("does not apply")
    }) {
        blocked_reasons
            .push("guardrails must state the artifact does not apply patches".to_string());
    }
    if !artifact.guardrails.iter().any(|guardrail| {
        let guardrail = guardrail.to_ascii_lowercase();
        guardrail.contains("read-only") || guardrail.contains("command-inert")
    }) {
        blocked_reasons
            .push("guardrails must preserve read-only/command-inert UI surfaces".to_string());
    }
    for required in ["merge", "write", "command"] {
        if !artifact
            .guardrails
            .iter()
            .any(|guardrail| guardrail.to_ascii_lowercase().contains(required))
        {
            blocked_reasons.push(format!(
                "guardrails must mention forbidden {required} authority"
            ));
        }
    }
}

pub fn inspect_source_patch_test_command_allowlist(
    artifact: &SourcePatchTestCommandAllowlistArtifact,
) -> SourcePatchTestCommandAllowlistValidation {
    let mut blocked_reasons = Vec::<String>::new();
    let mut normalized_commands = Vec::<String>::new();
    let mut ids_seen = BTreeSet::<String>::new();

    if artifact.schema_version != SOURCE_PATCH_TEST_COMMAND_ALLOWLIST_SCHEMA_VERSION {
        blocked_reasons.push(format!(
            "schemaVersion must be {SOURCE_PATCH_TEST_COMMAND_ALLOWLIST_SCHEMA_VERSION}"
        ));
    }
    push_if_blank(&mut blocked_reasons, "policyId", &artifact.policy_id);
    if artifact.commands.is_empty() {
        blocked_reasons.push("commands must not be empty".to_string());
    }
    if !artifact
        .guardrails
        .iter()
        .any(|guardrail| guardrail.contains("does not execute"))
    {
        blocked_reasons
            .push("guardrails must state the policy does not execute commands".to_string());
    }

    for (index, command) in artifact.commands.iter().enumerate() {
        let field = format!("commands[{index}]");
        if !ids_seen.insert(command.id.clone()) {
            blocked_reasons.push(format!("duplicate command id {}", command.id));
        }
        push_if_blank(&mut blocked_reasons, &format!("{field}.id"), &command.id);
        push_if_blank(
            &mut blocked_reasons,
            &format!("{field}.command"),
            &command.command,
        );
        push_if_blank(
            &mut blocked_reasons,
            &format!("{field}.workingDirectory"),
            &command.working_directory,
        );
        push_if_blank(
            &mut blocked_reasons,
            &format!("{field}.rationale"),
            &command.rationale,
        );
        if command.argv.is_empty() {
            blocked_reasons.push(format!("{field}.argv must not be empty"));
            continue;
        }
        if command.argv.iter().any(|arg| arg.trim().is_empty()) {
            blocked_reasons.push(format!("{field}.argv entries must not be empty"));
        }
        if command.working_directory != "." {
            blocked_reasons.push(format!(
                "{field}.workingDirectory must be repository root '.' for this policy"
            ));
        }
        if command.timeout_seconds == 0 || command.timeout_seconds > 1800 {
            blocked_reasons.push(format!("{field}.timeoutSeconds must be between 1 and 1800"));
        }
        if command.may_write_generated_artifacts && command.generated_output_roots.is_empty() {
            blocked_reasons.push(format!(
                "{field}.generatedOutputRoots required when generated writes are declared"
            ));
        }
        let normalized = normalize_source_patch_test_command(&command.argv);
        if command.command != normalized {
            blocked_reasons.push(format!(
                "{field}.command must match normalized argv `{normalized}`"
            ));
        }
        let test_command = SourcePatchTestCommand {
            command: command.command.clone(),
            argv: command.argv.clone(),
        };
        if let Some(forbidden) = classify_source_patch_forbidden_test_command(&test_command) {
            blocked_reasons.push(format!("{field}.argv forbidden: {}", forbidden.reason));
        } else if !source_patch_test_command_matches_allowlist(command) {
            blocked_reasons.push(format!(
                "{field}.argv is not in the source patch test command allowlist"
            ));
        }
        normalized_commands.push(normalized);
    }

    blocked_reasons.sort();
    blocked_reasons.dedup();

    SourcePatchTestCommandAllowlistValidation {
        schema_version: "source-patch-test-command-allowlist-validation-v1".to_string(),
        status: if blocked_reasons.is_empty() {
            "passed".to_string()
        } else {
            "blocked".to_string()
        },
        policy_id: artifact.policy_id.clone(),
        allowed_command_count: artifact.commands.len(),
        normalized_commands,
        blocked_reasons,
        guardrails: vec![
            "test command allowlist is inert policy data; it does not execute commands".to_string(),
            "source patch apply to the trusted worktree remains unimplemented and forbidden"
                .to_string(),
            "browser/dashboard/Studio surfaces may display command text read-only only".to_string(),
            "sandbox dry-run execution is future-scoped and must stay allowlist-only".to_string(),
        ],
    }
}

pub fn validate_source_patch_test_command_allowlist(
    artifact: &SourcePatchTestCommandAllowlistArtifact,
) -> Result<SourcePatchTestCommandAllowlistValidation> {
    let validation = inspect_source_patch_test_command_allowlist(artifact);
    if validation.is_blocked() {
        return Err(anyhow!(
            "source patch test command allowlist blocked: {}",
            validation.blocked_reasons.join("; ")
        ));
    }
    Ok(validation)
}

pub fn inspect_source_patch_sandbox_evaluator_plan(
    plan: &SourcePatchSandboxEvaluatorPlan,
) -> SourcePatchSandboxEvaluatorPlanValidation {
    let mut blocked_reasons = Vec::<String>::new();

    if plan.schema_version != SOURCE_PATCH_SANDBOX_EVALUATOR_PLAN_SCHEMA_VERSION {
        blocked_reasons.push(format!(
            "schemaVersion must be {SOURCE_PATCH_SANDBOX_EVALUATOR_PLAN_SCHEMA_VERSION}"
        ));
    }
    if plan.evaluation_id.trim().is_empty() {
        blocked_reasons.push("evaluationId must not be empty".to_string());
    } else if let Err(error) = validate_sandbox_id(&plan.evaluation_id) {
        blocked_reasons.push(format!("evaluationId invalid: {error}"));
    }
    if plan.created_at.trim().is_empty() {
        blocked_reasons.push("createdAt must not be empty".to_string());
    }
    if plan.source_mutation_apply_status != SourcePatchPreviewApplyStatus::Blocked {
        blocked_reasons.push(
            "sourceMutationApplyStatus must remain blocked for trusted worktree apply".to_string(),
        );
    }
    if plan.inputs.patch_preview_id.trim().is_empty() {
        blocked_reasons.push("inputs.patchPreviewId must not be empty".to_string());
    }
    if plan.inputs.patch_preview_id != plan.layout.sandbox_id {
        blocked_reasons.push(
            "inputs.patchPreviewId must match layout.sandboxId for deterministic isolation"
                .to_string(),
        );
    }
    if plan.inputs.file_class_validation_ref.trim().is_empty() {
        blocked_reasons.push("inputs.fileClassValidationRef must not be empty".to_string());
    } else if let Err(error) = validate_relative_artifact_path(
        "inputs.fileClassValidationRef",
        &plan.inputs.file_class_validation_ref,
    ) {
        blocked_reasons.push(error.to_string());
    }
    if plan.inputs.diff_integrity_validation_ref.trim().is_empty() {
        blocked_reasons.push("inputs.diffIntegrityValidationRef must not be empty".to_string());
    } else if let Err(error) = validate_relative_artifact_path(
        "inputs.diffIntegrityValidationRef",
        &plan.inputs.diff_integrity_validation_ref,
    ) {
        blocked_reasons.push(error.to_string());
    }
    if plan.inputs.allowlist_policy_id != "source-patch-preview-safe-local-checks-v1" {
        blocked_reasons.push(
            "inputs.allowlistPolicyId must be source-patch-preview-safe-local-checks-v1"
                .to_string(),
        );
    }

    inspect_source_patch_sandbox_layout_policy(
        &plan.layout,
        &plan.evaluation_id,
        &mut blocked_reasons,
    );
    inspect_source_patch_sandbox_cleanup_policy(
        &plan.cleanup,
        &plan.layout.sandbox_root,
        &mut blocked_reasons,
    );

    if plan.required_tests.is_empty() {
        blocked_reasons.push("requiredTests must not be empty".to_string());
    }
    for (index, required_test) in plan.required_tests.iter().enumerate() {
        let field = format!("requiredTests[{index}]");
        if required_test.command.trim().is_empty() {
            blocked_reasons.push(format!("{field}.command must not be empty"));
        }
        if !required_test.execution_authority.contains("copyable")
            || !required_test.execution_authority.contains("not_executed")
        {
            blocked_reasons.push(format!(
                "{field}.executionAuthority must remain copyable/not_executed metadata"
            ));
        }
        if required_test.allowlist_policy_id.as_deref()
            != Some("source-patch-preview-safe-local-checks-v1")
        {
            blocked_reasons.push(format!(
                "{field}.allowlistPolicyId must be source-patch-preview-safe-local-checks-v1"
            ));
        }
        if required_test.argv.is_empty() {
            blocked_reasons.push(format!("{field}.argv must not be empty"));
            continue;
        }
        let normalized = normalize_source_patch_test_command(&required_test.argv);
        if required_test.command != normalized {
            blocked_reasons.push(format!(
                "{field}.command must match normalized argv `{normalized}`"
            ));
        }
        let command = SourcePatchTestCommand {
            command: required_test.command.clone(),
            argv: required_test.argv.clone(),
        };
        if let Some(forbidden) = classify_source_patch_forbidden_test_command(&command) {
            blocked_reasons.push(format!("{field}.argv forbidden: {}", forbidden.reason));
        } else if default_source_patch_test_command_allowlist()
            .match_command(&command)
            .is_none()
        {
            blocked_reasons.push(format!(
                "{field}.argv is not in the source patch test command allowlist"
            ));
        }
    }

    if !plan
        .guardrails
        .iter()
        .any(|guardrail| guardrail.contains("does not execute"))
    {
        blocked_reasons
            .push("guardrails must state the plan does not execute commands".to_string());
    }
    if !plan
        .guardrails
        .iter()
        .any(|guardrail| guardrail.contains("trusted main worktree"))
    {
        blocked_reasons
            .push("guardrails must state the trusted main worktree is not modified".to_string());
    }

    blocked_reasons.sort();
    blocked_reasons.dedup();

    SourcePatchSandboxEvaluatorPlanValidation {
        schema_version: "source-patch-sandbox-evaluator-plan-validation-v1".to_string(),
        status: if blocked_reasons.is_empty() {
            "passed".to_string()
        } else {
            "blocked".to_string()
        },
        evaluation_id: plan.evaluation_id.clone(),
        blocked_reasons,
        guardrails: vec![
            "sandbox evaluator plan is inert metadata; it does not execute commands".to_string(),
            "patch application is future-scoped and must stay sandbox-only".to_string(),
            "trusted main worktree source patch apply remains blocked".to_string(),
            "sandbox/generated outputs remain under sandbox/<id>/ until fixture-scoped".to_string(),
        ],
    }
}

fn inspect_source_patch_sandbox_layout_policy(
    layout: &SourcePatchSandboxLayoutPolicy,
    evaluation_id: &str,
    blocked_reasons: &mut Vec<String>,
) {
    if layout.sandbox_id.trim().is_empty() {
        blocked_reasons.push("layout.sandboxId must not be empty".to_string());
    } else if let Err(error) = validate_sandbox_id(&layout.sandbox_id) {
        blocked_reasons.push(format!("layout.sandboxId invalid: {error}"));
    }
    if layout.sandbox_id != evaluation_id {
        blocked_reasons.push("layout.sandboxId must match evaluationId".to_string());
    }
    let expected_root = format!("sandbox/{evaluation_id}");
    if layout.sandbox_root != expected_root {
        blocked_reasons.push(format!("layout.sandboxRoot must be {expected_root}"));
    }
    let layout_paths = [
        ("layout.sandboxRoot", layout.sandbox_root.as_str()),
        ("layout.worktreePath", layout.worktree_path.as_str()),
        ("layout.evidencePath", layout.evidence_path.as_str()),
        ("layout.reportPath", layout.report_path.as_str()),
        ("layout.cleanupPath", layout.cleanup_path.as_str()),
    ];
    for (field, value) in layout_paths {
        if let Err(error) = validate_run_relative_sandbox_path(value) {
            blocked_reasons.push(format!("{field}: {error}"));
        }
        if !value_stays_under_sandbox_root(value, &layout.sandbox_root) {
            blocked_reasons.push(format!("{field} must stay under layout.sandboxRoot"));
        }
    }
    if !layout.worktree_path.ends_with("/worktree") {
        blocked_reasons.push("layout.worktreePath must end with /worktree".to_string());
    }
    if !layout.evidence_path.ends_with("/evidence") {
        blocked_reasons.push("layout.evidencePath must end with /evidence".to_string());
    }
    if !layout.report_path.ends_with("/evidence/report.json") {
        blocked_reasons.push("layout.reportPath must end with /evidence/report.json".to_string());
    }
    if !layout.cleanup_path.ends_with("/cleanup.json") {
        blocked_reasons.push("layout.cleanupPath must end with /cleanup.json".to_string());
    }
}

fn inspect_source_patch_sandbox_cleanup_policy(
    cleanup: &SourcePatchSandboxCleanupPolicy,
    sandbox_root: &str,
    blocked_reasons: &mut Vec<String>,
) {
    if !cleanup.cleanup_required {
        blocked_reasons.push("cleanup.cleanupRequired must be true".to_string());
    }
    if !cleanup.preserve_evidence {
        blocked_reasons.push("cleanup.preserveEvidence must be true".to_string());
    }
    if cleanup.on_success.trim().is_empty() || !cleanup.on_success.contains("remove") {
        blocked_reasons.push("cleanup.onSuccess must describe sandbox cleanup/removal".to_string());
    }
    if cleanup.on_failure.trim().is_empty() || !cleanup.on_failure.contains("preserve") {
        blocked_reasons
            .push("cleanup.onFailure must describe preserved failure evidence".to_string());
    }
    if cleanup.generated_output_roots.is_empty() {
        blocked_reasons.push("cleanup.generatedOutputRoots must not be empty".to_string());
    }
    for (index, root) in cleanup.generated_output_roots.iter().enumerate() {
        let field = format!("cleanup.generatedOutputRoots[{index}]");
        if let Err(error) = validate_run_relative_sandbox_path(root) {
            blocked_reasons.push(format!("{field}: {error}"));
        }
        if !value_stays_under_sandbox_root(root, sandbox_root) {
            blocked_reasons.push(format!("{field} must stay under layout.sandboxRoot"));
        }
    }
}

fn value_stays_under_sandbox_root(value: &str, sandbox_root: &str) -> bool {
    value == sandbox_root || value.starts_with(&format!("{sandbox_root}/"))
}

fn validate_source_patch_sandbox_preview_inputs(
    artifact: &SourcePatchPreviewArtifact,
    plan: &SourcePatchSandboxEvaluatorPlan,
) -> Result<SourcePatchPreviewValidation> {
    let validation =
        validate_source_patch_preview_artifact(artifact, PatchDiffIntegrityLimits::default())?;
    if validation.patch_preview_id != plan.inputs.patch_preview_id {
        return Err(anyhow!(
            "validated patch preview id {} does not match sandbox plan input {}",
            validation.patch_preview_id,
            plan.inputs.patch_preview_id
        ));
    }
    let diff_validation = validation
        .diff_integrity_validation
        .as_ref()
        .ok_or_else(|| anyhow!("source patch sandbox requires diff integrity validation"))?;
    if validation.file_class_validation.status != "passed" || diff_validation.status != "passed" {
        return Err(anyhow!(
            "source patch sandbox requires passed file-class and diff-integrity validation before evaluation"
        ));
    }
    if plan.inputs.allowlist_policy_id != "source-patch-preview-safe-local-checks-v1" {
        return Err(anyhow!(
            "source patch sandbox plan allowlistPolicyId must be source-patch-preview-safe-local-checks-v1"
        ));
    }
    Ok(validation)
}

pub fn validate_source_patch_sandbox_evaluator_plan(
    plan: &SourcePatchSandboxEvaluatorPlan,
) -> Result<SourcePatchSandboxEvaluatorPlanValidation> {
    let validation = inspect_source_patch_sandbox_evaluator_plan(plan);
    if validation.is_blocked() {
        return Err(anyhow!(
            "source patch sandbox evaluator plan blocked: {}",
            validation.blocked_reasons.join("; ")
        ));
    }
    Ok(validation)
}

pub fn apply_source_patch_preview_in_sandbox(
    artifact: &SourcePatchPreviewArtifact,
    plan: &SourcePatchSandboxEvaluatorPlan,
    trusted_repo_root: impl AsRef<Path>,
    run_dir: impl AsRef<Path>,
) -> Result<SourcePatchSandboxApplyResult> {
    validate_source_patch_sandbox_evaluator_plan(plan)?;
    validate_source_patch_sandbox_preview_inputs(artifact, plan)?;
    if artifact.patch_preview_id != plan.inputs.patch_preview_id {
        return Err(anyhow!(
            "patch preview id {} does not match sandbox plan input {}",
            artifact.patch_preview_id,
            plan.inputs.patch_preview_id
        ));
    }
    if artifact.source_mutation_apply_status != SourcePatchPreviewApplyStatus::Blocked {
        return Err(anyhow!(
            "trusted source mutation apply must remain blocked for sandbox preview"
        ));
    }
    let diff_text = artifact
        .diff_summary
        .diff_text
        .as_deref()
        .ok_or_else(|| anyhow!("source patch sandbox apply requires diffSummary.diffText"))?;
    let diff_files = parse_source_patch_sandbox_apply_diff(diff_text)?;
    let run_dir = run_dir.as_ref();
    let trusted_repo_root = trusted_repo_root.as_ref();
    let sandbox_root = run_dir.join(&plan.layout.sandbox_root);
    let worktree_root = run_dir.join(&plan.layout.worktree_path);
    let evidence_root = run_dir.join(&plan.layout.evidence_path);
    let report_path = run_dir.join(&plan.layout.report_path);

    fs::create_dir_all(&sandbox_root).with_context(|| {
        format!(
            "failed to create source patch sandbox root {}",
            sandbox_root.display()
        )
    })?;
    fs::create_dir_all(&worktree_root).with_context(|| {
        format!(
            "failed to create source patch sandbox worktree {}",
            worktree_root.display()
        )
    })?;
    fs::create_dir_all(&evidence_root).with_context(|| {
        format!(
            "failed to create source patch sandbox evidence {}",
            evidence_root.display()
        )
    })?;
    ensure_path_inside(&sandbox_root, &worktree_root)?;
    ensure_path_inside(&sandbox_root, &evidence_root)?;
    ensure_path_inside(&sandbox_root, &report_path)?;

    let diff_paths = diff_files
        .iter()
        .map(|file| file.target_path.clone())
        .collect::<BTreeSet<_>>();
    let target_paths = artifact
        .targets
        .iter()
        .map(|target| target.path.clone())
        .collect::<BTreeSet<_>>();
    if diff_paths != target_paths {
        return Err(anyhow!(
            "sandbox apply diff targets must match preview targets exactly"
        ));
    }

    let mut trusted_before_hashes = BTreeMap::<String, String>::new();
    for target in &artifact.targets {
        validate_patch_draft_target_path(&target.path)?;
        let trusted_path = trusted_repo_root.join(&target.path);
        let trusted_expected_hash =
            source_patch_sandbox_file_hash_for_expected(&trusted_path, &target.before_hash)
                .with_context(|| {
                    format!(
                        "failed to hash trusted source patch target {}",
                        trusted_path.display()
                    )
                })?;
        if target.before_hash != trusted_expected_hash {
            return Err(anyhow!(
                "stale source patch target {}: expected {}, found {}; trusted worktree was not modified",
                target.path,
                target.before_hash,
                trusted_expected_hash
            ));
        }
        let trusted_snapshot_hash =
            source_patch_sandbox_file_hash(&trusted_path).with_context(|| {
                format!(
                    "failed to snapshot trusted source patch target {}",
                    trusted_path.display()
                )
            })?;
        trusted_before_hashes.insert(target.path.clone(), trusted_snapshot_hash);
    }

    copy_source_patch_sandbox_worktree(trusted_repo_root, &worktree_root)?;

    for diff_file in &diff_files {
        let sandbox_path = worktree_root.join(&diff_file.target_path);
        ensure_path_inside(&worktree_root, &sandbox_path)?;
        let original = fs::read_to_string(&sandbox_path).with_context(|| {
            format!(
                "failed to read sandbox target before apply {}",
                sandbox_path.display()
            )
        })?;
        let patched =
            apply_source_patch_sandbox_hunks(&original, &diff_file.hunks).with_context(|| {
                format!(
                    "failed to apply source patch preview to sandbox target {}",
                    diff_file.target_path
                )
            })?;
        fs::write(&sandbox_path, patched).with_context(|| {
            format!(
                "failed to write patched sandbox target {}",
                sandbox_path.display()
            )
        })?;
    }

    let mut target_snapshots = Vec::new();
    for target in &artifact.targets {
        let trusted_path = trusted_repo_root.join(&target.path);
        let sandbox_path = worktree_root.join(&target.path);
        let trusted_before_hash = trusted_before_hashes
            .get(&target.path)
            .cloned()
            .unwrap_or_default();
        let sandbox_before_hash = trusted_before_hash.clone();
        let sandbox_after_hash =
            source_patch_sandbox_file_hash(&sandbox_path).with_context(|| {
                format!(
                    "failed to hash sandbox target after apply {}",
                    sandbox_path.display()
                )
            })?;
        let trusted_after_hash =
            source_patch_sandbox_file_hash(&trusted_path).with_context(|| {
                format!(
                    "failed to hash trusted target after sandbox apply {}",
                    trusted_path.display()
                )
            })?;
        if trusted_after_hash != trusted_before_hash {
            return Err(anyhow!(
                "trusted target {} changed during sandbox apply; refusing result",
                target.path
            ));
        }
        target_snapshots.push(SourcePatchSandboxTargetSnapshot {
            path: target.path.clone(),
            trusted_before_hash,
            sandbox_before_hash,
            sandbox_after_hash,
            trusted_after_hash,
        });
    }

    let result = SourcePatchSandboxApplyResult {
        schema_version: "source-patch-sandbox-apply-result-v1".to_string(),
        status: "passed".to_string(),
        patch_preview_id: artifact.patch_preview_id.clone(),
        sandbox_root: plan.layout.sandbox_root.clone(),
        worktree_path: plan.layout.worktree_path.clone(),
        report_path: plan.layout.report_path.clone(),
        target_snapshots,
        commands_run: Vec::new(),
        guardrails: vec![
            "source patch preview applied only to sandbox worktree copies".to_string(),
            "trusted main worktree files are hashed before and after and are not written".to_string(),
            "no shell, git apply, network, install, credential, dependency, or test commands are run".to_string(),
            "sandbox report is generated under sandbox evidence only".to_string(),
        ],
        blocked_reasons: Vec::new(),
    };
    write_json_atomic(&report_path, &json!(result))?;
    Ok(result)
}

fn copy_source_patch_sandbox_worktree(
    trusted_repo_root: &Path,
    worktree_root: &Path,
) -> Result<()> {
    copy_source_patch_sandbox_dir(trusted_repo_root, trusted_repo_root, worktree_root)
}

fn copy_source_patch_sandbox_dir(
    trusted_repo_root: &Path,
    source_dir: &Path,
    worktree_root: &Path,
) -> Result<()> {
    for entry in fs::read_dir(source_dir)
        .with_context(|| format!("failed to read trusted directory {}", source_dir.display()))?
    {
        let entry = entry?;
        let source_path = entry.path();
        let relative_path = source_path.strip_prefix(trusted_repo_root)?;
        if source_patch_sandbox_copy_skip_path(relative_path) {
            continue;
        }
        let destination_path = worktree_root.join(relative_path);
        ensure_path_inside(worktree_root, &destination_path)?;
        let file_type = entry.file_type()?;
        if file_type.is_dir() {
            fs::create_dir_all(&destination_path)?;
            copy_source_patch_sandbox_dir(trusted_repo_root, &source_path, worktree_root)?;
        } else if file_type.is_file() {
            if let Some(parent) = destination_path.parent() {
                fs::create_dir_all(parent)?;
            }
            fs::copy(&source_path, &destination_path)?;
        }
    }
    Ok(())
}

fn source_patch_sandbox_copy_skip_path(relative_path: &Path) -> bool {
    let first_component = relative_path
        .components()
        .find_map(|component| match component {
            std::path::Component::Normal(value) => Some(value.to_string_lossy()),
            _ => None,
        });
    first_component.is_some_and(|value| {
        matches!(
            value.as_ref(),
            ".git"
                | "runs"
                | "sandbox"
                | "target"
                | "dashboard-data"
                | ".omx"
                | ".openchrome"
                | ".omc"
                | ".claude"
        )
    })
}

#[derive(Debug, Clone)]
struct SourcePatchSandboxApplyDiffFile {
    target_path: String,
    hunks: Vec<SourcePatchSandboxApplyHunk>,
}

#[derive(Debug, Clone)]
struct SourcePatchSandboxApplyHunk {
    old_start: usize,
    lines: Vec<String>,
}

fn parse_source_patch_sandbox_apply_diff(
    diff_text: &str,
) -> Result<Vec<SourcePatchSandboxApplyDiffFile>> {
    validate_unified_patch_diff_for_preview(diff_text, PatchDiffIntegrityLimits::default())?;
    let mut files = Vec::<SourcePatchSandboxApplyDiffFile>::new();
    let mut current_path: Option<String> = None;
    let mut current_hunks = Vec::<SourcePatchSandboxApplyHunk>::new();
    let mut current_hunk: Option<SourcePatchSandboxApplyHunk> = None;

    for line in diff_text.lines() {
        if line.starts_with("diff --git ") {
            finish_source_patch_sandbox_apply_hunk(&mut current_hunks, &mut current_hunk);
            finish_source_patch_sandbox_apply_file(
                &mut files,
                &mut current_path,
                &mut current_hunks,
            );
        } else if line.starts_with("+++ ") {
            let path = normalize_diff_path(line.trim_start_matches("+++ ").trim());
            if path == "/dev/null" {
                return Err(anyhow!(
                    "source patch sandbox apply does not support deleting targets"
                ));
            }
            current_path = Some(path);
        } else if line.starts_with("@@ ") {
            finish_source_patch_sandbox_apply_hunk(&mut current_hunks, &mut current_hunk);
            let hunk = parse_unified_hunk_header(line).ok_or_else(|| {
                anyhow!("source patch sandbox apply hunk header could not be parsed")
            })?;
            current_hunk = Some(SourcePatchSandboxApplyHunk {
                old_start: hunk.old_start as usize,
                lines: Vec::new(),
            });
        } else if let Some(hunk) = &mut current_hunk {
            if matches!(line.as_bytes().first(), Some(b' ' | b'+' | b'-' | b'\\')) {
                hunk.lines.push(line.to_string());
            }
        }
    }
    finish_source_patch_sandbox_apply_hunk(&mut current_hunks, &mut current_hunk);
    finish_source_patch_sandbox_apply_file(&mut files, &mut current_path, &mut current_hunks);
    if files.is_empty() {
        return Err(anyhow!(
            "source patch sandbox apply requires at least one diff target"
        ));
    }
    Ok(files)
}

fn finish_source_patch_sandbox_apply_hunk(
    hunks: &mut Vec<SourcePatchSandboxApplyHunk>,
    current_hunk: &mut Option<SourcePatchSandboxApplyHunk>,
) {
    if let Some(hunk) = current_hunk.take() {
        hunks.push(hunk);
    }
}

fn finish_source_patch_sandbox_apply_file(
    files: &mut Vec<SourcePatchSandboxApplyDiffFile>,
    current_path: &mut Option<String>,
    current_hunks: &mut Vec<SourcePatchSandboxApplyHunk>,
) {
    if let Some(target_path) = current_path.take() {
        files.push(SourcePatchSandboxApplyDiffFile {
            target_path,
            hunks: std::mem::take(current_hunks),
        });
    }
}

fn apply_source_patch_sandbox_hunks(
    original: &str,
    hunks: &[SourcePatchSandboxApplyHunk],
) -> Result<String> {
    let had_trailing_newline = original.ends_with('\n');
    let mut lines = original.split('\n').map(str::to_string).collect::<Vec<_>>();
    if had_trailing_newline {
        lines.pop();
    }
    let mut output = Vec::<String>::new();
    let mut cursor = 0usize;
    for hunk in hunks {
        let hunk_start = hunk.old_start.saturating_sub(1);
        if hunk_start < cursor || hunk_start > lines.len() {
            return Err(anyhow!(
                "source patch sandbox hunk start is outside target content"
            ));
        }
        output.extend(lines[cursor..hunk_start].iter().cloned());
        cursor = hunk_start;
        for line in &hunk.lines {
            if line.starts_with('\\') {
                continue;
            }
            if let Some(expected) = line.strip_prefix(' ') {
                let actual = lines.get(cursor).ok_or_else(|| {
                    anyhow!("source patch sandbox context line is outside target")
                })?;
                if actual != expected {
                    return Err(anyhow!(
                        "source patch sandbox context mismatch: expected `{expected}`, found `{actual}`"
                    ));
                }
                output.push(actual.clone());
                cursor += 1;
            } else if let Some(expected) = line.strip_prefix('-') {
                let actual = lines.get(cursor).ok_or_else(|| {
                    anyhow!("source patch sandbox removal line is outside target")
                })?;
                if actual != expected {
                    return Err(anyhow!(
                        "source patch sandbox removal mismatch: expected `{expected}`, found `{actual}`"
                    ));
                }
                cursor += 1;
            } else if let Some(added) = line.strip_prefix('+') {
                output.push(added.to_string());
            } else {
                return Err(anyhow!(
                    "source patch sandbox hunk line has unsupported prefix"
                ));
            }
        }
    }
    output.extend(lines[cursor..].iter().cloned());
    let mut patched = output.join("\n");
    if had_trailing_newline {
        patched.push('\n');
    }
    Ok(patched)
}

pub fn run_source_patch_sandbox_allowlisted_tests(
    plan: &SourcePatchSandboxEvaluatorPlan,
    required_tests: &[SourcePatchPreviewRequiredTest],
    run_dir: impl AsRef<Path>,
) -> Result<SourcePatchSandboxTestExecutionReport> {
    validate_source_patch_sandbox_evaluator_plan(plan)?;
    if required_tests.is_empty() {
        return Err(anyhow!(
            "source patch sandbox test execution requires at least one required test"
        ));
    }
    let run_dir = run_dir.as_ref();
    let sandbox_root = run_dir.join(&plan.layout.sandbox_root);
    let worktree_root = run_dir.join(&plan.layout.worktree_path);
    let evidence_root = run_dir.join(&plan.layout.evidence_path);
    let report_path = evidence_root.join("test-execution-report.json");
    if !worktree_root.exists() {
        return Err(anyhow!(
            "source patch sandbox worktree does not exist for test execution: {}",
            worktree_root.display()
        ));
    }
    fs::create_dir_all(&evidence_root).with_context(|| {
        format!(
            "failed to create source patch sandbox test evidence {}",
            evidence_root.display()
        )
    })?;
    ensure_path_inside(&sandbox_root, &worktree_root)?;
    ensure_path_inside(&sandbox_root, &evidence_root)?;
    ensure_path_inside(&sandbox_root, &report_path)?;

    let allowlist = default_source_patch_test_command_allowlist();
    let mut outputs = Vec::new();
    let mut blocked_reasons = Vec::<String>::new();
    for (index, required_test) in required_tests.iter().enumerate() {
        let field = format!("requiredTests[{index}]");
        if required_test.argv.is_empty() {
            blocked_reasons.push(format!("{field}.argv must not be empty"));
            continue;
        }
        let normalized = normalize_source_patch_test_command(&required_test.argv);
        if required_test.command != normalized {
            blocked_reasons.push(format!(
                "{field}.command must match normalized argv `{normalized}`"
            ));
            continue;
        }
        if required_test.allowlist_policy_id.as_deref()
            != Some("source-patch-preview-safe-local-checks-v1")
        {
            blocked_reasons.push(format!(
                "{field}.allowlistPolicyId must be source-patch-preview-safe-local-checks-v1"
            ));
            continue;
        }
        let command = SourcePatchTestCommand {
            command: required_test.command.clone(),
            argv: required_test.argv.clone(),
        };
        if let Some(forbidden) = classify_source_patch_forbidden_test_command(&command) {
            blocked_reasons.push(format!("{field}.argv forbidden: {}", forbidden.reason));
            continue;
        }
        let Some(match_result) = allowlist.match_command(&command) else {
            blocked_reasons.push(format!(
                "{field}.argv is not in the source patch test command allowlist"
            ));
            continue;
        };
        if required_test.argv.first().is_some_and(|arg| arg == "cargo")
            && !worktree_root.join("Cargo.toml").is_file()
        {
            blocked_reasons.push(format!(
                "{field}.argv cargo command requires sandbox worktree Cargo.toml to avoid trusted parent workspace discovery"
            ));
            continue;
        }
        let mut command_runner = Command::new(&required_test.argv[0]);
        command_runner
            .args(&required_test.argv[1..])
            .current_dir(&worktree_root);
        if required_test.argv.first().is_some_and(|arg| arg == "cargo") {
            command_runner.env("CARGO_TARGET_DIR", worktree_root.join("target"));
        }
        let output = command_runner.output().with_context(|| {
            format!(
                "failed to run allowlisted sandbox test `{}` in {}",
                required_test.command,
                worktree_root.display()
            )
        })?;
        let exit_code = output.status.code();
        let status = if output.status.success() {
            "passed"
        } else {
            "failed"
        }
        .to_string();
        if !output.status.success() {
            blocked_reasons.push(format!(
                "{field}.command exited with status {}",
                exit_code
                    .map(|code| code.to_string())
                    .unwrap_or_else(|| "terminated-by-signal".to_string())
            ));
        }
        outputs.push(SourcePatchSandboxTestExecutionOutput {
            command: required_test.command.clone(),
            argv: required_test.argv.clone(),
            allowlist_policy_id: match_result.policy_id,
            exit_code,
            status,
            stdout_preview: bounded_utf8_preview(&output.stdout, 4096),
            stderr_preview: bounded_utf8_preview(&output.stderr, 4096),
        });
    }
    blocked_reasons.sort();
    blocked_reasons.dedup();
    let commands_run = outputs
        .iter()
        .map(|output| output.command.clone())
        .collect::<Vec<_>>();
    let report = SourcePatchSandboxTestExecutionReport {
        schema_version: "source-patch-sandbox-test-execution-report-v1".to_string(),
        status: if blocked_reasons.is_empty() {
            "passed".to_string()
        } else {
            "blocked".to_string()
        },
        sandbox_root: plan.layout.sandbox_root.clone(),
        worktree_path: plan.layout.worktree_path.clone(),
        report_path: report_path
            .strip_prefix(run_dir)
            .ok()
            .and_then(|path| path.to_str())
            .unwrap_or("sandbox/test-execution-report.json")
            .to_string(),
        commands_run,
        tests: outputs,
        blocked_reasons,
        guardrails: vec![
            "sandbox tests execute only argv vectors matched by the source patch test command allowlist".to_string(),
            "sandbox tests run with current_dir set to the sandbox worktree and cargo requires a sandbox Cargo.toml".to_string(),
            "cargo sandbox tests use a sandbox-local CARGO_TARGET_DIR".to_string(),
            "no shell, network, install, credential, dependency, merge, or trusted apply commands are allowed".to_string(),
            "test evidence is written under sandbox evidence only".to_string(),
        ],
    };
    write_json_atomic(&report_path, &json!(report))?;
    if report.status == "blocked" {
        return Err(anyhow!(
            "source patch sandbox test execution blocked: {}",
            report.blocked_reasons.join("; ")
        ));
    }
    Ok(report)
}

fn bounded_utf8_preview(bytes: &[u8], max_chars: usize) -> String {
    String::from_utf8_lossy(bytes)
        .chars()
        .take(max_chars)
        .collect()
}

fn source_patch_sandbox_file_hash_for_expected(path: &Path, expected: &str) -> Result<String> {
    let bytes = fs::read(path).with_context(|| format!("failed to read {}", path.display()))?;
    if expected.starts_with("sha256:") {
        return Ok(format!(
            "sha256:{}",
            source_patch_sandbox_sha256_hex(&bytes)
        ));
    }
    if expected.starts_with("fnv1a64-file-v1:") {
        return Ok(format!("fnv1a64-file-v1:{:016x}", fnv1a64(&bytes)));
    }
    Err(anyhow!(
        "source patch sandbox beforeHash must use sha256: or fnv1a64-file-v1:"
    ))
}

fn source_patch_sandbox_file_hash(path: &Path) -> Result<String> {
    let bytes = fs::read(path).with_context(|| format!("failed to read {}", path.display()))?;
    Ok(format!("fnv1a64-file-v1:{:016x}", fnv1a64(&bytes)))
}

fn source_patch_sandbox_sha256_hex(bytes: &[u8]) -> String {
    const INITIAL: [u32; 8] = [
        0x6a09e667, 0xbb67ae85, 0x3c6ef372, 0xa54ff53a, 0x510e527f, 0x9b05688c, 0x1f83d9ab,
        0x5be0cd19,
    ];
    const K: [u32; 64] = [
        0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1, 0x923f82a4,
        0xab1c5ed5, 0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3, 0x72be5d74, 0x80deb1fe,
        0x9bdc06a7, 0xc19bf174, 0xe49b69c1, 0xefbe4786, 0x0fc19dc6, 0x240ca1cc, 0x2de92c6f,
        0x4a7484aa, 0x5cb0a9dc, 0x76f988da, 0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7,
        0xc6e00bf3, 0xd5a79147, 0x06ca6351, 0x14292967, 0x27b70a85, 0x2e1b2138, 0x4d2c6dfc,
        0x53380d13, 0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85, 0xa2bfe8a1, 0xa81a664b,
        0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070, 0x19a4c116,
        0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a, 0x5b9cca4f, 0x682e6ff3,
        0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208, 0x90befffa, 0xa4506ceb, 0xbef9a3f7,
        0xc67178f2,
    ];
    let mut message = bytes.to_vec();
    let bit_len = (message.len() as u64) * 8;
    message.push(0x80);
    while (message.len() % 64) != 56 {
        message.push(0);
    }
    message.extend_from_slice(&bit_len.to_be_bytes());

    let mut hash = INITIAL;
    for chunk in message.chunks(64) {
        let mut w = [0u32; 64];
        for (index, word) in w.iter_mut().take(16).enumerate() {
            let start = index * 4;
            *word = u32::from_be_bytes([
                chunk[start],
                chunk[start + 1],
                chunk[start + 2],
                chunk[start + 3],
            ]);
        }
        for index in 16..64 {
            let s0 = w[index - 15].rotate_right(7)
                ^ w[index - 15].rotate_right(18)
                ^ (w[index - 15] >> 3);
            let s1 = w[index - 2].rotate_right(17)
                ^ w[index - 2].rotate_right(19)
                ^ (w[index - 2] >> 10);
            w[index] = w[index - 16]
                .wrapping_add(s0)
                .wrapping_add(w[index - 7])
                .wrapping_add(s1);
        }
        let [mut a, mut b, mut c, mut d, mut e, mut f, mut g, mut h] = hash;
        for index in 0..64 {
            let s1 = e.rotate_right(6) ^ e.rotate_right(11) ^ e.rotate_right(25);
            let ch = (e & f) ^ ((!e) & g);
            let temp1 = h
                .wrapping_add(s1)
                .wrapping_add(ch)
                .wrapping_add(K[index])
                .wrapping_add(w[index]);
            let s0 = a.rotate_right(2) ^ a.rotate_right(13) ^ a.rotate_right(22);
            let maj = (a & b) ^ (a & c) ^ (b & c);
            let temp2 = s0.wrapping_add(maj);
            h = g;
            g = f;
            f = e;
            e = d.wrapping_add(temp1);
            d = c;
            c = b;
            b = a;
            a = temp1.wrapping_add(temp2);
        }
        for (slot, value) in hash.iter_mut().zip([a, b, c, d, e, f, g, h]) {
            *slot = slot.wrapping_add(value);
        }
    }
    hash.iter()
        .map(|word| format!("{word:08x}"))
        .collect::<Vec<_>>()
        .join("")
}

pub fn normalize_source_patch_test_command(argv: &[String]) -> String {
    argv.iter()
        .map(|arg| arg.trim())
        .collect::<Vec<_>>()
        .join(" ")
}

fn source_patch_test_command_matches_allowlist(command: &SourcePatchAllowedTestCommand) -> bool {
    let argv = command.argv.iter().map(String::as_str).collect::<Vec<_>>();
    match command.match_policy {
        SourcePatchTestCommandMatchPolicy::Exact => source_patch_exact_test_commands()
            .iter()
            .any(|allowed| allowed.as_slice() == argv.as_slice()),
        SourcePatchTestCommandMatchPolicy::Prefix => source_patch_prefix_test_commands()
            .iter()
            .any(|allowed| argv.starts_with(allowed.as_slice())),
    }
}

fn source_patch_exact_test_commands() -> Vec<Vec<&'static str>> {
    vec![
        vec!["cargo", "fmt", "--check"],
        vec!["cargo", "test"],
        vec![
            "cargo",
            "clippy",
            "--all-targets",
            "--all-features",
            "--",
            "-D",
            "warnings",
        ],
        vec![
            "node",
            "--check",
            "examples/evidence-dashboard/dashboard.js",
        ],
        vec!["node", "examples/evidence-dashboard/dashboard.test.cjs"],
        vec!["node", "--check", "examples/authoring-cockpit/cockpit.js"],
        vec!["node", "examples/authoring-cockpit/cockpit.test.cjs"],
    ]
}

fn source_patch_prefix_test_commands() -> Vec<Vec<&'static str>> {
    vec![
        vec!["cargo", "test", "-p", "ouroforge-core"],
        vec!["cargo", "test", "-p", "ouroforge-cli"],
    ]
}

pub fn source_patch_preview_read_model(
    validation: &SourcePatchPreviewValidation,
) -> SourcePatchPreviewReadModel {
    let (diff_file_count, changed_lines) = validation
        .diff_integrity_validation
        .as_ref()
        .map(|diff| {
            (
                diff.report.file_count,
                diff.report.counts.added + diff.report.counts.removed,
            )
        })
        .unwrap_or((0, 0));
    SourcePatchPreviewReadModel {
        schema_version: "source-patch-preview-read-model-v1".to_string(),
        status: validation.status.clone(),
        patch_preview_id: validation.patch_preview_id.clone(),
        target_count: validation.file_class_validation.targets.len(),
        diff_file_count,
        changed_lines,
        blocked_reasons: validation.blocked_reasons.clone(),
        target_summaries: validation
            .file_class_validation
            .targets
            .iter()
            .map(|target| {
                let class = serde_json::to_value(&target.class)
                    .ok()
                    .and_then(|value| value.as_str().map(ToOwned::to_owned))
                    .unwrap_or_else(|| "unknown".to_string());
                let decision = serde_json::to_value(&target.decision)
                    .ok()
                    .and_then(|value| value.as_str().map(ToOwned::to_owned))
                    .unwrap_or_else(|| "unknown".to_string());
                format!("{}: {class}/{decision}", target.path)
            })
            .collect(),
        guardrails: validation.guardrails.clone(),
    }
}

impl SourcePatchPreviewArtifact {
    pub fn apply_is_blocked(&self) -> bool {
        self.source_mutation_apply_status == SourcePatchPreviewApplyStatus::Blocked
    }
}

pub fn inspect_source_patch_preview_artifact(
    artifact: &SourcePatchPreviewArtifact,
    limits: PatchDiffIntegrityLimits,
) -> SourcePatchPreviewValidation {
    let mut blocked_reasons = Vec::<String>::new();

    if artifact.schema_version != SOURCE_PATCH_PREVIEW_SCHEMA_VERSION {
        blocked_reasons.push(format!(
            "schemaVersion must be {SOURCE_PATCH_PREVIEW_SCHEMA_VERSION}"
        ));
    }
    if artifact.patch_preview_id.trim().is_empty() {
        blocked_reasons.push("patchPreviewId must not be empty".to_string());
    }
    if artifact.proposal_id.trim().is_empty() {
        blocked_reasons.push("proposalId must not be empty".to_string());
    }
    if artifact.created_at.trim().is_empty() {
        blocked_reasons.push("createdAt must not be empty".to_string());
    }
    if artifact.stale_target_policy.trim().is_empty() {
        blocked_reasons.push("staleTargetPolicy must not be empty".to_string());
    }
    if artifact.artifact_hash.trim().is_empty() {
        blocked_reasons.push("artifactHash must not be empty".to_string());
    }
    if artifact.targets.is_empty() {
        blocked_reasons.push("targets must not be empty".to_string());
    }

    let mut target_paths_seen = BTreeSet::<String>::new();
    let mut target_path_set = BTreeSet::<String>::new();
    for (index, target) in artifact.targets.iter().enumerate() {
        let field = format!("targets[{index}]");
        if !target_paths_seen.insert(target.path.clone()) {
            blocked_reasons.push(format!("duplicate target path {}", target.path));
        }
        target_path_set.insert(target.path.clone());
        push_if_blank(&mut blocked_reasons, &format!("{field}.path"), &target.path);
        require_sha256_like(
            &mut blocked_reasons,
            &format!("{field}.beforeHash"),
            &target.before_hash,
        );
        if let Some(after_hash) = &target.after_hash {
            require_sha256_like(
                &mut blocked_reasons,
                &format!("{field}.afterHash"),
                after_hash,
            );
        }
        push_if_blank(
            &mut blocked_reasons,
            &format!("{field}.fileClass"),
            &target.file_class,
        );
        push_if_blank(
            &mut blocked_reasons,
            &format!("{field}.reviewLevel"),
            &target.review_level,
        );
        push_if_blank(
            &mut blocked_reasons,
            &format!("{field}.classificationRationale"),
            &target.classification_rationale,
        );
        if !matches!(
            target.classification_status.as_str(),
            "potentially_allowed_later" | "restricted_separate_approval" | "blocked_by_design"
        ) {
            blocked_reasons.push(format!(
                "{field}.classificationStatus has unsupported value {}",
                target.classification_status
            ));
        }
        let class_report = classify_source_file_path_str(&target.path);
        let expected_file_class = source_file_class_label_value(&class_report.class);
        if target.file_class != expected_file_class {
            blocked_reasons.push(format!(
                "{field}.fileClass expected {expected_file_class} from current file-class policy for {}",
                target.path
            ));
        }
        let expected_status = match class_report.decision {
            SourceFileClassDecision::Allowed => "potentially_allowed_later",
            SourceFileClassDecision::NeedsApproval => "restricted_separate_approval",
            SourceFileClassDecision::Blocked => "blocked_by_design",
        };
        if class_report.is_blocked() && target.blocked_reasons.is_empty() {
            blocked_reasons.push(format!(
                "{field}.blockedReasons required for blocked target {}",
                target.path
            ));
        }
        if target.classification_status != expected_status {
            blocked_reasons.push(format!(
                "{field}.classificationStatus expected {expected_status} from current file-class policy for {}",
                target.path
            ));
        }
    }

    push_if_blank(
        &mut blocked_reasons,
        "diffSummary.summary",
        &artifact.diff_summary.summary,
    );
    if artifact.diff_summary.diff_stats.truncated
        && artifact.diff_summary.large_diff_warning.is_none()
    {
        blocked_reasons
            .push("largeDiffWarning required when diffStats.truncated is true".to_string());
    }
    if artifact.diff_summary.diff_stats.binary_or_opaque
        && artifact.diff_summary.binary_or_opaque_warning.is_none()
    {
        blocked_reasons.push(
            "binaryOrOpaqueWarning required when diffStats.binaryOrOpaque is true".to_string(),
        );
    }
    if artifact.diff_summary.diff_stats.generated_origin
        && !preview_has_blocked_reason_containing(artifact, "generated")
    {
        blocked_reasons.push(
            "generated-origin preview requires generated blocked/promotion rationale".to_string(),
        );
    }
    for (index, hunk) in artifact.diff_summary.hunks.iter().enumerate() {
        if !target_path_set.contains(&hunk.path) {
            blocked_reasons.push(format!(
                "diffSummary.hunks[{index}].path {} is missing from targets",
                hunk.path
            ));
        }
        push_if_blank(
            &mut blocked_reasons,
            &format!("diffSummary.hunks[{index}].summary"),
            &hunk.summary,
        );
    }

    if artifact.risk_ids.is_empty() {
        blocked_reasons.push("riskIds must not be empty".to_string());
    }
    for risk_id in &artifact.risk_ids {
        if !is_known_source_patch_risk_id(risk_id) {
            blocked_reasons.push(format!(
                "riskIds contains unsupported threat-model id {risk_id}"
            ));
        }
    }
    if artifact.linked_evidence.is_empty() {
        blocked_reasons.push("linkedEvidence must not be empty".to_string());
    }
    if artifact.required_tests.is_empty() {
        blocked_reasons.push("requiredTests must not be empty".to_string());
    }
    if artifact.risk_ids.is_empty() {
        blocked_reasons.push("riskIds must not be empty".to_string());
    }
    if artifact.expected_behavior_change.trim().is_empty() {
        blocked_reasons.push("expectedBehaviorChange must not be empty".to_string());
    }
    if artifact.reviewer_checklist.is_empty() {
        blocked_reasons.push("reviewerChecklist must not be empty".to_string());
    }
    if !artifact.rollback_expectations.required_before_apply {
        blocked_reasons
            .push("rollbackExpectations.requiredBeforeApply must remain true".to_string());
    }

    let mut seen_targets = BTreeSet::<String>::new();
    for target in &artifact.targets {
        if target.path.trim().is_empty() {
            blocked_reasons.push("target path must not be empty".to_string());
        } else if !seen_targets.insert(target.path.clone()) {
            blocked_reasons.push(format!("duplicate target file {}", target.path));
        }
        if target.before_hash.trim().is_empty() {
            blocked_reasons.push(format!("{} beforeHash must not be empty", target.path));
        }
        if target.file_class.trim().is_empty() {
            blocked_reasons.push(format!("{} fileClass must not be empty", target.path));
        }
        if target.review_level.trim().is_empty() {
            blocked_reasons.push(format!("{} reviewLevel must not be empty", target.path));
        }
        if target.classification_rationale.trim().is_empty() {
            blocked_reasons.push(format!(
                "{} classificationRationale must not be empty",
                target.path
            ));
        }
        if matches!(
            target.classification_status.as_str(),
            "restricted_separate_approval" | "blocked_by_design"
        ) && target.blocked_reasons.is_empty()
        {
            blocked_reasons.push(format!(
                "{} blockedReasons must explain restricted or blocked classification",
                target.path
            ));
        }
    }

    for evidence in &artifact.linked_evidence {
        if evidence.kind.trim().is_empty() || evidence.path.trim().is_empty() {
            blocked_reasons.push("linkedEvidence entries require kind and path".to_string());
        }
    }
    for required_test in &artifact.required_tests {
        if required_test.command.trim().is_empty() {
            blocked_reasons.push("requiredTests command must not be empty".to_string());
        }
        if !required_test.execution_authority.contains("copyable")
            || !required_test.execution_authority.contains("not_executed")
        {
            blocked_reasons.push(format!(
                "required test command '{}' must remain copyable/not_executed metadata",
                required_test.command
            ));
        }
        if let Some(policy_id) = &required_test.allowlist_policy_id {
            if policy_id.trim().is_empty() {
                blocked_reasons
                    .push("requiredTests allowlistPolicyId must not be empty".to_string());
            }
            if policy_id != "source-patch-preview-safe-local-checks-v1" {
                blocked_reasons.push(format!(
                    "requiredTests allowlistPolicyId {policy_id} is unsupported"
                ));
            }
            if required_test.argv.is_empty() {
                blocked_reasons.push(
                    "requiredTests argv required when allowlistPolicyId is present".to_string(),
                );
            }
        }
        if !required_test.argv.is_empty() {
            let normalized = normalize_source_patch_test_command(&required_test.argv);
            if required_test.command != normalized {
                blocked_reasons.push(format!(
                    "requiredTests command must match normalized argv `{normalized}`"
                ));
            }
            let command = SourcePatchTestCommand {
                command: required_test.command.clone(),
                argv: required_test.argv.clone(),
            };
            if let Some(forbidden) = classify_source_patch_forbidden_test_command(&command) {
                blocked_reasons.push(format!(
                    "requiredTests command forbidden by allowlist policy: {}",
                    forbidden.reason
                ));
            } else if default_source_patch_test_command_allowlist()
                .match_command(&command)
                .is_none()
            {
                blocked_reasons.push(
                    "requiredTests command is not in the source patch test command allowlist"
                        .to_string(),
                );
            }
        }
    }

    let target_paths: Vec<PathBuf> = artifact
        .targets
        .iter()
        .map(|target| PathBuf::from(&target.path))
        .collect();
    let file_class_validation = classify_source_patch_preview_targets(target_paths.iter());
    blocked_reasons.extend(
        file_class_validation
            .blocked_reasons
            .iter()
            .map(|reason| format!("file class blocked: {reason}")),
    );

    let diff_integrity_validation = match artifact.diff_summary.diff_text.as_deref() {
        Some(diff_text) if !diff_text.trim().is_empty() => {
            match inspect_unified_patch_diff_for_preview(diff_text, limits) {
                Ok(validation) => {
                    blocked_reasons.extend(
                        validation
                            .blocked_reasons
                            .iter()
                            .map(|reason| format!("diff integrity blocked: {reason}")),
                    );
                    let changed_lines =
                        validation.report.counts.added + validation.report.counts.removed;
                    if validation.report.file_count
                        != artifact.diff_summary.diff_stats.files_changed
                    {
                        blocked_reasons.push(format!(
                            "diffStats.filesChanged {} does not match parsed fileCount {}",
                            artifact.diff_summary.diff_stats.files_changed,
                            validation.report.file_count
                        ));
                    }
                    if validation.report.counts.added != artifact.diff_summary.diff_stats.additions
                    {
                        blocked_reasons.push(format!(
                            "diffStats.additions {} does not match parsed additions {}",
                            artifact.diff_summary.diff_stats.additions,
                            validation.report.counts.added
                        ));
                    }
                    if validation.report.counts.removed
                        != artifact.diff_summary.diff_stats.deletions
                    {
                        blocked_reasons.push(format!(
                            "diffStats.deletions {} does not match parsed deletions {}",
                            artifact.diff_summary.diff_stats.deletions,
                            validation.report.counts.removed
                        ));
                    }
                    if changed_lines == 0 {
                        blocked_reasons.push("diffText must include changed lines".to_string());
                    }
                    Some(validation)
                }
                Err(error) => {
                    blocked_reasons.push(format!("diffText parse failed: {error}"));
                    None
                }
            }
        }
        _ => {
            blocked_reasons.push("diffSummary.diffText must not be empty".to_string());
            None
        }
    };

    blocked_reasons.sort();
    blocked_reasons.dedup();

    SourcePatchPreviewValidation {
        schema_version: "source-patch-preview-validation-v1".to_string(),
        status: if blocked_reasons.is_empty() {
            "passed".to_string()
        } else {
            "blocked".to_string()
        },
        patch_preview_id: artifact.patch_preview_id.clone(),
        file_class_validation,
        diff_integrity_validation,
        blocked_reasons,
        guardrails: vec![
            "source patch preview validation only; no source patch apply".to_string(),
            "diff integrity and file class checks run before any sandbox evaluation".to_string(),
            "required tests remain inert copyable metadata, not command execution".to_string(),
            "browser/dashboard/Studio surfaces remain read-only and command-inert".to_string(),
        ],
    }
}

pub fn validate_source_patch_preview_artifact(
    artifact: &SourcePatchPreviewArtifact,
    limits: PatchDiffIntegrityLimits,
) -> Result<SourcePatchPreviewValidation> {
    let validation = inspect_source_patch_preview_artifact(artifact, limits);
    if validation.is_blocked() {
        return Err(anyhow!(
            "source patch preview validation blocked: {}",
            validation.blocked_reasons.join("; ")
        ));
    }
    Ok(validation)
}

fn push_if_blank(blocked_reasons: &mut Vec<String>, field: &str, value: &str) {
    if value.trim().is_empty() {
        blocked_reasons.push(format!("{field} must not be empty"));
    }
}

fn require_sha256_like(blocked_reasons: &mut Vec<String>, field: &str, value: &str) {
    push_if_blank(blocked_reasons, field, value);
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return;
    }
    let Some(hex) = trimmed.strip_prefix("sha256:") else {
        blocked_reasons.push(format!("{field} must use sha256: prefix"));
        return;
    };
    if hex.len() != 64 || !hex.chars().all(|ch| ch.is_ascii_hexdigit()) {
        blocked_reasons.push(format!(
            "{field} must be sha256: followed by exactly 64 hex characters"
        ));
    }
}

fn source_file_class_label_value(class: &SourceFileClassLabel) -> String {
    serde_json::to_value(class)
        .ok()
        .and_then(|value| value.as_str().map(ToOwned::to_owned))
        .map(|value| value.replace('-', "_"))
        .unwrap_or_else(|| "unknown".to_string())
}

fn preview_has_blocked_reason_containing(
    artifact: &SourcePatchPreviewArtifact,
    needle: &str,
) -> bool {
    artifact.targets.iter().any(|target| {
        target
            .blocked_reasons
            .iter()
            .any(|reason| reason.to_ascii_lowercase().contains(needle))
    }) || artifact
        .read_model_prototype
        .as_ref()
        .is_some_and(|model| model.primary_blocked_reason.contains(needle))
}

fn is_known_source_patch_risk_id(risk_id: &str) -> bool {
    matches!(
        risk_id,
        "STM-01"
            | "STM-02"
            | "STM-03"
            | "STM-04"
            | "STM-05"
            | "STM-06"
            | "STM-07"
            | "STM-08"
            | "STM-09"
            | "STM-10"
            | "STM-11"
            | "STM-12"
            | "STM-13"
            | "STM-14"
            | "STM-15"
    )
}

pub const PATCH_DIFF_INTEGRITY_SCHEMA_VERSION: &str = "patch-diff-integrity-v1";

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum PatchDiffFileStatus {
    Added,
    Modified,
    Deleted,
    Renamed,
    Copied,
    Unknown,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum PatchDiffIntegrityWarningKind {
    MissingFileHeader,
    MissingHunk,
    MalformedGitHeader,
    MalformedFileHeader,
    MalformedHunkHeader,
    HunkLineCountMismatch,
    BinaryPatch,
    ModeChange,
    RenameMetadata,
    CopyMetadata,
    UnexpectedContent,
}

#[derive(Debug, Clone, Default, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffLineCounts {
    pub added: usize,
    pub removed: usize,
    pub context: usize,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffHunkIntegrity {
    #[serde(rename = "oldStart")]
    pub old_start: u32,
    #[serde(rename = "oldLines")]
    pub old_lines: u32,
    #[serde(rename = "newStart")]
    pub new_start: u32,
    #[serde(rename = "newLines")]
    pub new_lines: u32,
    #[serde(rename = "actualOldLines")]
    pub actual_old_lines: u32,
    #[serde(rename = "actualNewLines")]
    pub actual_new_lines: u32,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub section: Option<String>,
    pub counts: PatchDiffLineCounts,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffFileIntegrity {
    #[serde(rename = "oldPath")]
    pub old_path: String,
    #[serde(rename = "newPath")]
    pub new_path: String,
    pub status: PatchDiffFileStatus,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub index: Option<String>,
    #[serde(rename = "oldMode", default, skip_serializing_if = "Option::is_none")]
    pub old_mode: Option<String>,
    #[serde(rename = "newMode", default, skip_serializing_if = "Option::is_none")]
    pub new_mode: Option<String>,
    #[serde(rename = "isBinary")]
    pub is_binary: bool,
    pub hunks: Vec<PatchDiffHunkIntegrity>,
    pub counts: PatchDiffLineCounts,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffIntegrityWarning {
    pub kind: PatchDiffIntegrityWarningKind,
    #[serde(rename = "lineNumber")]
    pub line_number: usize,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub path: Option<String>,
    pub message: String,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffIntegrityReport {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    #[serde(rename = "fileCount")]
    pub file_count: usize,
    #[serde(rename = "hunkCount")]
    pub hunk_count: usize,
    #[serde(rename = "hasWarnings")]
    pub has_warnings: bool,
    pub counts: PatchDiffLineCounts,
    pub files: Vec<PatchDiffFileIntegrity>,
    pub warnings: Vec<PatchDiffIntegrityWarning>,
}

pub fn parse_unified_patch_diff_integrity(diff_text: &str) -> Result<PatchDiffIntegrityReport> {
    let mut parser = UnifiedPatchDiffIntegrityParser::default();
    parser.parse(diff_text)
}

#[derive(Default)]
struct UnifiedPatchDiffIntegrityParser {
    files: Vec<PatchDiffFileIntegrity>,
    warnings: Vec<PatchDiffIntegrityWarning>,
    current_file: Option<PatchDiffFileIntegrity>,
    current_hunk: Option<PatchDiffHunkIntegrity>,
}

impl UnifiedPatchDiffIntegrityParser {
    fn parse(&mut self, diff_text: &str) -> Result<PatchDiffIntegrityReport> {
        for (line_index, line) in diff_text.lines().enumerate() {
            let line_number = line_index + 1;
            if line.starts_with("diff --git ") {
                self.finish_current_hunk(line_number);
                self.finish_current_file(line_number);
                self.current_file = Some(parse_diff_git_header(line).unwrap_or_else(|| {
                    self.warn(
                        PatchDiffIntegrityWarningKind::MalformedGitHeader,
                        line_number,
                        None,
                        "diff --git header did not contain two paths".to_string(),
                    );
                    empty_patch_diff_file()
                }));
            } else if line.starts_with("--- ") {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.old_path = normalize_diff_path(line.trim_start_matches("--- ").trim());
                    file.status = derive_patch_diff_status(file);
                }
            } else if line.starts_with("+++ ") {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.new_path = normalize_diff_path(line.trim_start_matches("+++ ").trim());
                    file.status = derive_patch_diff_status(file);
                }
            } else if line.starts_with("@@ ") {
                self.ensure_current_file(line_number);
                self.finish_current_hunk(line_number);
                match parse_unified_hunk_header(line) {
                    Some(hunk) => self.current_hunk = Some(hunk),
                    None => self.warn(
                        PatchDiffIntegrityWarningKind::MalformedHunkHeader,
                        line_number,
                        self.current_path(),
                        "hunk header could not be parsed".to_string(),
                    ),
                }
            } else if let Some(rest) = line.strip_prefix("index ") {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.index = Some(rest.trim().to_string());
                }
            } else if let Some(rest) = line.strip_prefix("old mode ") {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.old_mode = Some(rest.trim().to_string());
                }
                self.warn(
                    PatchDiffIntegrityWarningKind::ModeChange,
                    line_number,
                    self.current_path(),
                    "mode metadata is recorded but not rejected by parser v1".to_string(),
                );
            } else if let Some(rest) = line.strip_prefix("new mode ") {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.new_mode = Some(rest.trim().to_string());
                }
                self.warn(
                    PatchDiffIntegrityWarningKind::ModeChange,
                    line_number,
                    self.current_path(),
                    "mode metadata is recorded but not rejected by parser v1".to_string(),
                );
            } else if line.starts_with("deleted file mode ") || line.starts_with("new file mode ") {
                self.ensure_current_file(line_number);
                self.warn(
                    PatchDiffIntegrityWarningKind::ModeChange,
                    line_number,
                    self.current_path(),
                    "file mode metadata is recorded as a parser warning".to_string(),
                );
            } else if line.starts_with("rename from ") || line.starts_with("rename to ") {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.status = PatchDiffFileStatus::Renamed;
                }
                self.warn(
                    PatchDiffIntegrityWarningKind::RenameMetadata,
                    line_number,
                    self.current_path(),
                    "rename metadata is recorded but not rejected by parser v1".to_string(),
                );
            } else if line.starts_with("copy from ") || line.starts_with("copy to ") {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.status = PatchDiffFileStatus::Copied;
                }
                self.warn(
                    PatchDiffIntegrityWarningKind::CopyMetadata,
                    line_number,
                    self.current_path(),
                    "copy metadata is recorded but not rejected by parser v1".to_string(),
                );
            } else if line.starts_with("Binary files ") || line == "GIT binary patch" {
                self.ensure_current_file(line_number);
                if let Some(file) = &mut self.current_file {
                    file.is_binary = true;
                }
                self.warn(
                    PatchDiffIntegrityWarningKind::BinaryPatch,
                    line_number,
                    self.current_path(),
                    "binary patch content is recorded but not parsed into hunks".to_string(),
                );
            } else if let Some(hunk) = &mut self.current_hunk {
                match line.as_bytes().first().copied() {
                    Some(b'+') => {
                        hunk.counts.added += 1;
                        hunk.actual_new_lines += 1;
                    }
                    Some(b'-') => {
                        hunk.counts.removed += 1;
                        hunk.actual_old_lines += 1;
                    }
                    Some(b' ') => {
                        hunk.counts.context += 1;
                        hunk.actual_old_lines += 1;
                        hunk.actual_new_lines += 1;
                    }
                    Some(b'\\') => {}
                    _ => self.warn(
                        PatchDiffIntegrityWarningKind::UnexpectedContent,
                        line_number,
                        self.current_path(),
                        "content inside hunk did not start with expected unified diff prefix"
                            .to_string(),
                    ),
                }
            } else if !line.trim().is_empty() {
                self.warn(
                    PatchDiffIntegrityWarningKind::UnexpectedContent,
                    line_number,
                    self.current_path(),
                    "line was outside a recognized diff file or hunk section".to_string(),
                );
            }
        }

        let final_line = diff_text.lines().count().saturating_add(1);
        self.finish_current_hunk(final_line);
        self.finish_current_file(final_line);

        let file_count = self.files.len();
        let hunk_count = self.files.iter().map(|file| file.hunks.len()).sum();
        let counts = self
            .files
            .iter()
            .fold(PatchDiffLineCounts::default(), |mut counts, file| {
                counts.added += file.counts.added;
                counts.removed += file.counts.removed;
                counts.context += file.counts.context;
                counts
            });
        let warnings = std::mem::take(&mut self.warnings);

        Ok(PatchDiffIntegrityReport {
            schema_version: PATCH_DIFF_INTEGRITY_SCHEMA_VERSION.to_string(),
            file_count,
            hunk_count,
            has_warnings: !warnings.is_empty(),
            counts,
            files: std::mem::take(&mut self.files),
            warnings,
        })
    }

    fn ensure_current_file(&mut self, line_number: usize) {
        if self.current_file.is_none() {
            self.warn(
                PatchDiffIntegrityWarningKind::MissingFileHeader,
                line_number,
                None,
                "diff content appeared before a diff --git header".to_string(),
            );
            self.current_file = Some(empty_patch_diff_file());
        }
    }

    fn finish_current_hunk(&mut self, line_number: usize) {
        if let Some(hunk) = self.current_hunk.take() {
            let current_path = self.current_path();
            let count_matches =
                hunk.old_lines == hunk.actual_old_lines && hunk.new_lines == hunk.actual_new_lines;
            if !count_matches {
                self.warn(
                    PatchDiffIntegrityWarningKind::HunkLineCountMismatch,
                    line_number,
                    current_path,
                    format!(
                        "hunk expected -{} +{} lines but observed -{} +{} lines",
                        hunk.old_lines,
                        hunk.new_lines,
                        hunk.actual_old_lines,
                        hunk.actual_new_lines
                    ),
                );
            }
            if let Some(file) = &mut self.current_file {
                file.counts.added += hunk.counts.added;
                file.counts.removed += hunk.counts.removed;
                file.counts.context += hunk.counts.context;
                file.hunks.push(hunk);
            }
        }
    }

    fn finish_current_file(&mut self, line_number: usize) {
        if let Some(mut file) = self.current_file.take() {
            if file.old_path.is_empty() || file.new_path.is_empty() {
                self.warn(
                    PatchDiffIntegrityWarningKind::MalformedFileHeader,
                    line_number,
                    Some(first_non_empty_path(&file).unwrap_or_else(|| "<unknown>".to_string())),
                    "file diff was missing old or new file header".to_string(),
                );
            }
            if file.hunks.is_empty() && !file.is_binary {
                self.warn(
                    PatchDiffIntegrityWarningKind::MissingHunk,
                    line_number,
                    Some(first_non_empty_path(&file).unwrap_or_else(|| "<unknown>".to_string())),
                    "file diff contained no hunks".to_string(),
                );
            }
            file.status = derive_patch_diff_status(&file);
            self.files.push(file);
        }
    }

    fn warn(
        &mut self,
        kind: PatchDiffIntegrityWarningKind,
        line_number: usize,
        path: Option<String>,
        message: String,
    ) {
        self.warnings.push(PatchDiffIntegrityWarning {
            kind,
            line_number,
            path,
            message,
        });
    }

    fn current_path(&self) -> Option<String> {
        self.current_file.as_ref().and_then(first_non_empty_path)
    }
}

fn empty_patch_diff_file() -> PatchDiffFileIntegrity {
    PatchDiffFileIntegrity {
        old_path: String::new(),
        new_path: String::new(),
        status: PatchDiffFileStatus::Unknown,
        index: None,
        old_mode: None,
        new_mode: None,
        is_binary: false,
        hunks: Vec::new(),
        counts: PatchDiffLineCounts::default(),
    }
}

fn first_non_empty_path(file: &PatchDiffFileIntegrity) -> Option<String> {
    if !file.new_path.is_empty() && file.new_path != "/dev/null" {
        Some(file.new_path.clone())
    } else if !file.old_path.is_empty() && file.old_path != "/dev/null" {
        Some(file.old_path.clone())
    } else {
        None
    }
}

fn derive_patch_diff_status(file: &PatchDiffFileIntegrity) -> PatchDiffFileStatus {
    if matches!(
        file.status,
        PatchDiffFileStatus::Renamed | PatchDiffFileStatus::Copied
    ) {
        return file.status.clone();
    }
    match (file.old_path.as_str(), file.new_path.as_str()) {
        ("/dev/null", new_path) if !new_path.is_empty() => PatchDiffFileStatus::Added,
        (old_path, "/dev/null") if !old_path.is_empty() => PatchDiffFileStatus::Deleted,
        (old_path, new_path) if old_path.is_empty() || new_path.is_empty() => {
            PatchDiffFileStatus::Unknown
        }
        (old_path, new_path) if old_path != new_path => PatchDiffFileStatus::Renamed,
        _ => PatchDiffFileStatus::Modified,
    }
}

fn parse_diff_git_header(line: &str) -> Option<PatchDiffFileIntegrity> {
    let mut parts = line.split_whitespace();
    if parts.next()? != "diff" || parts.next()? != "--git" {
        return None;
    }
    let old_path = normalize_diff_path(parts.next()?);
    let new_path = normalize_diff_path(parts.next()?);
    let mut file = empty_patch_diff_file();
    file.old_path = old_path;
    file.new_path = new_path;
    file.status = derive_patch_diff_status(&file);
    Some(file)
}

fn normalize_diff_path(path: &str) -> String {
    let path = path.trim();
    if path == "/dev/null" {
        return path.to_string();
    }
    path.strip_prefix("a/")
        .or_else(|| path.strip_prefix("b/"))
        .unwrap_or(path)
        .to_string()
}

fn parse_unified_hunk_header(line: &str) -> Option<PatchDiffHunkIntegrity> {
    let after_open = line.strip_prefix("@@ ")?;
    let (range_text, section) = after_open.split_once(" @@")?;
    let mut ranges = range_text.split_whitespace();
    let (old_start, old_lines) = parse_unified_hunk_range(ranges.next()?, '-')?;
    let (new_start, new_lines) = parse_unified_hunk_range(ranges.next()?, '+')?;
    if ranges.next().is_some() {
        return None;
    }
    Some(PatchDiffHunkIntegrity {
        old_start,
        old_lines,
        new_start,
        new_lines,
        actual_old_lines: 0,
        actual_new_lines: 0,
        section: section.trim().strip_prefix(' ').map(str::to_string),
        counts: PatchDiffLineCounts::default(),
    })
}

fn parse_unified_hunk_range(range: &str, prefix: char) -> Option<(u32, u32)> {
    let range = range.strip_prefix(prefix)?;
    let (start, count) = match range.split_once(',') {
        Some((start, count)) => (start.parse().ok()?, count.parse().ok()?),
        None => (range.parse().ok()?, 1),
    };
    Some((start, count))
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffIntegrityLimits {
    #[serde(rename = "maxFiles")]
    pub max_files: usize,
    #[serde(rename = "maxChangedLines")]
    pub max_changed_lines: usize,
}

impl Default for PatchDiffIntegrityLimits {
    fn default() -> Self {
        Self {
            max_files: 32,
            max_changed_lines: 5_000,
        }
    }
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffIntegrityValidation {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub status: String,
    pub report: PatchDiffIntegrityReport,
    #[serde(rename = "fileClassValidation")]
    pub file_class_validation: SourcePatchTargetClassValidation,
    pub limits: PatchDiffIntegrityLimits,
    #[serde(rename = "blockedReasons")]
    pub blocked_reasons: Vec<String>,
    pub guardrails: Vec<String>,
}

impl PatchDiffIntegrityValidation {
    pub fn is_blocked(&self) -> bool {
        self.status == "blocked"
    }
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct PatchDiffIntegrityReadModel {
    #[serde(rename = "schemaVersion")]
    pub schema_version: String,
    pub status: String,
    #[serde(rename = "fileCount")]
    pub file_count: usize,
    #[serde(rename = "hunkCount")]
    pub hunk_count: usize,
    #[serde(rename = "changedLines")]
    pub changed_lines: usize,
    #[serde(rename = "warningCount")]
    pub warning_count: usize,
    #[serde(rename = "blockedReasons")]
    pub blocked_reasons: Vec<String>,
    #[serde(rename = "targetSummaries")]
    pub target_summaries: Vec<String>,
    pub guardrails: Vec<String>,
}

pub fn patch_diff_integrity_read_model(
    validation: &PatchDiffIntegrityValidation,
) -> PatchDiffIntegrityReadModel {
    PatchDiffIntegrityReadModel {
        schema_version: "patch-diff-integrity-read-model-v1".to_string(),
        status: validation.status.clone(),
        file_count: validation.report.file_count,
        hunk_count: validation.report.hunk_count,
        changed_lines: validation.report.counts.added + validation.report.counts.removed,
        warning_count: validation.report.warnings.len(),
        blocked_reasons: validation.blocked_reasons.clone(),
        target_summaries: validation
            .file_class_validation
            .targets
            .iter()
            .map(|target| {
                let class = serde_json::to_value(&target.class)
                    .ok()
                    .and_then(|value| value.as_str().map(ToOwned::to_owned))
                    .unwrap_or_else(|| "unknown".to_string());
                let decision = serde_json::to_value(&target.decision)
                    .ok()
                    .and_then(|value| value.as_str().map(ToOwned::to_owned))
                    .unwrap_or_else(|| "unknown".to_string());
                format!("{}: {class}/{decision}", target.path)
            })
            .collect(),
        guardrails: validation.guardrails.clone(),
    }
}

pub fn inspect_unified_patch_diff_for_preview(
    diff_text: &str,
    limits: PatchDiffIntegrityLimits,
) -> Result<PatchDiffIntegrityValidation> {
    let report = parse_unified_patch_diff_integrity(diff_text)?;
    Ok(validate_patch_diff_integrity_report_for_preview(
        report, limits,
    ))
}

pub fn validate_unified_patch_diff_for_preview(
    diff_text: &str,
    limits: PatchDiffIntegrityLimits,
) -> Result<PatchDiffIntegrityValidation> {
    let validation = inspect_unified_patch_diff_for_preview(diff_text, limits)?;
    if validation.is_blocked() {
        return Err(anyhow!(
            "patch diff integrity validation blocked: {}",
            validation.blocked_reasons.join("; ")
        ));
    }
    Ok(validation)
}

pub fn validate_patch_diff_integrity_report_for_preview(
    report: PatchDiffIntegrityReport,
    limits: PatchDiffIntegrityLimits,
) -> PatchDiffIntegrityValidation {
    let target_paths = patch_diff_target_paths(&report);
    let file_class_validation = classify_source_patch_preview_targets(target_paths.iter());
    let mut blocked_reasons = Vec::<String>::new();
    blocked_reasons.extend(
        file_class_validation
            .blocked_reasons
            .iter()
            .map(|reason| format!("file class blocked: {reason}")),
    );

    if report.file_count > limits.max_files {
        blocked_reasons.push(format!(
            "diff touches {} files, exceeding limit {}",
            report.file_count, limits.max_files
        ));
    }
    let changed_lines = report.counts.added + report.counts.removed;
    if changed_lines > limits.max_changed_lines {
        blocked_reasons.push(format!(
            "diff changes {changed_lines} lines, exceeding limit {}",
            limits.max_changed_lines
        ));
    }

    for warning in &report.warnings {
        match warning.kind {
            PatchDiffIntegrityWarningKind::MissingFileHeader => blocked_reasons.push(format!(
                "missing file header at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::MissingHunk => blocked_reasons.push(format!(
                "missing hunk at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::MalformedGitHeader => blocked_reasons.push(format!(
                "malformed git header at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::MalformedFileHeader => blocked_reasons.push(format!(
                "malformed file header at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::MalformedHunkHeader => blocked_reasons.push(format!(
                "malformed hunk header at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::HunkLineCountMismatch => blocked_reasons.push(format!(
                "hunk line count mismatch at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::BinaryPatch => blocked_reasons.push(format!(
                "binary patch marker at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::ModeChange => blocked_reasons.push(format!(
                "file mode metadata at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::RenameMetadata => blocked_reasons.push(format!(
                "rename metadata at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::CopyMetadata => blocked_reasons.push(format!(
                "copy metadata at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
            PatchDiffIntegrityWarningKind::UnexpectedContent => blocked_reasons.push(format!(
                "unexpected diff content at line {} for {}",
                warning.line_number,
                warning.path.as_deref().unwrap_or("<unknown>")
            )),
        }
    }

    for file in &report.files {
        if file.is_binary {
            blocked_reasons.push(format!(
                "binary diff target {}",
                first_non_empty_path(file).unwrap_or_else(|| "<unknown>".to_string())
            ));
        }
        if file.old_mode.is_some() || file.new_mode.is_some() {
            blocked_reasons.push(format!(
                "mode change target {}",
                first_non_empty_path(file).unwrap_or_else(|| "<unknown>".to_string())
            ));
        }
        if file.status == PatchDiffFileStatus::Deleted
            && is_critical_patch_diff_path(&file.old_path)
        {
            blocked_reasons.push(format!("critical file deletion target {}", file.old_path));
        }
    }
    blocked_reasons.sort();
    blocked_reasons.dedup();

    PatchDiffIntegrityValidation {
        schema_version: "patch-diff-integrity-validation-v1".to_string(),
        status: if blocked_reasons.is_empty() {
            "passed".to_string()
        } else {
            "blocked".to_string()
        },
        report,
        file_class_validation,
        limits,
        blocked_reasons,
        guardrails: vec![
            "diff integrity validation only; no source patch apply".to_string(),
            "blocked diffs stop before sandbox dry-run or trusted source writes".to_string(),
            "browser/dashboard/Studio surfaces remain read-only and command-inert".to_string(),
            "generated preview/sandbox/report artifacts remain untracked unless fixture-scoped"
                .to_string(),
        ],
    }
}

fn patch_diff_target_paths(report: &PatchDiffIntegrityReport) -> Vec<PathBuf> {
    let mut paths = Vec::new();
    for file in &report.files {
        if !file.old_path.is_empty() && file.old_path != "/dev/null" {
            paths.push(PathBuf::from(&file.old_path));
        }
        if !file.new_path.is_empty() && file.new_path != "/dev/null" {
            paths.push(PathBuf::from(&file.new_path));
        }
    }
    paths
}

fn is_critical_patch_diff_path(path: &str) -> bool {
    let normalized = normalize_diff_path(path);
    matches!(
        normalized.as_str(),
        "Cargo.toml" | "Cargo.lock" | "README.md" | "AGENTS.md"
    ) || normalized.starts_with(".github/workflows/")
}

