impl VisualDiffOperationSummary {
    pub fn validate(&self) -> Result<()> {
        validate_path_component(
            "visual diff summary operationSummaries.operationId",
            &self.operation_id,
        )?;
        if let Some(transaction_id) = &self.transaction_id {
            validate_path_component(
                "visual diff summary operationSummaries.transactionId",
                transaction_id,
            )?;
        }
        validate_visual_edit_draft_operation_path(
            "visual diff summary operationSummaries.path",
            &self.path,
        )?;
        require_text(
            "visual diff summary operationSummaries.summary",
            &self.summary,
        )?;
        if let Some(before_text) = &self.before_text {
            require_text(
                "visual diff summary operationSummaries.beforeText",
                before_text,
            )?;
        }
        if let Some(after_text) = &self.after_text {
            require_text(
                "visual diff summary operationSummaries.afterText",
                after_text,
            )?;
        }
        for entity_id in &self.affected_entity_ids {
            validate_path_component(
                "visual diff summary operationSummaries.affectedEntityIds",
                entity_id,
            )?;
        }
        for tilemap_id in &self.affected_tilemap_ids {
            validate_path_component(
                "visual diff summary operationSummaries.affectedTilemapIds",
                tilemap_id,
            )?;
        }
        for asset_id in &self.affected_asset_ids {
            validate_path_component(
                "visual diff summary operationSummaries.affectedAssetIds",
                asset_id,
            )?;
        }
        self.collision_trigger_summary
            .validate("visual diff summary operationSummaries.collisionTriggerSummary")?;
        Ok(())
    }
}

fn validate_visual_diff_scene_transaction_link(
    operation: &VisualEditDraftOperation,
    transaction: &SceneEditTransaction,
    scene_path: &str,
    before_hash: &SceneHash,
    expected_edit: &SceneEdit,
) -> Result<()> {
    validate_path_component("visual diff summary transaction id", &transaction.id)?;
    if transaction.schema_version != "ouroforge.scene-edit-transaction.v1" {
        return Err(anyhow!(
            "visual diff summary transaction {} has unsupported schemaVersion {}",
            transaction.id,
            transaction.schema_version
        ));
    }
    if transaction.scene_path != scene_path {
        return Err(anyhow!(
            "visual diff summary transaction {} scenePath mismatch: expected {}, found {}",
            transaction.id,
            scene_path,
            transaction.scene_path
        ));
    }
    if transaction.before_scene_hash != *before_hash {
        return Err(anyhow!(
            "visual diff summary transaction {} beforeSceneHash does not match draft beforeHash",
            transaction.id
        ));
    }
    if transaction.validation_result.status != "passed" {
        return Err(anyhow!(
            "visual diff summary transaction {} must be passed before summary generation",
            transaction.id
        ));
    }
    if transaction.after_scene_hash.is_none() {
        return Err(anyhow!(
            "visual diff summary transaction {} missing afterSceneHash",
            transaction.id
        ));
    }
    if transaction.edit != *expected_edit {
        return Err(anyhow!(
            "visual diff summary transaction {} edit does not match draft operation {}",
            transaction.id,
            operation.id
        ));
    }
    Ok(())
}

fn visual_diff_summary_transaction_ref(transactions: &[SceneEditTransaction]) -> Result<String> {
    match transactions {
        [] => Err(anyhow!(
            "visual diff summary generation requires at least one transaction"
        )),
        [transaction] => Ok(transaction.id.clone()),
        _ => {
            let ids = transactions
                .iter()
                .map(|transaction| transaction.id.as_str())
                .collect::<Vec<_>>();
            Ok(format!(
                "transaction-set-{:016x}",
                fnv1a64(&serde_json::to_vec(&canonical_json_value(json!(ids)))?)
            ))
        }
    }
}

fn visual_diff_scene_snapshot_summary(
    summary_text: &str,
    scene: &SceneDocument,
    entity_ids: &[String],
    change: VisualDiffChangeKind,
) -> Result<VisualDiffSnapshotSummary> {
    let mut entity_summaries = Vec::new();
    for entity_id in entity_ids {
        let entity = find_scene_entity(scene, entity_id)?;
        entity_summaries.push(VisualDiffEntitySummary {
            entity_id: entity.id.clone(),
            change: change.clone(),
            summary: format!(
                "Entity {} sprite color {} at ({}, {}).",
                entity.id,
                entity.sprite.color,
                entity.components.transform.x,
                entity.components.transform.y
            ),
            sprite: Some(entity.sprite.color.clone()),
            transform: Some(entity.components.transform.clone()),
            size: Some(entity.components.size.clone()),
        });
    }
    Ok(VisualDiffSnapshotSummary {
        summary_text: summary_text.to_string(),
        entity_summaries,
        tile_summaries: Vec::new(),
        asset_summaries: Vec::new(),
        collision_trigger_summary: VisualDiffCollisionTriggerSummary::default(),
    })
}

fn find_scene_entity<'a>(scene: &'a SceneDocument, entity_id: &str) -> Result<&'a SceneEntity> {
    scene
        .entities
        .iter()
        .find(|entity| entity.id == entity_id)
        .ok_or_else(|| anyhow!("scene entity not found: {entity_id}"))
}

fn scene_edit_value_summary(entity: &SceneEntity, path: &str) -> Result<String> {
    let value = match path {
        "sprite.color" => json!(entity.sprite.color),
        "components.transform.x" => json!(entity.components.transform.x),
        "components.transform.y" => json!(entity.components.transform.y),
        "components.velocity.x" => json!(entity.components.velocity.x),
        "components.velocity.y" => json!(entity.components.velocity.y),
        "components.size.width" => json!(entity.components.size.width),
        "components.size.height" => json!(entity.components.size.height),
        "components.controllable" => json!(entity.components.controllable),
        "components.status.hitPoints" => json!(entity
            .components
            .status
            .as_ref()
            .and_then(|status| status.hit_points)),
        "components.status.maxHitPoints" => json!(entity
            .components
            .status
            .as_ref()
            .and_then(|status| status.max_hit_points)),
        "components.input.moveSpeed" => json!(entity
            .components
            .input
            .as_ref()
            .and_then(|input| input.move_speed)),
        "components.input.jumpImpulse" => json!(entity
            .components
            .input
            .as_ref()
            .and_then(|input| input.jump_impulse)),
        "components.cameraTarget.weight" => json!(entity
            .components
            .camera_target
            .as_ref()
            .map(|camera_target| camera_target.weight)),
        "components.uiText.text" => json!(entity
            .components
            .ui_text
            .as_ref()
            .map(|ui_text| ui_text.text.as_str())),
        _ => {
            return Err(anyhow!(
                "unsupported visual diff summary scene edit path `{path}`"
            ))
        }
    };
    Ok(value.to_string())
}

impl VisualDiffScenarioImpact {
    pub fn validate(&self) -> Result<()> {
        require_text(
            "visual diff summary expectedScenarioImpact.summary",
            &self.summary,
        )?;
        if self.status == VisualDiffScenarioImpactStatus::Known && self.scenario_ids.is_empty() {
            return Err(anyhow!(
                "known visual diff summary expectedScenarioImpact requires at least one scenarioId"
            ));
        }
        for scenario_id in &self.scenario_ids {
            validate_path_component(
                "visual diff summary expectedScenarioImpact.scenarioIds",
                scenario_id,
            )?;
        }
        for evidence_ref in &self.evidence {
            validate_project_manifest_path(
                "visual diff summary expectedScenarioImpact.evidence",
                evidence_ref,
            )?;
        }
        Ok(())
    }
}

impl VisualEditDraftTarget {
    pub fn validate(&self) -> Result<()> {
        validate_project_manifest_path("visual edit draft target.path", &self.path)?;
        if let Some(id) = &self.id {
            validate_path_component("visual edit draft target.id", id)?;
        }
        Ok(())
    }
}

impl VisualEditDraftOperation {
    pub fn validate(&self) -> Result<()> {
        validate_path_component("visual edit draft operation id", &self.id)?;
        validate_visual_edit_draft_operation_path("visual edit draft operation path", &self.path)?;
        if let Some(summary) = &self.summary {
            require_text("visual edit draft operation summary", summary)?;
        }
        if let Some(scene_operation) = &self.scene_operation {
            scene_operation.validate()?;
        }
        if let Some(tilemap_operation) = &self.tilemap_operation {
            tilemap_operation.validate()?;
        }
        if let Some(asset_reference_operation) = &self.asset_reference_operation {
            asset_reference_operation.validate()?;
        }
        if self.value.is_none() && self.summary.is_none() {
            return Err(anyhow!(
                "visual edit draft operation must include summary or value"
            ));
        }
        Ok(())
    }
}

impl VisualEditTilemapDraftOperation {
    pub fn validate(&self) -> Result<()> {
        validate_path_component(
            "visual edit tilemap draft operation layerId",
            &self.layer_id,
        )?;
        if let Some(tile_id) = &self.tile_id {
            validate_path_component("visual edit tilemap draft operation tileId", tile_id)?;
        }
        if let Some(tileset_asset_id) = &self.tileset_asset_id {
            validate_path_component(
                "visual edit tilemap draft operation tilesetAssetId",
                tileset_asset_id,
            )?;
        }
        for (key, value) in &self.metadata {
            require_text("visual edit tilemap draft operation metadata key", key)?;
            require_text(
                &format!("visual edit tilemap draft operation metadata.{key}"),
                value,
            )?;
        }
        if let Some(summary) = &self.summary {
            require_text("visual edit tilemap draft operation summary", summary)?;
        }
        Ok(())
    }

    fn validate_preflight(
        &self,
        tilemap: &ProjectTilemapManifest,
        layers_by_id: &BTreeMap<&str, &ProjectTilemapLayer>,
        tiles_by_id: &BTreeMap<&str, &ProjectTilesetTile>,
    ) -> Result<u32> {
        self.validate()?;
        layers_by_id.get(self.layer_id.as_str()).ok_or_else(|| {
            anyhow!(
                "visual edit tilemap draft layerId references unknown layer: {}",
                self.layer_id
            )
        })?;
        if let Some(tileset_asset_id) = &self.tileset_asset_id {
            if tileset_asset_id != &tilemap.tileset_asset_id {
                return Err(anyhow!(
                    "visual edit tilemap draft tilesetAssetId mismatch: expected {}, found {}",
                    tilemap.tileset_asset_id,
                    tileset_asset_id
                ));
            }
        }

        match self.kind {
            VisualEditTilemapDraftOperationKind::TileSet
            | VisualEditTilemapDraftOperationKind::CollisionPreview
            | VisualEditTilemapDraftOperationKind::TriggerPreview => {
                self.require_point_in_bounds(tilemap)?;
                self.require_known_tile(tiles_by_id)?;
                Ok(1)
            }
            VisualEditTilemapDraftOperationKind::TileRemove => {
                self.require_point_in_bounds(tilemap)?;
                if let Some(tile_id) = &self.tile_id {
                    require_known_tile_id(tile_id, tiles_by_id)?;
                }
                Ok(1)
            }
            VisualEditTilemapDraftOperationKind::RectangleFill => {
                self.require_known_tile(tiles_by_id)?;
                self.require_rectangle_in_bounds(tilemap)
            }
            VisualEditTilemapDraftOperationKind::LayerVisibilityChange => {
                self.visible.ok_or_else(|| {
                    anyhow!("visual edit tilemap draft layer visibility change requires visible")
                })?;
                Ok(0)
            }
            VisualEditTilemapDraftOperationKind::LayerConfigChange => {
                if self.metadata.is_empty() {
                    return Err(anyhow!(
                        "visual edit tilemap draft layer config change requires metadata"
                    ));
                }
                Ok(0)
            }
            VisualEditTilemapDraftOperationKind::TilePropertyReferenceChange => {
                self.require_known_tile(tiles_by_id)?;
                if self.metadata.is_empty() {
                    return Err(anyhow!(
                        "visual edit tilemap draft tile property reference change requires metadata"
                    ));
                }
                Ok(0)
            }
        }
    }

    fn require_point_in_bounds(&self, tilemap: &ProjectTilemapManifest) -> Result<()> {
        let x = self.x.ok_or_else(|| {
            anyhow!(
                "visual edit tilemap draft operation {:?} requires x",
                self.kind
            )
        })?;
        let y = self.y.ok_or_else(|| {
            anyhow!(
                "visual edit tilemap draft operation {:?} requires y",
                self.kind
            )
        })?;
        if x >= tilemap.width || y >= tilemap.height {
            return Err(anyhow!(
                "visual edit tilemap draft coordinates ({x},{y}) are outside tilemap bounds {}x{}",
                tilemap.width,
                tilemap.height
            ));
        }
        Ok(())
    }

    fn require_rectangle_in_bounds(&self, tilemap: &ProjectTilemapManifest) -> Result<u32> {
        let x = self
            .x
            .ok_or_else(|| anyhow!("visual edit tilemap draft rectangle fill requires x"))?;
        let y = self
            .y
            .ok_or_else(|| anyhow!("visual edit tilemap draft rectangle fill requires y"))?;
        let width = self
            .width
            .ok_or_else(|| anyhow!("visual edit tilemap draft rectangle fill requires width"))?;
        let height = self
            .height
            .ok_or_else(|| anyhow!("visual edit tilemap draft rectangle fill requires height"))?;
        if width == 0 || height == 0 {
            return Err(anyhow!(
                "visual edit tilemap draft rectangle width and height must be greater than zero"
            ));
        }
        let end_x = x
            .checked_add(width)
            .ok_or_else(|| anyhow!("visual edit tilemap draft rectangle x + width overflows"))?;
        let end_y = y
            .checked_add(height)
            .ok_or_else(|| anyhow!("visual edit tilemap draft rectangle y + height overflows"))?;
        if end_x > tilemap.width || end_y > tilemap.height {
            return Err(anyhow!(
                "visual edit tilemap draft rectangle ({x},{y},{width},{height}) is outside tilemap bounds {}x{}",
                tilemap.width,
                tilemap.height
            ));
        }
        let area = width
            .checked_mul(height)
            .ok_or_else(|| anyhow!("visual edit tilemap draft rectangle cell count overflows"))?;
        if area > VISUAL_EDIT_TILEMAP_DRAFT_MAX_RECTANGLE_CELLS {
            return Err(anyhow!(
                "visual edit tilemap draft rectangle affects {area} cells, above limit {}",
                VISUAL_EDIT_TILEMAP_DRAFT_MAX_RECTANGLE_CELLS
            ));
        }
        Ok(area)
    }

    fn require_known_tile(&self, tiles_by_id: &BTreeMap<&str, &ProjectTilesetTile>) -> Result<()> {
        let tile_id = self.tile_id.as_ref().ok_or_else(|| {
            anyhow!(
                "visual edit tilemap draft operation {:?} requires tileId",
                self.kind
            )
        })?;
        require_known_tile_id(tile_id, tiles_by_id)
    }

    fn apply_to_tilemap_preview(
        &self,
        candidate: &mut ProjectTilemapManifest,
        original: &ProjectTilemapManifest,
    ) -> Result<BTreeSet<usize>> {
        let mut affected_indexes = BTreeSet::new();
        match self.kind {
            VisualEditTilemapDraftOperationKind::TileSet
            | VisualEditTilemapDraftOperationKind::CollisionPreview
            | VisualEditTilemapDraftOperationKind::TriggerPreview => {
                let index = tilemap_cell_index(original, self.x, self.y)?;
                let layer = candidate_layer_mut(candidate, &self.layer_id)?;
                layer.data[index] = self.tile_id.clone();
                affected_indexes.insert(index);
            }
            VisualEditTilemapDraftOperationKind::TileRemove => {
                let index = tilemap_cell_index(original, self.x, self.y)?;
                let layer = candidate_layer_mut(candidate, &self.layer_id)?;
                layer.data[index] = None;
                affected_indexes.insert(index);
            }
            VisualEditTilemapDraftOperationKind::RectangleFill => {
                let x = self.x.expect("rectangle x validated");
                let y = self.y.expect("rectangle y validated");
                let width = self.width.expect("rectangle width validated");
                let height = self.height.expect("rectangle height validated");
                let tile_id = self.tile_id.clone();
                let map_width = original.width;
                let layer = candidate_layer_mut(candidate, &self.layer_id)?;
                for dy in 0..height {
                    for dx in 0..width {
                        let index = ((y + dy) * map_width + (x + dx)) as usize;
                        layer.data[index] = tile_id.clone();
                        affected_indexes.insert(index);
                    }
                }
            }
            VisualEditTilemapDraftOperationKind::LayerVisibilityChange => {
                let visible = self.visible.expect("visible validated");
                let layer = candidate_layer_mut(candidate, &self.layer_id)?;
                layer
                    .metadata
                    .insert("visible".to_string(), visible.to_string());
            }
            VisualEditTilemapDraftOperationKind::LayerConfigChange => {
                let layer = candidate_layer_mut(candidate, &self.layer_id)?;
                for (key, value) in &self.metadata {
                    layer.metadata.insert(key.clone(), value.clone());
                }
            }
            VisualEditTilemapDraftOperationKind::TilePropertyReferenceChange => {
                for (index, tile_id) in original
                    .layers
                    .iter()
                    .flat_map(|layer| layer.data.iter())
                    .enumerate()
                {
                    if tile_id.as_deref() == self.tile_id.as_deref() {
                        affected_indexes.insert(index);
                    }
                }
            }
        }
        Ok(affected_indexes)
    }

    fn preview_summary(&self, affected_cells: u32) -> String {
        match self.kind {
            VisualEditTilemapDraftOperationKind::TileSet => {
                format!(
                    "Set tile on layer `{}`; {affected_cells} cell affected.",
                    self.layer_id
                )
            }
            VisualEditTilemapDraftOperationKind::TileRemove => {
                format!(
                    "Remove tile on layer `{}`; {affected_cells} cell affected.",
                    self.layer_id
                )
            }
            VisualEditTilemapDraftOperationKind::RectangleFill => {
                format!(
                    "Fill rectangle on layer `{}`; {affected_cells} cells affected.",
                    self.layer_id
                )
            }
            VisualEditTilemapDraftOperationKind::LayerVisibilityChange => {
                format!(
                    "Preview layer `{}` visibility metadata change.",
                    self.layer_id
                )
            }
            VisualEditTilemapDraftOperationKind::LayerConfigChange => {
                format!("Preview layer `{}` config metadata change.", self.layer_id)
            }
            VisualEditTilemapDraftOperationKind::TilePropertyReferenceChange => {
                format!(
                    "Preview tile property reference change for tile `{}`.",
                    self.tile_id.as_deref().unwrap_or("<missing>")
                )
            }
            VisualEditTilemapDraftOperationKind::CollisionPreview => {
                format!(
                    "Preview collision metadata on layer `{}`; {affected_cells} cell affected.",
                    self.layer_id
                )
            }
            VisualEditTilemapDraftOperationKind::TriggerPreview => {
                format!(
                    "Preview trigger metadata on layer `{}`; {affected_cells} cell affected.",
                    self.layer_id
                )
            }
        }
    }
}

impl VisualEditAssetReferenceDraftOperation {
    pub fn validate(&self) -> Result<()> {
        validate_visual_edit_draft_operation_path(
            "visual edit asset reference draft operation targetReferencePath",
            &self.target_reference_path,
        )?;
        validate_path_component(
            "visual edit asset reference draft operation replacementAssetId",
            &self.replacement_asset_id,
        )?;
        if let Some(expected_content_hash) = &self.expected_content_hash {
            expected_content_hash.validate_schema(
                "visual edit asset reference draft operation expectedContentHash",
            )?;
        }
        if let Some(frame_id) = &self.frame_id {
            validate_path_component(
                "visual edit asset reference draft operation frameId",
                frame_id,
            )?;
        }
        if let Some(event_id) = &self.event_id {
            validate_path_component(
                "visual edit asset reference draft operation eventId",
                event_id,
            )?;
        }
        for (key, value) in &self.metadata {
            require_text(
                "visual edit asset reference draft operation metadata key",
                key,
            )?;
            require_text(
                &format!("visual edit asset reference draft operation metadata.{key}"),
                value,
            )?;
        }
        if let Some(summary) = &self.summary {
            require_text(
                "visual edit asset reference draft operation summary",
                summary,
            )?;
        }
        Ok(())
    }

    pub fn preflight(
        &self,
        manifest: &ProjectAssetManifest,
        manifest_base_dir: impl AsRef<Path>,
    ) -> Result<VisualEditAssetReferenceDraftPreflight> {
        self.validate()?;
        manifest.validate_schema()?;
        let manifest_base_dir = manifest_base_dir.as_ref();
        let manifest_base = manifest_base_dir.canonicalize().with_context(|| {
            format!(
                "failed to resolve project asset manifest base {}",
                manifest_base_dir.display()
            )
        })?;
        validate_asset_reference_target_compatibility(&self.kind, &self.target_reference_path)?;
        let expected_types = visual_edit_asset_reference_expected_types(&self.kind);
        let (asset_index, asset) = manifest
            .assets
            .iter()
            .enumerate()
            .find(|(_, asset)| asset.id == self.replacement_asset_id)
            .ok_or_else(|| {
                anyhow!(
                    "visual edit asset reference draft replacementAssetId references unknown project asset id: {}",
                    self.replacement_asset_id
                )
            })?;
        if !expected_types.contains(&asset.asset_type) {
            return Err(anyhow!(
                "visual edit asset reference draft replacementAssetId {} has type {:?}, expected one of {:?}",
                asset.id,
                asset.asset_type,
                expected_types
            ));
        }
        if let Some(expected_asset_type) = self.expected_asset_type {
            if expected_asset_type != asset.asset_type {
                return Err(anyhow!(
                    "visual edit asset reference draft expectedAssetType {:?} does not match manifest asset {} type {:?}",
                    expected_asset_type,
                    asset.id,
                    asset.asset_type
                ));
            }
        }
        if let Some(expected_content_hash) = &self.expected_content_hash {
            if expected_content_hash.algorithm != asset.content_hash.algorithm
                || expected_content_hash.value != asset.content_hash.value
            {
                return Err(anyhow!(
                    "visual edit asset reference draft expectedContentHash mismatch for asset {}: expected {}:{}, manifest has {}:{}",
                    asset.id,
                    expected_content_hash.algorithm,
                    expected_content_hash.value,
                    asset.content_hash.algorithm,
                    asset.content_hash.value
                ));
            }
        }
        validate_asset_reference_kind_payload(self, asset)?;
        asset
            .validate_integrity(asset_index, manifest_base_dir, &manifest_base)
            .with_context(|| {
                format!(
                    "visual edit asset reference draft integrity preflight failed for asset {}",
                    asset.id
                )
            })?;
        Ok(VisualEditAssetReferenceDraftPreflight {
            manifest_id: manifest.id.clone(),
            kind: self.kind.clone(),
            target_reference_path: self.target_reference_path.clone(),
            replacement_asset_id: asset.id.clone(),
            asset_type: asset.asset_type,
            path: asset.path.clone(),
            content_hash: asset.content_hash.clone(),
            frame_id: self.frame_id.clone(),
            event_id: self.event_id.clone(),
            status: "ready".to_string(),
        })
    }

    fn preview_summary(&self) -> String {
        match self.kind {
            VisualEditAssetReferenceDraftOperationKind::SpriteAssetReference => format!(
                "Preview sprite asset reference `{}` for `{}`.",
                self.replacement_asset_id, self.target_reference_path
            ),
            VisualEditAssetReferenceDraftOperationKind::SpriteFrameReference => format!(
                "Preview sprite frame `{}` from atlas `{}` for `{}`.",
                self.frame_id.as_deref().unwrap_or("<missing-frame>"),
                self.replacement_asset_id,
                self.target_reference_path
            ),
            VisualEditAssetReferenceDraftOperationKind::AudioEventAssetReference => format!(
                "Preview audio event `{}` asset `{}` for `{}`.",
                self.event_id.as_deref().unwrap_or("<missing-event>"),
                self.replacement_asset_id,
                self.target_reference_path
            ),
            VisualEditAssetReferenceDraftOperationKind::FontAssetReference => format!(
                "Preview font asset `{}` for `{}`.",
                self.replacement_asset_id, self.target_reference_path
            ),
            VisualEditAssetReferenceDraftOperationKind::TilemapTilesetReference => format!(
                "Preview tilemap tileset asset `{}` for `{}`.",
                self.replacement_asset_id, self.target_reference_path
            ),
        }
    }
}

fn visual_edit_asset_reference_expected_types(
    kind: &VisualEditAssetReferenceDraftOperationKind,
) -> &'static [ProjectAssetType] {
    match kind {
        VisualEditAssetReferenceDraftOperationKind::SpriteAssetReference => {
            &[ProjectAssetType::Image]
        }
        VisualEditAssetReferenceDraftOperationKind::SpriteFrameReference => {
            &[ProjectAssetType::SpriteAtlas]
        }
        VisualEditAssetReferenceDraftOperationKind::AudioEventAssetReference => {
            &[ProjectAssetType::Audio]
        }
        VisualEditAssetReferenceDraftOperationKind::FontAssetReference => &[ProjectAssetType::Font],
        VisualEditAssetReferenceDraftOperationKind::TilemapTilesetReference => {
            &[ProjectAssetType::Tileset]
        }
    }
}

fn validate_asset_reference_target_compatibility(
    kind: &VisualEditAssetReferenceDraftOperationKind,
    target_reference_path: &str,
) -> Result<()> {
    let compatible = match kind {
        VisualEditAssetReferenceDraftOperationKind::SpriteAssetReference => {
            target_reference_path.contains(".sprite.asset")
                || target_reference_path.contains(".sprite.assetId")
        }
        VisualEditAssetReferenceDraftOperationKind::SpriteFrameReference => {
            target_reference_path.contains(".sprite.frame")
                || target_reference_path.contains(".sprite.frameId")
                || target_reference_path.contains(".animation.")
        }
        VisualEditAssetReferenceDraftOperationKind::AudioEventAssetReference => {
            target_reference_path.contains(".audio.")
                || target_reference_path.contains("audio.events")
        }
        VisualEditAssetReferenceDraftOperationKind::FontAssetReference => {
            target_reference_path.contains(".font")
                || target_reference_path.contains(".fontAsset")
                || target_reference_path.contains(".fontAssetId")
        }
        VisualEditAssetReferenceDraftOperationKind::TilemapTilesetReference => {
            target_reference_path.contains("tilemap") && target_reference_path.contains("tileset")
        }
    };
    if compatible {
        Ok(())
    } else {
        Err(anyhow!(
            "visual edit asset reference draft targetReferencePath {} is not compatible with {:?}",
            target_reference_path,
            kind
        ))
    }
}

fn validate_asset_reference_kind_payload(
    operation: &VisualEditAssetReferenceDraftOperation,
    asset: &ProjectAssetManifestEntry,
) -> Result<()> {
    match operation.kind {
        VisualEditAssetReferenceDraftOperationKind::SpriteFrameReference => {
            let frame_id = operation.frame_id.as_ref().ok_or_else(|| {
                anyhow!("visual edit sprite frame asset reference requires frameId")
            })?;
            let atlas = asset.atlas.as_ref().ok_or_else(|| {
                anyhow!(
                    "visual edit sprite frame asset reference asset {} requires atlas payload",
                    asset.id
                )
            })?;
            if !atlas.frames.iter().any(|frame| frame.id == *frame_id) {
                return Err(anyhow!(
                    "visual edit sprite frame asset reference frameId {} is not declared by atlas asset {}",
                    frame_id,
                    asset.id
                ));
            }
        }
        VisualEditAssetReferenceDraftOperationKind::AudioEventAssetReference => {
            if operation.event_id.is_none() {
                return Err(anyhow!(
                    "visual edit audio event asset reference requires eventId"
                ));
            }
        }
        VisualEditAssetReferenceDraftOperationKind::TilemapTilesetReference => {
            if asset.tileset.is_none() {
                return Err(anyhow!(
                    "visual edit tilemap tileset reference asset {} requires tileset payload",
                    asset.id
                ));
            }
        }
        VisualEditAssetReferenceDraftOperationKind::SpriteAssetReference
        | VisualEditAssetReferenceDraftOperationKind::FontAssetReference => {}
    }
    Ok(())
}

fn require_known_tile_id(
    tile_id: &str,
    tiles_by_id: &BTreeMap<&str, &ProjectTilesetTile>,
) -> Result<()> {
    if !tiles_by_id.contains_key(tile_id) {
        return Err(anyhow!(
            "visual edit tilemap draft tileId references unknown tile: {tile_id}"
        ));
    }
    Ok(())
}

fn candidate_layer_mut<'a>(
    tilemap: &'a mut ProjectTilemapManifest,
    layer_id: &str,
) -> Result<&'a mut ProjectTilemapLayer> {
    tilemap
        .layers
        .iter_mut()
        .find(|layer| layer.id == layer_id)
        .ok_or_else(|| anyhow!("visual edit tilemap draft preview missing layer: {layer_id}"))
}

fn tilemap_cell_index(
    tilemap: &ProjectTilemapManifest,
    x: Option<u32>,
    y: Option<u32>,
) -> Result<usize> {
    let x = x.ok_or_else(|| anyhow!("visual edit tilemap draft preview requires x"))?;
    let y = y.ok_or_else(|| anyhow!("visual edit tilemap draft preview requires y"))?;
    if x >= tilemap.width || y >= tilemap.height {
        return Err(anyhow!(
            "visual edit tilemap draft preview coordinates ({x},{y}) are outside tilemap bounds {}x{}",
            tilemap.width,
            tilemap.height
        ));
    }
    Ok((y * tilemap.width + x) as usize)
}

fn affected_extracted_cells(
    cells: &[ProjectTilemapExtractedCell],
    affected_indexes: &BTreeSet<usize>,
) -> Vec<ProjectTilemapExtractedCell> {
    cells
        .iter()
        .filter(|cell| affected_indexes.contains(&cell.index))
        .cloned()
        .collect()
}

pub fn hash_project_tilemap_manifest(
    tilemap: &ProjectTilemapManifest,
) -> Result<ProjectAssetContentHash> {
    let value = canonical_json_value(json!(tilemap));
    let bytes = serde_json::to_vec(&value).context("failed to serialize canonical tilemap JSON")?;
    Ok(ProjectAssetContentHash {
        algorithm: "fnv1a64-canonical-json-v1".to_string(),
        value: format!("{:016x}", fnv1a64(&bytes)),
    })
}

impl VisualEditSceneDraftOperation {
    pub fn validate(&self) -> Result<()> {
        validate_path_component(
            "visual edit scene draft operation entityId",
            &self.entity_id,
        )?;
        validate_visual_edit_draft_operation_path(
            "visual edit scene draft operation sceneEditPath",
            &self.scene_edit_path,
        )?;
        if let Some(summary) = &self.summary {
            require_text("visual edit scene draft operation summary", summary)?;
        }
        Ok(())
    }

    pub fn to_scene_edit(&self) -> Result<SceneEdit> {
        self.validate()?;
        match self.kind {
            VisualEditSceneDraftOperationKind::TransformMove
            | VisualEditSceneDraftOperationKind::SpriteColorChange
            | VisualEditSceneDraftOperationKind::ColliderSizeChange
            | VisualEditSceneDraftOperationKind::HudTextChange
            | VisualEditSceneDraftOperationKind::HudValueChange
            | VisualEditSceneDraftOperationKind::CameraTargetSelection => {
                if !supported_scene_edit_paths().contains(&self.scene_edit_path.as_str()) {
                    return Err(anyhow!(
                        "unsupported visual edit scene draft path `{}`; supported paths are {}",
                        self.scene_edit_path,
                        supported_scene_edit_paths().join(", ")
                    ));
                }
            }
            VisualEditSceneDraftOperationKind::SpriteFrameChange
            | VisualEditSceneDraftOperationKind::ColliderToggle
            | VisualEditSceneDraftOperationKind::TriggerConfigChange => {
                return Err(anyhow!(
                    "visual edit scene draft operation kind {:?} is not supported by scene edit transaction preflight yet",
                    self.kind
                ));
            }
        }
        let value = self.value.clone().ok_or_else(|| {
            anyhow!(
                "visual edit scene draft operation {} requires value",
                self.scene_edit_path
            )
        })?;
        Ok(SceneEdit {
            entity_id: self.entity_id.clone(),
            path: self.scene_edit_path.clone(),
            value,
        })
    }
}

