fn validate_visual_edit_draft_hash(field: &str, value: &str) -> Result<()> {
    parse_visual_edit_draft_hash(field, value)?;
    Ok(())
}

fn parse_visual_edit_draft_hash(field: &str, value: &str) -> Result<(String, String)> {
    require_text(field, value)?;
    if let Some(hash) = value.strip_prefix("sha256:") {
        if hash.len() == 64
            && hash
                .chars()
                .all(|ch| ch.is_ascii_digit() || matches!(ch, 'a'..='f'))
        {
            return Ok(("sha256".to_string(), hash.to_string()));
        }
        return Err(anyhow!("{field} must use sha256:<64 lowercase hex>"));
    }
    if let Some(hash) = value.strip_prefix("fnv1a64-canonical-json-v1:") {
        if hash.len() == 16
            && hash
                .chars()
                .all(|ch| ch.is_ascii_digit() || matches!(ch, 'a'..='f'))
        {
            return Ok(("fnv1a64-canonical-json-v1".to_string(), hash.to_string()));
        }
        return Err(anyhow!(
            "{field} must use fnv1a64-canonical-json-v1:<16 lowercase hex>"
        ));
    }
    if let Some(hash) = value.strip_prefix("fnv1a64-file-v1:") {
        if hash.len() == 16
            && hash
                .chars()
                .all(|ch| ch.is_ascii_digit() || matches!(ch, 'a'..='f'))
        {
            return Ok(("fnv1a64-file-v1".to_string(), hash.to_string()));
        }
        return Err(anyhow!(
            "{field} must use fnv1a64-file-v1:<16 lowercase hex>"
        ));
    }
    Err(anyhow!(
        "{field} must use sha256:<64 lowercase hex>, fnv1a64-canonical-json-v1:<16 lowercase hex>, or fnv1a64-file-v1:<16 lowercase hex>"
    ))
}

fn validate_visual_edit_draft_operation_path(field: &str, value: &str) -> Result<()> {
    require_text(field, value)?;
    if !value.chars().all(|ch| {
        ch.is_ascii_alphanumeric() || matches!(ch, '.' | '-' | '_' | '[' | ']' | ',' | '/')
    }) {
        return Err(anyhow!(
            "{field} may only contain ASCII letters, numbers, '.', '-', '_', '[', ']', ',' or '/'"
        ));
    }
    if value.contains("..") || value.starts_with('/') || value.starts_with('.') {
        return Err(anyhow!(
            "{field} must stay inside the target draft address space"
        ));
    }
    Ok(())
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum MutationReviewState {
    PendingReview,
    Accepted,
    Rejected,
    Deferred,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(rename_all = "snake_case")]
pub enum MutationReviewReviewerType {
    Human,
    Agent,
    System,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq, Default)]
#[serde(deny_unknown_fields)]
pub struct MutationReviewExpectedHashes {
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub proposal_index_hash: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub patch_draft_hash: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub evidence_index_hash: Option<String>,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct MutationReviewGuardrailChecklist {
    pub proposal_is_record_only: bool,
    pub accepted_does_not_apply: bool,
    pub browser_read_only: bool,
    pub evidence_refs_checked: bool,
}

impl Default for MutationReviewGuardrailChecklist {
    fn default() -> Self {
        Self {
            proposal_is_record_only: true,
            accepted_does_not_apply: true,
            browser_read_only: true,
            evidence_refs_checked: true,
        }
    }
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct MutationReviewDecision {
    pub id: String,
    pub patch_draft_id: String,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub proposal_id: Option<String>,
    pub state: MutationReviewState,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub decision_status: Option<MutationReviewState>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub reviewer_type: Option<MutationReviewReviewerType>,
    pub reason: String,
    pub evidence_refs: Vec<String>,
    pub reviewer: String,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub expected_hashes: Option<MutationReviewExpectedHashes>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub guardrail_checklist: Option<MutationReviewGuardrailChecklist>,
    #[serde(
        rename = "sourcePatchReview",
        default,
        skip_serializing_if = "Option::is_none"
    )]
    pub source_patch_review: Option<SourcePatchReviewDecisionLink>,
    pub decided_at_unix_ms: u128,
}

#[derive(Debug, Clone, Deserialize, Serialize, PartialEq, Eq)]
#[serde(deny_unknown_fields)]
pub struct MutationReviewArtifact {
    pub schema_version: String,
    pub run_id: String,
    pub decisions: Vec<MutationReviewDecision>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct MutationReviewDecisionInput {
    pub patch_draft_id: String,
    pub proposal_id: Option<String>,
    pub state: MutationReviewState,
    pub reviewer_type: Option<MutationReviewReviewerType>,
    pub reason: String,
    pub evidence_refs: Vec<String>,
    pub reviewer: String,
    pub expected_hashes: Option<MutationReviewExpectedHashes>,
    pub guardrail_checklist: Option<MutationReviewGuardrailChecklist>,
    pub source_patch_review: Option<SourcePatchReviewDecisionLink>,
}

impl PatchDraftArtifact {
    pub fn validate(&self) -> Result<()> {
        if self.schema_version != "1" {
            return Err(anyhow!("patch draft schema_version must be \"1\""));
        }
        require_text("patch draft run_id", &self.run_id)?;
        if self.drafts.is_empty() {
            return Err(anyhow!(
                "patch draft artifact must include at least one draft"
            ));
        }
        let mut ids = std::collections::HashSet::new();
        for draft in &self.drafts {
            draft.validate()?;
            if !ids.insert(draft.id.as_str()) {
                return Err(anyhow!("duplicate patch draft id: {}", draft.id));
            }
        }
        Ok(())
    }
}

impl PatchDraft {
    pub fn validate(&self) -> Result<()> {
        require_text("patch draft id", &self.id)?;
        require_text("patch draft proposal_id", &self.proposal_id)?;
        require_text("patch draft classification_id", &self.classification_id)?;
        validate_patch_draft_target_path(&self.target_path)?;
        require_text("patch draft rationale", &self.rationale)?;
        if self.evidence_refs.is_empty() {
            return Err(anyhow!("patch draft requires at least one evidence ref"));
        }
        for evidence_ref in &self.evidence_refs {
            require_text("patch draft evidence_ref", evidence_ref)?;
        }
        require_text("patch draft draft_text", &self.draft_text)?;
        Ok(())
    }
}

impl MutationReviewArtifact {
    pub fn validate(&self, run_dir: impl AsRef<Path>) -> Result<()> {
        if self.schema_version != "1" {
            return Err(anyhow!("mutation review schema_version must be \"1\""));
        }
        require_text("mutation review run_id", &self.run_id)?;
        let drafts = read_patch_draft_artifact(run_dir.as_ref())?;
        let draft_ids = drafts
            .drafts
            .iter()
            .map(|draft| draft.id.as_str())
            .collect::<std::collections::HashSet<_>>();
        let proposals = read_mutation_proposals(run_dir.as_ref())?;
        let proposal_ids = proposals
            .proposals
            .iter()
            .map(|proposal| proposal.id.as_str())
            .collect::<std::collections::HashSet<_>>();
        let mut decision_ids = std::collections::HashSet::new();
        for decision in &self.decisions {
            decision.validate(&draft_ids, &proposal_ids)?;
            if !decision_ids.insert(decision.id.as_str()) {
                return Err(anyhow!(
                    "duplicate mutation review decision id: {}",
                    decision.id
                ));
            }
        }
        Ok(())
    }
}

impl MutationReviewDecision {
    fn validate(
        &self,
        draft_ids: &std::collections::HashSet<&str>,
        proposal_ids: &std::collections::HashSet<&str>,
    ) -> Result<()> {
        require_text("mutation review decision id", &self.id)?;
        validate_path_component("mutation review decision id", &self.id)?;
        require_text("mutation review patch_draft_id", &self.patch_draft_id)?;
        if !draft_ids.contains(self.patch_draft_id.as_str()) {
            return Err(anyhow!(
                "mutation review patch draft id not found: {}",
                self.patch_draft_id
            ));
        }
        if let Some(proposal_id) = &self.proposal_id {
            require_text("mutation review proposal_id", proposal_id)?;
            if !proposal_ids.contains(proposal_id.as_str()) {
                return Err(anyhow!(
                    "mutation review proposal id not found: {}",
                    proposal_id
                ));
            }
        }
        if let Some(status) = &self.decision_status {
            if status != &self.state {
                return Err(anyhow!("mutation review decision_status must match state"));
            }
        }
        match self.state {
            MutationReviewState::Accepted
            | MutationReviewState::Rejected
            | MutationReviewState::Deferred => {
                require_text("mutation review reason", &self.reason)?;
                if self.evidence_refs.is_empty() {
                    return Err(anyhow!(
                        "mutation review decision requires evidence or comparison ref"
                    ));
                }
            }
            MutationReviewState::PendingReview => {}
        }
        for evidence_ref in &self.evidence_refs {
            validate_mutation_review_ref(evidence_ref)?;
        }
        require_text("mutation review reviewer", &self.reviewer)?;
        if let Some(expected_hashes) = &self.expected_hashes {
            expected_hashes.validate()?;
        }
        if let Some(checklist) = &self.guardrail_checklist {
            checklist.validate()?;
        }
        if let Some(source_patch_review) = &self.source_patch_review {
            validate_source_patch_review_decision_link(source_patch_review)?;
            if source_patch_review.review_decision_id != self.id {
                return Err(anyhow!(
                    "source patch reviewDecisionId {} must match mutation review decision id {}",
                    source_patch_review.review_decision_id,
                    self.id
                ));
            }
            if !self.evidence_refs.iter().any(|evidence_ref| {
                source_patch_review
                    .linked_evidence
                    .iter()
                    .any(|source_ref| source_ref.path == *evidence_ref)
            }) {
                return Err(anyhow!("source patch review linkage must share at least one mutation review evidence ref"));
            }
            if matches!(self.state, MutationReviewState::Accepted)
                && !matches!(
                    source_patch_review.status,
                    SourcePatchReviewStatus::Reviewed
                )
            {
                return Err(anyhow!(
                    "accepted mutation review decisions must map to reviewed source patch status"
                ));
            }
        }
        Ok(())
    }
}

impl MutationReviewExpectedHashes {
    fn validate(&self) -> Result<()> {
        for hash in [
            self.proposal_index_hash.as_deref(),
            self.patch_draft_hash.as_deref(),
            self.evidence_index_hash.as_deref(),
        ]
        .into_iter()
        .flatten()
        {
            require_text("mutation review expected hash", hash)?;
            if hash.contains('/') || hash.contains('\\') || hash.contains("..") {
                return Err(anyhow!(
                    "mutation review expected hash must be a scalar digest"
                ));
            }
        }
        Ok(())
    }
}

impl MutationReviewGuardrailChecklist {
    fn validate(&self) -> Result<()> {
        if !self.proposal_is_record_only
            || !self.accepted_does_not_apply
            || !self.browser_read_only
            || !self.evidence_refs_checked
        {
            return Err(anyhow!(
                "mutation review guardrail checklist must pass before recording a decision"
            ));
        }
        Ok(())
    }
}

pub fn read_mutation_review_artifact(run_dir: impl AsRef<Path>) -> Result<MutationReviewArtifact> {
    let run_dir = run_dir.as_ref();
    let path = run_dir.join("mutation/review-decisions.json");
    if !path.is_file() {
        let run = read_json_value(run_dir.join("run.json"))?;
        let run_id = json_string(&run, "id").unwrap_or_else(|| {
            run_dir
                .file_name()
                .and_then(|name| name.to_str())
                .unwrap_or("unknown-run")
                .to_string()
        });
        return Ok(MutationReviewArtifact {
            schema_version: "1".to_string(),
            run_id,
            decisions: Vec::new(),
        });
    }
    let input = fs::read_to_string(&path)
        .with_context(|| format!("failed to read mutation review {}", path.display()))?;
    let artifact: MutationReviewArtifact = serde_json::from_str(&input)
        .with_context(|| format!("failed to parse mutation review {}", path.display()))?;
    artifact.validate(run_dir)?;
    Ok(artifact)
}

pub fn write_mutation_review_artifact(
    run_dir: impl AsRef<Path>,
    artifact: &MutationReviewArtifact,
) -> Result<PathBuf> {
    let run_dir = run_dir.as_ref();
    artifact.validate(run_dir)?;
    let dir = run_dir.join("mutation");
    fs::create_dir_all(&dir).context("failed to create mutation directory")?;
    let path = dir.join("review-decisions.json");
    write_json_atomic(&path, &json!(artifact))?;
    Ok(path)
}

pub fn append_mutation_review_decision(
    run_dir: impl AsRef<Path>,
    input: MutationReviewDecisionInput,
) -> Result<MutationReviewDecision> {
    let run_dir = run_dir.as_ref();
    let mut artifact = read_mutation_review_artifact(run_dir)?;
    let next_index = artifact.decisions.len() + 1;
    let drafts = read_patch_draft_artifact(run_dir)?;
    let draft = drafts
        .drafts
        .iter()
        .find(|draft| draft.id == input.patch_draft_id)
        .ok_or_else(|| {
            anyhow!(
                "mutation review patch draft id not found: {}",
                input.patch_draft_id
            )
        })?;
    let proposals = read_mutation_proposals(run_dir)?;
    let proposal_ids = proposals
        .proposals
        .iter()
        .map(|proposal| proposal.id.as_str())
        .collect::<std::collections::HashSet<_>>();
    let proposal_id = match input.proposal_id {
        Some(proposal_id) => {
            if !proposal_ids.contains(proposal_id.as_str()) {
                return Err(anyhow!(
                    "mutation review proposal id not found: {}",
                    proposal_id
                ));
            }
            if proposal_id.as_str() != draft.proposal_id.as_str() {
                return Err(anyhow!(
                    "mutation review proposal_id {} does not match patch draft {} proposal_id {}",
                    proposal_id,
                    draft.id,
                    draft.proposal_id
                ));
            }
            Some(proposal_id)
        }
        None => Some(draft.proposal_id.clone()),
    };
    let state = input.state;
    let decision = MutationReviewDecision {
        id: format!("review-decision-{next_index}"),
        patch_draft_id: input.patch_draft_id,
        proposal_id,
        state: state.clone(),
        decision_status: Some(state),
        reviewer_type: input
            .reviewer_type
            .or(Some(MutationReviewReviewerType::Human)),
        reason: input.reason,
        evidence_refs: input.evidence_refs,
        reviewer: input.reviewer,
        expected_hashes: input.expected_hashes,
        guardrail_checklist: input.guardrail_checklist.or(Some(Default::default())),
        source_patch_review: input.source_patch_review,
        decided_at_unix_ms: unix_millis()?,
    };
    let draft_ids = drafts
        .drafts
        .iter()
        .map(|draft| draft.id.as_str())
        .collect::<std::collections::HashSet<_>>();
    decision.validate(&draft_ids, &proposal_ids)?;
    artifact.decisions.push(decision.clone());
    write_mutation_review_artifact(run_dir, &artifact)?;
    append_ledger_event(
        run_dir,
        "mutation.review_decision",
        "mutation-review",
        json!({
            "decision_id": decision.id,
            "patch_draft_id": decision.patch_draft_id,
            "proposal_id": decision.proposal_id,
            "state": decision.state,
            "decision_status": decision.decision_status,
            "reviewer_type": decision.reviewer_type,
            "evidence_refs": decision.evidence_refs,
            "reviewer": decision.reviewer,
        }),
    )?;
    update_journal(run_dir)?;
    Ok(decision)
}

pub fn append_mutation_review_decision_from_path(
    run_or_draft_path: impl AsRef<Path>,
    state: MutationReviewState,
    reason: String,
    evidence_refs: Vec<String>,
    reviewer: String,
) -> Result<MutationReviewDecision> {
    append_mutation_review_decision_for_proposal_from_path(
        run_or_draft_path,
        None,
        state,
        reason,
        evidence_refs,
        reviewer,
        Some(MutationReviewReviewerType::Human),
    )
}

pub fn append_mutation_review_decision_for_proposal_from_path(
    run_or_draft_path: impl AsRef<Path>,
    proposal_id: Option<String>,
    state: MutationReviewState,
    reason: String,
    evidence_refs: Vec<String>,
    reviewer: String,
    reviewer_type: Option<MutationReviewReviewerType>,
) -> Result<MutationReviewDecision> {
    let run_dir = resolve_patch_sandbox_run_dir(run_or_draft_path.as_ref())?;
    let drafts = read_patch_draft_artifact(&run_dir)?;
    let patch_draft = match proposal_id.as_deref() {
        Some(proposal_id) => drafts
            .drafts
            .iter()
            .find(|draft| draft.proposal_id == proposal_id)
            .ok_or_else(|| anyhow!("mutation review proposal id not found: {proposal_id}"))?,
        None => drafts
            .drafts
            .first()
            .ok_or_else(|| anyhow!("mutation review requires at least one patch draft"))?,
    };
    let patch_draft_id = patch_draft.id.clone();
    let evidence_refs = if evidence_refs.is_empty() {
        default_mutation_review_evidence_refs(&run_dir, &patch_draft_id)?
    } else {
        evidence_refs
    };
    append_mutation_review_decision(
        run_dir,
        MutationReviewDecisionInput {
            patch_draft_id,
            proposal_id,
            state,
            reviewer_type,
            reason,
            evidence_refs,
            reviewer,
            expected_hashes: None,
            guardrail_checklist: Some(Default::default()),
            source_patch_review: None,
        },
    )
}

fn default_mutation_review_evidence_refs(
    run_dir: &Path,
    patch_draft_id: &str,
) -> Result<Vec<String>> {
    let comparison = run_dir.join("mutation/rerun-orchestration.json");
    if comparison.is_file() {
        return Ok(vec!["mutation/rerun-orchestration.json".to_string()]);
    }
    let sandbox_result = format!("sandbox/{patch_draft_id}/evidence/result.json");
    if run_dir.join(&sandbox_result).is_file() {
        return Ok(vec![sandbox_result]);
    }
    Err(anyhow!(
        "mutation review requires evidence or comparison ref; run evolve compare first or pass --evidence"
    ))
}

fn validate_mutation_review_ref(reference: &str) -> Result<()> {
    require_text("mutation review evidence ref", reference)?;
    let path = Path::new(reference);
    if path.is_absolute()
        || path.components().any(|component| {
            matches!(
                component,
                Component::ParentDir | Component::RootDir | Component::Prefix(_)
            )
        })
    {
        return Err(anyhow!(
            "mutation review evidence ref must be run-relative and must not escape the run"
        ));
    }
    if !(reference.starts_with("evidence/")
        || reference.starts_with("mutation/")
        || reference.starts_with("sandbox/"))
    {
        return Err(anyhow!(
            "mutation review evidence ref must point to evidence/, mutation/, or sandbox/"
        ));
    }
    Ok(())
}

/// Validate that a regression promotion `scenarioResultPath` actually anchors a
/// scenario result artifact. Scenario results are written under
/// `evidence/scenarios/<scenario-id>/scenario-result.json` by legacy fixtures
/// and `scenario-result-*.json` by current scenario runs, so accepting any
/// `evidence/`, `mutation/`, or `sandbox/` ref (as the generic mutation review
/// ref validator does) would let a draft pass while pointing at an unrelated
/// artifact that downstream promotion/preview code cannot rely on.
fn validate_scenario_result_ref(reference: &str) -> Result<()> {
    validate_evidence_artifact_path(reference)?;
    if !is_scenario_result_artifact_path(reference) {
        return Err(anyhow!(
            "regression promotion scenarioResultPath must reference a scenario result under evidence/scenarios/ (scenario-result.json or scenario-result-*.json)"
        ));
    }
    Ok(())
}

fn is_scenario_result_artifact_path(reference: &str) -> bool {
    reference.starts_with("evidence/scenarios/")
        && Path::new(reference)
            .file_name()
            .and_then(|name| name.to_str())
            .is_some_and(|name| {
                name == "scenario-result.json"
                    || (name.starts_with("scenario-result-") && name.ends_with(".json"))
            })
}

/// Extract `<scenario-id>` from an `evidence/scenarios/<scenario-id>/scenario-result*.json`
/// artifact path, used to surface unreadable scenario results in the regression
/// matrix without needing to parse the (broken) result body.
fn scenario_id_from_scenario_result_path(path: &str) -> Option<String> {
    if !is_scenario_result_artifact_path(path) {
        return None;
    }
    Path::new(path)
        .strip_prefix("evidence/scenarios")
        .ok()
        .and_then(|rest| rest.components().next())
        .and_then(|component| component.as_os_str().to_str())
        .map(|id| id.to_string())
}

fn validate_patch_draft_target_path(target_path: &str) -> Result<()> {
    require_text("patch draft target_path", target_path)?;
    let path = Path::new(target_path);
    if path.is_absolute() {
        return Err(anyhow!("patch draft target_path must be relative"));
    }
    if path.components().any(|component| {
        matches!(
            component,
            Component::ParentDir | Component::RootDir | Component::Prefix(_)
        )
    }) {
        return Err(anyhow!(
            "patch draft target_path must not escape the repository"
        ));
    }
    Ok(())
}

pub fn read_patch_draft_artifact(run_dir: impl AsRef<Path>) -> Result<PatchDraftArtifact> {
    let path = run_dir.as_ref().join("mutation/patch-drafts.json");
    let input = fs::read_to_string(&path)
        .with_context(|| format!("failed to read patch drafts {}", path.display()))?;
    let artifact: PatchDraftArtifact = serde_json::from_str(&input)
        .with_context(|| format!("failed to parse patch drafts {}", path.display()))?;
    artifact.validate()?;
    Ok(artifact)
}

pub fn write_patch_draft_artifact(
    run_dir: impl AsRef<Path>,
    artifact: &PatchDraftArtifact,
) -> Result<PathBuf> {
    artifact.validate()?;
    let dir = run_dir.as_ref().join("mutation");
    fs::create_dir_all(&dir).context("failed to create mutation directory")?;
    let path = dir.join("patch-drafts.json");
    write_json_atomic(&path, &json!(artifact))?;
    Ok(path)
}

pub fn generate_patch_drafts(run_dir: impl AsRef<Path>) -> Result<PatchDraftArtifact> {
    let run_dir = run_dir.as_ref();
    let run = read_json_value(run_dir.join("run.json"))?;
    let run_id = json_string(&run, "id").unwrap_or_else(|| {
        run_dir
            .file_name()
            .and_then(|name| name.to_str())
            .unwrap_or("unknown-run")
            .to_string()
    });
    let proposals = read_mutation_proposals(run_dir)?.proposals;
    if proposals.is_empty() {
        return Err(anyhow!(
            "patch draft generation requires a mutation proposal"
        ));
    }
    let classifications = read_mutation_classification_artifact(run_dir)?;
    let mut drafts = Vec::new();
    for (index, proposal) in proposals.iter().enumerate() {
        validate_patch_draft_target_path(&proposal.target)
            .with_context(|| format!("unsupported mutation proposal target for {}", proposal.id))?;
        let classification = classifications
            .classifications
            .iter()
            .find(|classification| {
                classification.proposal_id.as_deref() == Some(proposal.id.as_str())
            })
            // Only fall back to positional matching for legacy classifications
            // that carry no proposal_id; otherwise an index hit could pair this
            // proposal with a classification that explicitly belongs to another.
            .or_else(|| {
                classifications
                    .classifications
                    .get(index)
                    .filter(|candidate| candidate.proposal_id.is_none())
            })
            .ok_or_else(|| {
                anyhow!(
                    "patch draft generation requires classification for proposal {}",
                    proposal.id
                )
            })?;
        let mut evidence_refs = classification.evidence_refs.clone();
        push_unique_ref(&mut evidence_refs, &proposal.evidence_id);
        let draft = PatchDraft {
            id: format!("patch-draft-{}", index + 1),
            proposal_id: proposal.id.clone(),
            classification_id: classification.id.clone(),
            lifecycle_state: PatchDraftState::Drafted,
            target_path: proposal.target.clone(),
            rationale: format!(
                "Draft derived from proposal {} and classification {} ({:?}).",
                proposal.id, classification.id, classification.category
            ),
            evidence_refs,
            draft_text: render_patch_draft_text(proposal, classification),
        };
        draft.validate()?;
        drafts.push(draft);
    }

    let artifact = PatchDraftArtifact {
        schema_version: "1".to_string(),
        run_id,
        drafts,
    };
    let path = write_patch_draft_artifact(run_dir, &artifact)?;
    append_ledger_event(
        run_dir,
        "mutation.drafted",
        "evolve-cli",
        json!({
            "path": path
                .strip_prefix(run_dir)
                .ok()
                .and_then(|path| path.to_str())
                .unwrap_or("mutation/patch-drafts.json"),
            "patch_draft_ids": artifact
                .drafts
                .iter()
                .map(|draft| draft.id.clone())
                .collect::<Vec<_>>()
        }),
    )?;
    Ok(artifact)
}

fn render_patch_draft_text(
    proposal: &MutationProposal,
    classification: &MutationClassification,
) -> String {
    let evidence_refs = classification.evidence_refs.join(", ");
    let category = format!("{:?}", classification.category);
    let escaped = |value: &str| {
        serde_yaml::to_string(value)
            .unwrap_or_else(|_| format!("{value:?}"))
            .trim()
            .to_string()
    };
    format!(
        "\
# Ouroforge patch draft v1
# This is an inspectable draft artifact only. It has not been applied.
# proposal_id: {proposal_id}
# classification_id: {classification_id}
# category: {category}
# target: {target}
# path: {path}
# evidence_refs: {evidence_refs}
id: patch-draft.{proposal_id}
title: Ouroforge Patch Draft {proposal_id}
goal: Review an evidence-linked mutation draft without applying it.
constraints:
  target: patch-draft-inspection
acceptance:
  - {reason_yaml}
  - {from_yaml}
  - {to_yaml}
scenarios:
  - id: patch-draft-inspection
    description: Inspectable draft metadata for a sandbox-only mutation review.
",
        proposal_id = proposal.id,
        classification_id = classification.id,
        category = category,
        target = proposal.target,
        path = proposal.path,
        evidence_refs = evidence_refs,
        reason_yaml = escaped(&format!("reason: {}", proposal.reason)),
        from_yaml = escaped(&format!("from: {}", proposal.from)),
        to_yaml = escaped(&format!("to: {}", proposal.to))
    )
}

