#[derive(Debug, Clone)]
struct RunComparisonDetails {
    snapshot: RunComparisonSnapshot,
    scenario_statuses: BTreeMap<String, String>,
    world_state: BTreeMap<String, serde_json::Value>,
    events: BTreeSet<String>,
    performance: BTreeMap<String, serde_json::Value>,
    evidence_keys: BTreeSet<String>,
    input_replay_keys: BTreeSet<String>,
    project: Option<ProjectRunMetadata>,
    transaction_provenance: Option<RunTransactionProvenance>,
    warnings: Vec<String>,
}

pub fn compare_runs(
    before_run_dir: impl AsRef<Path>,
    after_run_dir: impl AsRef<Path>,
) -> Result<RunComparison> {
    let before_run_dir = before_run_dir.as_ref();
    let after_run_dir = after_run_dir.as_ref();
    let before_details = load_run_comparison_details(before_run_dir, "before")?;
    let after_details = load_run_comparison_details(after_run_dir, "after")?;
    let before = before_details.snapshot.clone();
    let after = after_details.snapshot.clone();
    let classification = classify_run_comparison(&before, &after).to_string();
    let semantic = build_run_semantic_diff(&before_details, &after_details, &classification);
    let evidence_refs = vec![
        before_run_dir.join("run.json").display().to_string(),
        before_run_dir.join("verdict.json").display().to_string(),
        before_run_dir
            .join("evidence/index.json")
            .display()
            .to_string(),
        after_run_dir.join("run.json").display().to_string(),
        after_run_dir.join("verdict.json").display().to_string(),
        after_run_dir
            .join("evidence/index.json")
            .display()
            .to_string(),
    ];
    Ok(RunComparison {
        before_run_id: before.run_id.clone(),
        after_run_id: after.run_id.clone(),
        classification,
        deltas: json!({
            "scenario_results": after.scenario_results as i64 - before.scenario_results as i64,
            "failed_scenarios": after.failed_scenarios as i64 - before.failed_scenarios as i64,
            "assertion_failures": after.assertion_failures as i64 - before.assertion_failures as i64,
            "performance_artifacts": after.performance_artifacts as i64 - before.performance_artifacts as i64,
            "evidence_artifacts": after.evidence_artifacts as i64 - before.evidence_artifacts as i64,
            "input_replay_artifacts": after.input_replay_artifacts as i64 - before.input_replay_artifacts as i64,
            "mutation_proposals": after.mutation_proposals as i64 - before.mutation_proposals as i64
        }),
        semantic,
        before,
        after,
        evidence_refs,
        unsupported: vec![
            "semantic gameplay quality is not inferred beyond verdict/scenario/evidence deltas"
                .to_string(),
        ],
    })
}

fn build_run_semantic_diff(
    before: &RunComparisonDetails,
    after: &RunComparisonDetails,
    classification: &str,
) -> RunSemanticDiff {
    let scenarios = semantic_scenario_diffs(before, after);
    let world_state = semantic_map_diff(&before.world_state, &after.world_state, 24);
    let events = semantic_set_diff(&before.events, &after.events);
    let mut performance_warnings = Vec::new();
    let performance = RunSemanticPerformanceDiff {
        changed: semantic_value_diffs(&before.performance, &after.performance, 24),
        warnings: {
            if before.performance.is_empty() || after.performance.is_empty() {
                performance_warnings.push(
                    "performance diff is partial because one side has no performance artifacts"
                        .to_string(),
                );
            }
            performance_warnings
        },
    };
    let evidence = semantic_evidence_set_diff(&before.evidence_keys, &after.evidence_keys);
    let input_replay_set = semantic_set_diff(&before.input_replay_keys, &after.input_replay_keys);
    let input_replay = RunSemanticReplayDiff {
        before_count: before.snapshot.input_replay_artifacts,
        after_count: after.snapshot.input_replay_artifacts,
        added: input_replay_set.added,
        removed: input_replay_set.removed,
    };
    let project = semantic_project_diff(&before.project, &after.project);
    let transaction_provenance = RunSemanticTransactionDiff {
        before: before.transaction_provenance.clone(),
        after: after.transaction_provenance.clone(),
        changed: before.transaction_provenance != after.transaction_provenance,
    };
    let mut warnings = before
        .warnings
        .iter()
        .chain(after.warnings.iter())
        .cloned()
        .collect::<Vec<_>>();
    warnings.sort();
    warnings.dedup();
    let reasons = semantic_reasons(RunSemanticReasonInputs {
        classification,
        scenarios: &scenarios,
        world_state: &world_state,
        events: &events,
        performance: &performance,
        evidence: &evidence,
        input_replay: &input_replay,
        project: &project,
        transaction: &transaction_provenance,
        warnings: &warnings,
    });
    RunSemanticDiff {
        schema_version: "run-semantic-diff-v1".to_string(),
        reasons,
        project,
        scenarios,
        world_state,
        events,
        performance,
        evidence,
        input_replay,
        transaction_provenance,
        warnings,
    }
}

pub fn write_run_comparison_artifact(
    before_run_dir: impl AsRef<Path>,
    after_run_dir: impl AsRef<Path>,
    output_dir: impl AsRef<Path>,
) -> Result<PathBuf> {
    let comparison = compare_runs(before_run_dir, after_run_dir)?;
    validate_path_component("before run id", &comparison.before_run_id)?;
    validate_path_component("after run id", &comparison.after_run_id)?;
    let output_dir = output_dir.as_ref();
    fs::create_dir_all(output_dir).with_context(|| {
        format!(
            "failed to create comparison output dir {}",
            output_dir.display()
        )
    })?;
    let path = output_dir.join(format!(
        "run-comparison-{}--{}.json",
        comparison.before_run_id, comparison.after_run_id
    ));
    write_json(&path, &json!(comparison))?;
    Ok(path)
}

fn load_run_comparison_details(run_dir: &Path, label: &str) -> Result<RunComparisonDetails> {
    let run_path = run_dir.join("run.json");
    let verdict_path = run_dir.join("verdict.json");
    let evidence_path = run_dir.join("evidence/index.json");
    for path in [&run_path, &verdict_path, &evidence_path] {
        if !path.is_file() {
            return Err(anyhow!(
                "{label} run is missing required artifact {}",
                path.display()
            ));
        }
    }
    let run = read_json_value(&run_path)?;
    let verdict = read_json_value(&verdict_path)?;
    let evidence = read_evidence_index(run_dir)?;
    let transaction_provenance = run
        .get("transaction_provenance")
        .cloned()
        .and_then(|value| serde_json::from_value(value).ok());
    let project = match run.get("project") {
        Some(value) => match serde_json::from_value(value.clone()) {
            Ok(project) => Some(project),
            Err(error) => {
                let warnings = vec![format!(
                    "{label} run project metadata could not be parsed: {error}"
                )];
                // Keep the rest of comparison readable; malformed project
                // metadata is surfaced as a warning rather than trusted.
                let mut details = load_run_comparison_details_without_project(
                    run_dir,
                    label,
                    run,
                    verdict,
                    evidence,
                    transaction_provenance,
                    warnings,
                )?;
                details.project = None;
                return Ok(details);
            }
        },
        None => None,
    };
    load_run_comparison_details_without_project(
        run_dir,
        label,
        run,
        verdict,
        evidence,
        transaction_provenance,
        Vec::new(),
    )
    .map(|mut details| {
        details.project = project;
        details
    })
}

fn load_run_comparison_details_without_project(
    run_dir: &Path,
    label: &str,
    run: serde_json::Value,
    verdict: serde_json::Value,
    evidence: EvidenceIndex,
    transaction_provenance: Option<RunTransactionProvenance>,
    warnings: Vec<String>,
) -> Result<RunComparisonDetails> {
    let mut failed_scenarios = 0usize;
    let mut assertion_failures = 0usize;
    let mut scenario_results = 0usize;
    let mut performance_artifacts = 0usize;
    let mut scenario_statuses = BTreeMap::new();
    let mut world_state = BTreeMap::new();
    let mut events = BTreeSet::new();
    let mut performance = BTreeMap::new();
    let mut evidence_keys = BTreeSet::new();
    let mut input_replay_keys = BTreeSet::new();
    let mut input_replay_artifacts = 0usize;
    let mut warnings = warnings;
    for artifact in &evidence.artifacts {
        evidence_keys.insert(format!(
            "{}|{}|{}",
            artifact.id, artifact.kind, artifact.path
        ));
        match artifact
            .metadata
            .get("artifact")
            .and_then(|value| value.as_str())
        {
            Some("scenario_result") => {
                scenario_results += 1;
                // Scenario results are required comparison inputs: classification
                // and deltas are derived from these counters, so an indexed but
                // unreadable/corrupt scenario_result must fail the comparison
                // rather than silently contributing zero failures (which could be
                // reported as no_change/improved on incomplete data).
                let result = read_json_value(run_dir.join(&artifact.path)).with_context(|| {
                    format!(
                        "{label} scenario_result artifact could not be read: {}",
                        artifact.path
                    )
                })?;
                let scenario_id = result
                    .get("scenario_id")
                    .and_then(|value| value.as_str())
                    .unwrap_or(&artifact.id)
                    .to_string();
                let status = result
                    .get("status")
                    .and_then(|value| value.as_str())
                    .unwrap_or("unknown")
                    .to_string();
                scenario_statuses.insert(scenario_id, status.clone());
                if result.get("status").and_then(|value| value.as_str()) != Some("passed") {
                    failed_scenarios += 1;
                }
                assertion_failures += result
                    .get("assertions")
                    .and_then(|value| value.as_array())
                    .map(|assertions| {
                        assertions
                            .iter()
                            .filter(|assertion| {
                                assertion.get("passed").and_then(|value| value.as_bool())
                                    == Some(false)
                            })
                            .count()
                    })
                    .unwrap_or(0);
            }
            Some("world_state") => match read_json_value(run_dir.join(&artifact.path)) {
                // Namespace per artifact (like performance/frame_stats) so multiple
                // world_state artifacts from different scenarios don't overwrite
                // each other under a shared "world/..." key and drop a change.
                Ok(value) => collect_semantic_scalars(
                    &format!("world/{}", artifact.id),
                    &value,
                    &mut world_state,
                    64,
                ),
                Err(_) => warnings.push(format!(
                    "{label} world_state artifact could not be read: {}",
                    artifact.path
                )),
            },
            Some("console_log") => match read_json_value(run_dir.join(&artifact.path)) {
                Ok(value) => collect_semantic_events("console", &value, &mut events, 64),
                Err(_) => warnings.push(format!(
                    "{label} console_log artifact could not be read: {}",
                    artifact.path
                )),
            },
            Some("performance_metrics") => {
                performance_artifacts += 1;
                match read_json_value(run_dir.join(&artifact.path)) {
                    Ok(value) => collect_semantic_scalars(
                        &format!("performance/{}", artifact.id),
                        &value,
                        &mut performance,
                        32,
                    ),
                    Err(_) => warnings.push(format!(
                        "{label} performance_metrics artifact could not be read: {}",
                        artifact.path
                    )),
                }
            }
            Some("frame_stats") => match read_json_value(run_dir.join(&artifact.path)) {
                Ok(value) => collect_semantic_scalars(
                    &format!("frame_stats/{}", artifact.id),
                    &value,
                    &mut performance,
                    32,
                ),
                Err(_) => warnings.push(format!(
                    "{label} frame_stats artifact could not be read: {}",
                    artifact.path
                )),
            },
            Some("input_replay") | Some("scenario_input_replay") => {
                input_replay_artifacts += 1;
                input_replay_keys.insert(input_replay_semantic_key(
                    run_dir,
                    label,
                    artifact,
                    &mut warnings,
                ));
            }
            _ => {}
        }
    }
    // Proposals live in mutation/proposals.json (not the evidence index), so
    // count them there; the evidence index never carries mutation_proposal
    // artifacts, which previously made this count always zero.
    let mutation_proposals = list_mutation_proposals(run_dir)
        .map(|proposals| proposals.len())
        .unwrap_or(0);
    let snapshot = RunComparisonSnapshot {
        run_id: run
            .get("id")
            .and_then(|value| value.as_str())
            .ok_or_else(|| anyhow!("{label} run.json missing id"))?
            .to_string(),
        verdict_status: verdict
            .get("status")
            .and_then(|value| value.as_str())
            .unwrap_or("unknown")
            .to_string(),
        scenario_results,
        failed_scenarios,
        assertion_failures,
        performance_artifacts,
        evidence_artifacts: evidence.artifacts.len(),
        input_replay_artifacts,
        mutation_proposals,
    };
    Ok(RunComparisonDetails {
        snapshot,
        scenario_statuses,
        world_state,
        events,
        performance,
        evidence_keys,
        input_replay_keys,
        project: None,
        transaction_provenance,
        warnings,
    })
}

fn input_replay_semantic_key(
    run_dir: &Path,
    label: &str,
    artifact: &EvidenceArtifact,
    warnings: &mut Vec<String>,
) -> String {
    match read_json_value(run_dir.join(&artifact.path)) {
        Ok(value) => {
            let scenario_id = value
                .get("scenarioId")
                .or_else(|| value.get("scenario_id"))
                .and_then(|value| value.as_str())
                .or_else(|| {
                    artifact
                        .metadata
                        .get("scenario_id")
                        .and_then(|value| value.as_str())
                })
                .unwrap_or("unknown-scenario");
            let action = value
                .get("action")
                .and_then(|value| value.get("kind"))
                .and_then(|value| value.as_str())
                .or_else(|| {
                    value
                        .get("replay")
                        .and_then(|replay| replay.get("id"))
                        .and_then(|value| value.as_str())
                })
                .or_else(|| value.get("id").and_then(|value| value.as_str()))
                .unwrap_or("input_replay");
            let frame = value
                .get("frame")
                .and_then(|value| value.as_u64())
                .map(|frame| frame.to_string())
                .unwrap_or_else(|| "sequence".to_string());
            format!("{}|{}|{}|{}", artifact.path, scenario_id, action, frame)
        }
        Err(error) => {
            warnings.push(format!(
                "{label} input replay artifact could not be read: {} ({error})",
                artifact.path
            ));
            artifact.path.clone()
        }
    }
}

fn collect_semantic_scalars(
    prefix: &str,
    value: &serde_json::Value,
    out: &mut BTreeMap<String, serde_json::Value>,
    limit: usize,
) {
    if out.len() >= limit {
        return;
    }
    match value {
        serde_json::Value::Null
        | serde_json::Value::Bool(_)
        | serde_json::Value::Number(_)
        | serde_json::Value::String(_) => {
            out.insert(prefix.to_string(), value.clone());
        }
        serde_json::Value::Array(items) => {
            for (index, item) in items.iter().enumerate() {
                if out.len() >= limit {
                    break;
                }
                collect_semantic_scalars(&format!("{prefix}/{index}"), item, out, limit);
            }
        }
        serde_json::Value::Object(map) => {
            for (key, item) in map {
                if out.len() >= limit {
                    break;
                }
                collect_semantic_scalars(&format!("{prefix}/{key}"), item, out, limit);
            }
        }
    }
}

fn collect_semantic_events(
    prefix: &str,
    value: &serde_json::Value,
    out: &mut BTreeSet<String>,
    limit: usize,
) {
    if out.len() >= limit {
        return;
    }
    match value {
        serde_json::Value::Array(items) => {
            for item in items {
                collect_semantic_events(prefix, item, out, limit);
                if out.len() >= limit {
                    break;
                }
            }
        }
        serde_json::Value::Object(map) => {
            if let Some(text) = map
                .get("text")
                .or_else(|| map.get("name"))
                .or_else(|| map.get("type"))
                .and_then(|value| value.as_str())
            {
                let level = map
                    .get("level")
                    .and_then(|value| value.as_str())
                    .unwrap_or("event");
                out.insert(format!("{prefix}:{level}:{text}"));
            }
            for item in map.values() {
                if out.len() >= limit {
                    break;
                }
                collect_semantic_events(prefix, item, out, limit);
            }
        }
        _ => {}
    }
}

fn semantic_scenario_diffs(
    before: &RunComparisonDetails,
    after: &RunComparisonDetails,
) -> Vec<RunSemanticScenarioDiff> {
    before
        .scenario_statuses
        .keys()
        .chain(after.scenario_statuses.keys())
        .cloned()
        .collect::<BTreeSet<_>>()
        .into_iter()
        .filter_map(|scenario_id| {
            let before_status = before
                .scenario_statuses
                .get(&scenario_id)
                .cloned()
                .unwrap_or_else(|| "missing".to_string());
            let after_status = after
                .scenario_statuses
                .get(&scenario_id)
                .cloned()
                .unwrap_or_else(|| "missing".to_string());
            if before_status == after_status {
                return None;
            }
            Some(RunSemanticScenarioDiff {
                scenario_id,
                classification: scenario_status_diff_classification(&before_status, &after_status)
                    .to_string(),
                before: before_status,
                after: after_status,
                evidence_refs: Vec::new(),
            })
        })
        .collect()
}

fn scenario_status_diff_classification(before: &str, after: &str) -> &'static str {
    match (before, after) {
        (before, "passed") if before != "passed" => "improved",
        ("passed", after) if after != "passed" => "regressed",
        _ => "changed",
    }
}

fn semantic_map_diff(
    before: &BTreeMap<String, serde_json::Value>,
    after: &BTreeMap<String, serde_json::Value>,
    limit: usize,
) -> RunSemanticWorldStateDiff {
    let before_keys = before.keys().cloned().collect::<BTreeSet<_>>();
    let after_keys = after.keys().cloned().collect::<BTreeSet<_>>();
    RunSemanticWorldStateDiff {
        changed: semantic_value_diffs(before, after, limit),
        added: after_keys
            .difference(&before_keys)
            .take(limit)
            .cloned()
            .collect(),
        removed: before_keys
            .difference(&after_keys)
            .take(limit)
            .cloned()
            .collect(),
    }
}

fn semantic_value_diffs(
    before: &BTreeMap<String, serde_json::Value>,
    after: &BTreeMap<String, serde_json::Value>,
    limit: usize,
) -> Vec<RunSemanticValueDiff> {
    before
        .keys()
        .filter(|key| after.contains_key(*key))
        .filter_map(|key| {
            let before_value = before.get(key)?;
            let after_value = after.get(key)?;
            (before_value != after_value).then(|| RunSemanticValueDiff {
                path: key.clone(),
                before: before_value.clone(),
                after: after_value.clone(),
            })
        })
        .take(limit)
        .collect()
}

fn semantic_set_diff(before: &BTreeSet<String>, after: &BTreeSet<String>) -> RunSemanticEventDiff {
    RunSemanticEventDiff {
        added: after.difference(before).take(64).cloned().collect(),
        removed: before.difference(after).take(64).cloned().collect(),
    }
}

fn semantic_evidence_set_diff(
    before: &BTreeSet<String>,
    after: &BTreeSet<String>,
) -> RunSemanticEvidenceDiff {
    RunSemanticEvidenceDiff {
        added: after.difference(before).take(64).cloned().collect(),
        removed: before.difference(after).take(64).cloned().collect(),
    }
}

fn semantic_project_diff(
    before: &Option<ProjectRunMetadata>,
    after: &Option<ProjectRunMetadata>,
) -> RunSemanticProjectDiff {
    let relation = match (before, after) {
        (None, None) => "legacy".to_string(),
        (None, Some(_)) => "project_added".to_string(),
        (Some(_), None) => "project_removed".to_string(),
        (Some(before), Some(after)) if before.id == after.id => "same_project".to_string(),
        (Some(_), Some(_)) => "different_project".to_string(),
    };
    let mut changes = Vec::new();
    let mut warnings = Vec::new();

    match (before, after) {
        (None, Some(project)) => {
            warnings
                .push("before run has no project metadata; after run is project-bound".to_string());
            changes.push(RunSemanticProjectChange {
                kind: "project_presence".to_string(),
                summary: "project metadata was added".to_string(),
                before: None,
                after: Some(project.id.clone()),
            });
        }
        (Some(project), None) => {
            warnings
                .push("before run is project-bound; after run has no project metadata".to_string());
            changes.push(RunSemanticProjectChange {
                kind: "project_presence".to_string(),
                summary: "project metadata was removed".to_string(),
                before: Some(project.id.clone()),
                after: None,
            });
        }
        (Some(before), Some(after)) => {
            push_project_change(
                &mut changes,
                "project_id",
                "project id changed",
                Some(before.id.as_str()),
                Some(after.id.as_str()),
            );
            push_project_change(
                &mut changes,
                "manifest_hash",
                "project manifest hash changed",
                Some(before.manifest_hash.value.as_str()),
                Some(after.manifest_hash.value.as_str()),
            );
            push_project_change(
                &mut changes,
                "seed_path",
                "project seed path changed",
                Some(before.seed_path.as_str()),
                Some(after.seed_path.as_str()),
            );
            push_project_change(
                &mut changes,
                "scenario_pack",
                "scenario pack changed",
                before.scenario_pack.as_ref().map(|pack| pack.id.as_str()),
                after.scenario_pack.as_ref().map(|pack| pack.id.as_str()),
            );
            push_project_change(
                &mut changes,
                "transaction_id",
                "linked transaction id changed",
                before.transaction_id.as_deref(),
                after.transaction_id.as_deref(),
            );
            for change in project_scene_hash_changes(before, after) {
                changes.push(change);
            }
        }
        (None, None) => {}
    }

    RunSemanticProjectDiff {
        before: before.clone(),
        after: after.clone(),
        relation,
        changed: !changes.is_empty(),
        changes,
        warnings,
    }
}

fn push_project_change(
    changes: &mut Vec<RunSemanticProjectChange>,
    kind: &str,
    summary: &str,
    before: Option<&str>,
    after: Option<&str>,
) {
    if before != after {
        changes.push(RunSemanticProjectChange {
            kind: kind.to_string(),
            summary: summary.to_string(),
            before: before.map(ToString::to_string),
            after: after.map(ToString::to_string),
        });
    }
}

fn project_scene_hash_changes(
    before: &ProjectRunMetadata,
    after: &ProjectRunMetadata,
) -> Vec<RunSemanticProjectChange> {
    let before_scenes = before
        .scenes
        .iter()
        .map(|scene| (scene.path.as_str(), scene.hash.value.as_str()))
        .collect::<BTreeMap<_, _>>();
    let after_scenes = after
        .scenes
        .iter()
        .map(|scene| (scene.path.as_str(), scene.hash.value.as_str()))
        .collect::<BTreeMap<_, _>>();
    before_scenes
        .keys()
        .chain(after_scenes.keys())
        .copied()
        .collect::<BTreeSet<_>>()
        .into_iter()
        .filter_map(|path| {
            let before_hash = before_scenes.get(path).copied();
            let after_hash = after_scenes.get(path).copied();
            (before_hash != after_hash).then(|| RunSemanticProjectChange {
                kind: "scene_hash".to_string(),
                summary: format!("scene hash changed for {path}"),
                before: before_hash.map(ToString::to_string),
                after: after_hash.map(ToString::to_string),
            })
        })
        .collect()
}

struct RunSemanticReasonInputs<'a> {
    classification: &'a str,
    scenarios: &'a [RunSemanticScenarioDiff],
    world_state: &'a RunSemanticWorldStateDiff,
    events: &'a RunSemanticEventDiff,
    performance: &'a RunSemanticPerformanceDiff,
    evidence: &'a RunSemanticEvidenceDiff,
    project: &'a RunSemanticProjectDiff,
    transaction: &'a RunSemanticTransactionDiff,
    input_replay: &'a RunSemanticReplayDiff,
    warnings: &'a [String],
}

fn semantic_reasons(inputs: RunSemanticReasonInputs<'_>) -> Vec<RunSemanticReason> {
    let mut reasons = Vec::new();
    if inputs.project.changed {
        let severity = match inputs.project.relation.as_str() {
            "project_added" | "project_removed" => "warning",
            _ => "changed",
        };
        reasons.push(RunSemanticReason {
            kind: "project_context".to_string(),
            severity: severity.to_string(),
            summary: format!(
                "project context {} with {} project change(s)",
                inputs.project.relation,
                inputs.project.changes.len()
            ),
            evidence_refs: Vec::new(),
        });
    } else if !inputs.project.warnings.is_empty() {
        reasons.push(RunSemanticReason {
            kind: "project_context".to_string(),
            severity: "warning".to_string(),
            summary: format!(
                "project context {} with {} warning(s)",
                inputs.project.relation,
                inputs.project.warnings.len()
            ),
            evidence_refs: Vec::new(),
        });
    }
    for scenario in inputs.scenarios {
        reasons.push(RunSemanticReason {
            kind: "scenario_verdict".to_string(),
            severity: scenario.classification.clone(),
            summary: format!(
                "scenario {} changed from {} to {}",
                scenario.scenario_id, scenario.before, scenario.after
            ),
            evidence_refs: scenario.evidence_refs.clone(),
        });
    }
    if !inputs.world_state.changed.is_empty()
        || !inputs.world_state.added.is_empty()
        || !inputs.world_state.removed.is_empty()
    {
        reasons.push(RunSemanticReason {
            kind: "world_state".to_string(),
            severity: "changed".to_string(),
            summary: format!(
                "{} world-state values changed, {} added, {} removed",
                inputs.world_state.changed.len(),
                inputs.world_state.added.len(),
                inputs.world_state.removed.len()
            ),
            evidence_refs: Vec::new(),
        });
    }
    if !inputs.events.added.is_empty() || !inputs.events.removed.is_empty() {
        reasons.push(RunSemanticReason {
            kind: "events".to_string(),
            severity: "changed".to_string(),
            summary: format!(
                "{} events added, {} removed",
                inputs.events.added.len(),
                inputs.events.removed.len()
            ),
            evidence_refs: Vec::new(),
        });
    }
    if !inputs.performance.changed.is_empty() {
        reasons.push(RunSemanticReason {
            kind: "performance".to_string(),
            severity: "changed".to_string(),
            summary: format!(
                "{} performance values changed",
                inputs.performance.changed.len()
            ),
            evidence_refs: Vec::new(),
        });
    }
    if !inputs.input_replay.added.is_empty()
        || !inputs.input_replay.removed.is_empty()
        || inputs.input_replay.before_count != inputs.input_replay.after_count
    {
        reasons.push(RunSemanticReason {
            kind: "input_replay".to_string(),
            severity: "changed".to_string(),
            summary: format!(
                "input replay evidence changed from {} to {} artifact(s), {} added, {} removed",
                inputs.input_replay.before_count,
                inputs.input_replay.after_count,
                inputs.input_replay.added.len(),
                inputs.input_replay.removed.len()
            ),
            evidence_refs: inputs
                .input_replay
                .added
                .iter()
                .chain(inputs.input_replay.removed.iter())
                .take(8)
                .cloned()
                .collect(),
        });
    }
    if !inputs.evidence.added.is_empty() || !inputs.evidence.removed.is_empty() {
        reasons.push(RunSemanticReason {
            kind: "evidence_artifacts".to_string(),
            severity: "changed".to_string(),
            summary: format!(
                "{} evidence artifacts added, {} removed",
                inputs.evidence.added.len(),
                inputs.evidence.removed.len()
            ),
            evidence_refs: Vec::new(),
        });
    }
    if inputs.transaction.changed {
        reasons.push(RunSemanticReason {
            kind: "transaction_provenance".to_string(),
            severity: "changed".to_string(),
            summary: "scene edit transaction provenance changed".to_string(),
            evidence_refs: Vec::new(),
        });
    }
    if !inputs.warnings.is_empty() {
        reasons.push(RunSemanticReason {
            kind: "warnings".to_string(),
            severity: "warning".to_string(),
            summary: format!("{} semantic diff warning(s)", inputs.warnings.len()),
            evidence_refs: Vec::new(),
        });
    }
    if reasons.is_empty() {
        reasons.push(RunSemanticReason {
            kind: "classification".to_string(),
            severity: inputs.classification.to_string(),
            summary: format!("comparison classification is {}", inputs.classification),
            evidence_refs: Vec::new(),
        });
    }
    reasons
}

fn classify_run_comparison(
    before: &RunComparisonSnapshot,
    after: &RunComparisonSnapshot,
) -> &'static str {
    match (
        before.verdict_status.as_str(),
        after.verdict_status.as_str(),
    ) {
        (before_status, after_status) if before_status != "passed" && after_status == "passed" => {
            "improved"
        }
        ("passed", after_status) if after_status != "passed" => "regressed",
        _ if after.failed_scenarios < before.failed_scenarios
            || after.assertion_failures < before.assertion_failures =>
        {
            "improved"
        }
        _ if after.failed_scenarios > before.failed_scenarios
            || after.assertion_failures > before.assertion_failures =>
        {
            "regressed"
        }
        _ if run_comparison_snapshots_match(before, after) => "no_change",
        _ => "changed",
    }
}

fn run_comparison_snapshots_match(
    before: &RunComparisonSnapshot,
    after: &RunComparisonSnapshot,
) -> bool {
    before.verdict_status == after.verdict_status
        && before.scenario_results == after.scenario_results
        && before.failed_scenarios == after.failed_scenarios
        && before.assertion_failures == after.assertion_failures
        && before.performance_artifacts == after.performance_artifacts
        && before.evidence_artifacts == after.evidence_artifacts
        && before.input_replay_artifacts == after.input_replay_artifacts
        && before.mutation_proposals == after.mutation_proposals
}

fn apply_explicit_evaluator_checks(
    run_dir: &Path,
    evidence: &EvidenceIndex,
    config: &EvaluatorConfig,
    failures: &mut Vec<serde_json::Value>,
) -> Result<()> {
    if let Some(console) = &config.console {
        for artifact in evidence.artifacts.iter().filter(|artifact| {
            artifact
                .metadata
                .get("artifact")
                .and_then(|value| value.as_str())
                == Some("console_log")
        }) {
            let value = read_json_value(run_dir.join(&artifact.path))?;
            for entry in console_entries(&value) {
                let level = entry
                    .get("level")
                    .and_then(|value| value.as_str())
                    .unwrap_or("");
                if console
                    .fail_on_levels
                    .iter()
                    .any(|expected| expected == level)
                {
                    failures.push(json!({
                        "kind": "console_level_matched",
                        "level": level,
                        "path": artifact.path,
                        "text": entry.get("text").cloned().unwrap_or(serde_json::Value::Null)
                    }));
                }
            }
        }
    }

    if let Some(performance) = &config.performance {
        for artifact in evidence.artifacts.iter().filter(|artifact| {
            artifact
                .metadata
                .get("artifact")
                .and_then(|value| value.as_str())
                == Some("performance_metrics")
        }) {
            let value = read_json_value(run_dir.join(&artifact.path))?;
            for (metric, threshold) in &performance.max_metrics {
                if let Some(actual) = performance_metric_value(&value, metric) {
                    if actual > *threshold {
                        failures.push(json!({
                            "kind": "performance_threshold_exceeded",
                            "metric": metric,
                            "threshold": threshold,
                            "actual": actual,
                            "path": artifact.path
                        }));
                    }
                }
            }
        }
    }
    Ok(())
}

fn console_entries(value: &serde_json::Value) -> Vec<&serde_json::Value> {
    value
        .as_array()
        .or_else(|| value.get("logs").and_then(|logs| logs.as_array()))
        .map(|entries| entries.iter().collect())
        .unwrap_or_default()
}

fn performance_metric_value(value: &serde_json::Value, metric_name: &str) -> Option<f64> {
    let metrics = value
        .get("metrics")
        .or_else(|| value.get("Metrics"))
        .unwrap_or(value);
    let metrics = metrics
        .get("metrics")
        .or_else(|| metrics.get("Metrics"))
        .unwrap_or(metrics);
    metrics.as_array()?.iter().find_map(|metric| {
        let name = metric
            .get("name")
            .or_else(|| metric.get("Name"))
            .and_then(|value| value.as_str())?;
        if name != metric_name {
            return None;
        }
        metric
            .get("value")
            .or_else(|| metric.get("Value"))
            .and_then(|value| value.as_f64())
    })
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScenarioRunConfig {
    pub run_dir: PathBuf,
    pub url: String,
    pub debugging_http_url: String,
}

impl ScenarioRunConfig {
    pub fn new(run_dir: impl Into<PathBuf>, url: impl Into<String>) -> Result<Self> {
        let url = url.into();
        require_http_url("scenario run URL", &url)?;
        Ok(Self {
            run_dir: run_dir.into(),
            url,
            debugging_http_url: "http://127.0.0.1:9222".to_string(),
        })
    }
}

#[derive(Debug, Clone, Serialize, PartialEq, Eq)]
pub struct ScenarioRunSummary {
    pub scenarios: usize,
    pub completed: usize,
    pub passed: usize,
    pub failed: usize,
    pub scenario_order: Vec<String>,
    pub suite_summary_path: String,
    pub evidence_paths: Vec<String>,
    pub result_paths: Vec<String>,
}

impl ScenarioRunSummary {
    pub fn has_failures(&self) -> bool {
        self.failed > 0
    }
}

pub fn run_scenarios(config: &ScenarioRunConfig) -> Result<ScenarioRunSummary> {
    let seed = Seed::from_path(config.run_dir.join("seed.snapshot.yaml"))?;
    let connection = create_cdp_page_target(&config.debugging_http_url, "about:blank")?;
    let transport = WebSocketCdpTransport::connect(&connection)?;
    let mut client = CdpClient::new(transport);

    client.enable_page()?;
    install_console_capture(&mut client)?;
    let _ = client.bring_page_to_front();
    client.navigate(&config.url)?;
    std::thread::sleep(Duration::from_millis(300));

    run_scenarios_with_client(config, &seed, &mut client)
}

fn run_scenarios_with_client<T: CdpTransport>(
    config: &ScenarioRunConfig,
    seed: &Seed,
    client: &mut CdpClient<T>,
) -> Result<ScenarioRunSummary> {
    let mut evidence_paths = Vec::new();
    let mut result_paths = Vec::new();
    let mut scenario_order = Vec::new();
    let mut scenario_summaries = Vec::new();
    let mut passed = 0;
    let mut failed = 0;
    for scenario in &seed.scenarios {
        scenario_order.push(scenario.id.clone());
        let result = run_scenario(config, client, scenario)?;
        evidence_paths.extend(result.evidence_paths);
        result_paths.push(result.result_path.clone());
        if result.passed {
            passed += 1;
        } else {
            failed += 1;
        }
        scenario_summaries.push(json!({
            "scenario_id": scenario.id,
            "status": if result.passed { "passed" } else { "failed" },
            "result_path": result.result_path
        }));
    }
    let suite_summary_path = format!("evidence/suite-summary-{}.json", unix_millis()?);
    write_json(
        &config.run_dir.join(&suite_summary_path),
        &json!({
            "artifact": "suite_summary",
            "status": if failed == 0 { "passed" } else { "failed" },
            "scenarios": seed.scenarios.len(),
            "completed": result_paths.len(),
            "passed": passed,
            "failed": failed,
            "scenario_order": scenario_order.clone(),
            "scenario_results": scenario_summaries,
            "result_paths": result_paths.clone(),
            "evidence_paths": evidence_paths.clone()
        }),
    )?;
    add_evidence_artifact(
        &config.run_dir,
        &format!("suite-summary-{}", unix_millis()?),
        "application/json",
        &suite_summary_path,
        json!({
            "artifact": "suite_summary",
            "scenarios": seed.scenarios.len(),
            "passed": passed,
            "failed": failed
        }),
    )?;
    evidence_paths.push(suite_summary_path.clone());

    Ok(ScenarioRunSummary {
        scenarios: seed.scenarios.len(),
        completed: result_paths.len(),
        passed,
        failed,
        scenario_order,
        suite_summary_path,
        evidence_paths,
        result_paths,
    })
}

struct ScenarioExecutionResult {
    passed: bool,
    evidence_paths: Vec<String>,
    result_path: String,
}

fn run_scenario<T: CdpTransport>(
    config: &ScenarioRunConfig,
    client: &mut CdpClient<T>,
    scenario: &Scenario,
) -> Result<ScenarioExecutionResult> {
    validate_path_component("scenario id", &scenario.id)?;
    append_ledger_event(
        &config.run_dir,
        "scenario.started",
        "scenario-runner",
        json!({ "scenario_id": scenario.id, "url": config.url }),
    )?;

    let suffix = unix_millis()?;
    let scenario_dir = format!("evidence/scenarios/{}", scenario.id);
    fs::create_dir_all(config.run_dir.join(&scenario_dir)).with_context(|| {
        format!(
            "failed to create scenario evidence directory {}",
            config.run_dir.join(&scenario_dir).display()
        )
    })?;

    let mut replay_paths = Vec::new();
    let mut snapshot_paths = Vec::new();
    let mut visual_checkpoint_paths = Vec::new();
    let mut visual_checkpoint_screenshot_paths = Vec::new();
    let mut visual_checkpoint_summaries = Vec::new();
    let mut snapshot_ids = std::collections::BTreeMap::new();
    let mut pending_replay_artifacts = Vec::new();
    let mut scenario_frame = 0u32;
    for (step_index, step) in scenario.steps.iter().enumerate() {
        match step {
            ScenarioStep::Replay { replay } => {
                let replay_path = write_scenario_json_artifact(
                    config,
                    scenario,
                    &scenario_dir,
                    "input-replay",
                    "input_replay",
                    unix_millis()?,
                    &json!(replay),
                )?;
                replay_paths.push(replay_path.clone());
                pending_replay_artifacts.extend(pending_replay_artifacts_from_replay(
                    scenario,
                    step_index,
                    scenario_frame,
                    replay,
                    "inline_replay_event",
                )?);
                scenario_frame = scenario_frame
                    .checked_add(input_replay_last_frame(replay))
                    .ok_or_else(|| anyhow!("scenario replay frame overflow"))?;
                append_ledger_event(
                    &config.run_dir,
                    "scenario.input_replay",
                    "scenario-runner",
                    json!({
                        "scenario_id": scenario.id,
                        "replay_id": replay.id,
                        "events": replay.events.len(),
                        "path": replay_path,
                        "source": "inline"
                    }),
                )?;
                execute_scenario_step(client, step)?;
            }
            ScenarioStep::ReplayRef { replay_ref } => {
                let replay = replay_ref.load_from_base(&config.run_dir)?;
                let replay_path = write_scenario_json_artifact(
                    config,
                    scenario,
                    &scenario_dir,
                    "input-replay",
                    "input_replay",
                    unix_millis()?,
                    &json!({
                        "reference": replay_ref,
                        "replay": replay
                    }),
                )?;
                replay_paths.push(replay_path.clone());
                pending_replay_artifacts.extend(pending_replay_artifacts_from_replay(
                    scenario,
                    step_index,
                    scenario_frame,
                    &replay,
                    "referenced_replay_event",
                )?);
                scenario_frame = scenario_frame
                    .checked_add(input_replay_last_frame(&replay))
                    .ok_or_else(|| anyhow!("scenario replay frame overflow"))?;
                append_ledger_event(
                    &config.run_dir,
                    "scenario.input_replay",
                    "scenario-runner",
                    json!({
                        "scenario_id": scenario.id,
                        "replay_id": replay.id,
                        "events": replay.events.len(),
                        "path": replay_path,
                        "source": "replayRef",
                        "reference_path": replay_ref.path
                    }),
                )?;
                execute_input_replay(client, &replay)?;
            }
            ScenarioStep::Snapshot { snapshot } => {
                let snapshot_result = client.evaluate_json("window.__OUROFORGE__.snapshot()")?;
                let snapshot_id = snapshot_result
                    .get("snapshotId")
                    .and_then(|value| value.as_str())
                    .ok_or_else(|| anyhow!("snapshot probe did not return snapshotId"))?
                    .to_string();
                snapshot_ids.insert(snapshot.id.clone(), snapshot_id.clone());
                let world_state = client.evaluate_json("window.__OUROFORGE__.getWorldState()")?;
                let snapshot_path = write_scenario_json_artifact(
                    config,
                    scenario,
                    &scenario_dir,
                    &format!("snapshot-{}", snapshot.id),
                    "snapshot",
                    unix_millis()?,
                    &json!({
                        "step_id": snapshot.id,
                        "snapshot_id": snapshot_id,
                        "snapshot": snapshot_result,
                        "world_state": world_state
                    }),
                )?;
                snapshot_paths.push(snapshot_path.clone());
                append_ledger_event(
                    &config.run_dir,
                    "scenario.snapshot",
                    "scenario-runner",
                    json!({
                        "scenario_id": scenario.id,
                        "step_id": snapshot.id,
                        "snapshot_id": snapshot_id,
                        "path": snapshot_path
                    }),
                )?;
            }
            ScenarioStep::Restore { restore } => {
                let snapshot_id = snapshot_ids
                    .get(&restore.id)
                    .ok_or_else(|| anyhow!("snapshot id not found for restore: {}", restore.id))?;
                let snapshot_json = serde_json::to_string(snapshot_id)
                    .context("failed to serialize snapshot id")?;
                let restored_world_state = client
                    .evaluate_json(&format!("window.__OUROFORGE__.restore({snapshot_json})"))?;
                let restore_path = write_scenario_json_artifact(
                    config,
                    scenario,
                    &scenario_dir,
                    &format!("restore-{}", restore.id),
                    "snapshot_restore",
                    unix_millis()?,
                    &json!({
                        "step_id": restore.id,
                        "snapshot_id": snapshot_id,
                        "world_state": restored_world_state
                    }),
                )?;
                snapshot_paths.push(restore_path.clone());
                append_ledger_event(
                    &config.run_dir,
                    "scenario.restore",
                    "scenario-runner",
                    json!({
                        "scenario_id": scenario.id,
                        "step_id": restore.id,
                        "snapshot_id": snapshot_id,
                        "path": restore_path
                    }),
                )?;
            }
            ScenarioStep::VisualCheckpoint { visual_checkpoint } => {
                let capture = capture_visual_checkpoint(
                    config,
                    scenario,
                    &scenario_dir,
                    visual_checkpoint,
                    client,
                )?;
                visual_checkpoint_paths.push(capture.metadata_path.clone());
                visual_checkpoint_screenshot_paths.push(capture.screenshot_path.clone());
                visual_checkpoint_summaries.push(capture.summary.clone());
                append_ledger_event(
                    &config.run_dir,
                    "scenario.visual_checkpoint",
                    "scenario-runner",
                    json!({
                        "scenario_id": scenario.id,
                        "checkpoint_id": visual_checkpoint.id,
                        "screenshot_path": capture.screenshot_path,
                        "metadata_path": capture.metadata_path,
                        "advisory": true
                    }),
                )?;
            }
            ScenarioStep::Wait { wait } => {
                execute_scenario_step(client, step)?;
                scenario_frame = scenario_frame
                    .checked_add(wait.frames)
                    .ok_or_else(|| anyhow!("scenario wait frame overflow"))?;
            }
            ScenarioStep::Input { input } => {
                pending_replay_artifacts.push(ScenarioInputReplayArtifact {
                    schema_version: SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION.to_string(),
                    scenario_id: scenario.id.clone(),
                    worker_id: None,
                    step_index,
                    action: ScenarioInputReplayAction {
                        kind: "scenario_input_step".to_string(),
                        key: None,
                        pressed: None,
                    },
                    frame: scenario_frame,
                    tick: Some(u64::from(scenario_frame)),
                    input: input.clone(),
                    probe: None,
                    result: None,
                });
                execute_scenario_step(client, step)?;
            }
            ScenarioStep::Transition { transition } => {
                execute_scenario_step(client, step)?;
                append_ledger_event(
                    &config.run_dir,
                    "scenario.transition",
                    "scenario-runner",
                    json!({
                        "scenario_id": scenario.id,
                        "transition_id": transition.id,
                        "frame": scenario_frame
                    }),
                )?;
            }
        }
    }

    let mut prior_evidence_paths = replay_paths.clone();
    prior_evidence_paths.extend(snapshot_paths.clone());
    prior_evidence_paths.extend(visual_checkpoint_paths.clone());
    prior_evidence_paths.extend(visual_checkpoint_screenshot_paths.clone());

    let world_state = match evaluate_runtime_probe_object(
        client,
        "getWorldState",
        "window.__OUROFORGE__.getWorldState()",
    ) {
        Ok(value) => value,
        Err(error) => {
            return write_runtime_probe_contract_failure_result(
                config,
                scenario,
                &scenario_dir,
                "getWorldState",
                "JSON object world state",
                error,
                prior_evidence_paths,
            );
        }
    };
    let world_state_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "world-state",
        "world_state",
        suffix,
        &world_state,
    )?;
    prior_evidence_paths.push(world_state_path.clone());
    let mut asset_load_paths = Vec::new();
    if let Some(asset_load_evidence) = runtime_asset_load_evidence_from_world_state(
        config,
        scenario,
        &world_state,
        unix_millis()?,
    )? {
        let path = write_scenario_json_artifact(
            config,
            scenario,
            &scenario_dir,
            "asset-load-evidence",
            "runtime_asset_load_evidence",
            unix_millis()?,
            &json!(asset_load_evidence),
        )?;
        prior_evidence_paths.push(path.clone());
        asset_load_paths.push(path);
    }
    let frame_stats = match evaluate_runtime_probe_object(
        client,
        "getFrameStats",
        "window.__OUROFORGE__.getFrameStats()",
    ) {
        Ok(value) => value,
        Err(error) => {
            return write_runtime_probe_contract_failure_result(
                config,
                scenario,
                &scenario_dir,
                "getFrameStats",
                "JSON object frame stats",
                error,
                prior_evidence_paths,
            );
        }
    };
    let frame_stats_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "frame-stats",
        "frame_stats",
        unix_millis()?,
        &frame_stats,
    )?;
    let mut runtime_event_paths = Vec::new();
    let runtime_event_source = match evaluate_runtime_probe_object(
        client,
        "getEvents",
        "({ events: window.__OUROFORGE__.getEvents() })",
    ) {
        Ok(value) => {
            let path = write_scenario_json_artifact(
                config,
                scenario,
                &scenario_dir,
                "runtime-events",
                "runtime_events",
                unix_millis()?,
                &value,
            )?;
            runtime_event_paths.push(path);
            value
        }
        Err(_) => json!({ "events": [] }),
    };
    let mut console_paths = Vec::new();
    let mut performance_paths = Vec::new();
    let mut trace_paths = Vec::new();
    let mut console_source = json!({ "logs": [], "count": 0 });
    if let Ok(console_logs) = client.evaluate_json("window.__OUROFORGE_CONSOLE__ || []") {
        console_source = json!({
            "logs": console_entries(&console_logs)
                .into_iter()
                .filter(|entry| entry.get("level").and_then(|value| value.as_str()) == Some("error"))
                .cloned()
                .collect::<Vec<_>>(),
            "count": console_entries(&console_logs)
                .into_iter()
                .filter(|entry| entry.get("level").and_then(|value| value.as_str()) == Some("error"))
                .count()
        });
        let console_path = write_scenario_json_artifact(
            config,
            scenario,
            &scenario_dir,
            "console-log",
            "console_log",
            unix_millis()?,
            &json!({
                "bounded": true,
                "limit": 100,
                "logs": console_logs
            }),
        )?;
        console_paths.push(console_path);
    }
    let mut scenario_performance_metric_count = None;
    let mut performance_source = json!({});
    if let Ok(performance_metrics) = client
        .enable_performance()
        .and_then(|_| client.performance_metrics())
    {
        scenario_performance_metric_count = Some(count_cdp_metrics(&performance_metrics));
        performance_source = performance_metrics_by_name(&performance_metrics);
        let performance_path = write_scenario_json_artifact(
            config,
            scenario,
            &scenario_dir,
            "performance-metrics",
            "performance_metrics",
            unix_millis()?,
            &json!({
                "bounded": true,
                "metrics": performance_metrics
            }),
        )?;
        performance_paths.push(performance_path);
    }
    let trace_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "cdp-trace-summary",
        "cdp_trace_summary",
        unix_millis()?,
        &json!({
            "bounded": true,
            "limit": 32,
            "source": "scenario-cdp-summary",
            "scenarioId": scenario.id,
            "events": [
                { "name": "Scenario.steps", "count": scenario.steps.len() },
                { "name": "Scenario.assertions", "count": scenario.assertions.len() },
                { "name": "Runtime.getWorldState", "captured": true },
                { "name": "Runtime.getFrameStats", "captured": true },
                { "name": "Performance.getMetrics", "metricCount": scenario_performance_metric_count.unwrap_or(0) }
            ]
        }),
    )?;
    trace_paths.push(trace_path.clone());

    let runtime_events = json!({
        "steps": &scenario.steps,
        "stepCount": scenario.steps.len(),
        "inputReplays": &replay_paths,
        "snapshots": &snapshot_paths,
        "events": runtime_event_source
            .get("events")
            .cloned()
            .unwrap_or_else(|| json!([]))
    });
    let collision_source = world_state
        .get("collisions")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let physics_source = world_state
        .get("physics")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let world_flags_source = world_state
        .get("goalFlags")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    // The runtime exposes audio under `audioEvents` and animation per-entity
    // under `entities[*].components.animation` (examples/game-runtime/runtime.js),
    // so point the audio/animation assertion sources at the data that actually
    // exists instead of nonexistent top-level `audio`/`animation` keys (which
    // would make every audio_evidence/animation_evidence assertion read Null).
    let audio_source = world_state
        .get("audioEvents")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let audio_warnings_source = world_state
        .get("audioWarnings")
        .cloned()
        .unwrap_or_else(|| json!([]));
    let audio_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "audio-evidence",
        "audio_evidence",
        unix_millis()?,
        &json!({
            "bounded": true,
            "audioEvents": audio_source.clone(),
            "audioEventCount": audio_source.as_array().map_or(0, Vec::len),
            "audioWarnings": audio_warnings_source.clone(),
            "audioWarningCount": audio_warnings_source.as_array().map_or(0, Vec::len),
            "browserAudioAuthority": "intent_evidence_only"
        }),
    )?;
    let animation_source = world_state
        .get("entities")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let vfx_source = world_state
        .get("vfxEvents")
        .cloned()
        .unwrap_or(serde_json::Value::Null);
    let vfx_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "vfx-evidence",
        "vfx_evidence",
        unix_millis()?,
        &json!({
            "bounded": true,
            "vfxEvents": vfx_source.clone(),
            "vfxEventCount": vfx_source.as_array().map_or(0, Vec::len)
        }),
    )?;
    let transition_source = world_state
        .get("transitionEvents")
        .cloned()
        .unwrap_or_else(|| json!([]));
    let transition_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "transition-evidence",
        "transition_evidence",
        unix_millis()?,
        &json!({
            "bounded": true,
            "currentSceneId": world_state.get("sceneId").cloned().unwrap_or(serde_json::Value::Null),
            "declaredTransitions": world_state.get("sceneTransitions").cloned().unwrap_or_else(|| json!([])),
            "transitionEvents": transition_source.clone()
        }),
    )?;
    let scene3d_camera_source = scene3d_camera_evidence_from_world_state(&world_state);
    let scene3d_camera_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "scene3d-camera-evidence",
        "scene3d_camera",
        unix_millis()?,
        &scene3d_camera_source,
    )?;
    let scene3d_animation_source = scene3d_animation_evidence_from_world_state(&world_state);
    let scene3d_animation_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "scene3d-animation-evidence",
        "scene3d_animation",
        unix_millis()?,
        &scene3d_animation_source,
    )?;
    let scene3d_probe_source = scene3d_probe_evidence_from_world_state(&world_state);
    let scene3d_probe_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "scene3d-probe-evidence",
        "scene3d_probe",
        unix_millis()?,
        &scene3d_probe_source,
    )?;
    let scene3d_transform_source = scene3d_transform_evidence_from_world_state(&world_state);
    let scene3d_transform_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "scene3d-transform-evidence",
        "scene3d_transform",
        unix_millis()?,
        &scene3d_transform_source,
    )?;
    let scene3d_render_source = scene3d_render_evidence_from_world_state(&world_state);
    let scene3d_render_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "scene3d-render-evidence",
        "scene3d_render",
        unix_millis()?,
        &scene3d_render_source,
    )?;
    let scene3d_collision_source = scene3d_collision_evidence_from_world_state(&world_state);
    let scene3d_collision_path = write_scenario_json_artifact(
        config,
        scenario,
        &scenario_dir,
        "scene3d-collision-evidence",
        "scene3d_collision",
        unix_millis()?,
        &scene3d_collision_source,
    )?;
    let assertion_sources = ScenarioAssertionSources {
        world_state: AssertionSource {
            value: &world_state,
            evidence_ref: &world_state_path,
        },
        frame_stats: AssertionSource {
            value: &frame_stats,
            evidence_ref: &frame_stats_path,
        },
        runtime_events: AssertionSource {
            value: &runtime_events,
            evidence_ref: runtime_event_paths
                .first()
                .map_or(trace_path.as_str(), String::as_str),
        },
        world_flags: AssertionSource {
            value: &world_flags_source,
            evidence_ref: &world_state_path,
        },
        physics_evidence: AssertionSource {
            value: &physics_source,
            evidence_ref: &world_state_path,
        },
        performance_metrics: AssertionSource {
            value: &performance_source,
            evidence_ref: performance_paths
                .first()
                .map_or(frame_stats_path.as_str(), String::as_str),
        },
        console_errors: AssertionSource {
            value: &console_source,
            evidence_ref: console_paths
                .first()
                .map_or(trace_path.as_str(), String::as_str),
        },
        collision_evidence: AssertionSource {
            value: &collision_source,
            evidence_ref: &world_state_path,
        },
        audio_evidence: AssertionSource {
            value: &audio_source,
            evidence_ref: &audio_path,
        },
        animation_evidence: AssertionSource {
            value: &animation_source,
            evidence_ref: &world_state_path,
        },
        vfx_evidence: AssertionSource {
            value: &vfx_source,
            evidence_ref: &vfx_path,
        },
        transition_evidence: AssertionSource {
            value: &transition_source,
            evidence_ref: &transition_path,
        },
        scene3d_camera: AssertionSource {
            value: &scene3d_camera_source,
            evidence_ref: &scene3d_camera_path,
        },
        scene3d_animation: AssertionSource {
            value: &scene3d_animation_source,
            evidence_ref: &scene3d_animation_path,
        },
        scene3d_probe: AssertionSource {
            value: &scene3d_probe_source,
            evidence_ref: &scene3d_probe_path,
        },
        scene3d_transform: AssertionSource {
            value: &scene3d_transform_source,
            evidence_ref: &scene3d_transform_path,
        },
        scene3d_render: AssertionSource {
            value: &scene3d_render_source,
            evidence_ref: &scene3d_render_path,
        },
        scene3d_collision: AssertionSource {
            value: &scene3d_collision_source,
            evidence_ref: &scene3d_collision_path,
        },
    };
    let assertions = evaluate_scenario_assertions(scenario, &assertion_sources);
    for assertion in &assertions {
        append_ledger_event(
            &config.run_dir,
            "scenario.assertion",
            "scenario-runner",
            json!({
                "scenario_id": scenario.id,
                "target": assertion["target"],
                "path": assertion["path"],
                "passed": assertion["passed"],
                "evidence_path": assertion["evidence_ref"]
            }),
        )?;
    }
    let passed = assertions
        .iter()
        .all(|assertion| assertion["passed"].as_bool() == Some(true))
        && visual_checkpoint_summaries
            .iter()
            .all(|summary| summary["passed"].as_bool() != Some(false));
    let status = if passed { "passed" } else { "failed" };
    let result_path = format!("{scenario_dir}/scenario-result-{}.json", unix_millis()?);
    let deterministic_replay_paths = write_pending_replay_artifacts(
        config,
        scenario,
        &scenario_dir,
        pending_replay_artifacts,
        &world_state_path,
        &frame_stats_path,
        &result_path,
    )?;
    replay_paths.extend(deterministic_replay_paths.clone());
    write_json(
        &config.run_dir.join(&result_path),
        &json!({
            "scenario_id": scenario.id,
            "status": status,
            "evidence": {
                "world_state": world_state_path,
                "frame_stats": frame_stats_path,
                "runtime_events": runtime_event_paths.clone(),
                "input_replays": replay_paths.clone(),
                "scenario_input_replays": deterministic_replay_paths.clone(),
                "snapshots": snapshot_paths.clone(),
                "visual_checkpoints": visual_checkpoint_paths.clone(),
                "visual_checkpoint_screenshots": visual_checkpoint_screenshot_paths.clone(),
                "transition_evidence": transition_path.clone(),
                "scene3d_camera": scene3d_camera_path.clone(),
                "scene3d_animation": scene3d_animation_path.clone(),
                "scene3d_probe": scene3d_probe_path.clone(),
                "scene3d_transform": scene3d_transform_path.clone(),
                "scene3d_render": scene3d_render_path.clone(),
                "scene3d_collision": scene3d_collision_path.clone(),
                "audio_evidence": audio_path.clone(),
                "vfx_evidence": vfx_path.clone(),
                "asset_load_evidence": asset_load_paths.clone(),
                "console_logs": console_paths.clone(),
                "performance_metrics": performance_paths.clone(),
                "cdp_trace_summaries": trace_paths.clone()
            },
            "assertions": assertions,
            "visual_checkpoints": visual_checkpoint_summaries
        }),
    )?;
    add_evidence_artifact(
        &config.run_dir,
        &format!("scenario-result-{}-{}", scenario.id, unix_millis()?),
        "application/json",
        &result_path,
        json!({ "scenario_id": scenario.id, "url": config.url, "artifact": "scenario_result", "status": status }),
    )?;
    append_ledger_event(
        &config.run_dir,
        "scenario.completed",
        "scenario-runner",
        json!({
            "scenario_id": scenario.id,
            "status": status,
            "world_state_path": world_state_path,
            "frame_stats_path": frame_stats_path,
            "input_replay_paths": replay_paths.clone(),
            "scenario_input_replay_paths": deterministic_replay_paths.clone(),
            "snapshot_paths": snapshot_paths.clone(),
            "visual_checkpoint_paths": visual_checkpoint_paths.clone(),
            "visual_checkpoint_screenshot_paths": visual_checkpoint_screenshot_paths.clone(),
            "transition_evidence_path": transition_path.clone(),
            "scene3d_camera_path": scene3d_camera_path.clone(),
            "scene3d_animation_path": scene3d_animation_path.clone(),
            "scene3d_probe_path": scene3d_probe_path.clone(),
            "scene3d_transform_path": scene3d_transform_path.clone(),
            "scene3d_render_path": scene3d_render_path.clone(),
            "scene3d_collision_path": scene3d_collision_path.clone(),
            "audio_evidence_path": audio_path.clone(),
            "vfx_evidence_path": vfx_path.clone(),
            "asset_load_evidence_paths": asset_load_paths.clone(),
            "console_log_paths": console_paths.clone(),
            "performance_metric_paths": performance_paths.clone(),
            "cdp_trace_summary_paths": trace_paths.clone(),
            "result_path": result_path
        }),
    )?;
    let mut evidence_paths = replay_paths;
    evidence_paths.extend(snapshot_paths);
    evidence_paths.extend(visual_checkpoint_paths);
    evidence_paths.extend(visual_checkpoint_screenshot_paths);
    evidence_paths.push(world_state_path);
    evidence_paths.push(transition_path);
    evidence_paths.push(scene3d_camera_path);
    evidence_paths.push(scene3d_animation_path);
    evidence_paths.push(scene3d_probe_path);
    evidence_paths.push(scene3d_transform_path);
    evidence_paths.push(scene3d_render_path);
    evidence_paths.push(scene3d_collision_path);
    evidence_paths.push(audio_path);
    evidence_paths.push(vfx_path);
    evidence_paths.extend(asset_load_paths);
    evidence_paths.push(frame_stats_path);
    evidence_paths.extend(console_paths);
    evidence_paths.extend(performance_paths);
    evidence_paths.extend(trace_paths);
    Ok(ScenarioExecutionResult {
        passed,
        evidence_paths,
        result_path,
    })
}

fn input_replay_last_frame(replay: &InputReplay) -> u32 {
    replay.events.last().map_or(0, |event| event.frame)
}

fn scene3d_camera_evidence_from_world_state(world_state: &serde_json::Value) -> serde_json::Value {
    let camera_summary = world_state
        .get("camera")
        .and_then(|camera| {
            camera
                .get("scene3dCamera")
                .or_else(|| camera.get("scene3d_camera"))
                .or_else(|| camera.get("camera3d"))
        })
        .or_else(|| world_state.get("scene3dCamera"))
        .or_else(|| world_state.get("scene3d_camera"))
        .or_else(|| world_state.get("camera3d"));
    let Some(camera_summary) = camera_summary else {
        return json!({
            "present": false,
            "schemaVersion": "ouroforge.scene3d-camera-scenario-evidence.v1",
            "emptyState": "No scene3d camera evidence is available in world state.",
            "readOnlyInspection": {
                "trustedEmitter": "scenario-runtime-probe",
                "browserStudioMode": "read-only 3D camera scenario evidence",
                "disallowedActions": ["trusted writes", "command bridge", "scene mutation", "viewport persistence", "camera editor tooling"]
            }
        });
    };
    json!({
        "present": camera_summary
            .get("present")
            .and_then(|value| value.as_bool())
            .unwrap_or(true),
        "schemaVersion": "ouroforge.scene3d-camera-scenario-evidence.v1",
        "sourceSchemaVersion": camera_summary.get("schemaVersion").cloned().unwrap_or(serde_json::Value::Null),
        "activeCameraId": camera_summary.get("activeCameraId").cloned().unwrap_or(serde_json::Value::Null),
        "activeCamera": camera_summary.get("activeCamera").cloned().unwrap_or(serde_json::Value::Null),
        "cameraCount": camera_summary.get("cameraCount").cloned().unwrap_or_else(|| {
            camera_summary
                .get("cameras")
                .and_then(|value| value.as_array())
                .map(|cameras| json!(cameras.len()))
                .unwrap_or_else(|| json!(0))
        }),
        "cameras": camera_summary.get("cameras").cloned().unwrap_or_else(|| json!([])),
        "readOnlyInspection": {
            "trustedEmitter": "scenario-runtime-probe",
            "browserStudioMode": "read-only 3D camera scenario evidence",
            "disallowedActions": ["trusted writes", "command bridge", "scene mutation", "viewport persistence", "camera editor tooling"]
        }
    })
}

fn scene3d_animation_evidence_from_world_state(
    world_state: &serde_json::Value,
) -> serde_json::Value {
    let animation_summary = world_state
        .get("scene3dAnimation")
        .or_else(|| world_state.get("scene3d_animation"))
        .or_else(|| {
            world_state
                .get("scene3d")
                .and_then(|scene3d| scene3d.get("animation"))
        });
    let Some(animation_summary) = animation_summary else {
        return json!({
            "present": false,
            "schemaVersion": "ouroforge.scene3d-animation-scenario-evidence.v1",
            "sourceSchemaVersion": serde_json::Value::Null,
            "emptyState": "No scene3d animation evidence is available in world state.",
            "states": [],
            "events": [],
            "stateCount": 0,
            "activeStateCount": 0,
            "stoppedStateCount": 0,
            "warningCount": 0,
            "readOnlyInspection": {
                "trustedEmitter": "scenario-runtime-probe",
                "browserStudioMode": "read-only 3D animation scenario evidence",
                "disallowedActions": ["trusted writes", "command bridge", "scene mutation", "playback mutation", "animation editor tooling"]
            }
        });
    };
    let states = animation_summary
        .get("states")
        .or_else(|| animation_summary.get("animationStates"))
        .cloned()
        .unwrap_or_else(|| json!([]));
    let events = world_state
        .get("scene3dAnimationEvents")
        .or_else(|| world_state.get("scene3d_animation_events"))
        .or_else(|| animation_summary.get("events"))
        .cloned()
        .unwrap_or_else(|| json!([]));
    let active_state_count = animation_summary
        .get("activeStateCount")
        .cloned()
        .unwrap_or_else(|| {
            states
                .as_array()
                .map(|states| {
                    json!(states
                        .iter()
                        .filter(
                            |state| state.get("playing").and_then(|value| value.as_bool())
                                == Some(true)
                        )
                        .count())
                })
                .unwrap_or_else(|| json!(0))
        });
    let stopped_state_count = animation_summary
        .get("stoppedStateCount")
        .cloned()
        .unwrap_or_else(|| {
            states
                .as_array()
                .map(|states| {
                    json!(states
                        .iter()
                        .filter(
                            |state| state.get("playing").and_then(|value| value.as_bool())
                                == Some(false)
                        )
                        .count())
                })
                .unwrap_or_else(|| json!(0))
        });
    json!({
        "present": animation_summary
            .get("present")
            .and_then(|value| value.as_bool())
            .unwrap_or(true),
        "schemaVersion": "ouroforge.scene3d-animation-scenario-evidence.v1",
        "sourceSchemaVersion": animation_summary.get("schemaVersion").cloned().unwrap_or(serde_json::Value::Null),
        "frameId": animation_summary.get("frameId").cloned().unwrap_or(serde_json::Value::Null),
        "stateCount": animation_summary.get("stateCount").cloned().unwrap_or_else(|| {
            states
                .as_array()
                .map(|states| json!(states.len()))
                .unwrap_or_else(|| json!(0))
        }),
        "activeStateCount": active_state_count,
        "stoppedStateCount": stopped_state_count,
        "warningCount": animation_summary.get("warningCount").cloned().unwrap_or_else(|| json!(0)),
        "states": states,
        "events": events,
        "readOnlyInspection": {
            "trustedEmitter": "scenario-runtime-probe",
            "browserStudioMode": "read-only 3D animation scenario evidence",
            "disallowedActions": ["trusted writes", "command bridge", "scene mutation", "playback mutation", "animation editor tooling"]
        }
    })
}

