fn visual_comparison_evidence_refs(comparison: &VisualComparisonEvidenceArtifact) -> Vec<String> {
    let mut refs = Vec::new();
    refs.extend(comparison.evidence_refs.clone());
    refs.extend(comparison.metadata_refs.clone());
    refs.extend(comparison.before.screenshot_ref.clone());
    refs.extend(comparison.after.screenshot_ref.clone());
    refs.extend(comparison.before.metadata_ref.clone());
    refs.extend(comparison.after.metadata_ref.clone());
    refs.sort();
    refs.dedup();
    refs
}

fn dashboard_visual_comparison_summary(
    comparison: &VisualComparisonEvidenceArtifact,
) -> RunDashboardVisualComparisonSummary {
    let summary = comparison.pixel_diff_summary.as_ref();
    RunDashboardVisualComparisonSummary {
        comparison_id: comparison.comparison_id.clone(),
        run_id: comparison.run_id.clone(),
        scenario_id: comparison.scenario_id.clone(),
        checkpoint_id: comparison.checkpoint_id.clone(),
        outcome: comparison.outcome,
        failure_classification: visual_comparison_failure_classification(comparison.outcome)
            .to_string(),
        changed_pixels: summary.map(|summary| summary.changed_pixels),
        changed_percent_x1000: summary.map(|summary| summary.changed_percent_x1000),
        changed_region_count: comparison.changed_regions.len(),
        before_screenshot_ref: comparison.before.screenshot_ref.clone(),
        after_screenshot_ref: comparison.after.screenshot_ref.clone(),
        evidence_refs: visual_comparison_evidence_refs(comparison),
    }
}

fn visual_comparison_failure_classification(outcome: VisualComparisonOutcome) -> &'static str {
    match outcome {
        VisualComparisonOutcome::Unchanged => "visual_unchanged",
        VisualComparisonOutcome::Changed => "visual_regression_candidate",
        VisualComparisonOutcome::MissingScreenshot => "visual_missing_screenshot",
        VisualComparisonOutcome::MalformedScreenshot => "visual_malformed_screenshot",
        VisualComparisonOutcome::MismatchedDimensions => "visual_mismatched_dimensions",
        VisualComparisonOutcome::Unsupported => "visual_unsupported",
        VisualComparisonOutcome::Blocked => "visual_blocked",
    }
}

fn read_dashboard_qa_agent_work_queues(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardQaAgentWorkQueues> {
    let artifacts =
        select_dashboard_artifacts(run_dir, evidence, dashboard_artifact_is_qa_agent_work_queue)?;
    let boundary = "Read-only QA agent work queues; dashboard/Studio surfaces may display linked scenario, evaluator, run, task, work-package, review-gate, stale-ref, and expected-evidence refs but must not execute queue commands, spawn agents, write trusted state, auto-fix, auto-apply, auto-merge, self-approve, or claim quality guarantees.".to_string();
    if artifacts.is_empty() {
        return Ok(RunDashboardQaAgentWorkQueues {
            present: false,
            empty_state: "No QA agent work queues are indexed for this run.".to_string(),
            status: "missing".to_string(),
            queue_count: 0,
            item_count: 0,
            passed_count: 0,
            failed_count: 0,
            deferred_count: 0,
            blocked_count: 0,
            flaky_count: 0,
            needs_rerun_count: 0,
            malformed_count: 0,
            evidence_refs: Vec::new(),
            queues: Vec::new(),
            artifacts,
            boundary,
        });
    }

    let mut evidence_refs = Vec::new();
    let mut queues = Vec::new();
    let mut malformed_count = 0usize;
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if artifact.read_error.is_some() {
            malformed_count += 1;
            continue;
        }
        let Some(value) = &artifact.value else {
            malformed_count += 1;
            continue;
        };
        match serde_json::from_value::<QaAgentWorkQueueArtifact>(value.clone()) {
            Ok(queue) if queue.validate().is_ok() => {
                evidence_refs.extend(qa_agent_work_queue_evidence_refs(&queue));
                queues.push(queue);
            }
            _ => malformed_count += 1,
        }
    }
    queues.sort_by(|left, right| left.queue_id.cmp(&right.queue_id));
    evidence_refs.sort();
    evidence_refs.dedup();

    let queue_count = queues.len();
    let mut item_count = 0usize;
    let mut passed_count = 0usize;
    let mut failed_count = 0usize;
    let mut deferred_count = 0usize;
    let mut blocked_count = 0usize;
    let mut flaky_count = 0usize;
    let mut needs_rerun_count = 0usize;
    for queue in &queues {
        item_count += queue.items.len();
        for item in &queue.items {
            match item.status {
                QaAgentQueueStatus::Pass => passed_count += 1,
                QaAgentQueueStatus::Fail => failed_count += 1,
                QaAgentQueueStatus::Deferred => deferred_count += 1,
                QaAgentQueueStatus::Blocked => blocked_count += 1,
                QaAgentQueueStatus::Flaky => flaky_count += 1,
                QaAgentQueueStatus::NeedsRerun => needs_rerun_count += 1,
            }
        }
    }
    let status = if malformed_count > 0 {
        "malformed"
    } else if blocked_count > 0 {
        "blocked"
    } else if needs_rerun_count > 0 {
        "needs-rerun"
    } else if flaky_count > 0 {
        "flaky"
    } else if failed_count > 0 {
        "failed"
    } else if deferred_count > 0 {
        "deferred"
    } else if item_count > 0 && passed_count == item_count {
        "passed"
    } else if item_count > 0 {
        "queued"
    } else {
        "missing"
    };
    Ok(RunDashboardQaAgentWorkQueues {
        present: true,
        empty_state: String::new(),
        status: status.to_string(),
        queue_count,
        item_count,
        passed_count,
        failed_count,
        deferred_count,
        blocked_count,
        flaky_count,
        needs_rerun_count,
        malformed_count,
        evidence_refs,
        queues,
        artifacts,
        boundary,
    })
}

fn qa_agent_work_queue_evidence_refs(queue: &QaAgentWorkQueueArtifact) -> Vec<String> {
    let mut refs = Vec::new();
    for item in &queue.items {
        refs.push(item.scenario_target.scenario_pack_ref.path.clone());
        refs.extend(
            item.expected_evidence
                .iter()
                .map(|reference| reference.path.clone()),
        );
        refs.push(item.task_ref.path.clone());
        refs.push(item.work_package_ref.path.clone());
        if let Some(reference) = &item.review_gate_ref {
            refs.push(reference.path.clone());
        }
        refs.extend(
            item.run_evidence_refs
                .iter()
                .map(|reference| reference.path.clone()),
        );
        refs.extend(
            item.evaluator_evidence_refs
                .iter()
                .map(|reference| reference.path.clone()),
        );
        refs.extend(item.stale_run_refs.clone());
    }
    refs.sort();
    refs.dedup();
    refs
}

fn read_dashboard_performance_regression_lanes(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardPerformanceRegressionLanes> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_performance_regression_lane,
    )?;
    let boundary = "Read-only performance/regression lanes; dashboard/Studio surfaces may display linked run comparison, frame budget, scenario matrix, QA queue, review-gate, stale-ref, and browser-warning refs but must not execute commands, spawn agents, write trusted state, promote regressions, auto-apply, auto-merge, self-approve, or claim production guarantees.".to_string();
    if artifacts.is_empty() {
        return Ok(RunDashboardPerformanceRegressionLanes {
            present: false,
            empty_state: "No performance/regression lanes are indexed for this run.".to_string(),
            status: "missing".to_string(),
            lane_count: 0,
            improved_count: 0,
            unchanged_count: 0,
            regressed_count: 0,
            inconclusive_count: 0,
            missing_baseline_count: 0,
            unsupported_count: 0,
            stale_count: 0,
            malformed_count: 0,
            evidence_refs: Vec::new(),
            lanes: Vec::new(),
            artifacts,
            boundary,
        });
    }

    let mut evidence_refs = Vec::new();
    let mut lanes = Vec::new();
    let mut malformed_count = 0usize;
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        let Some(value) = &artifact.value else {
            malformed_count += 1;
            continue;
        };
        match serde_json::from_value::<PerformanceRegressionLaneArtifact>(value.clone()) {
            Ok(lane) if lane.validate().is_ok() => {
                evidence_refs.extend(performance_regression_lane_evidence_refs(&lane));
                lanes.push(lane);
            }
            _ => malformed_count += 1,
        }
    }
    lanes.sort_by(|left, right| left.lane_id.cmp(&right.lane_id));
    evidence_refs.sort();
    evidence_refs.dedup();

    let lane_count = lanes.len();
    let mut improved_count = 0usize;
    let mut unchanged_count = 0usize;
    let mut regressed_count = 0usize;
    let mut inconclusive_count = 0usize;
    let mut missing_baseline_count = 0usize;
    let mut unsupported_count = 0usize;
    let mut stale_count = 0usize;
    for lane in &lanes {
        match lane.classification {
            PerformanceRegressionClassification::Improved => improved_count += 1,
            PerformanceRegressionClassification::Unchanged => unchanged_count += 1,
            PerformanceRegressionClassification::Regressed => regressed_count += 1,
            PerformanceRegressionClassification::Inconclusive => inconclusive_count += 1,
            PerformanceRegressionClassification::MissingBaseline => missing_baseline_count += 1,
            PerformanceRegressionClassification::Unsupported => unsupported_count += 1,
            PerformanceRegressionClassification::Stale => stale_count += 1,
        }
    }
    let status = if malformed_count > 0 {
        "malformed"
    } else if regressed_count > 0 {
        "regressed"
    } else if missing_baseline_count > 0 {
        "missing-baseline"
    } else if stale_count > 0 {
        "stale"
    } else if unsupported_count > 0 {
        "unsupported"
    } else if inconclusive_count > 0 {
        "inconclusive"
    } else if lane_count > 0 && improved_count + unchanged_count == lane_count {
        "passed"
    } else if lane_count > 0 {
        "mixed"
    } else {
        "missing"
    };
    Ok(RunDashboardPerformanceRegressionLanes {
        present: true,
        empty_state: String::new(),
        status: status.to_string(),
        lane_count,
        improved_count,
        unchanged_count,
        regressed_count,
        inconclusive_count,
        missing_baseline_count,
        unsupported_count,
        stale_count,
        malformed_count,
        evidence_refs,
        lanes,
        artifacts,
        boundary,
    })
}

fn performance_regression_lane_evidence_refs(
    lane: &PerformanceRegressionLaneArtifact,
) -> Vec<String> {
    let mut refs = Vec::new();
    refs.extend(
        lane.baseline_runs
            .iter()
            .map(|reference| reference.path.clone()),
    );
    refs.extend(
        lane.comparison_runs
            .iter()
            .map(|reference| reference.path.clone()),
    );
    refs.extend(lane.stale_run_refs.clone());
    refs.extend(
        lane.evidence_links
            .run_comparison_refs
            .iter()
            .map(|reference| reference.path.clone()),
    );
    refs.extend(
        lane.evidence_links
            .frame_budget_refs
            .iter()
            .map(|reference| reference.path.clone()),
    );
    refs.extend(
        lane.evidence_links
            .scenario_matrix_refs
            .iter()
            .map(|reference| reference.path.clone()),
    );
    refs.extend(
        lane.evidence_links
            .qa_queue_refs
            .iter()
            .map(|reference| reference.path.clone()),
    );
    refs.extend(
        lane.evidence_links
            .review_gate_refs
            .iter()
            .map(|reference| reference.path.clone()),
    );
    refs.sort();
    refs.dedup();
    refs
}

fn read_dashboard_qa_worker_assignments(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardQaWorkerAssignments> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_qa_worker_assignment,
    )?;
    let boundary = "Read-only QA worker assignment evidence; dashboard/Studio surfaces must not spawn workers, execute commands, write trusted state, auto-fix, auto-apply, auto-merge, or claim quality guarantees.".to_string();
    if artifacts.is_empty() {
        return Ok(RunDashboardQaWorkerAssignments {
            present: false,
            empty_state: "No QA worker assignment evidence is indexed for this run.".to_string(),
            status: "missing".to_string(),
            assignment_count: 0,
            passed_count: 0,
            failed_count: 0,
            deferred_count: 0,
            blocked_count: 0,
            exhausted_count: 0,
            malformed_count: 0,
            evidence_refs: Vec::new(),
            plans: Vec::new(),
            artifacts,
            boundary,
        });
    }

    let mut evidence_refs = Vec::new();
    let mut plans = Vec::new();
    let mut malformed_count = 0usize;
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if artifact.read_error.is_some() {
            malformed_count += 1;
            continue;
        }
        let Some(value) = &artifact.value else {
            malformed_count += 1;
            continue;
        };
        match serde_json::from_value::<QaWorkerAssignmentArtifact>(value.clone()) {
            Ok(plan) if plan.validate().is_ok() => plans.push(plan),
            _ => malformed_count += 1,
        }
    }
    plans.sort_by(|left, right| {
        (left.run_id.as_str(), left.plan_id.as_str())
            .cmp(&(right.run_id.as_str(), right.plan_id.as_str()))
    });
    evidence_refs.sort();
    evidence_refs.dedup();
    let mut assignment_count = 0usize;
    let mut passed_count = 0usize;
    let mut failed_count = 0usize;
    let mut deferred_count = 0usize;
    let mut blocked_count = 0usize;
    let mut exhausted_count = 0usize;
    for plan in &plans {
        assignment_count += plan.assignments.len();
        for assignment in &plan.assignments {
            match assignment.status {
                QaWorkerAssignmentStatus::Passed => passed_count += 1,
                QaWorkerAssignmentStatus::Failed => failed_count += 1,
                QaWorkerAssignmentStatus::Deferred => deferred_count += 1,
                QaWorkerAssignmentStatus::Blocked => blocked_count += 1,
                QaWorkerAssignmentStatus::Exhausted => exhausted_count += 1,
                QaWorkerAssignmentStatus::Assigned => {}
            }
        }
    }
    let status = if malformed_count > 0 {
        "malformed"
    } else if blocked_count > 0 {
        "blocked"
    } else if exhausted_count > 0 {
        "exhausted"
    } else if failed_count > 0 {
        "failed"
    } else if deferred_count > 0 {
        "deferred"
    } else if assignment_count > 0 && passed_count == assignment_count {
        "passed"
    } else if assignment_count > 0 {
        "assigned"
    } else {
        "missing"
    };
    Ok(RunDashboardQaWorkerAssignments {
        present: true,
        empty_state: String::new(),
        status: status.to_string(),
        assignment_count,
        passed_count,
        failed_count,
        deferred_count,
        blocked_count,
        exhausted_count,
        malformed_count,
        evidence_refs,
        plans,
        artifacts,
        boundary,
    })
}

fn dashboard_artifact_is_runtime_invariant_evidence(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("runtime_invariant_evidence")
        || artifact.id.contains("runtime-invariant")
        || artifact.id.contains("invariant-evidence")
        || artifact.path.contains("runtime-invariant")
        || artifact.path.contains("invariant-evidence")
}

fn read_dashboard_runtime_invariants(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
    run: &serde_json::Value,
) -> Result<RunDashboardRuntimeInvariants> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_runtime_invariant_evidence,
    )?;
    let boundary = "Read-only runtime invariant evidence linked from Rust validation; dashboard/Studio surfaces must not mutate source, execute commands, launch workers, auto-fix, auto-apply, auto-merge, or claim gameplay quality guarantees.".to_string();
    if artifacts.is_empty() {
        return Ok(RunDashboardRuntimeInvariants {
            present: false,
            empty_state: "No runtime invariant evidence is indexed for this run.".to_string(),
            status: "missing".to_string(),
            check_count: 0,
            passed_count: 0,
            failed_count: 0,
            unsupported_count: 0,
            missing_count: 0,
            malformed_count: 0,
            stale_count: 0,
            evidence_refs: Vec::new(),
            summaries: Vec::new(),
            evidence: Vec::new(),
            artifacts,
            boundary,
        });
    }

    let current_run_id = json_string(run, "id").unwrap_or_else(|| run_id_from_run_dir(run_dir));
    let mut evidence_refs = Vec::new();
    let mut parsed_evidence = Vec::new();
    let mut summaries = Vec::new();
    let mut malformed_artifact_count = 0usize;
    let mut stale_artifact_count = 0usize;
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if artifact.read_error.is_some() {
            malformed_artifact_count += 1;
            continue;
        }
        let Some(value) = &artifact.value else {
            malformed_artifact_count += 1;
            continue;
        };
        match serde_json::from_value::<RuntimeInvariantEvidence>(value.clone()) {
            Ok(runtime_evidence) if runtime_evidence.validate().is_ok() => {
                let summary = runtime_evidence.summary();
                if runtime_evidence.run_id != current_run_id {
                    stale_artifact_count += 1;
                }
                summaries.push(summary);
                parsed_evidence.push(runtime_evidence);
            }
            _ => malformed_artifact_count += 1,
        }
    }
    summaries.sort_by(|left, right| {
        (
            left.run_id.as_str(),
            left.scenario_id.as_deref().unwrap_or_default(),
            left.model_id.as_str(),
        )
            .cmp(&(
                right.run_id.as_str(),
                right.scenario_id.as_deref().unwrap_or_default(),
                right.model_id.as_str(),
            ))
    });
    parsed_evidence.sort_by(|left, right| {
        (
            left.run_id.as_str(),
            left.scenario_id.as_deref().unwrap_or_default(),
            left.model_id.as_str(),
        )
            .cmp(&(
                right.run_id.as_str(),
                right.scenario_id.as_deref().unwrap_or_default(),
                right.model_id.as_str(),
            ))
    });
    evidence_refs.sort();
    evidence_refs.dedup();
    let check_count = summaries.iter().map(|summary| summary.check_count).sum();
    let passed_count = summaries.iter().map(|summary| summary.passed_count).sum();
    let failed_count = summaries.iter().map(|summary| summary.failed_count).sum();
    let unsupported_count = summaries
        .iter()
        .map(|summary| summary.unsupported_count)
        .sum();
    let missing_count = summaries.iter().map(|summary| summary.missing_count).sum();
    let malformed_count = summaries
        .iter()
        .map(|summary| summary.malformed_count)
        .sum::<usize>()
        + malformed_artifact_count;
    let stale_count = summaries
        .iter()
        .map(|summary| summary.stale_count)
        .sum::<usize>()
        + stale_artifact_count;
    let status = if malformed_count > 0 {
        "malformed"
    } else if stale_count > 0 {
        "stale"
    } else if failed_count > 0 {
        "failed"
    } else if unsupported_count > 0 || missing_count > 0 {
        "attention"
    } else if check_count > 0 {
        "passed"
    } else {
        "missing"
    };

    Ok(RunDashboardRuntimeInvariants {
        present: true,
        empty_state: String::new(),
        status: status.to_string(),
        check_count,
        passed_count,
        failed_count,
        unsupported_count,
        missing_count,
        malformed_count,
        stale_count,
        evidence_refs,
        summaries,
        evidence: parsed_evidence,
        artifacts,
        boundary,
    })
}

fn dashboard_artifact_is_source_apply_worktree_context(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("source_apply_worktree_context")
        || artifact.id.contains("source-apply-worktree-context")
        || artifact.path.contains("source-apply-worktree-context")
}

fn read_dashboard_source_apply_worktree_context(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardSourceApplyWorktreeContext> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_source_apply_worktree_context,
    )?;
    let boundary = "Read-only source apply worktree context evidence from Rust validation; browser/dashboard/Studio surfaces must not apply patches, execute commands, write trusted files, merge branches, or bypass review gates.".to_string();
    if artifacts.is_empty() {
        return Ok(RunDashboardSourceApplyWorktreeContext {
            present: false,
            empty_state: "No source apply worktree context evidence is indexed for this run."
                .to_string(),
            status: "missing".to_string(),
            target_count: 0,
            blocked_count: 0,
            evidence_refs: Vec::new(),
            reports: Vec::new(),
            artifacts,
            boundary,
        });
    }

    let mut evidence_refs = Vec::new();
    let mut reports = Vec::new();
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if let Some(value) = &artifact.value {
            if let Ok(report) =
                serde_json::from_value::<SourceApplyWorktreeContextReport>(value.clone())
            {
                reports.push(report);
            }
        }
    }
    reports.sort_by(|left, right| {
        (
            left.policy_id.as_str(),
            left.branch.as_str(),
            left.head_commit.as_str(),
        )
            .cmp(&(
                right.policy_id.as_str(),
                right.branch.as_str(),
                right.head_commit.as_str(),
            ))
    });
    evidence_refs.sort();
    evidence_refs.dedup();
    let target_count = reports.iter().map(|report| report.targets.len()).sum();
    let blocked_count = reports
        .iter()
        .map(|report| report.blocked_reasons.len())
        .sum();
    let status = if artifacts
        .iter()
        .any(|artifact| artifact.read_error.is_some())
    {
        "malformed"
    } else if reports
        .iter()
        .any(SourceApplyWorktreeContextReport::is_blocked)
    {
        "blocked"
    } else if reports.is_empty() {
        "malformed"
    } else {
        "passed"
    };
    Ok(RunDashboardSourceApplyWorktreeContext {
        present: true,
        empty_state: String::new(),
        status: status.to_string(),
        target_count,
        blocked_count,
        evidence_refs,
        reports,
        artifacts,
        boundary,
    })
}

fn dashboard_asset_inspector(
    integrity: &RunDashboardAssetIntegrity,
    loading: &RunDashboardAssetLoading,
    preview: &RunDashboardAssetPreview,
) -> RunDashboardAssetInspector {
    let present = integrity.present || loading.present || preview.present;
    let boundary = "Read-only Studio asset inspector data assembled from Rust-exported dashboard evidence; browser surfaces must not upload, write, fetch remote assets, edit manifests, or execute commands.".to_string();
    if !present {
        return RunDashboardAssetInspector {
            present: false,
            empty_state: "No asset inspector evidence is available for this run.".to_string(),
            status: "missing".to_string(),
            asset_count: 0,
            warning_count: 0,
            runtime_attempt_count: 0,
            loaded_count: 0,
            failed_count: 0,
            preview_count: 0,
            atlas_frame_count: 0,
            tilemap_count: 0,
            evidence_refs: Vec::new(),
            assets: Vec::new(),
            boundary,
        };
    }

    let mut assets: BTreeMap<String, RunDashboardAssetInspectorAsset> = BTreeMap::new();
    for record in &preview.records {
        let entry = assets.entry(record.asset_id.clone()).or_insert_with(|| {
            RunDashboardAssetInspectorAsset {
                asset_id: record.asset_id.clone(),
                asset_type: format!("{:?}", record.asset_type),
                source_path: Some(record.source_path.clone()),
                preview_kind: Some(format!("{:?}", record.preview_kind)),
                image: record.image.clone(),
                atlas_frame_count: record.atlas_frames.len(),
                tilemap: record.tilemap.clone(),
                runtime_statuses: Vec::new(),
                warnings: Vec::new(),
            }
        });
        entry.asset_type = format!("{:?}", record.asset_type);
        entry.source_path = Some(record.source_path.clone());
        entry.preview_kind = Some(format!("{:?}", record.preview_kind));
        entry.image = record.image.clone();
        entry.atlas_frame_count = record.atlas_frames.len();
        entry.tilemap = record.tilemap.clone();
        for warning in &record.warnings {
            entry
                .warnings
                .push(format!("{}: {}", warning.kind, warning.message));
        }
    }
    for warning in &preview.warnings {
        if let Some(asset_id) = &warning.asset_id {
            assets
                .entry(asset_id.clone())
                .or_insert_with(|| RunDashboardAssetInspectorAsset {
                    asset_id: asset_id.clone(),
                    asset_type: "unknown".to_string(),
                    source_path: warning.path.clone(),
                    preview_kind: None,
                    image: None,
                    atlas_frame_count: 0,
                    tilemap: None,
                    runtime_statuses: Vec::new(),
                    warnings: Vec::new(),
                })
                .warnings
                .push(format!("{}: {}", warning.kind, warning.message));
        }
    }
    for warning in &integrity.warnings {
        assets
            .entry(warning.asset_id.clone())
            .or_insert_with(|| RunDashboardAssetInspectorAsset {
                asset_id: warning.asset_id.clone(),
                asset_type: warning
                    .observed_type
                    .map(|asset_type| format!("{:?}", asset_type))
                    .unwrap_or_else(|| "unknown".to_string()),
                source_path: warning.path.clone(),
                preview_kind: None,
                image: None,
                atlas_frame_count: 0,
                tilemap: None,
                runtime_statuses: Vec::new(),
                warnings: Vec::new(),
            })
            .warnings
            .push(format!("{}: {}", warning.kind, warning.message));
    }
    for load in &loading.records {
        assets
            .entry(load.asset_id.clone())
            .or_insert_with(|| RunDashboardAssetInspectorAsset {
                asset_id: load.asset_id.clone(),
                asset_type: format!("{:?}", load.asset_type),
                source_path: load.path.clone(),
                preview_kind: None,
                image: load
                    .width
                    .zip(load.height)
                    .map(|(width, height)| AssetPreviewImageMetadata { width, height }),
                atlas_frame_count: 0,
                tilemap: None,
                runtime_statuses: Vec::new(),
                warnings: Vec::new(),
            })
            .runtime_statuses
            .push(format!("{:?}", load.status));
    }

    let mut evidence_refs = Vec::new();
    evidence_refs.extend(integrity.evidence_refs.clone());
    evidence_refs.extend(loading.evidence_refs.clone());
    evidence_refs.extend(preview.evidence_refs.clone());
    evidence_refs.sort();
    evidence_refs.dedup();
    let warning_count = integrity.warning_count + preview.warning_count;
    let status = if warning_count > 0 || loading.failed_count > 0 || loading.rejected_count > 0 {
        "warnings"
    } else {
        "ready"
    };
    let assets = assets.into_values().collect::<Vec<_>>();
    RunDashboardAssetInspector {
        present,
        empty_state: String::new(),
        status: status.to_string(),
        asset_count: assets.len(),
        warning_count,
        runtime_attempt_count: loading.attempt_count,
        loaded_count: loading.loaded_count,
        failed_count: loading.failed_count,
        preview_count: preview.preview_count,
        atlas_frame_count: preview.atlas_frame_count,
        tilemap_count: preview.tilemap_count,
        evidence_refs,
        assets,
        boundary,
    }
}

fn read_dashboard_asset_preview(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardAssetPreview> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_asset_preview_evidence,
    )?;
    let boundary = "Read-only asset preview evidence from Rust-exported artifacts; browser surfaces display escaped local metadata only and never fetch remote assets, upload files, write trusted state, or execute commands.".to_string();
    if artifacts.is_empty() {
        return Ok(RunDashboardAssetPreview {
            present: false,
            empty_state: "No asset preview evidence is indexed for this run.".to_string(),
            preview_count: 0,
            warning_count: 0,
            image_count: 0,
            atlas_frame_count: 0,
            tilemap_count: 0,
            audio_count: 0,
            font_count: 0,
            evidence_refs: Vec::new(),
            records: Vec::new(),
            warnings: Vec::new(),
            artifacts,
            boundary,
        });
    }

    let mut evidence_refs = Vec::new();
    let mut records = Vec::new();
    let mut warnings = Vec::new();
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if let Some(value) = &artifact.value {
            if let Ok(evidence) = serde_json::from_value::<AssetPreviewEvidence>(value.clone()) {
                records.extend(evidence.previews);
                warnings.extend(evidence.warnings);
            }
        }
    }
    records.sort_by(|left, right| left.asset_id.cmp(&right.asset_id));
    warnings.sort_by(|left, right| {
        (
            left.asset_id.as_deref(),
            left.kind.as_str(),
            left.message.as_str(),
        )
            .cmp(&(
                right.asset_id.as_deref(),
                right.kind.as_str(),
                right.message.as_str(),
            ))
    });
    evidence_refs.sort();
    evidence_refs.dedup();
    let image_count = records
        .iter()
        .filter(|record| record.image.is_some())
        .count();
    let atlas_frame_count = records.iter().map(|record| record.atlas_frames.len()).sum();
    let tilemap_count = records
        .iter()
        .filter(|record| record.tilemap.is_some())
        .count();
    let audio_count = records
        .iter()
        .filter(|record| record.audio.is_some())
        .count();
    let font_count = records
        .iter()
        .filter(|record| record.font.is_some())
        .count();
    Ok(RunDashboardAssetPreview {
        present: true,
        empty_state: String::new(),
        preview_count: records.len(),
        warning_count: warnings.len(),
        image_count,
        atlas_frame_count,
        tilemap_count,
        audio_count,
        font_count,
        evidence_refs,
        records,
        warnings,
        artifacts,
        boundary,
    })
}

fn read_dashboard_asset_loading(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardAssetLoading> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_runtime_asset_load_evidence,
    )?;
    let boundary = "Read-only runtime loading evidence from Rust-exported artifacts; browser surfaces display escaped local evidence only and never fetch remote assets, upload files, write trusted state, or execute commands.".to_string();
    if artifacts.is_empty() {
        return Ok(RunDashboardAssetLoading {
            present: false,
            empty_state: "No runtime asset loading evidence is indexed for this run.".to_string(),
            attempt_count: 0,
            loaded_count: 0,
            failed_count: 0,
            rejected_count: 0,
            fallback_count: 0,
            evidence_refs: Vec::new(),
            records: Vec::new(),
            artifacts,
            boundary,
        });
    }

    let mut evidence_refs = Vec::new();
    let mut records = Vec::new();
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if let Some(value) = &artifact.value {
            if let Ok(evidence) = serde_json::from_value::<RuntimeAssetLoadEvidence>(value.clone())
            {
                records.extend(evidence.loads);
            }
        }
    }
    records.sort_by(|left, right| {
        (
            left.asset_id.as_str(),
            left.attempt_id.as_str(),
            left.started_at_unix_ms,
        )
            .cmp(&(
                right.asset_id.as_str(),
                right.attempt_id.as_str(),
                right.started_at_unix_ms,
            ))
    });
    evidence_refs.sort();
    evidence_refs.dedup();
    let loaded_count = records
        .iter()
        .filter(|record| record.status == RuntimeAssetLoadStatus::Loaded)
        .count();
    let failed_count = records
        .iter()
        .filter(|record| record.status == RuntimeAssetLoadStatus::Failed)
        .count();
    let rejected_count = records
        .iter()
        .filter(|record| record.status == RuntimeAssetLoadStatus::Rejected)
        .count();
    let fallback_count = records
        .iter()
        .filter(|record| record.status == RuntimeAssetLoadStatus::Fallback)
        .count();
    Ok(RunDashboardAssetLoading {
        present: true,
        empty_state: String::new(),
        attempt_count: records.len(),
        loaded_count,
        failed_count,
        rejected_count,
        fallback_count,
        evidence_refs,
        records,
        artifacts,
        boundary,
    })
}

fn read_dashboard_asset_integrity(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardAssetIntegrity> {
    let artifacts = select_dashboard_artifacts(
        run_dir,
        evidence,
        dashboard_artifact_is_asset_reference_integrity,
    )?;
    if artifacts.is_empty() {
        return Ok(RunDashboardAssetIntegrity {
            present: false,
            empty_state: "No asset reference integrity evidence is indexed for this run."
                .to_string(),
            warning_count: 0,
            stale_hash_count: 0,
            missing_ref_count: 0,
            invalid_type_count: 0,
            evidence_refs: Vec::new(),
            warnings: Vec::new(),
            artifacts,
        });
    }

    let mut warnings = Vec::new();
    let mut evidence_refs = Vec::new();
    for artifact in &artifacts {
        evidence_refs.push(artifact.path.clone());
        if let Some(value) = &artifact.value {
            if let Some(items) = value.get("warnings").and_then(|value| value.as_array()) {
                for item in items {
                    if let Ok(warning) = serde_json::from_value::<
                        ProjectAssetReferenceIntegrityWarning,
                    >(item.clone())
                    {
                        warnings.push(warning);
                    }
                }
            }
        }
    }
    warnings.sort_by(|left, right| {
        (
            left.kind.as_str(),
            left.field.as_str(),
            left.asset_id.as_str(),
        )
            .cmp(&(
                right.kind.as_str(),
                right.field.as_str(),
                right.asset_id.as_str(),
            ))
    });
    warnings.dedup_by(|left, right| {
        left.kind == right.kind && left.field == right.field && left.asset_id == right.asset_id
    });
    evidence_refs.sort();
    evidence_refs.dedup();
    let warning_count = warnings.len();
    let stale_hash_count = warnings
        .iter()
        .filter(|warning| warning.kind == "stale_asset_hash")
        .count();
    let missing_ref_count = warnings
        .iter()
        .filter(|warning| {
            matches!(
                warning.kind.as_str(),
                "missing_asset_ref" | "missing_asset_file"
            )
        })
        .count();
    let invalid_type_count = warnings
        .iter()
        .filter(|warning| warning.kind == "invalid_asset_type")
        .count();
    Ok(RunDashboardAssetIntegrity {
        present: true,
        empty_state: String::new(),
        warning_count,
        stale_hash_count,
        missing_ref_count,
        invalid_type_count,
        evidence_refs,
        warnings,
        artifacts,
    })
}

fn dashboard_artifact_is_frame_metric(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("probe_call")
        .and_then(|value| value.as_str())
        == Some("getFrameStats")
        || artifact.id.contains("frame-stats")
        || artifact.path.contains("frame-stats")
}

fn dashboard_artifact_is_performance_metric(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("performance_metrics")
        || artifact.id.contains("performance")
        || artifact.path.contains("metrics")
}

fn dashboard_artifact_is_scenario_result(artifact: &EvidenceArtifact) -> bool {
    artifact
        .metadata
        .get("artifact")
        .and_then(|value| value.as_str())
        == Some("scenario_result")
        || artifact.id.contains("scenario-result")
        || artifact.path.contains("scenario-result")
}

fn dashboard_artifact_is_input_replay(artifact: &EvidenceArtifact) -> bool {
    matches!(
        artifact
            .metadata
            .get("artifact")
            .and_then(|value| value.as_str()),
        Some("input_replay") | Some("scenario_input_replay")
    ) || artifact.id.contains("input-replay")
        || artifact.path.contains("input-replay")
        || artifact.id.contains("scenario-input-replay")
        || artifact.path.contains("scenario-input-replay")
}

fn read_dashboard_replay(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
) -> Result<RunDashboardReplay> {
    let replay_artifacts =
        select_dashboard_artifacts(run_dir, evidence, dashboard_artifact_is_input_replay)?;
    if replay_artifacts.is_empty() {
        return Ok(RunDashboardReplay {
            present: false,
            empty_state: "No replay evidence artifacts were found for this run.".to_string(),
            sequences: Vec::new(),
        });
    }
    let scenario_results =
        select_dashboard_artifacts(run_dir, evidence, dashboard_artifact_is_scenario_result)?;
    let mut sequences = Vec::new();
    for artifact in replay_artifacts {
        let scenario_id = dashboard_artifact_scenario_id(&artifact);
        let replay_value = artifact
            .value
            .as_ref()
            .and_then(dashboard_replay_payload_value);
        let frames = replay_value.map_or_else(Vec::new, dashboard_replay_frames);
        let replay_id = replay_value
            .and_then(|value| json_string(value, "id"))
            .unwrap_or_else(|| artifact.id.clone());
        let event_count = replay_value
            .and_then(|value| value.get("events"))
            .and_then(|value| value.as_array())
            .map_or_else(
                || {
                    usize::from(
                        replay_value
                            .and_then(|value| value.get("schemaVersion"))
                            .and_then(|value| value.as_str())
                            == Some(SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION),
                    )
                },
                Vec::len,
            );
        let source = dashboard_replay_source(&artifact);
        let evidence_refs = std::iter::once(artifact.path.clone())
            .chain(
                scenario_results
                    .iter()
                    .filter(|result| {
                        dashboard_artifact_matches_scenario(result, scenario_id.as_deref())
                    })
                    .map(|result| result.path.clone()),
            )
            .collect::<Vec<_>>();
        sequences.push(RunDashboardReplaySequence {
            id: replay_id,
            source,
            scenario_id: scenario_id.clone(),
            replay_path: artifact.path.clone(),
            event_count,
            first_frame: frames.first().copied(),
            last_frame: frames.last().copied(),
            frames,
            evidence_refs,
            checkpoints: dashboard_replay_checkpoints(
                run_dir,
                scenario_id.as_deref(),
                &scenario_results,
            ),
            read_error: artifact.read_error.clone(),
        });
    }
    Ok(RunDashboardReplay {
        present: sequences
            .iter()
            .any(|sequence| sequence.read_error.is_none()),
        empty_state: if sequences
            .iter()
            .any(|sequence| sequence.read_error.is_none())
        {
            String::new()
        } else {
            "Replay evidence artifacts were indexed, but no readable replay files are available."
                .to_string()
        },
        sequences,
    })
}

fn dashboard_replay_payload_value(value: &serde_json::Value) -> Option<&serde_json::Value> {
    value.get("replay").unwrap_or(value).as_object()?;
    Some(value.get("replay").unwrap_or(value))
}

fn dashboard_replay_frames(replay: &serde_json::Value) -> Vec<u64> {
    let mut frames = replay
        .get("events")
        .and_then(|value| value.as_array())
        .map(|events| {
            events
                .iter()
                .filter_map(|event| event.get("frame").and_then(|value| value.as_u64()))
                .collect::<Vec<_>>()
        })
        .unwrap_or_else(|| {
            replay
                .get("frame")
                .and_then(|value| value.as_u64())
                .into_iter()
                .collect()
        });
    frames.sort_unstable();
    frames.dedup();
    frames
}

fn dashboard_replay_source(artifact: &RunDashboardArtifact) -> String {
    artifact
        .metadata
        .get("source")
        .and_then(|value| value.as_str())
        .map(str::to_string)
        .or_else(|| {
            artifact
                .value
                .as_ref()
                .and_then(|value| value.get("action"))
                .and_then(|value| value.get("kind"))
                .and_then(|value| value.as_str())
                .map(str::to_string)
        })
        .or_else(|| {
            artifact
                .value
                .as_ref()
                .and_then(|value| value.get("reference"))
                .map(|_| "replayRef".to_string())
        })
        .unwrap_or_else(|| "inline".to_string())
}

fn dashboard_artifact_scenario_id(artifact: &RunDashboardArtifact) -> Option<String> {
    artifact
        .metadata
        .get("scenario_id")
        .and_then(|value| value.as_str())
        .map(str::to_string)
        .or_else(|| dashboard_scenario_id_from_path(&artifact.path))
}

fn dashboard_scenario_id_from_path(path: &str) -> Option<String> {
    let mut parts = path.split('/');
    while let Some(part) = parts.next() {
        if part == "scenarios" {
            return parts.next().map(str::to_string);
        }
    }
    None
}

fn dashboard_artifact_matches_scenario(
    artifact: &RunDashboardArtifact,
    scenario_id: Option<&str>,
) -> bool {
    match scenario_id {
        Some(expected) => dashboard_artifact_scenario_id(artifact).as_deref() == Some(expected),
        None => true,
    }
}

fn dashboard_replay_checkpoints(
    run_dir: &Path,
    scenario_id: Option<&str>,
    scenario_results: &[RunDashboardArtifact],
) -> Vec<RunDashboardReplayCheckpoint> {
    scenario_results
        .iter()
        .filter(|result| dashboard_artifact_matches_scenario(result, scenario_id))
        .filter_map(|result| {
            let value = result.value.as_ref()?;
            let evidence = value.get("evidence")?;
            let world_state_path = evidence
                .get("world_state")
                .and_then(|value| value.as_str())
                .map(str::to_string);
            let frame_stats_path = evidence
                .get("frame_stats")
                .and_then(|value| value.as_str())
                .map(str::to_string);
            // These refs come from scenario-result JSON, which may be external or
            // malformed; unlike evidence-index paths they are otherwise unchecked.
            // Constrain them to the run's evidence tree before reading so a value
            // like "../../secret.json" cannot disclose arbitrary files.
            let world_state = world_state_path
                .as_ref()
                .filter(|path| validate_evidence_artifact_path(path.as_str()).is_ok())
                .and_then(|path| read_json_value(run_dir.join(path)).ok());
            let frame_stats = frame_stats_path
                .as_ref()
                .filter(|path| validate_evidence_artifact_path(path.as_str()).is_ok())
                .and_then(|path| read_json_value(run_dir.join(path)).ok());
            let tick = world_state
                .as_ref()
                .and_then(|value| value.get("tick"))
                .and_then(|value| value.as_u64())
                .or_else(|| {
                    frame_stats
                        .as_ref()
                        .and_then(|value| value.get("tick"))
                        .and_then(|value| value.as_u64())
                });
            let frame = frame_stats
                .as_ref()
                .and_then(|value| value.get("frame"))
                .and_then(|value| value.as_u64())
                .or(tick);
            let checkpoint_id = format!(
                "{}-checkpoint",
                json_string(value, "scenario_id")
                    .or_else(|| dashboard_artifact_scenario_id(result))
                    .unwrap_or_else(|| result.id.clone())
            );
            Some(RunDashboardReplayCheckpoint {
                id: checkpoint_id,
                label: "Post-replay world state".to_string(),
                frame,
                tick,
                world_state_path,
                frame_stats_path,
                world_state,
            })
        })
        .collect()
}

fn dashboard_array_len(value: Option<&serde_json::Value>) -> usize {
    value
        .and_then(|candidate| candidate.as_array())
        .map_or(0, Vec::len)
}

fn dashboard_entities_with_component(world_state: &serde_json::Value, component: &str) -> usize {
    world_state
        .get("entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter(|entity| {
                    entity
                        .get("components")
                        .and_then(|components| components.get(component))
                        .is_some()
                })
                .count()
        })
        .unwrap_or(0)
}

fn dashboard_component_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let mut counts = BTreeMap::<String, usize>::new();
    let mut entities = Vec::new();
    if let Some(items) = world_state
        .get("entities")
        .and_then(|value| value.as_array())
    {
        for entity in items {
            let entity_id = entity
                .get("id")
                .and_then(|value| value.as_str())
                .unwrap_or("unknown");
            let components = entity
                .get("components")
                .and_then(|value| value.as_object())
                .map(|components| {
                    let mut names = components.keys().cloned().collect::<Vec<_>>();
                    names.sort();
                    for name in &names {
                        *counts.entry(name.clone()).or_default() += 1;
                    }
                    names
                })
                .unwrap_or_default();
            entities.push(json!({ "entityId": entity_id, "components": components }));
        }
    }
    if let Some(model_counts) = world_state
        .pointer("/componentModel/counts")
        .and_then(|value| value.as_object())
    {
        for (name, count) in model_counts {
            if let Some(count) = count.as_u64() {
                counts.insert(name.clone(), count as usize);
            }
        }
    }
    json!({
        "present": !counts.is_empty() || !entities.is_empty(),
        "entityCount": entities.len(),
        "componentCounts": counts,
        "entities": entities
    })
}

fn dashboard_trigger_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let triggers = world_state
        .get("entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter_map(|entity| {
                    let trigger = entity.pointer("/components/trigger")?;
                    Some(json!({
                        "entityId": entity.get("id").cloned().unwrap_or(json!(null)),
                        "id": trigger.get("id").cloned().unwrap_or(json!(null)),
                        "kind": trigger.get("kind").cloned().unwrap_or(json!(null)),
                        "targetFlag": trigger.get("targetFlag").cloned().unwrap_or(json!(null)),
                        "requiredFlags": trigger.get("requiredFlags").cloned().unwrap_or(json!([])),
                        "onEnterCount": dashboard_array_len(trigger.get("onEnter")),
                    }))
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    json!({
        "present": !triggers.is_empty(),
        "triggerCount": triggers.len(),
        "triggerCollisionEventCount": world_state
            .get("collisionEvents")
            .and_then(|events| events.as_array())
            .map(|events| {
                events
                    .iter()
                    .filter(|event| {
                        event.get("type").and_then(|value| value.as_str())
                            == Some("runtime.collision.trigger")
                    })
                    .count()
            })
            .unwrap_or(0),
        "triggers": triggers
    })
}

fn dashboard_hud_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let values = world_state
        .pointer("/componentModel/hudValues")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    json!({
        "present": !values.is_empty() || dashboard_entities_with_component(world_state, "hudValue") > 0,
        "hudValueCount": values.len(),
        "hudValueEntityCount": world_state.pointer("/componentModel/counts/hudValue")
            .cloned()
            .unwrap_or_else(|| json!(dashboard_entities_with_component(world_state, "hudValue"))),
        "values": values
    })
}

fn dashboard_tilemap_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let tilemaps = world_state
        .pointer("/tilemaps/tilemaps")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let mut collision_cells = 0usize;
    let mut trigger_cells = 0usize;
    let mut hazard_cells = 0usize;
    let mut goal_cells = 0usize;
    let mut summaries = Vec::new();
    for tilemap in &tilemaps {
        let authoring = tilemap.get("authoring").cloned().unwrap_or(json!({}));
        let tilemap_collision_cells = dashboard_array_len(authoring.get("collisionCells"));
        let tilemap_trigger_cells = dashboard_array_len(authoring.get("triggerCells"));
        let tilemap_hazard_cells = dashboard_array_len(authoring.get("hazardCells"));
        let tilemap_goal_cells = dashboard_array_len(authoring.get("goalCells"));
        collision_cells += tilemap_collision_cells;
        trigger_cells += tilemap_trigger_cells;
        hazard_cells += tilemap_hazard_cells;
        goal_cells += tilemap_goal_cells;
        summaries.push(json!({
            "id": tilemap.get("id").cloned().unwrap_or(json!(null)),
            "grid": tilemap.get("grid").cloned().unwrap_or(json!({})),
            "tileCount": tilemap.get("tileCount").cloned().unwrap_or(json!(0)),
            "layerCount": dashboard_array_len(tilemap.get("layers")),
            "authoring": {
                "collisionCellCount": tilemap_collision_cells,
                "triggerCellCount": tilemap_trigger_cells,
                "hazardCellCount": tilemap_hazard_cells,
                "goalCellCount": tilemap_goal_cells,
                "collisionCells": authoring.get("collisionCells").cloned().unwrap_or(json!([])),
                "triggerCells": authoring.get("triggerCells").cloned().unwrap_or(json!([])),
                "hazardCells": authoring.get("hazardCells").cloned().unwrap_or(json!([])),
                "goalCells": authoring.get("goalCells").cloned().unwrap_or(json!([]))
            }
        }));
    }
    json!({
        "present": world_state.get("tilemaps").is_some(),
        "tilemapCount": tilemaps.len(),
        "layerCount": dashboard_array_len(world_state.pointer("/tilemaps/layerOrder")),
        "authoring": {
            "present": collision_cells > 0 || trigger_cells > 0 || hazard_cells > 0 || goal_cells > 0,
            "collisionCellCount": collision_cells,
            "triggerCellCount": trigger_cells,
            "hazardCellCount": hazard_cells,
            "goalCellCount": goal_cells
        },
        "tilemaps": summaries
    })
}

fn dashboard_collision_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let rules_present = world_state.get("collisionRules").is_some();
    json!({
        "present": rules_present
            || world_state.get("collisions").is_some()
            || world_state.get("collisionEvents").is_some()
            || dashboard_entities_with_component(world_state, "collider") > 0,
        "rules": world_state.get("collisionRules").cloned().unwrap_or(json!({})),
        "colliderEntityCount": dashboard_entities_with_component(world_state, "collider"),
        "collisionCount": dashboard_array_len(world_state.get("collisions")),
        "collisionEventCount": dashboard_array_len(world_state.get("collisionEvents")),
        "events": world_state.get("collisionEvents").cloned().unwrap_or(json!([]))
    })
}

fn dashboard_runtime_state_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let runtime_state = world_state
        .get("runtimeState")
        .filter(|value| value.is_object());
    let runtime_events = world_state
        .get("runtimeEvents")
        .or_else(|| world_state.get("events"))
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let save_events = runtime_events
        .iter()
        .filter(|event| {
            event
                .get("type")
                .and_then(|value| value.as_str())
                .is_some_and(|kind| kind == "runtime.save.created" || kind == "runtime.save.loaded")
        })
        .cloned()
        .collect::<Vec<_>>();
    let replay_events = runtime_events
        .iter()
        .filter(|event| {
            event.get("type").and_then(|value| value.as_str())
                == Some("runtime.replay.digest_compared")
        })
        .cloned()
        .collect::<Vec<_>>();
    let save_created_count = save_events
        .iter()
        .filter(|event| {
            event.get("type").and_then(|value| value.as_str()) == Some("runtime.save.created")
        })
        .count();
    let save_loaded_count = save_events
        .iter()
        .filter(|event| {
            event.get("type").and_then(|value| value.as_str()) == Some("runtime.save.loaded")
        })
        .count();
    let snapshots = world_state
        .get("snapshots")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let present = runtime_state.is_some()
        || !save_events.is_empty()
        || !replay_events.is_empty()
        || !snapshots.is_empty();
    let latest_save = save_events.last().cloned().unwrap_or(json!(null));
    let latest_replay = replay_events.last().cloned().unwrap_or(json!(null));
    json!({
        "present": present,
        "emptyState": if present { "" } else { "No runtime save/load/replay state read model is available." },
        "stateId": runtime_state.and_then(|value| value.get("stateId")).cloned().unwrap_or(json!(null)),
        "sceneId": runtime_state.and_then(|value| value.get("sceneId")).cloned().unwrap_or_else(|| world_state.get("sceneId").cloned().unwrap_or(json!(null))),
        "tick": runtime_state.and_then(|value| value.get("tick")).cloned().unwrap_or_else(|| world_state.get("tick").cloned().unwrap_or(json!(null))),
        "digest": runtime_state.and_then(|value| value.get("digest")).cloned().unwrap_or(json!(null)),
        "authority": runtime_state
            .and_then(|value| value.get("authority"))
            .cloned()
            .unwrap_or(json!("browser_runtime_evidence_input_not_trusted_persistence")),
        "snapshotCount": snapshots.len(),
        "saveEventCount": save_events.len(),
        "saveCreatedCount": save_created_count,
        "saveLoadedCount": save_loaded_count,
        "replayDigestComparedCount": replay_events.len(),
        "latestSaveEvent": latest_save,
        "latestReplayDigestComparison": latest_replay,
        "saveEvents": save_events,
        "replayEvents": replay_events,
        "snapshots": snapshots,
        "readOnlyInspection": runtime_state
            .and_then(|value| value.get("readOnlyInspection").or_else(|| value.get("read_only_inspection")))
            .cloned()
            .unwrap_or_else(|| json!({
                "trustedEmitter": "browser-runtime-world-state",
                "browserStudioMode": "read-only runtime state evidence inspection",
                "disallowedActions": ["trusted writes", "command bridge", "live mutation"]
            }))
    })
}

fn dashboard_input_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let action_state = world_state.get("actionState").cloned().unwrap_or(json!({}));
    let raw_input = world_state.get("rawInput").cloned().unwrap_or(json!({}));
    let action_input = world_state.get("actionInput").cloned().unwrap_or(json!({}));
    let diagnostics = world_state
        .get("inputDiagnostics")
        .cloned()
        .unwrap_or(json!({ "present": false, "warningCount": 0 }));
    let active_actions = action_state
        .as_object()
        .map(|actions| {
            actions
                .iter()
                .filter(|(_, value)| value.as_bool() == Some(true))
                .map(|(action, _)| json!(action))
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let mapped_action_count = world_state
        .pointer("/componentModel/entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter_map(|entity| entity.pointer("/components/input/actionMap/actions"))
                .filter_map(|actions| actions.as_array())
                .map(Vec::len)
                .sum::<usize>()
        })
        .unwrap_or(0);
    let active_action_count = active_actions.len();
    json!({
        "present": world_state.get("actionState").is_some() || world_state.get("inputDiagnostics").is_some(),
        "rawInput": raw_input,
        "actionState": action_state,
        "actionInput": action_input,
        "activeActions": active_actions,
        "activeActionCount": active_action_count,
        "mappedActionCount": mapped_action_count,
        "diagnostics": diagnostics,
        "warningCount": world_state
            .pointer("/inputDiagnostics/warningCount")
            .and_then(|value| value.as_u64())
            .unwrap_or(0)
    })
}

fn dashboard_transition_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let transition_events = world_state
        .get("transitionEvents")
        .cloned()
        .unwrap_or(json!([]));
    let declared_transitions = world_state
        .get("sceneTransitions")
        .cloned()
        .unwrap_or(json!([]));
    json!({
        "present": world_state.get("sceneId").is_some()
            || world_state.get("reloads").is_some()
            || transition_events.as_array().is_some_and(|events| !events.is_empty())
            || declared_transitions.as_array().is_some_and(|transitions| !transitions.is_empty()),
        "currentSceneId": world_state.get("sceneId").cloned().unwrap_or(json!(null)),
        "declaredTransitionCount": declared_transitions.as_array().map_or(0, Vec::len),
        "declaredTransitions": declared_transitions,
        "transitionEventCount": transition_events.as_array().map_or(0, Vec::len),
        "transitions": transition_events,
        "reloadCount": dashboard_array_len(world_state.get("reloads")),
        "lastReloadStatus": world_state.get("reloads")
            .and_then(|reloads| reloads.as_array())
            .and_then(|reloads| reloads.last())
            .and_then(|reload| reload.get("status"))
            .cloned()
            .unwrap_or(json!(null))
    })
}

fn dashboard_runtime_event_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let audio_events = world_state.get("audioEvents").cloned().unwrap_or(json!([]));
    let audio_warnings = world_state
        .get("audioWarnings")
        .cloned()
        .unwrap_or(json!([]));
    let collision_events = world_state
        .get("collisionEvents")
        .cloned()
        .unwrap_or(json!([]));
    let vfx_events = world_state.get("vfxEvents").cloned().unwrap_or(json!([]));
    let animation_entities = world_state
        .get("entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter_map(|entity| {
                    let animation = entity.pointer("/components/animation")?;
                    Some(json!({
                        "entityId": entity.get("id").cloned().unwrap_or(json!(null)),
                        "mode": animation.get("mode").cloned().unwrap_or(json!(null)),
                        "currentClip": animation
                            .get("currentClip")
                            .cloned()
                            .or_else(|| animation.pointer("/state/currentClip").cloned())
                            .unwrap_or(json!(null)),
                        "activeState": animation
                            .get("activeState")
                            .cloned()
                            .or_else(|| animation.pointer("/state/activeState").cloned())
                            .unwrap_or(json!(null)),
                        "frameIndex": animation.pointer("/state/frameIndex").cloned().unwrap_or(json!(null)),
                    }))
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    json!({
        "present": !animation_entities.is_empty()
            || audio_events.as_array().is_some_and(|events| !events.is_empty())
            || collision_events.as_array().is_some_and(|events| !events.is_empty())
            || vfx_events.as_array().is_some_and(|events| !events.is_empty()),
        "animationEntityCount": animation_entities.len(),
        "audioEventCount": audio_events.as_array().map_or(0, Vec::len),
        "audioWarningCount": audio_warnings.as_array().map_or(0, Vec::len),
        "collisionEventCount": collision_events.as_array().map_or(0, Vec::len),
        "vfxEventCount": vfx_events.as_array().map_or(0, Vec::len),
        "animationEntities": animation_entities,
        "audioEvents": audio_events,
        "audioWarnings": audio_warnings,
        "collisionEvents": collision_events,
        "vfxEvents": vfx_events
    })
}

fn dashboard_vfx_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let vfx_events = world_state.get("vfxEvents").cloned().unwrap_or(json!([]));
    let emitters = world_state
        .get("entities")
        .and_then(|entities| entities.as_array())
        .map(|entities| {
            entities
                .iter()
                .filter_map(|entity| {
                    let vfx = entity.pointer("/components/vfx")?;
                    let emitters = vfx
                        .get("emitters")
                        .and_then(|emitters| emitters.as_array())
                        .cloned()
                        .unwrap_or_default();
                    Some(json!({
                        "entityId": entity.get("id").cloned().unwrap_or(json!(null)),
                        "emitterCount": emitters.len(),
                        "emitters": emitters
                    }))
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    json!({
        "present": !emitters.is_empty()
            || vfx_events.as_array().is_some_and(|events| !events.is_empty()),
        "vfxEntityCount": emitters.len(),
        "vfxEmitterCount": emitters
            .iter()
            .map(|entry| entry.get("emitterCount").and_then(|count| count.as_u64()).unwrap_or(0))
            .sum::<u64>(),
        "vfxEventCount": vfx_events.as_array().map_or(0, Vec::len),
        "entities": emitters,
        "events": vfx_events,
        "readOnlyInspection": {
            "trustedEmitter": "browser-runtime-evidence-helper",
            "browserStudioMode": "read-only evidence inspection",
            "disallowedActions": ["trusted writes", "command bridge", "scene mutation", "browser runtime control"]
        }
    })
}

