fn read_dashboard_engine_summaries(
    world_states: &[RunDashboardArtifact],
) -> RunDashboardEngineSummaries {
    let source = world_states.iter().find(|artifact| {
        artifact.exists && artifact.read_error.is_none() && artifact.value.is_some()
    });
    let Some(artifact) = source else {
        return RunDashboardEngineSummaries {
            present: false,
            empty_state:
                "No readable world-state artifacts are available for Engine Expansion summaries."
                    .to_string(),
            source_world_state: None,
            scene: json!({}),
            components: json!({}),
            renderer: json!({}),
            camera: json!({ "present": false, "emptyState": "No camera/layer read model is available." }),
            render_breakdown: json!({ "present": false, "emptyState": "No scene render breakdown evidence is available." }),
            render_queue: json!({ "present": false, "emptyState": "No scene render queue evidence is available." }),
            scene3d_hierarchy: json!({ "present": false, "emptyState": "No 3D hierarchy evidence is available." }),
            scene3d_camera: json!({ "present": false, "emptyState": "No 3D camera evidence is available." }),
            scene3d_animation: json!({ "present": false, "emptyState": "No 3D animation evidence is available." }),
            scene3d_probe: json!({ "present": false, "emptyState": "No 3D runtime probe evidence is available." }),
            scene3d_render: json!({ "present": false, "emptyState": "No 3D render smoke evidence is available." }),
            scene3d_collision: json!({ "present": false, "emptyState": "No 3D collision evidence is available." }),
            scene3d_scenario_verdicts: json!({ "present": false, "emptyState": "No 3D scenario verdict evidence is available." }),
            tilemaps: json!({}),
            assets: json!({}),
            animation: json!({}),
            vfx: json!({ "present": false, "emptyState": "No VFX read model is available." }),
            audio: json!({}),
            physics: json!({}),
            input: json!({ "present": false, "emptyState": "No input action read model is available." }),
            runtime_state: json!({ "present": false, "emptyState": "No runtime save/load/replay state read model is available." }),
            collision: json!({}),
            gameplay: json!({}),
            triggers: json!({}),
            hud: json!({}),
            transition: json!({}),
            events: json!({}),
            reload: json!({}),
            composition: json!({}),
        };
    };
    let world_state = artifact.value.as_ref().expect("checked world-state value");
    let entities = dashboard_array_len(world_state.get("entities"));
    RunDashboardEngineSummaries {
        present: true,
        empty_state: String::new(),
        source_world_state: Some(artifact.path.clone()),
        scene: json!({
            "sceneId": world_state.get("sceneId").cloned().unwrap_or(json!(null)),
            "schemaVersion": world_state.get("schemaVersion").cloned().unwrap_or(json!(null)),
            "entityCount": entities,
            "tick": world_state.get("tick").cloned().unwrap_or(json!(null))
        }),
        components: dashboard_component_summary(world_state),
        renderer: json!({
            "present": world_state.get("renderer").is_some(),
            "version": world_state.pointer("/renderer/version").cloned().unwrap_or(json!(null)),
            "renderedEntities": dashboard_array_len(world_state.pointer("/renderer/renderedEntities")),
            "camera": world_state.pointer("/renderer/camera").cloned().unwrap_or(json!(null)),
            "viewport": world_state.pointer("/renderer/viewport").cloned().unwrap_or(json!(null)),
            "layers": world_state.pointer("/renderer/layers").cloned().unwrap_or(json!([]))
        }),
        camera: dashboard_camera_summary(world_state),
        render_breakdown: dashboard_render_breakdown_summary(world_state),
        render_queue: dashboard_render_queue_summary(world_state),
        scene3d_hierarchy: dashboard_scene3d_hierarchy_summary(world_state),
        scene3d_camera: dashboard_scene3d_camera_summary(world_state),
        scene3d_animation: dashboard_scene3d_animation_summary(world_state),
        scene3d_probe: dashboard_scene3d_probe_summary(world_state),
        scene3d_render: dashboard_scene3d_render_summary(world_state),
        scene3d_collision: dashboard_scene3d_collision_summary(world_state),
        scene3d_scenario_verdicts: dashboard_scene3d_scenario_verdicts_summary(world_state),
        tilemaps: dashboard_tilemap_summary(world_state),
        assets: json!({
            "manifestId": world_state.pointer("/assetManifest/id").cloned().unwrap_or(json!(null)),
            "assetCount": dashboard_array_len(world_state.get("assets")),
            "manifestAssetCount": world_state.pointer("/assetManifest/assetCount").cloned().unwrap_or(json!(null))
        }),
        animation: json!({
            "animatedEntityCount": dashboard_entities_with_component(world_state, "animation"),
            "activeStateCount": world_state
                .get("entities")
                .and_then(|entities| entities.as_array())
                .map(|entities| entities.iter().filter(|entity| {
                    entity.pointer("/components/animation/state/activeState")
                        .or_else(|| entity.pointer("/components/animation/activeState"))
                        .is_some_and(|value| !value.is_null())
                }).count())
                .unwrap_or(0)
        }),
        vfx: dashboard_vfx_summary(world_state),
        audio: json!({
            "audioEventCount": dashboard_array_len(world_state.get("audioEvents")),
            "audioWarningCount": dashboard_array_len(world_state.get("audioWarnings")),
            "audioEntityCount": dashboard_entities_with_component(world_state, "audio"),
            "audioEvents": world_state.get("audioEvents").cloned().unwrap_or_else(|| json!([])),
            "audioWarnings": world_state.get("audioWarnings").cloned().unwrap_or_else(|| json!([])),
            "browserAudioAuthority": "intent_evidence_only"
        }),
        physics: json!({
            "collisionCount": dashboard_array_len(world_state.get("collisions")),
            "collisionEventCount": dashboard_array_len(world_state.get("collisionEvents")),
            "colliderEntityCount": dashboard_entities_with_component(world_state, "collider"),
            "grounded": world_state.pointer("/physics/grounded").cloned().unwrap_or(json!({})),
            "contacts": world_state.pointer("/physics/contacts").cloned().unwrap_or(json!({})),
            "contactPairs": world_state.pointer("/physics/contactPairs").cloned().unwrap_or(json!([])),
            "contactPairCount": dashboard_array_len(world_state.pointer("/physics/contactPairs")),
            "blockedMovement": world_state.pointer("/physics/blockedMovement").cloned().unwrap_or(json!({}))
        }),
        input: dashboard_input_summary(world_state),
        runtime_state: dashboard_runtime_state_summary(world_state),
        collision: dashboard_collision_summary(world_state),
        gameplay: dashboard_gameplay_summary(world_state),
        triggers: dashboard_trigger_summary(world_state),
        hud: dashboard_hud_summary(world_state),
        transition: dashboard_transition_summary(world_state),
        events: dashboard_runtime_event_summary(world_state),
        reload: json!({
            "reloadCount": dashboard_array_len(world_state.get("reloads")),
            "lastStatus": world_state.get("reloads")
                .and_then(|reloads| reloads.as_array())
                .and_then(|reloads| reloads.last())
                .and_then(|reload| reload.get("status"))
                .cloned()
                .unwrap_or(json!(null))
        }),
        composition: json!({
            "present": world_state.get("composition").is_some(),
            "entityCount": dashboard_array_len(world_state.pointer("/composition/entities")),
            "parentedEntityCount": world_state
                .pointer("/composition/entities")
                .and_then(|entities| entities.as_array())
                .map(|entities| entities.iter().filter(|entity| entity.get("parent").is_some_and(|parent| !parent.is_null())).count())
                .unwrap_or(0)
        }),
    }
}

fn dashboard_render_breakdown_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let Some(breakdown) = world_state.get("renderBreakdown") else {
        return json!({
            "present": false,
            "emptyState": "No scene render breakdown evidence is available."
        });
    };
    if !breakdown.is_object() {
        return json!({
            "present": false,
            "malformed": true,
            "emptyState": "Scene render breakdown evidence is malformed."
        });
    }
    let elements = breakdown
        .get("elements")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let absence = breakdown
        .get("absenceDiagnostics")
        .or_else(|| breakdown.get("absence_diagnostics"))
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let read_only = breakdown
        .get("readOnlyInspection")
        .or_else(|| breakdown.get("read_only_inspection"))
        .cloned()
        .unwrap_or_else(|| {
            json!({
                "trustedEmitter": "unknown",
                "browserStudioMode": "read-only evidence inspection",
                "disallowedActions": ["trusted writes", "command bridge", "live mutation"]
            })
        });
    json!({
        "present": true,
        "schemaVersion": breakdown.get("schemaVersion").cloned().unwrap_or(json!(null)),
        "frameId": breakdown.get("frameId").or_else(|| breakdown.get("frame_id")).cloned().unwrap_or(json!(null)),
        "sceneId": breakdown.get("sceneId").or_else(|| breakdown.get("scene_id")).cloned().unwrap_or(json!(null)),
        "elementCount": elements.len(),
        "absenceDiagnosticCount": absence.len(),
        "elements": elements,
        "absenceDiagnostics": absence,
        "readOnlyInspection": read_only
    })
}

fn dashboard_render_queue_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let Some(queue) = world_state.get("renderQueue") else {
        return json!({
            "present": false,
            "emptyState": "No scene render queue evidence is available."
        });
    };
    if !queue.is_object() {
        return json!({
            "present": false,
            "malformed": true,
            "emptyState": "Scene render queue evidence is malformed."
        });
    }
    let layers = queue
        .get("layers")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let renderables = queue
        .get("renderables")
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let validation = queue.get("validation").cloned().unwrap_or_else(|| {
        json!({
            "status": "unknown",
            "blockedReasons": [],
            "warnings": []
        })
    });
    let blocked_count = validation
        .get("blockedReasons")
        .or_else(|| validation.get("blocked_reasons"))
        .and_then(|value| value.as_array())
        .map(Vec::len)
        .unwrap_or(0);
    let warning_count = validation
        .get("warnings")
        .and_then(|value| value.as_array())
        .map(Vec::len)
        .unwrap_or(0);
    let skipped_count = renderables
        .iter()
        .filter(|renderable| {
            renderable.get("visible").and_then(|value| value.as_bool()) == Some(false)
        })
        .count();
    let read_only = queue
        .get("readOnlyInspection")
        .or_else(|| queue.get("read_only_inspection"))
        .cloned()
        .unwrap_or_else(|| {
            json!({
                "trustedEmitter": "unknown",
                "browserStudioMode": "read-only evidence inspection",
                "disallowedActions": ["trusted writes", "command bridge", "live mutation"]
            })
        });
    json!({
        "present": true,
        "schemaVersion": queue.get("schemaVersion").cloned().unwrap_or(json!(null)),
        "frameId": queue.get("frameId").or_else(|| queue.get("frame_id")).cloned().unwrap_or(json!(null)),
        "sceneId": queue.get("sceneId").or_else(|| queue.get("scene_id")).cloned().unwrap_or(json!(null)),
        "layerCount": layers.len(),
        "renderableCount": renderables.len(),
        "drawCallCount": renderables.iter().filter(|renderable| renderable.get("visible").and_then(|value| value.as_bool()) != Some(false)).count(),
        "skippedRenderableCount": skipped_count,
        "blockedReasonCount": blocked_count,
        "warningCount": warning_count,
        "validation": validation,
        "layers": layers,
        "renderables": renderables,
        "tilemapStats": queue.get("tilemapStats").or_else(|| queue.get("tilemap_stats")).cloned().unwrap_or(json!({})),
        "readOnlyInspection": read_only
    })
}

fn dashboard_scene3d_hierarchy_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let Some(summary) = world_state
        .get("scene3dTransforms")
        .or_else(|| world_state.get("scene3d_transforms"))
        .or_else(|| world_state.get("scene3dHierarchy"))
        .or_else(|| world_state.get("scene3d_hierarchy"))
    else {
        return json!({
            "present": false,
            "emptyState": "No 3D hierarchy evidence is available."
        });
    };
    if !summary.is_object() {
        return json!({
            "present": false,
            "malformed": true,
            "emptyState": "3D hierarchy evidence is malformed."
        });
    }
    let transforms = summary
        .get("transforms")
        .or_else(|| summary.get("nodes"))
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let parented_count = transforms
        .iter()
        .filter(|entry| {
            entry
                .get("parentId")
                .or_else(|| entry.get("parent_id"))
                .is_some_and(|value| !value.is_null())
        })
        .count();
    json!({
        "present": summary.get("present").and_then(|value| value.as_bool()).unwrap_or(true),
        "schemaVersion": summary.get("schemaVersion").or_else(|| summary.get("schema_version")).cloned().unwrap_or(json!(null)),
        "sceneId": summary.get("sceneId").or_else(|| summary.get("scene_id")).cloned().unwrap_or(json!(null)),
        "nodeCount": summary.get("nodeCount").or_else(|| summary.get("node_count")).cloned().unwrap_or_else(|| json!(transforms.len())),
        "rootCount": summary.get("rootCount").or_else(|| summary.get("root_count")).cloned().unwrap_or_else(|| json!(transforms.len().saturating_sub(parented_count))),
        "parentedNodeCount": summary.get("parentedNodeCount").or_else(|| summary.get("parented_node_count")).cloned().unwrap_or_else(|| json!(parented_count)),
        "transforms": transforms,
        "boundary": summary.get("boundary").cloned().unwrap_or_else(|| json!("Read-only bounded 3D hierarchy evidence; no 3D editor or viewport persistence claim.")),
        "readOnlyInspection": summary.get("readOnlyInspection").or_else(|| summary.get("read_only_inspection")).cloned().unwrap_or_else(|| json!({
            "trustedEmitter": "browser-runtime-transform",
            "browserStudioMode": "read-only 3D hierarchy evidence inspection",
            "disallowedActions": ["trusted writes", "command bridge", "viewport persistence", "scene mutation"]
        }))
    })
}

