fn dashboard_camera_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let camera = world_state.get("camera");
    let renderer = world_state
        .get("renderer")
        .unwrap_or(&serde_json::Value::Null);
    let cameras = camera
        .and_then(|value| value.get("cameras"))
        .or_else(|| world_state.get("cameras"))
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    // Layer evidence may be emitted under renderer.layers, the camera-scoped
    // camera.layers, or top-level layers. Fall back across all three (mirroring
    // how cameras already resolves camera.cameras / worldState.cameras) so layers
    // emitted under worldState.camera are not silently dropped.
    let layers = renderer
        .get("layers")
        .or_else(|| camera.and_then(|value| value.get("layers")))
        .or_else(|| world_state.get("layers"))
        .and_then(|value| value.as_array())
        .cloned()
        .unwrap_or_default();
    let world_to_screen = camera
        .and_then(|value| value.get("worldToScreen"))
        .and_then(|value| value.as_object())
        .cloned()
        .unwrap_or_default();
    let scene_3d_camera = camera
        .and_then(|value| value.get("camera3d").or_else(|| value.get("scene3dCamera")))
        .or_else(|| world_state.get("camera3d"))
        .or_else(|| world_state.get("scene3dCamera"))
        .cloned()
        .unwrap_or_else(|| {
            json!({
                "present": false,
                "emptyState": "No 3D camera evidence is available."
            })
        });
    let active_camera_id = camera
        .and_then(|value| value.get("activeCameraId"))
        .or_else(|| world_state.get("activeCameraId"))
        .or_else(|| scene_3d_camera.get("activeCameraId"))
        .cloned()
        .unwrap_or(json!(null));
    let active_camera = cameras
        .iter()
        .find(|entry| entry.get("active").and_then(|value| value.as_bool()) == Some(true))
        .cloned()
        .unwrap_or(json!(null));
    let renderer_camera = camera
        .and_then(|value| value.get("rendererCamera"))
        .or_else(|| renderer.get("camera"))
        .cloned()
        .unwrap_or(json!(null));
    let viewport = camera
        .and_then(|value| value.get("viewport"))
        .or_else(|| renderer.get("viewport"))
        .cloned()
        .unwrap_or(json!(null));
    let parallax_layer_count = layers
        .iter()
        .filter(|layer| {
            layer
                .get("parallaxFactor")
                .and_then(|value| value.as_i64())
                .is_some_and(|factor| factor != 100)
        })
        .count();
    let camera_excluded_layer_count = layers
        .iter()
        .filter(|layer| {
            layer
                .get("cameraParticipation")
                .and_then(|value| value.as_bool())
                == Some(false)
        })
        .count();
    let scene_3d_camera_present = scene_3d_camera
        .get("present")
        .and_then(|value| value.as_bool())
        .unwrap_or(false);
    let present =
        camera.is_some() || !cameras.is_empty() || !layers.is_empty() || scene_3d_camera_present;
    json!({
        "present": present,
        "emptyState": if present { "" } else { "No camera/layer read model is available." },
        "activeCameraId": active_camera_id,
        "activeCamera": active_camera,
        "scene3dCamera": scene_3d_camera,
        "rendererCamera": renderer_camera,
        "viewport": viewport,
        "cameraCount": cameras.len(),
        "layerCount": layers.len(),
        "parallaxLayerCount": parallax_layer_count,
        "cameraExcludedLayerCount": camera_excluded_layer_count,
        "worldToScreenSampleCount": world_to_screen.len(),
        "cameras": cameras,
        "layers": layers,
        "worldToScreen": world_to_screen,
        "readOnlyInspection": {
            "trustedEmitter": "browser-runtime-world-state",
            "browserStudioMode": "read-only camera/layer evidence inspection",
            "disallowedActions": ["trusted writes", "command bridge", "scene mutation", "browser runtime control"]
        }
    })
}

fn dashboard_gameplay_summary(world_state: &serde_json::Value) -> serde_json::Value {
    let flag_entries = world_state
        .get("goalFlags")
        .and_then(|value| value.as_object())
        .map(|flags| {
            let mut entries = flags
                .iter()
                .map(|(id, value)| json!({ "id": id, "value": value.as_bool().unwrap_or(false) }))
                .collect::<Vec<_>>();
            entries.sort_by(|left, right| {
                left.get("id")
                    .and_then(|value| value.as_str())
                    .cmp(&right.get("id").and_then(|value| value.as_str()))
            });
            entries
        })
        .unwrap_or_default();
    let true_flags = flag_entries
        .iter()
        .filter(|entry| entry.get("value").and_then(|value| value.as_bool()) == Some(true))
        .filter_map(|entry| entry.get("id").and_then(|value| value.as_str()))
        .map(str::to_string)
        .collect::<Vec<_>>();
    let declared_flag_count = dashboard_array_len(world_state.pointer("/gameplayRules/flags"));
    let trigger_collision_event_count = world_state
        .get("collisionEvents")
        .and_then(|events| events.as_array())
        .map(|events| {
            events
                .iter()
                .filter(|event| {
                    event.get("type").and_then(|value| value.as_str())
                        == Some("runtime.collision.trigger")
                })
                .count()
        })
        .unwrap_or(0);
    let hud_values = world_state
        .pointer("/componentModel/hudValues")
        .and_then(|value| value.as_array())
        .map(|values| {
            values
                .iter()
                .map(|value| {
                    json!({
                        "entityId": value.get("entityId").cloned().unwrap_or(json!(null)),
                        "kind": value.get("kind").cloned().unwrap_or(json!(null)),
                        "label": value.get("label").cloned().unwrap_or(json!(null)),
                        "value": value.get("value").cloned().unwrap_or(json!(null)),
                        "bindFlag": value.get("bindFlag").cloned().unwrap_or(json!(null)),
                        "flagValue": value.get("flagValue").cloned().unwrap_or(json!(null)),
                        "text": value.get("text").cloned().unwrap_or(json!(null)),
                    })
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let hud_value_entity_count = world_state
        .pointer("/componentModel/counts/hudValue")
        .cloned()
        .unwrap_or_else(|| json!(hud_values.len()));
    json!({
        "present": world_state.get("goalFlags").is_some()
            || world_state.get("gameplayRules").is_some()
            || world_state.get("componentModel").is_some(),
        "declaredFlagCount": declared_flag_count,
        "worldFlagCount": flag_entries.len(),
        "trueFlagCount": true_flags.len(),
        "falseFlagCount": flag_entries.len().saturating_sub(true_flags.len()),
        "triggerEntityCount": world_state.pointer("/componentModel/counts/trigger")
            .cloned()
            .unwrap_or_else(|| json!(dashboard_entities_with_component(world_state, "trigger"))),
        "goalFlagEntityCount": world_state.pointer("/componentModel/counts/goalFlag")
            .cloned()
            .unwrap_or_else(|| json!(dashboard_entities_with_component(world_state, "goalFlag"))),
        "hudValueEntityCount": hud_value_entity_count,
        "hudValues": hud_values,
        "triggerCollisionEventCount": trigger_collision_event_count,
        "trueFlags": true_flags,
        "flags": flag_entries
    })
}

fn read_dashboard_comparison(run_dir: &Path) -> RunDashboardComparison {
    let paths = dashboard_run_comparison_artifact_paths(run_dir);
    if paths.is_empty() {
        return RunDashboardComparison {
            present: false,
            empty_state: "No run comparison artifacts were found for this run.".to_string(),
            artifacts: Vec::new(),
        };
    }
    let artifacts = paths
        .into_iter()
        .map(|path| dashboard_comparison_artifact(run_dir, path))
        .collect::<Vec<_>>();
    RunDashboardComparison {
        present: true,
        empty_state: String::new(),
        artifacts,
    }
}

fn dashboard_run_comparison_artifact_paths(run_dir: &Path) -> Vec<String> {
    let mut paths = Vec::new();
    for dir in ["mutation", "comparisons"] {
        if let Ok(entries) = fs::read_dir(run_dir.join(dir)) {
            for entry in entries.flatten() {
                let path = entry.path();
                let Some(name) = path.file_name().and_then(|value| value.to_str()) else {
                    continue;
                };
                if name.starts_with("run-comparison-") && name.ends_with(".json") {
                    paths.push(format!("{dir}/{name}"));
                }
            }
        }
    }
    paths.sort();
    paths
}

fn dashboard_comparison_artifact(run_dir: &Path, path: String) -> RunDashboardComparisonArtifact {
    let id = Path::new(&path)
        .file_stem()
        .and_then(|value| value.to_str())
        .unwrap_or("run-comparison")
        .to_string();
    let absolute_path = run_dir.join(&path);
    if !absolute_path.is_file() {
        return RunDashboardComparisonArtifact {
            id,
            path: path.clone(),
            exists: false,
            read_error: Some(format!("missing comparison artifact file: {path}")),
            before_run_id: None,
            after_run_id: None,
            classification: None,
            deltas: serde_json::Value::Null,
            semantic: serde_json::Value::Null,
            evidence_refs: Vec::new(),
            unsupported: Vec::new(),
            value: None,
        };
    }
    match read_json_value(&absolute_path) {
        Ok(value) => RunDashboardComparisonArtifact {
            id,
            path,
            exists: true,
            read_error: None,
            before_run_id: json_string(&value, "before_run_id"),
            after_run_id: json_string(&value, "after_run_id"),
            classification: json_string(&value, "classification"),
            deltas: value
                .get("deltas")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            semantic: value
                .get("semantic")
                .cloned()
                .unwrap_or(serde_json::Value::Null),
            evidence_refs: value
                .get("evidence_refs")
                .and_then(|refs| refs.as_array())
                .map(|refs| {
                    refs.iter()
                        .filter_map(|value| value.as_str().map(str::to_string))
                        .collect::<Vec<_>>()
                })
                .unwrap_or_default(),
            unsupported: value
                .get("unsupported")
                .and_then(|items| items.as_array())
                .map(|items| {
                    items
                        .iter()
                        .filter_map(|value| value.as_str().map(str::to_string))
                        .collect::<Vec<_>>()
                })
                .unwrap_or_default(),
            value: Some(value),
        },
        Err(error) => RunDashboardComparisonArtifact {
            id,
            path,
            exists: true,
            read_error: Some(error.to_string()),
            before_run_id: None,
            after_run_id: None,
            classification: None,
            deltas: serde_json::Value::Null,
            semantic: serde_json::Value::Null,
            evidence_refs: Vec::new(),
            unsupported: Vec::new(),
            value: None,
        },
    }
}

fn select_dashboard_mutation_artifacts(run_dir: &Path) -> Result<Vec<RunDashboardArtifact>> {
    [
        ("mutation-proposals", "mutation/proposals.json"),
        ("mutation-classifications", "mutation/classifications.json"),
        ("mutation-patch-drafts", "mutation/patch-drafts.json"),
        (
            "mutation-rerun-orchestration",
            "mutation/rerun-orchestration.json",
        ),
        (
            "mutation-scene-applications",
            "mutation/scene-applications.json",
        ),
        (
            "mutation-visual-edit-applications",
            "mutation/visual-edit-applications.json",
        ),
        (
            "mutation-review-decisions",
            "mutation/review-decisions.json",
        ),
        (
            "source-patch-evidence-bundle",
            "mutation/source-patch-evidence-bundle.json",
        ),
        (
            "source-patch-apply-transaction",
            "mutation/source-patch-apply-transaction.json",
        ),
        (
            "source-patch-stale-target-guard",
            "mutation/source-patch-stale-target-guard.json",
        ),
        (
            "mutation-evolve-v1-demo-summary",
            "mutation/evolve-v1-demo-summary.json",
        ),
    ]
    .into_iter()
    .filter(|(_, path)| run_dir.join(path).is_file())
    .map(|(id, path)| {
        dashboard_artifact_from_parts(
            run_dir,
            id.to_string(),
            "application/json".to_string(),
            path.to_string(),
            json!({ "artifact": "mutation_artifact", "read_only": true }),
        )
    })
    .collect()
}

struct DashboardCategoryArtifacts<'a> {
    screenshots: &'a [RunDashboardArtifact],
    world_states: &'a [RunDashboardArtifact],
    frame_metrics: &'a [RunDashboardArtifact],
    performance_metrics: &'a [RunDashboardArtifact],
    console_logs: &'a [RunDashboardArtifact],
    cdp_trace_summaries: &'a [RunDashboardArtifact],
    scenario_results: &'a [RunDashboardArtifact],
    mutation_artifacts: &'a [RunDashboardArtifact],
}

struct DashboardEvidenceFidelityInputs<'a> {
    transaction_provenance: Option<&'a RunTransactionProvenance>,
    probe_contract_status: &'a RunDashboardProbeContractStatus,
    replay: &'a RunDashboardReplay,
    screenshots: &'a [RunDashboardArtifact],
    console_logs: &'a [RunDashboardArtifact],
    performance_metrics: &'a [RunDashboardArtifact],
    cdp_trace_summaries: &'a [RunDashboardArtifact],
    command_context: Option<&'a RunCommandContext>,
}

fn dashboard_evidence_fidelity(
    inputs: DashboardEvidenceFidelityInputs<'_>,
) -> RunDashboardEvidenceFidelity {
    let transaction = match inputs.transaction_provenance {
        Some(provenance) => RunDashboardEvidenceFidelityStatus {
            id: "transaction".to_string(),
            label: "Transaction provenance".to_string(),
            status: "present".to_string(),
            summary: format!(
                "Transaction {} records scene edit provenance.",
                provenance.transaction_id
            ),
            observed_count: 1,
            missing_count: 0,
            warnings: Vec::new(),
            evidence_refs: vec![provenance.transaction_artifact_path.clone()],
        },
        None => RunDashboardEvidenceFidelityStatus {
            id: "transaction".to_string(),
            label: "Transaction provenance".to_string(),
            status: "missing".to_string(),
            summary: "No transaction provenance is recorded for this run.".to_string(),
            observed_count: 0,
            missing_count: 1,
            warnings: vec!["Scene edit transaction provenance is unavailable.".to_string()],
            evidence_refs: Vec::new(),
        },
    };

    let runtime_probe = RunDashboardEvidenceFidelityStatus {
        id: "runtime_probe".to_string(),
        label: "Runtime probe contract".to_string(),
        status: inputs.probe_contract_status.status.clone(),
        summary: format!(
            "{} {} observed; {} missing; {} malformed.",
            inputs.probe_contract_status.contract_name,
            inputs.probe_contract_status.observed_count,
            inputs.probe_contract_status.missing_count,
            inputs.probe_contract_status.malformed_count
        ),
        observed_count: inputs.probe_contract_status.observed_count,
        missing_count: inputs.probe_contract_status.missing_count,
        warnings: if inputs.probe_contract_status.status == "present" {
            Vec::new()
        } else {
            vec![format!(
                "Runtime probe contract status is {}.",
                inputs.probe_contract_status.status
            )]
        },
        evidence_refs: inputs.probe_contract_status.evidence_refs.clone(),
    };

    let readable_replay_count = inputs
        .replay
        .sequences
        .iter()
        .filter(|sequence| sequence.read_error.is_none())
        .count();
    let unreadable_replay_count = inputs
        .replay
        .sequences
        .iter()
        .filter(|sequence| sequence.read_error.is_some())
        .count();
    let replay_refs = inputs
        .replay
        .sequences
        .iter()
        .flat_map(|sequence| sequence.evidence_refs.clone())
        .collect::<Vec<_>>();
    let replay_warnings = inputs
        .replay
        .sequences
        .iter()
        .filter_map(|sequence| {
            sequence.read_error.as_ref().map(|error| {
                format!(
                    "Replay evidence {} is unavailable: {error}",
                    sequence.replay_path
                )
            })
        })
        .collect::<Vec<_>>();
    let input_replay = RunDashboardEvidenceFidelityStatus {
        id: "input_replay".to_string(),
        label: "Input replay evidence".to_string(),
        status: if readable_replay_count > 0 && unreadable_replay_count == 0 {
            "present"
        } else if readable_replay_count > 0 {
            "partial"
        } else {
            "missing"
        }
        .to_string(),
        summary: if readable_replay_count > 0 {
            format!(
                "{} replay sequence(s) available; {} unavailable.",
                readable_replay_count, unreadable_replay_count
            )
        } else {
            inputs.replay.empty_state.clone()
        },
        observed_count: readable_replay_count,
        missing_count: if inputs.replay.sequences.is_empty() {
            1
        } else {
            unreadable_replay_count
        },
        warnings: if replay_warnings.is_empty() && readable_replay_count == 0 {
            vec!["Input replay evidence is unavailable.".to_string()]
        } else {
            replay_warnings
        },
        evidence_refs: replay_refs,
    };

    let cdp_counts = [
        (
            "worker screenshots",
            dashboard_readable_artifact_count(inputs.screenshots),
        ),
        (
            "console logs",
            dashboard_readable_artifact_count(inputs.console_logs),
        ),
        (
            "performance metrics",
            dashboard_readable_artifact_count(inputs.performance_metrics),
        ),
        (
            "CDP trace summaries",
            dashboard_readable_artifact_count(inputs.cdp_trace_summaries),
        ),
    ];
    let missing_cdp = cdp_counts
        .iter()
        .filter(|(_, count)| *count == 0)
        .map(|(label, _)| (*label).to_string())
        .collect::<Vec<_>>();
    let malformed_cdp = inputs
        .screenshots
        .iter()
        .chain(inputs.console_logs.iter())
        .chain(inputs.performance_metrics.iter())
        .chain(inputs.cdp_trace_summaries.iter())
        .filter(|artifact| artifact.exists && artifact.read_error.is_some())
        .count();
    let missing_cdp_artifacts = inputs
        .screenshots
        .iter()
        .chain(inputs.console_logs.iter())
        .chain(inputs.performance_metrics.iter())
        .chain(inputs.cdp_trace_summaries.iter())
        .filter(|artifact| !artifact.exists)
        .count();
    let openchrome_refs = inputs
        .screenshots
        .iter()
        .chain(inputs.console_logs.iter())
        .chain(inputs.performance_metrics.iter())
        .chain(inputs.cdp_trace_summaries.iter())
        .map(|artifact| artifact.path.clone())
        .collect::<Vec<_>>();
    let openchrome_cdp = RunDashboardEvidenceFidelityStatus {
        id: "openchrome_cdp".to_string(),
        label: "Openchrome/CDP evidence".to_string(),
        status: if malformed_cdp > 0 {
            "malformed"
        } else if missing_cdp.is_empty() && missing_cdp_artifacts == 0 {
            "present"
        } else if openchrome_refs.is_empty() {
            "missing"
        } else {
            "partial"
        }
        .to_string(),
        summary: format!(
            "{} screenshot(s), {} console log(s), {} performance metric(s), {} CDP trace summarie(s).",
            inputs.screenshots.len(),
            inputs.console_logs.len(),
            inputs.performance_metrics.len(),
            inputs.cdp_trace_summaries.len()
        ),
        observed_count: cdp_counts.iter().map(|(_, count)| *count).sum(),
        missing_count: missing_cdp.len() + missing_cdp_artifacts,
        warnings: missing_cdp
            .iter()
            .map(|label| format!("Missing {label}."))
            .chain(
                inputs
                    .screenshots
                    .iter()
                    .chain(inputs.console_logs.iter())
                    .chain(inputs.performance_metrics.iter())
                    .chain(inputs.cdp_trace_summaries.iter())
                    .filter_map(|artifact| {
                        artifact.read_error.as_ref().map(|error| {
                            format!(
                                "Openchrome/CDP evidence {} is unavailable: {error}",
                                artifact.path
                            )
                        })
                    }),
            )
            .collect(),
        evidence_refs: openchrome_refs,
    };

    let command_context = match inputs.command_context {
        Some(context) => RunDashboardEvidenceFidelityStatus {
            id: "command_context".to_string(),
            label: "Reproducible command context".to_string(),
            status: "present".to_string(),
            summary: format!("{} worker(s), seed {}.", context.workers, context.seed_path),
            observed_count: 1,
            missing_count: 0,
            warnings: Vec::new(),
            evidence_refs: Vec::new(),
        },
        None => RunDashboardEvidenceFidelityStatus {
            id: "command_context".to_string(),
            label: "Reproducible command context".to_string(),
            status: "missing".to_string(),
            summary: "No reproducible command context is recorded.".to_string(),
            observed_count: 0,
            missing_count: 1,
            warnings: vec!["Command context is unavailable for this run.".to_string()],
            evidence_refs: Vec::new(),
        },
    };

    RunDashboardEvidenceFidelity {
        transaction,
        runtime_probe,
        input_replay,
        openchrome_cdp,
        command_context,
    }
}

fn dashboard_readable_artifact_count(artifacts: &[RunDashboardArtifact]) -> usize {
    artifacts
        .iter()
        .filter(|artifact| artifact.exists && artifact.read_error.is_none())
        .count()
}

fn dashboard_category_summaries(
    artifacts: DashboardCategoryArtifacts<'_>,
) -> Vec<RunDashboardCategorySummary> {
    vec![
        dashboard_category_summary("screenshots", "Screenshots", artifacts.screenshots),
        dashboard_category_summary(
            "world_states",
            "World-state snapshots",
            artifacts.world_states,
        ),
        dashboard_category_summary(
            "frame_performance_metrics",
            "Frame/performance metrics",
            &artifacts
                .frame_metrics
                .iter()
                .chain(artifacts.performance_metrics.iter())
                .cloned()
                .collect::<Vec<_>>(),
        ),
        dashboard_category_summary(
            "console_cdp_summaries",
            "Console/CDP summaries",
            &artifacts
                .console_logs
                .iter()
                .chain(artifacts.cdp_trace_summaries.iter())
                .cloned()
                .collect::<Vec<_>>(),
        ),
        dashboard_category_summary(
            "scenario_results",
            "Scenario results",
            artifacts.scenario_results,
        ),
        dashboard_category_summary(
            "mutation_artifacts",
            "Mutation artifacts",
            artifacts.mutation_artifacts,
        ),
    ]
}

fn dashboard_category_summary(
    id: &str,
    label: &str,
    artifacts: &[RunDashboardArtifact],
) -> RunDashboardCategorySummary {
    RunDashboardCategorySummary {
        id: id.to_string(),
        label: label.to_string(),
        count: artifacts.len(),
        missing_count: artifacts.iter().filter(|artifact| !artifact.exists).count(),
        malformed_count: artifacts
            .iter()
            .filter(|artifact| artifact.exists && artifact.read_error.is_some())
            .count(),
    }
}

fn dashboard_worker_count(evidence: &[EvidenceArtifact]) -> usize {
    let mut worker_ids = BTreeSet::new();
    for artifact in evidence {
        if let Some(worker_id) = artifact
            .metadata
            .get("worker_id")
            .and_then(|value| value.as_str())
        {
            worker_ids.insert(worker_id.to_string());
        }
    }
    worker_ids.len()
}

fn dashboard_scenario_status(verdict: &serde_json::Value) -> String {
    let scenario_results = verdict
        .get("metadata")
        .and_then(|metadata| metadata.get("scenario_results"))
        .and_then(|value| value.as_u64())
        .unwrap_or(0);
    if scenario_results == 0 {
        return "pending".to_string();
    }
    // Derive the scenario status from genuine scenario outcomes, not the overall
    // verdict status. A verdict can fail purely for evidence-consistency reasons
    // (e.g. missing_scenario_evidence) while the scenarios themselves passed, and
    // the dashboard needs to distinguish "scenario passed, evidence incomplete"
    // from an actually failed scenario.
    let scenario_failed = verdict
        .get("failures")
        .and_then(|value| value.as_array())
        .map(|failures| {
            failures.iter().any(|failure| {
                matches!(
                    failure.get("kind").and_then(|value| value.as_str()),
                    Some("scenario_failed" | "assertion_failed" | "visual_checkpoint_failed")
                )
            })
        })
        .unwrap_or(false);
    if scenario_failed {
        "failed".to_string()
    } else {
        "passed".to_string()
    }
}

fn read_dashboard_journal(
    run_dir: &Path,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) -> RunDashboardJournal {
    let path = "journal.md".to_string();
    let absolute_path = run_dir.join(&path);
    match fs::read_to_string(&absolute_path) {
        Ok(body) => parse_dashboard_journal(&path, true, None, &body, evidence, mutations),
        Err(error) if error.kind() == ErrorKind::NotFound => parse_dashboard_journal(
            &path,
            false,
            Some("missing journal artifact".to_string()),
            "",
            evidence,
            mutations,
        ),
        // The journal file is present but unreadable (e.g. invalid UTF-8 or a
        // permission error). Report it as existing with a read_error so it is
        // distinguishable from a genuinely missing journal.
        Err(error) => parse_dashboard_journal(
            &path,
            true,
            Some(format!("failed to read journal artifact: {error}")),
            "",
            evidence,
            mutations,
        ),
    }
}

fn parse_dashboard_journal(
    path: &str,
    exists: bool,
    read_error: Option<String>,
    journal: &str,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) -> RunDashboardJournal {
    let entries = dashboard_journal_entries(journal, evidence, mutations);
    let evidence_refs = collect_entry_refs(&entries, |entry| &entry.evidence_refs);
    let verdict_refs = collect_entry_refs(&entries, |entry| &entry.verdict_refs);
    let mutation_refs = collect_entry_refs(&entries, |entry| &entry.mutation_refs);
    RunDashboardJournal {
        path: path.to_string(),
        exists,
        read_error,
        summary: dashboard_journal_summary(journal, &entries),
        entries,
        evidence_refs,
        verdict_refs,
        mutation_refs,
    }
}

fn dashboard_journal_entries(
    journal: &str,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) -> Vec<RunDashboardJournalEntry> {
    let mut entries = Vec::new();
    let mut current_heading = String::new();
    let mut current_level = 0usize;
    let mut current_body = String::new();

    for line in journal.lines() {
        if let Some((level, heading)) = markdown_heading(line) {
            push_dashboard_journal_entry(
                &mut entries,
                &current_heading,
                current_level,
                &current_body,
                evidence,
                mutations,
            );
            current_heading = heading;
            current_level = level;
            current_body.clear();
        } else {
            current_body.push_str(line);
            current_body.push('\n');
        }
    }
    push_dashboard_journal_entry(
        &mut entries,
        &current_heading,
        current_level,
        &current_body,
        evidence,
        mutations,
    );
    entries
}

fn push_dashboard_journal_entry(
    entries: &mut Vec<RunDashboardJournalEntry>,
    heading: &str,
    level: usize,
    body: &str,
    evidence: &[EvidenceArtifact],
    mutations: &[MutationProposal],
) {
    let body = body.trim();
    if heading.trim().is_empty() && body.is_empty() {
        return;
    }
    let fallback_heading = if heading.trim().is_empty() {
        "Journal"
    } else {
        heading.trim()
    };
    let category = dashboard_journal_category(fallback_heading);
    let entry_text = format!("{fallback_heading}\n{body}");
    let index = entries.len() + 1;
    entries.push(RunDashboardJournalEntry {
        id: format!("journal-entry-{index}-{}", slug_for_id(fallback_heading)),
        heading: fallback_heading.to_string(),
        level,
        category,
        body: body.to_string(),
        evidence_refs: extract_journal_evidence_refs(&entry_text, evidence),
        verdict_refs: extract_journal_verdict_refs(&entry_text),
        mutation_refs: extract_journal_mutation_refs(&entry_text, mutations),
    });
}

fn markdown_heading(line: &str) -> Option<(usize, String)> {
    let trimmed = line.trim_start();
    let level = trimmed.chars().take_while(|ch| *ch == '#').count();
    if level == 0 || level > 6 {
        return None;
    }
    let rest = trimmed.get(level..)?.trim();
    if rest.is_empty() {
        return None;
    }
    Some((level, rest.to_string()))
}

fn dashboard_journal_category(heading: &str) -> String {
    let lowered = heading.to_ascii_lowercase();
    if lowered.contains("hypothesis") {
        "hypothesis"
    } else if lowered.contains("observation") || lowered.contains("evidence") {
        "observation"
    } else if lowered.contains("failed") || lowered.contains("failure") {
        "failure"
    } else if lowered.contains("mutation") {
        "next_mutation"
    } else if lowered.contains("verdict") {
        "verdict"
    } else {
        "summary"
    }
    .to_string()
}

fn dashboard_journal_summary(journal: &str, entries: &[RunDashboardJournalEntry]) -> String {
    for line in journal.lines() {
        let trimmed = line.trim();
        if let Some(summary) = trimmed.strip_prefix("- Summary:") {
            return summary.trim().to_string();
        }
    }
    entries
        .iter()
        .find_map(|entry| {
            entry
                .body
                .lines()
                .map(str::trim)
                .find(|line| !line.is_empty())
                .map(str::to_string)
        })
        .unwrap_or_else(|| "No journal content available.".to_string())
}

fn extract_journal_evidence_refs(text: &str, evidence: &[EvidenceArtifact]) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for artifact in evidence {
        if text.contains(&artifact.path) || text.contains(&artifact.id) {
            refs.insert(artifact.path.clone());
        }
    }
    refs.into_iter().collect()
}

fn extract_journal_verdict_refs(text: &str) -> Vec<String> {
    let lowered = text.to_ascii_lowercase();
    if lowered.contains("verdict") || lowered.contains("failed criteria") {
        vec!["verdict.json".to_string()]
    } else {
        Vec::new()
    }
}

fn extract_journal_mutation_refs(text: &str, mutations: &[MutationProposal]) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for mutation in mutations {
        if text.contains(&mutation.id) {
            refs.insert(mutation.id.clone());
        }
    }
    refs.into_iter().collect()
}

fn collect_entry_refs(
    entries: &[RunDashboardJournalEntry],
    selector: fn(&RunDashboardJournalEntry) -> &Vec<String>,
) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for entry in entries {
        for reference in selector(entry) {
            refs.insert(reference.clone());
        }
    }
    refs.into_iter().collect()
}

fn slug_for_id(value: &str) -> String {
    let mut slug = String::new();
    for ch in value.chars() {
        if ch.is_ascii_alphanumeric() {
            slug.push(ch.to_ascii_lowercase());
        } else if !slug.ends_with('-') {
            slug.push('-');
        }
    }
    slug.trim_matches('-').to_string()
}

fn read_dashboard_mutation_lifecycle(
    run_dir: &Path,
    proposals: &[MutationProposal],
) -> RunDashboardMutationLifecycle {
    let stages = vec![
        dashboard_lifecycle_stage_from_records(
            "proposed",
            "Proposed",
            if proposals.is_empty() {
                "missing"
            } else {
                "proposed"
            },
            Some("mutation/proposals.json"),
            proposals.iter().map(|proposal| json!(proposal)).collect(),
            proposals
                .iter()
                .map(|proposal| proposal.evidence_id.clone())
                .collect(),
            None,
        ),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "classified",
            "Classified",
            "classified",
            "mutation/classifications.json",
            "classifications",
        ),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "drafted",
            "Drafted",
            "drafted",
            "mutation/patch-drafts.json",
            "drafts",
        ),
        dashboard_sandbox_stage(run_dir),
        dashboard_comparison_stage(run_dir),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "scene_applied",
            "Applied scene mutation",
            "applied",
            "mutation/scene-applications.json",
            "applications",
        ),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "visual_draft_applied",
            "Applied visual draft",
            "applied",
            "mutation/visual-edit-applications.json",
            "applications",
        ),
        dashboard_lifecycle_stage_from_json_file(
            run_dir,
            "reviewed",
            "Manual review",
            "pending_review",
            "mutation/review-decisions.json",
            "decisions",
        ),
    ];
    let terminal_state = dashboard_lifecycle_terminal_state(&stages);
    let command_hints = dashboard_mutation_command_hints(run_dir, &stages);
    RunDashboardMutationLifecycle {
        terminal_state,
        stages,
        command_hints,
    }
}

fn dashboard_review_cockpit(
    lifecycle: &RunDashboardMutationLifecycle,
    promotions: &[RegressionPromotionPackResult],
) -> RunDashboardReviewCockpit {
    let proposals =
        dashboard_review_cockpit_stage_from_lifecycle(lifecycle, "proposed", "Proposals");
    let decisions =
        dashboard_review_cockpit_stage_from_lifecycle(lifecycle, "reviewed", "Review decisions");
    let applications = dashboard_review_cockpit_application_stage(lifecycle);
    let comparisons =
        dashboard_review_cockpit_stage_from_lifecycle(lifecycle, "compared", "Rerun comparisons");
    let promotions = dashboard_review_cockpit_promotion_stage(promotions);
    // Report the furthest lifecycle stage reached. Promotion outranks rerun
    // comparison, which outranks review-gated applications and earlier review
    // records, so accepted reviews do not hide applied visual draft evidence.
    let terminal_state = [
        &promotions,
        &comparisons,
        &applications,
        &decisions,
        &proposals,
    ]
    .into_iter()
    .find(|stage| stage.state != "missing")
    .map(|stage| stage.state.clone())
    .unwrap_or_else(|| "missing".to_string());
    RunDashboardReviewCockpit {
        schema_version: "ouroforge-studio-review-cockpit-v1".to_string(),
        terminal_state,
        proposals,
        decisions,
        applications,
        comparisons,
        promotions,
        matrix: RunDashboardReviewCockpitStage {
            id: "matrix".to_string(),
            label: "Regression matrix".to_string(),
            state: "export_level".to_string(),
            artifact_path: Some("regression_matrix".to_string()),
            record_count: 0,
            record_ids: Vec::new(),
            evidence_refs: Vec::new(),
            read_error: None,
        },
        command_hints: lifecycle.command_hints.clone(),
        boundary: "read-only exported evidence; commands are inert text only".to_string(),
    }
}

fn dashboard_review_cockpit_application_stage(
    lifecycle: &RunDashboardMutationLifecycle,
) -> RunDashboardReviewCockpitStage {
    let mut scene = dashboard_review_cockpit_stage_from_lifecycle(
        lifecycle,
        "scene_applied",
        "Review-gated applications",
    );
    let visual = dashboard_review_cockpit_stage_from_lifecycle(
        lifecycle,
        "visual_draft_applied",
        "Visual draft applications",
    );
    if scene.state == "missing" {
        return visual;
    }
    if visual.state == "missing" {
        return scene;
    }
    scene.id = "applications".to_string();
    scene.label = "Review-gated applications".to_string();
    scene.record_count += visual.record_count;
    scene.record_ids.extend(visual.record_ids);
    scene.record_ids.sort();
    scene.record_ids.dedup();
    scene.evidence_refs.extend(visual.evidence_refs);
    scene.evidence_refs.sort();
    scene.evidence_refs.dedup();
    scene.artifact_path = Some(
        "mutation/scene-applications.json + mutation/visual-edit-applications.json".to_string(),
    );
    if scene.state == "missing" {
        scene.state = visual.state;
    }
    scene
}

fn dashboard_review_cockpit_stage_from_lifecycle(
    lifecycle: &RunDashboardMutationLifecycle,
    stage_id: &str,
    fallback_label: &str,
) -> RunDashboardReviewCockpitStage {
    match lifecycle.stages.iter().find(|stage| stage.id == stage_id) {
        Some(stage) => RunDashboardReviewCockpitStage {
            id: stage.id.clone(),
            label: stage.label.clone(),
            state: stage.state.clone(),
            artifact_path: stage.artifact_path.clone(),
            record_count: stage.record_count,
            record_ids: stage
                .records
                .iter()
                .filter_map(dashboard_json_record_id)
                .collect(),
            evidence_refs: stage.evidence_refs.clone(),
            read_error: stage.read_error.clone(),
        },
        None => RunDashboardReviewCockpitStage {
            id: stage_id.to_string(),
            label: fallback_label.to_string(),
            state: "missing".to_string(),
            artifact_path: None,
            record_count: 0,
            record_ids: Vec::new(),
            evidence_refs: Vec::new(),
            read_error: Some("lifecycle stage missing from exported read model".to_string()),
        },
    }
}

fn dashboard_review_cockpit_promotion_stage(
    promotions: &[RegressionPromotionPackResult],
) -> RunDashboardReviewCockpitStage {
    RunDashboardReviewCockpitStage {
        id: "promotions".to_string(),
        label: "Regression promotions".to_string(),
        state: if promotions.is_empty() {
            "missing".to_string()
        } else {
            "promoted".to_string()
        },
        artifact_path: Some("regression-promotions/*.json".to_string()),
        record_count: promotions.len(),
        record_ids: promotions
            .iter()
            .map(|promotion| promotion.id.clone())
            .collect(),
        evidence_refs: promotions
            .iter()
            .flat_map(|promotion| {
                [
                    Some(promotion.source_run.verdict_path.clone()),
                    promotion.record_path.clone(),
                ]
                .into_iter()
                .flatten()
            })
            .collect::<BTreeSet<_>>()
            .into_iter()
            .collect(),
        read_error: None,
    }
}

fn dashboard_json_record_id(value: &serde_json::Value) -> Option<String> {
    value
        .get("id")
        .or_else(|| value.get("proposalId"))
        .or_else(|| value.get("decisionId"))
        .or_else(|| value.get("applicationId"))
        .and_then(|value| value.as_str())
        .map(str::to_string)
}

fn read_regression_promotion_records(run_dir: &Path) -> Vec<RegressionPromotionPackResult> {
    let dir = run_dir.join("regression-promotions");
    let mut records = Vec::new();
    let Ok(entries) = fs::read_dir(&dir) else {
        return records;
    };
    for entry in entries.flatten() {
        let path = entry.path();
        if path.extension().and_then(|value| value.to_str()) != Some("json") {
            continue;
        }
        if let Ok(value) = read_json_value(&path) {
            if let Ok(record) = serde_json::from_value::<RegressionPromotionPackResult>(value) {
                records.push(record);
            }
        }
    }
    records.sort_by(|left, right| left.id.cmp(&right.id));
    records
}

fn dashboard_lifecycle_stage_from_json_file(
    run_dir: &Path,
    id: &str,
    label: &str,
    present_state: &str,
    artifact_path: &str,
    array_field: &str,
) -> RunDashboardMutationLifecycleStage {
    let path = run_dir.join(artifact_path);
    if !path.is_file() {
        return dashboard_lifecycle_stage_from_records(
            id,
            label,
            "missing",
            Some(artifact_path),
            Vec::new(),
            Vec::new(),
            None,
        );
    }
    match read_json_value(&path) {
        Ok(value) => {
            let records = value
                .get(array_field)
                .and_then(|value| value.as_array())
                .cloned()
                .unwrap_or_else(|| vec![value]);
            let state = if id == "reviewed" {
                dashboard_review_state(&records)
            } else {
                present_state.to_string()
            };
            let mut evidence_refs = collect_json_evidence_refs(&records);
            push_unique_ref(&mut evidence_refs, artifact_path);
            dashboard_lifecycle_stage_from_records(
                id,
                label,
                &state,
                Some(artifact_path),
                records,
                evidence_refs,
                None,
            )
        }
        Err(error) => dashboard_lifecycle_stage_from_records(
            id,
            label,
            "malformed",
            Some(artifact_path),
            Vec::new(),
            Vec::new(),
            Some(error.to_string()),
        ),
    }
}

fn dashboard_lifecycle_stage_from_records(
    id: &str,
    label: &str,
    state: &str,
    artifact_path: Option<&str>,
    records: Vec<serde_json::Value>,
    evidence_refs: Vec<String>,
    read_error: Option<String>,
) -> RunDashboardMutationLifecycleStage {
    RunDashboardMutationLifecycleStage {
        id: id.to_string(),
        label: label.to_string(),
        state: state.to_string(),
        artifact_path: artifact_path.map(str::to_string),
        record_count: records.len(),
        evidence_refs,
        records,
        read_error,
    }
}

fn dashboard_sandbox_stage(run_dir: &Path) -> RunDashboardMutationLifecycleStage {
    let mut records = Vec::new();
    let sandbox_root = run_dir.join("sandbox");
    if let Ok(drafts) = fs::read_dir(&sandbox_root) {
        for draft in drafts.flatten() {
            let result_path = draft.path().join("evidence/result.json");
            if result_path.is_file() {
                if let Ok(value) = read_json_value(&result_path) {
                    records.push(value);
                }
            }
        }
    }
    let evidence_refs = collect_json_evidence_refs(&records);
    dashboard_lifecycle_stage_from_records(
        "sandboxed",
        "Sandboxed",
        if records.is_empty() {
            "missing"
        } else {
            "sandboxed"
        },
        Some("sandbox/*/evidence/result.json"),
        records,
        evidence_refs,
        None,
    )
}

fn dashboard_comparison_stage(run_dir: &Path) -> RunDashboardMutationLifecycleStage {
    let mut records = Vec::new();
    for path in dashboard_comparison_artifact_paths(run_dir) {
        if let Ok(value) = read_json_value(run_dir.join(&path)) {
            records.push(value);
        }
    }
    let evidence_refs = collect_json_evidence_refs(&records);
    dashboard_lifecycle_stage_from_records(
        "compared",
        "Compared",
        if records.is_empty() {
            "missing"
        } else {
            "compared"
        },
        Some("mutation/rerun-orchestration.json"),
        records,
        evidence_refs,
        None,
    )
}

fn dashboard_comparison_artifact_paths(run_dir: &Path) -> Vec<String> {
    let mut paths = Vec::new();
    if run_dir.join("mutation/rerun-orchestration.json").is_file() {
        paths.push("mutation/rerun-orchestration.json".to_string());
    }
    if let Ok(entries) = fs::read_dir(run_dir.join("mutation")) {
        for entry in entries.flatten() {
            let path = entry.path();
            let Some(name) = path.file_name().and_then(|value| value.to_str()) else {
                continue;
            };
            if name.starts_with("run-comparison-") && name.ends_with(".json") {
                paths.push(format!("mutation/{name}"));
            }
        }
    }
    paths.sort();
    paths
}

fn dashboard_review_state(records: &[serde_json::Value]) -> String {
    let mut has_pending = false;
    // Review decisions are append-only, so the CURRENT review outcome is the
    // latest terminal decision — scan newest-first so an accept followed by a
    // later reject reports "rejected", not the stale first decision.
    for record in records.iter().rev() {
        match record.get("state").and_then(|value| value.as_str()) {
            Some("accepted") => return "accepted".to_string(),
            Some("rejected") => return "rejected".to_string(),
            Some("pending_review") => has_pending = true,
            _ => {}
        }
    }
    if has_pending || !records.is_empty() {
        "pending_review".to_string()
    } else {
        "missing".to_string()
    }
}

fn dashboard_lifecycle_terminal_state(stages: &[RunDashboardMutationLifecycleStage]) -> String {
    stages
        .iter()
        .rev()
        .find(|stage| stage.state != "missing")
        .map(|stage| stage.state.clone())
        .unwrap_or_else(|| "missing".to_string())
}

fn dashboard_mutation_command_hints(
    run_dir: &Path,
    stages: &[RunDashboardMutationLifecycleStage],
) -> Vec<String> {
    let has_draft = stages
        .iter()
        .any(|stage| stage.id == "drafted" && stage.state != "missing");
    if !has_draft {
        return Vec::new();
    }
    let run_path = run_dir.to_string_lossy();
    vec![
        format!(
            "cargo run -p ouroforge-cli -- mutation review {run_path} --accept --reason \"manual evidence review accepted\""
        ),
        format!(
            "cargo run -p ouroforge-cli -- mutation review {run_path} --reject --reason \"manual evidence review rejected\""
        ),
    ]
}

fn collect_json_evidence_refs(values: &[serde_json::Value]) -> Vec<String> {
    let mut refs = BTreeSet::new();
    for value in values {
        collect_json_evidence_refs_inner(value, &mut refs);
    }
    refs.into_iter().collect()
}

fn collect_json_evidence_refs_inner(value: &serde_json::Value, refs: &mut BTreeSet<String>) {
    match value {
        serde_json::Value::String(text)
            if text.starts_with("evidence/")
                || text.starts_with("mutation/")
                || text.starts_with("sandbox/") =>
        {
            refs.insert(text.clone());
        }
        serde_json::Value::Array(items) => {
            for item in items {
                collect_json_evidence_refs_inner(item, refs);
            }
        }
        serde_json::Value::Object(map) => {
            for value in map.values() {
                collect_json_evidence_refs_inner(value, refs);
            }
        }
        _ => {}
    }
}

fn read_json_value(path: impl AsRef<Path>) -> Result<serde_json::Value> {
    let path = path.as_ref();
    let input = fs::read_to_string(path)
        .with_context(|| format!("failed to read JSON file {}", path.display()))?;
    serde_json::from_str(&input)
        .with_context(|| format!("failed to parse JSON file {}", path.display()))
}

fn json_string(value: &serde_json::Value, field: &str) -> Option<String> {
    value
        .get(field)
        .and_then(|value| value.as_str())
        .map(str::to_string)
}

