pub fn hash_project_manifest_file(path: impl AsRef<Path>) -> Result<ProjectArtifactHash> {
    let path = path.as_ref();
    let bytes = fs::read(path)
        .with_context(|| format!("failed to read project manifest {}", path.display()))?;
    Ok(ProjectArtifactHash {
        algorithm: "fnv1a64-file-v1".to_string(),
        value: format!("{:016x}", fnv1a64(&bytes)),
    })
}

pub fn project_run_metadata_from_manifest(
    manifest_path: impl AsRef<Path>,
    seed_path: impl AsRef<Path>,
    scenario_pack_id: Option<&str>,
) -> Result<ProjectRunMetadata> {
    let manifest_path = manifest_path.as_ref();
    let manifest = ProjectManifest::from_path(manifest_path)?;
    let project_root = manifest_path
        .parent()
        .filter(|path| !path.as_os_str().is_empty())
        .unwrap_or_else(|| Path::new("."));
    let seed_path = seed_path.as_ref();
    let relative_seed_path = project_relative_path(project_root, seed_path)?;
    if !manifest
        .seeds
        .iter()
        .any(|reference| reference.path == relative_seed_path)
    {
        return Err(anyhow!(
            "project run seed {} is not declared in project manifest seeds",
            relative_seed_path
        ));
    }
    let manifest_hash = hash_project_manifest_file(manifest_path)?;
    let mut scenes = Vec::new();
    for scene_ref in &manifest.scenes {
        let scene_path = project_root.join(&scene_ref.path);
        let scene = read_scene(&scene_path)
            .with_context(|| format!("failed to read project scene {}", scene_ref.path))?;
        scenes.push(ProjectRunSceneMetadata {
            id: scene_ref.id.clone(),
            path: scene_ref.path.clone(),
            hash: hash_scene_document(&scene)?,
        });
    }
    let resolved_packs = manifest.resolve_scenario_packs(project_root)?;
    let scenario_pack = match scenario_pack_id {
        Some(id) => {
            let pack_ref = manifest
                .scenario_packs
                .iter()
                .find(|reference| reference.id == id)
                .ok_or_else(|| anyhow!("scenario pack id not found in project manifest: {id}"))?;
            let pack = resolved_packs
                .iter()
                .find(|pack| pack.id == id)
                .ok_or_else(|| anyhow!("scenario pack id did not resolve: {id}"))?;
            Some(ProjectRunScenarioPackMetadata {
                id: pack.id.clone(),
                path: pack_ref.path.clone(),
                scenario_ids: pack.ordered_scenario_ids(),
            })
        }
        None => None,
    };
    Ok(ProjectRunMetadata {
        id: manifest.project.id,
        name: manifest.project.name,
        project_root: project_root.to_string_lossy().to_string(),
        manifest_path: manifest_path.to_string_lossy().to_string(),
        manifest_hash,
        seed_path: relative_seed_path,
        scenes,
        scenario_pack,
        transaction_id: None,
    })
}

pub fn run_command_context_for_run(
    seed_path: impl AsRef<Path>,
    runs_root: impl AsRef<Path>,
    workers: usize,
    project: Option<&ProjectRunMetadata>,
    transaction_path: Option<&Path>,
) -> RunCommandContext {
    let seed_path = seed_path.as_ref().to_string_lossy().to_string();
    let runs_root = runs_root.as_ref().to_string_lossy().to_string();
    let project_root = project.map(|metadata| metadata.project_root.clone());
    let manifest_path = project.map(|metadata| metadata.manifest_path.clone());
    let scenario_pack_id = project
        .and_then(|metadata| metadata.scenario_pack.as_ref())
        .map(|pack| pack.id.clone());
    let transaction_path = transaction_path.map(|path| path.to_string_lossy().to_string());

    let mut argv = vec![
        "cargo".to_string(),
        "run".to_string(),
        "-p".to_string(),
        "ouroforge-cli".to_string(),
        "--".to_string(),
        "run".to_string(),
        seed_path.clone(),
    ];
    if let Some(project_root) = &project_root {
        argv.push("--project".to_string());
        argv.push(project_root.clone());
    }
    argv.push("--workers".to_string());
    argv.push(workers.to_string());
    if let Some(scenario_pack_id) = &scenario_pack_id {
        argv.push("--scenario-pack".to_string());
        argv.push(scenario_pack_id.clone());
    }
    if let Some(transaction_path) = &transaction_path {
        argv.push("--transaction".to_string());
        argv.push(transaction_path.clone());
    }
    let command = argv
        .iter()
        .map(|arg| shell_quote_command_arg(arg))
        .collect::<Vec<_>>()
        .join(" ");

    RunCommandContext {
        schema_version: "run-command-context-v1".to_string(),
        command,
        argv,
        seed_path,
        workers,
        runs_root,
        project_root,
        manifest_path,
        scenario_pack_id,
        transaction_path,
        runtime_target: "local-static-browser".to_string(),
        browser_boundary: "openchrome_cdp".to_string(),
        cdp_transport: "chrome_devtools_protocol".to_string(),
        environment_hints: vec![
            "Local Chrome/CDP is required for browser smoke and scenario execution.".to_string(),
            "Generated run artifacts stay under the recorded runs root and remain untracked."
                .to_string(),
            "Dashboard and cockpit surfaces may display this context but must not execute it."
                .to_string(),
        ],
    }
}

fn shell_quote_command_arg(arg: &str) -> String {
    if !arg.is_empty()
        && arg
            .chars()
            .all(|ch| ch.is_ascii_alphanumeric() || matches!(ch, '/' | '.' | '_' | '-' | ':' | '='))
    {
        return arg.to_string();
    }
    format!("'{}'", arg.replace('\'', "'\\''"))
}

pub fn bind_run_command_context(
    run_dir: impl AsRef<Path>,
    context: RunCommandContext,
) -> Result<RunCommandContext> {
    let run_dir = run_dir.as_ref();
    let run_path = run_dir.join("run.json");
    let mut run = read_json_value(&run_path)?;
    let run_object = run
        .as_object_mut()
        .ok_or_else(|| anyhow!("run.json must be a JSON object"))?;
    run_object.insert("run_command_context".to_string(), json!(context.clone()));
    write_json_atomic(&run_path, &run)?;
    append_ledger_event(
        run_dir,
        "run.command_context_recorded",
        "run-core",
        json!({
            "schema_version": context.schema_version,
            "seed_path": context.seed_path,
            "workers": context.workers,
            "runs_root": context.runs_root,
            "project_root": context.project_root,
            "manifest_path": context.manifest_path,
            "scenario_pack_id": context.scenario_pack_id,
            "transaction_path": context.transaction_path,
            "runtime_target": context.runtime_target,
            "browser_boundary": context.browser_boundary,
            "cdp_transport": context.cdp_transport
        }),
    )?;
    Ok(context)
}

pub fn bind_run_project_metadata(
    run_dir: impl AsRef<Path>,
    metadata: ProjectRunMetadata,
) -> Result<ProjectRunMetadata> {
    let run_dir = run_dir.as_ref();
    let run_path = run_dir.join("run.json");
    let mut run = read_json_value(&run_path)?;
    let run_object = run
        .as_object_mut()
        .ok_or_else(|| anyhow!("run.json must be a JSON object"))?;
    run_object.insert("project".to_string(), json!(metadata.clone()));
    write_json_atomic(&run_path, &run)?;
    append_ledger_event(
        run_dir,
        "run.project_bound",
        "run-core",
        json!({
            "project_id": metadata.id,
            "manifest_path": metadata.manifest_path,
            "manifest_hash": metadata.manifest_hash,
            "seed_path": metadata.seed_path,
            "scene_paths": metadata.scenes.iter().map(|scene| scene.path.clone()).collect::<Vec<_>>(),
            "scenario_pack_id": metadata.scenario_pack.as_ref().map(|pack| pack.id.clone()),
            "transaction_id": metadata.transaction_id
        }),
    )?;
    Ok(metadata)
}

fn project_relative_path(root: &Path, path: &Path) -> Result<String> {
    let relative = if path.is_absolute() {
        path.strip_prefix(root).with_context(|| {
            format!(
                "{} is outside project root {}",
                path.display(),
                root.display()
            )
        })?
    } else if path.starts_with(root) {
        path.strip_prefix(root).unwrap_or(path)
    } else {
        path
    };
    relative
        .to_str()
        .map(str::to_string)
        .ok_or_else(|| anyhow!("project-relative path is not valid UTF-8"))
}

pub fn create_run(
    seed_path: impl AsRef<Path>,
    runs_root: impl AsRef<Path>,
) -> Result<RunArtifacts> {
    let seed_path = seed_path.as_ref();
    let runs_root = runs_root.as_ref();
    let seed_yaml = fs::read_to_string(seed_path)
        .with_context(|| format!("failed to read Seed file {}", seed_path.display()))?;
    let seed = Seed::from_path(seed_path)?;
    let seed_base_dir = seed_path.parent().unwrap_or_else(|| Path::new("."));

    fs::create_dir_all(runs_root)
        .with_context(|| format!("failed to create runs root {}", runs_root.display()))?;

    let created_at_unix_ms = unix_millis()?;
    let run_id = format!("run-{created_at_unix_ms}-{}", std::process::id());
    let run_dir = runs_root.join(&run_id);
    fs::create_dir(&run_dir)
        .with_context(|| format!("failed to create run directory {}", run_dir.display()))?;
    fs::create_dir(run_dir.join("evidence")).context("failed to create evidence directory")?;

    let command_context = run_command_context_for_run(seed_path, runs_root, 1, None, None);
    write_json(
        &run_dir.join("run.json"),
        &json!({
            "id": run_id,
            "seed_id": seed.id,
            "seed_title": seed.title,
            "status": "created",
            "created_at_unix_ms": created_at_unix_ms,
            "run_command_context": command_context,
        }),
    )?;
    fs::write(run_dir.join("seed.snapshot.yaml"), seed_yaml)
        .context("failed to write seed snapshot")?;
    copy_replay_references_to_run(&seed, seed_base_dir, &run_dir)?;
    write_ledger_created(&run_dir.join("ledger.jsonl"), created_at_unix_ms)?;
    fs::write(run_dir.join("journal.md"), initial_journal()).context("failed to write journal")?;
    write_json(
        &run_dir.join("verdict.json"),
        &json!({ "status": "pending" }),
    )?;
    write_evidence_index(
        &run_dir,
        &EvidenceIndex {
            artifacts: Vec::new(),
        },
    )?;
    if seed.id == "evolve.v1.demo" {
        materialize_evolve_demo_controlled_failure(&run_dir)?;
    }

    Ok(RunArtifacts { run_dir })
}

fn materialize_evolve_demo_controlled_failure(run_dir: &Path) -> Result<()> {
    let scenario_result_rel = "evidence/scenarios/evolve-controlled-failure/scenario-result.json";
    let scenario_result_path = run_dir.join(scenario_result_rel);
    if let Some(parent) = scenario_result_path.parent() {
        fs::create_dir_all(parent).with_context(|| {
            format!(
                "failed to create scenario evidence directory {}",
                parent.display()
            )
        })?;
    }
    write_json(
        &scenario_result_path,
        &json!({
            "schema_version": "1",
            "artifact": "scenario_result",
            "scenario_id": "evolve-controlled-failure",
            "status": "failed",
            "summary": "controlled assertion failure for evolve demo",
            "failures": [{
                "kind": "scenario_assertion_failure",
                "assertion": "world_state.object.x equals 999",
                "actual": 0,
                "expected": 999,
                "evidence_ref": scenario_result_rel
            }]
        }),
    )?;
    add_evidence_artifact(
        run_dir,
        "scenario-result-evolve-controlled-failure",
        "application/json",
        scenario_result_rel,
        json!({
            "artifact": "scenario_result",
            "scenario_id": "evolve-controlled-failure",
            "status": "failed",
            "controlled_demo": true
        }),
    )?;
    write_json(
        &run_dir.join("verdict.json"),
        &json!({
            "status": "failed",
            "summary": "controlled evolve demo scenario assertion failure",
            "failures": [{
                "kind": "scenario_assertion_failure",
                "path": scenario_result_rel,
                "evidence_ref": scenario_result_rel,
                "scenario_id": "evolve-controlled-failure"
            }],
            "evidence_refs": [scenario_result_rel],
            "metadata": {
                "evaluator": "ouroforge-evolve-demo-smoke-v1",
                "controlled_demo": true
            }
        }),
    )?;
    append_ledger_event(
        run_dir,
        "scenario.completed",
        "run-cli",
        json!({
            "scenario_id": "evolve-controlled-failure",
            "status": "failed",
            "path": scenario_result_rel,
            "controlled_demo": true
        }),
    )?;
    update_journal(run_dir)?;
    Ok(())
}

fn copy_replay_references_to_run(seed: &Seed, seed_base_dir: &Path, run_dir: &Path) -> Result<()> {
    let mut copied = std::collections::BTreeSet::new();
    for replay_ref in seed.replay_references() {
        if !copied.insert(replay_ref.path.clone()) {
            continue;
        }
        let source = seed_base_dir.join(&replay_ref.path);
        let target = run_dir.join(&replay_ref.path);
        if let Some(parent) = target.parent() {
            fs::create_dir_all(parent).with_context(|| {
                format!("failed to create replay directory {}", parent.display())
            })?;
        }
        fs::copy(&source, &target).with_context(|| {
            format!(
                "failed to copy replay reference {} to {}",
                source.display(),
                target.display()
            )
        })?;
    }
    Ok(())
}

fn unix_millis() -> Result<u128> {
    Ok(SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .context("system clock is before UNIX_EPOCH")?
        .as_millis())
}

fn write_json(path: &Path, value: &serde_json::Value) -> Result<()> {
    let body = serde_json::to_string_pretty(value).context("failed to serialize JSON")?;
    fs::write(path, format!("{body}\n"))
        .with_context(|| format!("failed to write {}", path.display()))
}

fn write_json_atomic(path: &Path, value: &serde_json::Value) -> Result<()> {
    let body = serde_json::to_string_pretty(value).context("failed to serialize JSON")?;
    let temp_path = path.with_extension(format!(
        "json.tmp-{}-{}",
        std::process::id(),
        unix_millis()?
    ));
    fs::write(&temp_path, format!("{body}\n"))
        .with_context(|| format!("failed to write {}", temp_path.display()))?;
    fs::rename(&temp_path, path).with_context(|| {
        format!(
            "failed to replace {} with {}",
            path.display(),
            temp_path.display()
        )
    })
}

fn write_ledger_created(path: &Path, created_at_unix_ms: u128) -> Result<()> {
    let mut file =
        File::create(path).with_context(|| format!("failed to write {}", path.display()))?;
    let line = serde_json::to_string(&json!({
        "event": "run.created",
        "created_at_unix_ms": created_at_unix_ms,
    }))
    .context("failed to serialize ledger event")?;
    writeln!(file, "{line}").context("failed to write ledger event")
}

fn initial_journal() -> &'static str {
    "# Ouroforge Run Journal\n\n## Seed\n\n## Hypothesis\n\n## Observations\n\n## Evidence\n\n## Verdict\n\n## Next Mutation\n"
}

