    #[test]
    fn production_task_board_v1_rejects_duplicate_ids_cycles_and_ownership_conflicts() {
        let body = read_json_fixture(
            "examples/multi-agent-pipeline-v1/production-task-board.fixture.json",
        );
        let base: serde_json::Value = serde_json::from_str(&body).expect("fixture json");

        let mut duplicate = base.clone();
        let duplicated_task = duplicate["tasks"][0].clone();
        duplicate["tasks"]
            .as_array_mut()
            .unwrap()
            .push(duplicated_task);
        let duplicate_error = ProductionTaskBoard::from_json_str(&duplicate.to_string())
            .expect_err("duplicate task id rejects board");
        assert!(duplicate_error.to_string().contains("duplicate"));

        let mut cycle = base.clone();
        cycle["tasks"][0]["dependsOn"] = json!(["task-board-schema"]);
        let cycle_error = ProductionTaskBoard::from_json_str(&cycle.to_string())
            .expect_err("dependency cycle rejects board");
        assert!(cycle_error.to_string().contains("cycle"));

        let mut conflict = base.clone();
        conflict["tasks"][2]["targetArtifacts"][0]["id"] =
            conflict["tasks"][1]["targetArtifacts"][0]["id"].clone();
        conflict["tasks"][2]["targetArtifacts"][0]["path"] =
            conflict["tasks"][1]["targetArtifacts"][0]["path"].clone();
        let conflict_error = ProductionTaskBoard::from_json_str(&conflict.to_string())
            .expect_err("duplicate target ownership rejects board");
        assert!(conflict_error.to_string().contains("ownership conflict"));

        // Cross-namespace: one task's artifact path equal to another task's
        // artifact id (different owners) is NOT an ownership conflict — ids and
        // paths are separate namespaces.
        let mut cross_namespace = base.clone();
        cross_namespace["tasks"][2]["targetArtifacts"][0]["path"] =
            cross_namespace["tasks"][1]["targetArtifacts"][0]["id"].clone();
        ProductionTaskBoard::from_json_str(&cross_namespace.to_string())
            .expect("artifact path matching a different task's id is not an ownership conflict");
    }

    #[test]
    fn production_task_board_v1_enforces_status_transition_matrix() {
        let body = read_json_fixture(
            "examples/multi-agent-pipeline-v1/production-task-board.fixture.json",
        );
        let mut board: serde_json::Value = serde_json::from_str(&body).expect("fixture json");

        board["tasks"][1]["status"] = json!("completed");
        board["tasks"][1]["timestamps"]["completedAt"] = json!("2026-06-04T16:30:00Z");
        board["tasks"][1]["statusTransition"] = json!({
            "from": "assigned",
            "to": "completed"
        });
        let invalid_transition = ProductionTaskBoard::from_json_str(&board.to_string())
            .expect_err("assigned cannot jump directly to completed");
        assert!(invalid_transition.to_string().contains("cannot transition"));

        board["tasks"][1]["status"] = json!("in-progress");
        board["tasks"][1]["statusTransition"] = json!({
            "from": "assigned",
            "to": "in-progress"
        });
        board["tasks"][1]["timestamps"]
            .as_object_mut()
            .unwrap()
            .remove("completedAt");
        let valid = ProductionTaskBoard::from_json_str(&board.to_string())
            .expect("assigned to in-progress is a valid metadata transition");
        assert_eq!(valid.tasks[1].status, ProductionTaskStatus::InProgress);
    }

    #[test]
    fn production_task_board_read_model_summarizes_ready_blocked_and_malformed_state() {
        let ready = production_task_board_read_model_from_json_str(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/production-task-board.fixture.json",
        ));
        assert_eq!(
            ready.schema_version,
            PRODUCTION_TASK_BOARD_READ_MODEL_SCHEMA_VERSION
        );
        assert_eq!(ready.board_id, "multi-agent-production-v1");
        assert_eq!(ready.status, "ready-for-review");
        assert_eq!(ready.task_count, 3);
        assert!(ready.boundary.contains("does not execute tasks"));

        let blocked = production_task_board_read_model_from_json_str(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/production-task-board.blocked.fixture.json",
        ));
        assert_eq!(blocked.status, "blocked");
        assert!(blocked
            .blockers
            .iter()
            .any(|blocker| blocker.contains("ownership-policy")));

        let malformed = production_task_board_read_model_from_json_str(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/production-task-board.malformed.fixture.json",
        ));
        assert_eq!(malformed.status, "malformed");
        assert!(malformed
            .malformed_reasons
            .iter()
            .any(|reason| reason.contains("requiredEvidence")));
    }

    #[test]
    fn multi_agent_pipeline_scope_contract_preserves_v1_boundaries() {
        let doc = fs::read_to_string(repo_fixture_path(
            "docs/multi-agent-production-pipeline-v1.md",
        ))
        .expect("multi-agent production pipeline scope doc reads");

        for required in [
            "local-first, evidence-gated collaboration",
            "Agent outputs are untrusted proposals",
            "Browser, dashboard, and Studio surfaces are read-only or draft-only",
            "No self-review, auto-apply, auto-merge",
            "Generated task boards, handoffs, work packages, snapshots, evidence bundles, runs, traces, screenshots, dashboard exports, temporary projects, and local tool state remain untracked unless explicitly fixture-scoped",
            "#666",
            "#680",
            "#1/#23 remaining open",
            "current Godot replacement",
        ] {
            assert!(
                doc.contains(required),
                "scope doc is missing required boundary: {required}"
            );
        }

        let non_goal_section = doc
            .split("## Explicit non-goals")
            .nth(1)
            .expect("non-goals section exists");
        for forbidden in [
            "hidden background agents",
            "remote worker pools",
            "browser command bridges",
            "dependency mutation",
            "CI/workflow/build-script mutation",
            "native export/platform packaging implementation",
        ] {
            assert!(
                non_goal_section.contains(forbidden),
                "non-goals must keep {forbidden} out of scope"
            );
        }
    }

    #[test]
    fn agent_role_model_v1_rejects_duplicate_and_underbounded_roles() {
        let body = read_json_fixture("examples/multi-agent-pipeline-v1/agent-roles.fixture.json");
        let mut value: serde_json::Value = serde_json::from_str(&body).expect("fixture json");
        let duplicate = value["roles"][0].clone();
        value["roles"].as_array_mut().unwrap().push(duplicate);
        let error = AgentRoleModel::from_json_str(&value.to_string()).unwrap_err();
        assert!(error.to_string().contains("duplicated"));

        let mut unsafe_value: serde_json::Value =
            serde_json::from_str(&body).expect("fixture json");
        unsafe_value["roles"][0]["forbiddenActions"] = json!(["trusted source write"]);
        let error = AgentRoleModel::from_json_str(&unsafe_value.to_string()).unwrap_err();
        assert!(error.to_string().contains("self-approval"));
    }

    #[test]
    fn multi_agent_demo_pipeline_fixtures_validate_task_board_handoff_and_boundaries() {
        let role_body =
            read_json_fixture("examples/multi-agent-pipeline-v1/agent-roles.fixture.json");
        let roles = AgentRoleModel::from_json_str(&role_body).expect("role fixture validates");
        let role_names = roles
            .roles
            .iter()
            .map(|role| role.role.as_str())
            .collect::<BTreeSet<_>>();

        let plan_body =
            read_json_fixture("examples/multi-agent-pipeline-v1/demo-task-board.fixture.json");
        let plan = AuthoringLoopPlan::from_json_str(&plan_body)
            .expect("multi-agent demo task board fixture validates");
        assert_eq!(plan.loop_id, "multi-agent-demo-fixture");
        assert_eq!(plan.steps.len(), 8);
        assert!(plan.generated_state.tracked_fixture_only);
        assert!(plan
            .generated_state
            .roots
            .iter()
            .any(|root| root == "runs/multi-agent-pipeline"));
        assert!(plan.steps.iter().any(|step| {
            step.id == "trusted-apply-placeholder"
                && step.kind == AuthoringLoopStepKind::ApplyAcceptedSceneMutation
                && !step.rollback_refs.is_empty()
                && !step.required_decisions.is_empty()
        }));
        assert!(plan.steps.iter().any(|step| step.id == "qa-queue-lane"));
        assert!(plan
            .steps
            .iter()
            .any(|step| step.id == "performance-regression-lane"));

        let handoff_body =
            read_json_fixture("examples/multi-agent-pipeline-v1/demo-handoff-v2.fixture.json");
        let handoff = AgentHandoffContract::from_json_str(&handoff_body)
            .expect("multi-agent demo handoff fixture validates");
        assert_eq!(handoff.loop_id, plan.loop_id);
        assert_eq!(handoff.status, AgentHandoffStatus::Ready);
        assert!(handoff
            .allowed_commands
            .iter()
            .all(|command| command.boundary.contains("inert")
                || command.boundary.contains("does not execute")));
        assert!(handoff
            .forbidden_actions
            .iter()
            .any(|action| action.contains("hidden background agents")));
        assert!(handoff
            .forbidden_actions
            .iter()
            .any(|action| action.contains("remote worker pool")));
        assert!(handoff
            .drift_guardrails
            .iter()
            .any(|guardrail| guardrail.contains("#1 remains open")));
        assert!(handoff
            .drift_guardrails
            .iter()
            .any(|guardrail| guardrail.contains("#23 remains open")));

        let bundle = build_authoring_loop_evidence_bundle(
            &plan,
            repo_fixture_path("examples/multi-agent-pipeline-v1"),
            repo_fixture_path("examples/multi-agent-pipeline-v1/demo-task-board.fixture.json"),
        )
        .expect("demo bundle read model builds from fixture-scoped plan");
        assert_eq!(bundle.loop_id, "multi-agent-demo-fixture");
        assert_eq!(bundle.status, AuthoringLoopEvidenceBundleStatus::Partial);
        assert!(
            !bundle.missing_refs.is_empty(),
            "tracked fixture intentionally does not materialize generated run artifacts"
        );
        assert!(bundle.generated_state.tracked_fixture_only);

        let handoff_v2_body = read_json_fixture(
            "examples/multi-agent-pipeline-v1/agent-handoff-v2.blocked.fixture.json",
        );
        let handoff_v2 = AgentHandoffV2::from_json_str(&handoff_v2_body)
            .expect("handoff v2 fixture validates for cockpit projection");
        let cockpit = build_studio_loop_cockpit_read_model(
            std::slice::from_ref(&bundle),
            std::slice::from_ref(&handoff),
            std::slice::from_ref(&handoff_v2),
        );
        assert_eq!(cockpit.loops.len(), 2);
        let v1_loop = cockpit
            .loops
            .iter()
            .find(|loop_row| loop_row.loop_id == "multi-agent-demo-fixture")
            .expect("v1 handoff loop remains present");
        assert_eq!(v1_loop.handoff_status.as_deref(), Some("ready"));
        assert_eq!(v1_loop.bundle_status.as_deref(), Some("partial"));
        let v2_loop = cockpit
            .loops
            .iter()
            .find(|loop_row| loop_row.handoff_id.as_deref() == Some("handoff-v2-blocked"))
            .expect("v2 handoff projection remains present");
        assert_eq!(v2_loop.loop_id, "task-board-schema");
        assert_eq!(v2_loop.handoff_status.as_deref(), Some("blocked"));
        assert_eq!(v2_loop.from_role.as_deref(), Some("designer"));
        assert_eq!(v2_loop.to_role.as_deref(), Some("reviewer"));
        assert!(!v2_loop.open_risks.is_empty());
        assert!(!v2_loop.acceptance_checklist.is_empty());
        assert!(cockpit.boundary.contains("does not execute commands"));

        let ownership: serde_json::Value = serde_json::from_str(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/demo-ownership-conflicts.fixture.json",
        ))
        .expect("ownership fixture parses");
        assert_eq!(
            ownership["schemaVersion"],
            json!("multi-agent-demo-ownership-report-v1")
        );
        let assignments = ownership["assignments"]
            .as_array()
            .expect("assignments array");
        assert!(assignments.iter().all(|assignment| {
            assignment["role"]
                .as_str()
                .is_some_and(|role| role_names.contains(role))
                && assignment["writeAuthority"] == json!("fixture-metadata-only")
        }));
        let conflicts = ownership["conflicts"].as_array().expect("conflicts array");
        assert!(conflicts.iter().any(|conflict| {
            conflict["status"] == json!("unresolved")
                && conflict["blockedReason"]
                    .as_str()
                    .is_some_and(|reason| reason.contains("Rust validation"))
        }));
        assert!(ownership["boundary"]
            .as_str()
            .expect("ownership boundary")
            .contains("does not lock files"));

        let snapshot: serde_json::Value = serde_json::from_str(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/demo-state-snapshot.fixture.json",
        ))
        .expect("state snapshot fixture parses");
        assert_eq!(
            snapshot["schemaVersion"],
            json!("multi-agent-demo-state-snapshot-v1")
        );
        assert_eq!(snapshot["staleness"]["status"], json!("stale"));
        assert!(snapshot["guardrails"]
            .as_array()
            .expect("guardrails")
            .iter()
            .any(|guardrail| guardrail
                .as_str()
                .is_some_and(|text| text.contains("no browser trusted writes"))));
        assert!(snapshot["boundary"]
            .as_str()
            .expect("snapshot boundary")
            .contains("does not mutate task boards"));
    }

    #[test]
    fn multi_agent_demo_pipeline_qa_review_bundle_flow_stays_inert_and_complete() {
        let flow: serde_json::Value = serde_json::from_str(&read_json_fixture(
            "examples/multi-agent-pipeline-v1/demo-qa-review-flow.fixture.json",
        ))
        .expect("demo QA/review flow fixture parses");
        assert_eq!(
            flow["schemaVersion"],
            json!("multi-agent-demo-qa-review-flow-v1")
        );
        assert_eq!(flow["qaQueue"]["status"], json!("queued"));
        assert!(flow["qaQueue"]["workerAssignment"]["boundary"]
            .as_str()
            .expect("worker boundary")
            .contains("does not spawn workers"));
        assert_eq!(
            flow["performanceRegressionLane"]["status"],
            json!("blocked-until-qa-evidence-refresh")
        );
        assert!(flow["performanceRegressionLane"]["forbiddenClaims"]
            .as_array()
            .expect("forbidden claims")
            .iter()
            .any(|claim| claim == "production ready"));
        assert_ne!(
            flow["reviewGate"]["reviewer"], flow["reviewGate"]["critic"],
            "reviewer and critic identities stay independent"
        );
        assert_eq!(flow["decisionLedger"]["appendOnly"], json!(true));
        let events = flow["decisionLedger"]["events"]
            .as_array()
            .expect("decision events");
        assert!(events.iter().any(|event| {
            event["kind"] == json!("multi_agent.review_decision")
                && event["actor"] == flow["reviewGate"]["reviewer"]
        }));
        assert!(events.iter().any(|event| {
            event["kind"] == json!("multi_agent.critic_finding")
                && event["actor"] == flow["reviewGate"]["critic"]
        }));
        let guardrails = flow["guardrails"]
            .as_array()
            .expect("flow guardrails")
            .iter()
            .filter_map(|value| value.as_str())
            .collect::<Vec<_>>()
            .join(" ");
        for required in [
            "no hidden background agents",
            "no unbounded spawning",
            "no auto-apply",
            "no browser trusted writes",
            "no remote worker pool",
        ] {
            assert!(
                guardrails.contains(required),
                "flow guardrails include {required}"
            );
        }
        assert!(flow["boundary"]
            .as_str()
            .expect("flow boundary")
            .contains("does not run QA workers"));

        let bundle_body =
            read_json_fixture("examples/multi-agent-pipeline-v1/demo-evidence-bundle.fixture.json");
        let bundle = AuthoringLoopEvidenceBundle::from_json_str(&bundle_body)
            .expect("demo evidence bundle fixture validates");
        assert_eq!(bundle.loop_id, "multi-agent-demo-fixture");
        assert_eq!(bundle.status, AuthoringLoopEvidenceBundleStatus::Completed);
        assert!(bundle.missing_refs.is_empty());
        assert!(bundle.generated_state.tracked_fixture_only);
        assert_eq!(bundle.steps.len(), 3);
        assert_eq!(bundle.runs.len(), 1);
        assert_eq!(bundle.comparisons.len(), 1);
        assert_eq!(bundle.proposals.len(), 1);
        assert_eq!(bundle.review_decisions.len(), 1);
        assert_eq!(bundle.transactions.len(), 1);
        assert_eq!(bundle.regression_promotions.len(), 1);
        assert_eq!(bundle.matrix_snapshots.len(), 1);
        assert_eq!(bundle.journal_summaries.len(), 1);
        assert!(bundle
            .steps
            .iter()
            .all(|step| step.missing_refs.is_empty() && !step.outputs.is_empty()));
        assert!(bundle.boundary.contains("does not move artifacts"));
        assert!(bundle.boundary.contains("spawn agents"));
        assert!(bundle.boundary.contains("claim production readiness"));

        let cockpit = build_studio_loop_cockpit_read_model(std::slice::from_ref(&bundle), &[], &[]);
        assert_eq!(cockpit.loops.len(), 1);
        assert_eq!(cockpit.loops[0].bundle_status.as_deref(), Some("completed"));
        assert!(cockpit.loops[0].bundle_missing_refs.is_empty());
        assert!(cockpit.boundary.contains("does not execute commands"));
    }

    #[test]
    fn agent_role_model_v1_rejects_unsupported_roles_and_forbidden_outputs() {
        let invalid =
            read_json_fixture("examples/multi-agent-pipeline-v1/agent-roles.invalid.fixture.json");
        let error = AgentRoleModel::from_json_str(&invalid).unwrap_err();
        assert!(error.to_string().contains("unsupported"));

        let body = read_json_fixture("examples/multi-agent-pipeline-v1/agent-roles.fixture.json");
        let mut value: serde_json::Value = serde_json::from_str(&body).expect("fixture json");
        value["roles"][0]["allowedOutputs"] = json!(["auto-apply"]);
        let error = AgentRoleModel::from_json_str(&value.to_string()).unwrap_err();
        assert!(error.to_string().contains("forbidden output authority"));

        let mut missing_evidence: serde_json::Value =
            serde_json::from_str(&body).expect("fixture json");
        missing_evidence["roles"][0]["requiredEvidence"] = json!([]);
        let error = AgentRoleModel::from_json_str(&missing_evidence.to_string()).unwrap_err();
        assert!(error.to_string().contains("requiredEvidence"));
    }

