    #[test]
    fn visual_edit_scene_draft_v1_rejects_stale_hash_missing_entity_and_unsupported_paths() {
        let scene =
            read_scene(repo_fixture_path("examples/game-runtime/scene.json")).expect("scene reads");

        let mut stale = valid_scene_visual_edit_draft_for_scene(&scene);
        stale.before_hash =
            "sha256:9999999999999999999999999999999999999999999999999999999999999999".to_string();
        let error = stale
            .validate_scene_preflight(&scene)
            .expect_err("stale hash fails");
        assert!(error.to_string().contains("beforeHash mismatch"));

        let mut missing_entity = valid_scene_visual_edit_draft_for_scene(&scene);
        missing_entity.proposed_operations[0]
            .scene_operation
            .as_mut()
            .expect("scene operation")
            .entity_id = "missing-player".to_string();
        let error = missing_entity
            .validate_scene_preflight(&scene)
            .expect_err("missing entity fails");
        assert!(error.to_string().contains("failed preflight"));

        let mut unsupported_path = valid_scene_visual_edit_draft_for_scene(&scene);
        unsupported_path.proposed_operations[0]
            .scene_operation
            .as_mut()
            .expect("scene operation")
            .scene_edit_path = "components.collider.sensor".to_string();
        let error = unsupported_path
            .validate_scene_preflight(&scene)
            .expect_err("unsupported path fails");
        assert!(error
            .to_string()
            .contains("unsupported visual edit scene draft path"));

        let mut unsupported_kind = valid_scene_visual_edit_draft_for_scene(&scene);
        unsupported_kind.proposed_operations[0]
            .scene_operation
            .as_mut()
            .expect("scene operation")
            .kind = VisualEditSceneDraftOperationKind::ColliderToggle;
        unsupported_kind.proposed_operations[0]
            .scene_operation
            .as_mut()
            .expect("scene operation")
            .scene_edit_path = "components.collider.sensor".to_string();
        let error = unsupported_kind
            .validate_scene_preflight(&scene)
            .expect_err("unsupported kind fails");
        assert!(error
            .to_string()
            .contains("not supported by scene edit transaction preflight yet"));
    }

    #[test]
    fn visual_edit_scene_draft_v1_generates_transaction_previews_without_apply() {
        let scene_path = repo_fixture_path("examples/game-runtime/scene.json");
        let before_bytes = fs::read(&scene_path).expect("scene bytes read before preview");
        let scene = read_scene(&scene_path).expect("scene reads");
        let before_hash = hash_scene_document(&scene).expect("scene hashes");
        let draft = valid_scene_visual_edit_draft_for_scene(&scene);

        let transactions = draft
            .preview_scene_edit_transactions(&scene_path)
            .expect("scene draft previews transactions");

        assert_eq!(transactions.len(), 2);
        for transaction in &transactions {
            assert_eq!(
                transaction.schema_version,
                "ouroforge.scene-edit-transaction.v1"
            );
            assert_eq!(transaction.scene_path, scene_path.to_string_lossy());
            assert_eq!(transaction.before_scene_hash, before_hash);
            assert_eq!(transaction.validation_result.status, "passed");
            assert!(transaction.after_scene_hash.is_some());
            assert!(transaction.rollback.strategy.contains("beforeSceneHash"));
        }
        assert_eq!(transactions[0].edit.path, "components.transform.x");
        assert_eq!(transactions[1].edit.path, "sprite.color");
        assert_eq!(
            fs::read(&scene_path).expect("scene bytes read after preview"),
            before_bytes
        );
        let scene_after_preview = read_scene(&scene_path).expect("scene reads after preview");
        assert_eq!(
            hash_scene_document(&scene_after_preview).expect("scene hashes"),
            before_hash
        );
    }

    #[test]
    fn visual_edit_scene_draft_v1_generates_visual_diff_summary_from_transactions_without_apply() {
        let scene_path = repo_fixture_path("examples/game-runtime/scene.json");
        let before_bytes = fs::read(&scene_path).expect("scene bytes read before summary");
        let scene = read_scene(&scene_path).expect("scene reads");
        let before_hash = hash_scene_document(&scene).expect("scene hashes");
        let draft = valid_scene_visual_edit_draft_for_scene(&scene);
        let transactions = draft
            .preview_scene_edit_transactions(&scene_path)
            .expect("scene draft previews transactions");

        let summary = draft
            .generate_scene_visual_diff_summary_from_transactions(&scene_path, &transactions)
            .expect("visual diff summary generated");

        summary.validate().expect("summary validates");
        assert_eq!(summary.schema_version, VISUAL_DIFF_SUMMARY_SCHEMA_VERSION);
        assert_eq!(
            summary.source_refs.draft_id.as_deref(),
            Some("draft-scene-preflight")
        );
        assert!(summary
            .source_refs
            .transaction_id
            .as_deref()
            .expect("transaction source ref")
            .starts_with("transaction-set-"));
        assert_eq!(summary.operation_summaries.len(), 2);
        assert_eq!(
            summary.operation_summaries[0].transaction_id.as_deref(),
            Some(transactions[0].id.as_str())
        );
        assert_eq!(
            summary.operation_summaries[0].before_text.as_deref(),
            Some("32")
        );
        assert_eq!(
            summary.operation_summaries[0].after_text.as_deref(),
            Some("48")
        );
        assert_eq!(
            summary.operation_summaries[1].before_text.as_deref(),
            Some("\"#5eead4\"")
        );
        assert_eq!(
            summary.operation_summaries[1].after_text.as_deref(),
            Some("\"#ffcc00\"")
        );
        assert_eq!(
            summary.before.entity_summaries[0]
                .transform
                .as_ref()
                .unwrap()
                .x,
            32
        );
        assert_eq!(
            summary.after.entity_summaries[0]
                .transform
                .as_ref()
                .unwrap()
                .x,
            48
        );
        assert!(summary
            .guardrail
            .contains("read-only generated visual diff summary"));
        assert_eq!(
            fs::read(&scene_path).expect("scene bytes read after summary"),
            before_bytes
        );
        let scene_after_summary = read_scene(&scene_path).expect("scene reads after summary");
        assert_eq!(
            hash_scene_document(&scene_after_summary).expect("scene hashes"),
            before_hash
        );
    }

