    #[test]
    fn loop_dry_run_prerequisite_inspection_reports_blockers() {
        let root = unique_temp_dir("loop-dry-run-blocked");
        write_loop_dry_run_project(&root);
        let plan_path = write_loop_dry_run_plan(&root, "stale_project");

        let summary = build_authoring_loop_dry_run_summary_from_path(&plan_path)
            .expect("blocked dry-run summary");

        assert_eq!(summary.status, "blocked");
        assert!(summary
            .missing_prerequisites
            .iter()
            .any(|missing| missing.contains("stale project context")));
        assert!(summary
            .missing_prerequisites
            .iter()
            .any(|missing| missing.contains("missing completed output:baseline-run")));
        assert!(summary
            .steps
            .iter()
            .find(|step| step.id == "generate-proposal")
            .expect("proposal step")
            .missing_prerequisites
            .iter()
            .any(|missing| missing.contains("missing artifact:comparison")));
        assert!(summary
            .steps
            .iter()
            .find(|step| step.id == "record-review")
            .expect("review step")
            .missing_prerequisites
            .iter()
            .any(|missing| missing.contains("missing decision:human-review")));
        assert!(summary
            .steps
            .iter()
            .find(|step| step.id == "apply-mutation")
            .expect("apply step")
            .missing_prerequisites
            .iter()
            .any(|missing| missing.contains("missing rollback:before-scene")));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn project_manifest_v1_validates_fixture_and_refs() {
        let manifest_path =
            repo_fixture_path("examples/project-workspace-fixtures/valid/ouroforge.project.json");
        let manifest = ProjectManifest::from_path(&manifest_path)
            .expect("valid project manifest fixture validates");
        assert_eq!(manifest.schema_version, "project-manifest-v1");
        assert_eq!(manifest.project.id, "project_workspace_fixture");
        assert_eq!(manifest.scenes[0].path, "scenes/main.scene.json");
        let report = manifest
            .validate_references(manifest_path.parent().expect("fixture parent"))
            .expect("references validate");
        assert_eq!(report.project_id, "project_workspace_fixture");
        assert_eq!(report.source_refs, 3);
        assert_eq!(report.asset_roots, 1);
        assert_eq!(report.runs_root, "runs");
    }

