    #[test]
    fn sprite_atlas_manifest_v1_validates_image_refs_bounds_frames_and_animation_refs() {
        let root = unique_temp_dir("sprite-atlas-manifest-validates");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::create_dir_all(root.join("assets/atlases")).expect("atlases dir");
        fs::write(
            root.join("assets/sprites/player-sheet.png"),
            b"sheet fixture",
        )
        .expect("sheet file");
        fs::write(
            root.join("assets/atlases/player-sheet.atlas.json"),
            br#"{"frames":["idle_0","idle_1"]}"#,
        )
        .expect("atlas file");
        let sheet_hash = hash_project_asset_file(root.join("assets/sprites/player-sheet.png"))
            .expect("sheet hash");
        let atlas_hash =
            hash_project_asset_file(root.join("assets/atlases/player-sheet.atlas.json"))
                .expect("atlas hash");

        let manifest_with = |image_asset_id: &str,
                             image_type: ProjectAssetType,
                             image_dimensions: Option<serde_json::Value>,
                             frames: serde_json::Value,
                             animations: serde_json::Value| {
            let mut image_asset = json!({
                "id": "player_sheet_image",
                "type": image_type,
                "path": if image_type == ProjectAssetType::Image { "assets/sprites/player-sheet.png" } else { "assets/atlases/player-sheet.atlas.json" },
                "contentHash": if image_type == ProjectAssetType::Image { sheet_hash.clone() } else { atlas_hash.clone() },
                "classification": "source_like"
            });
            if let Some(dimensions) = image_dimensions {
                image_asset["dimensions"] = dimensions;
            }
            ProjectAssetManifest::from_json_str(
                &json!({
                    "schemaVersion": "asset-manifest-v1",
                    "id": "sprite_atlas_validation_fixture",
                    "assets": [
                        image_asset,
                        {
                            "id": "player_sheet_atlas",
                            "type": "sprite_atlas",
                            "path": "assets/atlases/player-sheet.atlas.json",
                            "contentHash": atlas_hash.clone(),
                            "classification": "source_like",
                            "atlas": {
                                "imageAssetId": image_asset_id,
                                "frames": frames,
                                "animations": animations
                            }
                        }
                    ]
                })
                .to_string(),
            )
            .expect("manifest parses")
        };

        let valid_frames = json!([
            { "id": "idle_0", "rect": { "x": 0, "y": 0, "width": 16, "height": 16 } },
            { "id": "idle_1", "rect": { "x": 16, "y": 0, "width": 16, "height": 16 } }
        ]);
        let valid_animations = json!([
            { "id": "idle", "frames": [
                { "frameId": "idle_0", "durationMs": 120 },
                { "frameId": "idle_1", "durationMs": 120 }
            ]}
        ]);

        let valid = manifest_with(
            "player_sheet_image",
            ProjectAssetType::Image,
            Some(json!({ "width": 32, "height": 16 })),
            valid_frames.clone(),
            valid_animations.clone(),
        );
        let report = valid
            .validate_assets(&root)
            .expect("sprite atlas integrity validates");
        assert_eq!(report.sprite_atlases, 1);
        assert_eq!(report.sprite_atlas_frames, 2);
        assert_eq!(report.sprite_atlas_animations, 1);

        let unknown_image = manifest_with(
            "missing_sheet_image",
            ProjectAssetType::Image,
            Some(json!({ "width": 32, "height": 16 })),
            valid_frames.clone(),
            valid_animations.clone(),
        );
        let rejected = unknown_image
            .validate_assets(&root)
            .expect_err("unknown atlas image rejected");
        assert!(rejected.to_string().contains("unknown asset"));

        let missing_dimensions = manifest_with(
            "player_sheet_image",
            ProjectAssetType::Image,
            None,
            valid_frames.clone(),
            valid_animations.clone(),
        );
        let rejected = missing_dimensions
            .validate_assets(&root)
            .expect_err("atlas image dimensions required");
        assert!(rejected.to_string().contains("with dimensions"));

        let duplicate_frame = manifest_with(
            "player_sheet_image",
            ProjectAssetType::Image,
            Some(json!({ "width": 32, "height": 16 })),
            json!([
                { "id": "idle_0", "rect": { "x": 0, "y": 0, "width": 16, "height": 16 } },
                { "id": "idle_0", "rect": { "x": 16, "y": 0, "width": 16, "height": 16 } }
            ]),
            valid_animations.clone(),
        );
        let rejected = duplicate_frame
            .validate_assets(&root)
            .expect_err("duplicate frame rejected");
        assert!(rejected.to_string().contains("duplicate frame id"));

        let out_of_bounds = manifest_with(
            "player_sheet_image",
            ProjectAssetType::Image,
            Some(json!({ "width": 32, "height": 16 })),
            json!([
                { "id": "idle_0", "rect": { "x": 24, "y": 0, "width": 16, "height": 16 } }
            ]),
            json!([{ "id": "idle", "frames": [{ "frameId": "idle_0", "durationMs": 120 }] }]),
        );
        let rejected = out_of_bounds
            .validate_assets(&root)
            .expect_err("out of bounds frame rejected");
        assert!(rejected.to_string().contains("outside atlas image bounds"));

        let unknown_frame_ref = manifest_with(
            "player_sheet_image",
            ProjectAssetType::Image,
            Some(json!({ "width": 32, "height": 16 })),
            valid_frames,
            json!([{ "id": "idle", "frames": [{ "frameId": "missing_frame", "durationMs": 120 }] }]),
        );
        let rejected = unknown_frame_ref
            .validate_assets(&root)
            .expect_err("unknown animation frame rejected");
        assert!(rejected.to_string().contains("unknown frame"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn tilemap_authoring_v2_accepts_schema_fixture() {
        let fixture =
            include_str!("../../../examples/tilemap-authoring-v2/asset-manifest.valid.json");
        let manifest =
            ProjectAssetManifest::from_json_str(fixture).expect("tilemap authoring fixture parses");

        assert_eq!(manifest.id, "tilemap_authoring_v2_fixture");
        assert_eq!(manifest.assets.len(), 2);
        assert_eq!(manifest.assets[0].asset_type, ProjectAssetType::Tileset);
        let tileset = manifest.assets[0]
            .tileset
            .as_ref()
            .expect("tileset payload present");
        assert_eq!(tileset.tile_width, 16);
        assert!(tileset.tiles.iter().any(|tile| tile.solid));
        assert!(tileset
            .tiles
            .iter()
            .any(|tile| tile.trigger.as_deref() == Some("coin_collected")));
        assert!(tileset.tiles.iter().any(|tile| tile.hazard));
        assert!(tileset.tiles.iter().any(|tile| tile.goal));

        assert_eq!(manifest.assets[1].asset_type, ProjectAssetType::Tilemap);
        let tilemap = manifest.assets[1]
            .tilemap
            .as_ref()
            .expect("tilemap payload present");
        assert_eq!(tilemap.tileset_asset_id, "ground_tileset");
        assert_eq!(tilemap.width, 3);
        assert_eq!(tilemap.height, 2);
        assert_eq!(tilemap.layers.len(), 2);
        assert_eq!(tilemap.layers[0].kind, ProjectTilemapLayerKind::Visual);
        assert_eq!(tilemap.layers[1].kind, ProjectTilemapLayerKind::Collision);

        let serialized = serde_json::to_string(&manifest).expect("manifest serializes");
        assert!(serialized.contains("\"type\":\"tileset\""));
        assert!(serialized.contains("\"type\":\"tilemap\""));
        assert!(serialized.contains("\"tilesetAssetId\":\"ground_tileset\""));
    }

    #[test]
    fn tilemap_authoring_v2_validates_tile_refs_and_extracts_collision_trigger_cells() {
        let root = unique_temp_dir("tilemap-authoring-v2-validates");
        fs::create_dir_all(root.join("assets/tilesets")).expect("tileset dir");
        fs::create_dir_all(root.join("assets/tilemaps")).expect("tilemap dir");
        fs::write(
            root.join("assets/tilesets/ground.tileset.json"),
            b"tileset fixture",
        )
        .expect("tileset file");
        fs::write(
            root.join("assets/tilemaps/demo.tilemap.json"),
            b"tilemap fixture",
        )
        .expect("tilemap file");
        let tileset_hash =
            hash_project_asset_file(root.join("assets/tilesets/ground.tileset.json"))
                .expect("tileset hash");
        let tilemap_hash = hash_project_asset_file(root.join("assets/tilemaps/demo.tilemap.json"))
            .expect("tilemap hash");

        let manifest_with =
            |tiles: serde_json::Value, tileset_asset_id: &str, layers: serde_json::Value| {
                ProjectAssetManifest::from_json_str(
                    &json!({
                        "schemaVersion": "asset-manifest-v1",
                        "id": "tilemap_authoring_validation_fixture",
                        "assets": [
                            {
                                "id": "ground_tileset",
                                "type": "tileset",
                                "path": "assets/tilesets/ground.tileset.json",
                                "contentHash": tileset_hash.clone(),
                                "classification": "source_like",
                                "tileset": {
                                    "tileWidth": 16,
                                    "tileHeight": 16,
                                    "tiles": tiles
                                }
                            },
                            {
                                "id": "demo_tilemap",
                                "type": "tilemap",
                                "path": "assets/tilemaps/demo.tilemap.json",
                                "contentHash": tilemap_hash.clone(),
                                "classification": "source_like",
                                "tilemap": {
                                    "tilesetAssetId": tileset_asset_id,
                                    "width": 3,
                                    "height": 2,
                                    "layers": layers
                                }
                            }
                        ]
                    })
                    .to_string(),
                )
                .expect("manifest parses")
            };

        let valid_tiles = json!([
            { "id": "empty", "index": 0 },
            { "id": "solid_ground", "index": 1, "solid": true },
            { "id": "coin_trigger", "index": 2, "trigger": "coin_collected" },
            { "id": "spike_hazard", "index": 3, "hazard": true },
            { "id": "exit_goal", "index": 4, "goal": true }
        ]);
        let valid_layers = json!([
            { "id": "terrain", "kind": "visual", "data": ["solid_ground", "empty", "exit_goal", "solid_ground", "coin_trigger", "spike_hazard"] },
            { "id": "collision", "kind": "collision", "data": ["solid_ground", null, null, "solid_ground", null, null] },
            { "id": "triggers", "kind": "trigger", "data": [null, null, null, null, "coin_trigger", null] }
        ]);

        let valid = manifest_with(valid_tiles.clone(), "ground_tileset", valid_layers.clone());
        valid
            .validate_assets(&root)
            .expect("tilemap authoring validates");
        let extraction = valid
            .extract_tilemap_authoring()
            .expect("tilemap extraction succeeds");
        assert_eq!(extraction.tilemaps.len(), 1);
        let extracted = &extraction.tilemaps[0];
        assert_eq!(extracted.tilemap_asset_id, "demo_tilemap");
        assert_eq!(extracted.collision_cells.len(), 4);
        assert!(extracted
            .collision_cells
            .iter()
            .any(|cell| cell.tile_id == "solid_ground" && cell.x == 0 && cell.y == 0));
        assert!(extracted
            .trigger_cells
            .iter()
            .any(|cell| cell.trigger.as_deref() == Some("coin_collected")));
        assert_eq!(extracted.hazard_cells[0].tile_id, "spike_hazard");
        assert_eq!(extracted.goal_cells[0].tile_id, "exit_goal");

        let duplicate_tile_id = manifest_with(
            json!([
                { "id": "solid_ground", "index": 1, "solid": true },
                { "id": "solid_ground", "index": 2 }
            ]),
            "ground_tileset",
            json!([{ "id": "terrain", "kind": "visual", "data": ["solid_ground", null, null, null, null, null] }]),
        );
        let rejected = duplicate_tile_id
            .validate_assets(&root)
            .expect_err("duplicate tile id rejected");
        assert!(rejected.to_string().contains("duplicate tile id"));

        let duplicate_tile_index = manifest_with(
            json!([
                { "id": "solid_ground", "index": 1, "solid": true },
                { "id": "coin_trigger", "index": 1, "trigger": "coin_collected" }
            ]),
            "ground_tileset",
            json!([{ "id": "terrain", "kind": "visual", "data": ["solid_ground", null, null, null, null, null] }]),
        );
        let rejected = duplicate_tile_index
            .validate_assets(&root)
            .expect_err("duplicate tile index rejected");
        assert!(rejected.to_string().contains("duplicate tile index"));

        let unknown_tile_ref = manifest_with(
            valid_tiles.clone(),
            "ground_tileset",
            json!([{ "id": "terrain", "kind": "visual", "data": ["missing_tile", null, null, null, null, null] }]),
        );
        let rejected = unknown_tile_ref
            .validate_assets(&root)
            .expect_err("unknown tile ref rejected");
        assert!(rejected.to_string().contains("unknown tile id"));

        let bad_layer_len = manifest_with(
            valid_tiles.clone(),
            "ground_tileset",
            json!([{ "id": "terrain", "kind": "visual", "data": ["solid_ground"] }]),
        );
        let rejected = bad_layer_len
            .validate_assets(&root)
            .expect_err("layer data length rejected");
        assert!(rejected.to_string().contains("width*height"));

        let unknown_tileset = manifest_with(valid_tiles, "missing_tileset", valid_layers);
        let rejected = unknown_tileset
            .validate_assets(&root)
            .expect_err("unknown tileset ref rejected");
        assert!(rejected.to_string().contains("unknown asset"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

