    #[test]
    fn project_asset_manifest_rejects_broad_3d_import_and_material_drift() {
        let root = unique_temp_dir("project-asset-3d-mesh-material-invalid");
        fs::create_dir_all(root.join("assets/3d")).expect("3d asset dir");
        fs::create_dir_all(root.join("assets/audio")).expect("audio asset dir");
        fs::create_dir_all(root.join("assets/materials")).expect("material asset dir");
        fs::create_dir_all(root.join("assets/textures")).expect("texture asset dir");
        fs::create_dir_all(root.join("runs/3d")).expect("generated 3d dir");
        fs::write(root.join("assets/3d/cube.mesh.json"), b"mesh fixture").expect("mesh");
        fs::write(root.join("assets/3d/cube.gltf"), b"gltf fixture").expect("gltf");
        fs::write(root.join("runs/3d/cube.mesh.json"), b"generated mesh").expect("generated");
        fs::write(
            root.join("assets/materials/cube.material.json"),
            b"material fixture",
        )
        .expect("material");
        fs::write(
            root.join("assets/audio/not-a-texture.ogg"),
            b"audio fixture",
        )
        .expect("audio");
        fs::write(root.join("assets/textures/cube.png"), b"texture fixture").expect("texture");
        let mesh_hash =
            hash_project_asset_file(root.join("assets/3d/cube.mesh.json")).expect("mesh hash");
        let gltf_hash =
            hash_project_asset_file(root.join("assets/3d/cube.gltf")).expect("gltf hash");
        let generated_hash =
            hash_project_asset_file(root.join("runs/3d/cube.mesh.json")).expect("generated hash");
        let material_hash =
            hash_project_asset_file(root.join("assets/materials/cube.material.json"))
                .expect("material hash");
        let texture_hash =
            hash_project_asset_file(root.join("assets/textures/cube.png")).expect("texture hash");

        let mesh_missing_payload = json!({
            "schemaVersion": "asset-manifest-v1",
            "id": "missing_mesh_payload",
            "assets": [{
                "id": "cube_mesh",
                "type": "mesh",
                "path": "assets/3d/cube.mesh.json",
                "contentHash": mesh_hash,
                "classification": "source_like"
            }]
        });
        let rejected = ProjectAssetManifest::from_json_str(&mesh_missing_payload.to_string())
            .expect_err("mesh payload required");
        assert!(rejected.to_string().contains("mesh is required"));

        let pbr_material = json!({
            "schemaVersion": "asset-manifest-v1",
            "id": "pbr_material_fixture",
            "assets": [{
                "id": "cube_material",
                "type": "material",
                "path": "assets/materials/cube.material.json",
                "contentHash": material_hash,
                "classification": "source_like",
                "material": {
                    "baseColor": "#5eead4",
                    "shading": "lit",
                    "metallic": 1
                }
            }]
        });
        let rejected = ProjectAssetManifest::from_json_str(&pbr_material.to_string())
            .expect_err("pbr-ish material field rejected");
        assert!(format!("{rejected:#}").contains("unknown field"));

        let manifest_with =
            |path: &str,
             hash: ProjectAssetContentHash,
             classification: ProjectAssetClassification| {
                ProjectAssetManifest::from_json_str(
                    &json!({
                        "schemaVersion": "asset-manifest-v1",
                        "id": "invalid_3d_asset_fixture",
                        "assets": [{
                            "id": "cube_mesh",
                            "type": "mesh",
                            "path": path,
                            "contentHash": hash,
                            "classification": classification,
                            "mesh": {
                                "kind": "primitive_cube",
                                "vertexCount": 8
                            }
                        }]
                    })
                    .to_string(),
                )
                .expect("manifest parses")
            };
        let gltf = manifest_with(
            "assets/3d/cube.gltf",
            gltf_hash,
            ProjectAssetClassification::SourceLike,
        );
        let rejected = gltf
            .validate_assets(&root)
            .expect_err("broad gltf import rejected");
        assert!(rejected.to_string().contains("unsupported extension"));

        let generated_source = manifest_with(
            "runs/3d/cube.mesh.json",
            generated_hash,
            ProjectAssetClassification::SourceLike,
        );
        let rejected = generated_source
            .validate_assets(&root)
            .expect_err("source-like mesh cannot live under generated root");
        assert!(rejected.to_string().contains("generated root runs"));

        let wrong_texture_type = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "wrong_texture_type_fixture",
                "assets": [
                    {
                        "id": "cube_mesh",
                        "type": "mesh",
                        "path": "assets/3d/cube.mesh.json",
                        "contentHash": hash_project_asset_file(root.join("assets/3d/cube.mesh.json")).expect("mesh hash"),
                        "classification": "source_like",
                        "mesh": { "kind": "primitive_cube", "vertexCount": 8 }
                    },
                    {
                        "id": "not_a_texture",
                        "type": "audio",
                        "path": "assets/audio/not-a-texture.ogg",
                        "contentHash": hash_project_asset_file(root.join("assets/audio/not-a-texture.ogg")).expect("audio hash"),
                        "classification": "source_like",
                        "durationMs": 100
                    },
                    {
                        "id": "cube_material",
                        "type": "material",
                        "path": "assets/materials/cube.material.json",
                        "contentHash": hash_project_asset_file(root.join("assets/materials/cube.material.json")).expect("material hash"),
                        "classification": "source_like",
                        "material": {
                            "baseColor": "#5eead4",
                            "textureAssetId": "not_a_texture",
                            "shading": "unlit"
                        }
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let rejected = wrong_texture_type
            .validate_assets(&root)
            .expect_err("material texture must point to image asset");
        assert!(rejected
            .to_string()
            .contains("must reference an image asset"));

        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "mesh_material_warning_fixture",
                "assets": [
                    {
                        "id": "cube_mesh",
                        "type": "mesh",
                        "path": "assets/3d/cube.mesh.json",
                        "contentHash": hash_project_asset_file(root.join("assets/3d/cube.mesh.json")).expect("mesh hash"),
                        "classification": "source_like",
                        "mesh": { "kind": "primitive_cube", "vertexCount": 8 }
                    },
                    {
                        "id": "cube_texture",
                        "type": "image",
                        "path": "assets/textures/cube.png",
                        "contentHash": texture_hash,
                        "classification": "source_like",
                        "dimensions": { "width": 4, "height": 4 }
                    },
                    {
                        "id": "cube_material",
                        "type": "material",
                        "path": "assets/materials/cube.material.json",
                        "contentHash": hash_project_asset_file(root.join("assets/materials/cube.material.json")).expect("material hash"),
                        "classification": "source_like",
                        "material": { "baseColor": "#5eead4", "textureAssetId": "cube_texture" }
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let scene: SceneDocument = serde_json::from_value(json!({
            "schemaVersion": "1",
            "sceneKind": "3d",
            "id": "mesh-material-warning-scene",
            "bounds": { "width": 320, "height": 180 },
            "entities": [],
            "scene3d": {
                "version": "1",
                "nodes": [{
                    "id": "cube",
                    "localTransform": {
                        "translation": { "x": 0, "y": 0, "z": 0 },
                        "rotation": { "x": 0, "y": 0, "z": 0 },
                        "scale": { "x": 1, "y": 1, "z": 1 }
                    },
                    "meshRef": "missing_mesh",
                    "materialRef": "cube_mesh"
                }]
            }
        }))
        .expect("scene parses");
        let report = manifest
            .check_scene_reference_integrity(&scene, &root)
            .expect("3d warning report builds without remote fetch");
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "missing_asset_ref"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "invalid_asset_type"));
        assert!(!root.join("assets/remote.gltf").exists());

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn project_asset_manifest_rejects_unknown_type_mismatch_and_remote_scene_refs() {
        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "asset_reference_rejection_fixture",
                "assets": [
                    {
                        "id": "player_sprite",
                        "type": "image",
                        "path": "assets/sprites/player.png",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "1111111111111111" },
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    },
                    {
                        "id": "spawn_audio",
                        "type": "audio",
                        "path": "assets/audio/spawn.ogg",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "2222222222222222" },
                        "classification": "source_like",
                        "durationMs": 100
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let scene_with_sprite = |asset: &str| -> SceneDocument {
            serde_json::from_value(json!({
                "schemaVersion": "1",
                "id": "asset-ref-rejected-scene",
                "bounds": { "width": 64, "height": 32 },
                "entities": [{
                    "id": "player",
                    "sprite": { "color": "#5eead4", "asset": asset },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": true
                    }
                }]
            }))
            .expect("scene parses")
        };

        let missing = manifest
            .validate_scene_references(&scene_with_sprite("missing_sprite"))
            .expect_err("unknown scene ref rejected");
        assert!(missing.to_string().contains("unknown project asset id"));

        let wrong_type = manifest
            .validate_scene_references(&scene_with_sprite("spawn_audio"))
            .expect_err("sprite ref to audio rejected");
        assert!(wrong_type.to_string().contains("expected one of"));

        let remote = manifest
            .validate_scene_references(&scene_with_sprite("https://example.com/player.png"))
            .expect_err("remote URL-like scene ref rejected");
        assert!(remote.to_string().contains("ASCII letters"));
    }

    #[test]
    fn patch_diff_integrity_v1_parses_valid_fixture_reports_without_applying() {
        let diff =
            include_str!("../../../examples/patch-diff-integrity-v1/valid/two-file-basic.diff");
        let report = parse_unified_patch_diff_integrity(diff).expect("diff parses");

        assert_eq!(report.schema_version, PATCH_DIFF_INTEGRITY_SCHEMA_VERSION);
        assert_eq!(report.file_count, 2);
        assert_eq!(report.hunk_count, 2);
        assert!(!report.has_warnings, "{:?}", report.warnings);
        assert_eq!(report.counts.added, 3);
        assert_eq!(report.counts.removed, 2);
        assert_eq!(report.counts.context, 3);
        assert!(report.files.iter().any(|file| {
            file.old_path == "docs/example.md"
                && file.new_path == "docs/example.md"
                && file.status == PatchDiffFileStatus::Modified
        }));
        assert!(report.files.iter().any(|file| {
            file.old_path == "examples/source-file-class-v1/README.md"
                && file.new_path == "examples/source-file-class-v1/README.md"
                && file.status == PatchDiffFileStatus::Modified
        }));
    }

    #[test]
    fn patch_diff_integrity_v1_records_malformed_fixture_warnings_without_apply() {
        let diff = include_str!(
            "../../../examples/patch-diff-integrity-v1/invalid/hunk_count_mismatch.diff"
        );
        let report = parse_unified_patch_diff_integrity(diff).expect("diff report is generated");

        assert_eq!(report.file_count, 1);
        assert!(report.has_warnings);
        assert!(report.warnings.iter().any(|warning| {
            warning.kind == PatchDiffIntegrityWarningKind::HunkLineCountMismatch
        }));

        let orphan =
            include_str!("../../../examples/patch-diff-integrity-v1/invalid/orphan_hunk.diff");
        let orphan_report =
            parse_unified_patch_diff_integrity(orphan).expect("orphan report is generated");
        assert!(orphan_report
            .warnings
            .iter()
            .any(|warning| { warning.kind == PatchDiffIntegrityWarningKind::MissingFileHeader }));
    }

    #[test]
    fn project_asset_reference_integrity_reports_warnings_without_remote_fetch() {
        let root = unique_temp_dir("project-asset-reference-integrity-warnings");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::create_dir_all(root.join("assets/audio")).expect("audio dir");
        fs::write(root.join("assets/sprites/player.png"), b"sprite-v1").expect("sprite");
        fs::write(root.join("assets/audio/spawn.ogg"), b"audio").expect("audio");
        let sprite_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("sprite hash");
        let audio_hash =
            hash_project_asset_file(root.join("assets/audio/spawn.ogg")).expect("audio hash");
        fs::write(root.join("assets/sprites/player.png"), b"sprite-v2").expect("stale sprite");
        let manifest = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "warning_manifest",
                "assets": [
                    {
                        "id": "player_sprite",
                        "type": "image",
                        "path": "assets/sprites/player.png",
                        "contentHash": sprite_hash,
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    },
                    {
                        "id": "spawn_audio",
                        "type": "audio",
                        "path": "assets/audio/spawn.ogg",
                        "contentHash": audio_hash,
                        "classification": "source_like",
                        "durationMs": 100
                    },
                    {
                        "id": "missing_sprite",
                        "type": "image",
                        "path": "assets/sprites/missing.png",
                        "contentHash": { "algorithm": "fnv1a64-file-v1", "value": "1111111111111111" },
                        "classification": "source_like",
                        "dimensions": { "width": 16, "height": 16 }
                    }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let scene: SceneDocument = serde_json::from_value(json!({
            "schemaVersion": "1",
            "id": "warning-scene",
            "bounds": { "width": 64, "height": 32 },
            "entities": [
                {
                    "id": "player",
                    "sprite": { "color": "#5eead4", "asset": "player_sprite" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": true,
                        "audio": { "events": [{ "name": "spawn", "trigger": "scene_loaded", "asset": "missing_audio" }] }
                    }
                },
                {
                    "id": "remote",
                    "sprite": { "color": "#f97316", "asset": "https://example.com/remote.png" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": false
                    }
                },
                {
                    "id": "wrong_type",
                    "sprite": { "color": "#facc15", "asset": "spawn_audio" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": false
                    }
                },
                {
                    "id": "missing_file",
                    "sprite": { "color": "#94a3b8", "asset": "missing_sprite" },
                    "components": {
                        "transform": { "x": 0, "y": 0 },
                        "velocity": { "x": 0, "y": 0 },
                        "size": { "width": 16, "height": 16 },
                        "controllable": false
                    }
                }
            ]
        }))
        .expect("scene parses");

        let report = manifest
            .check_scene_reference_integrity(&scene, &root)
            .expect("warning report builds without fetching remote assets");

        assert_eq!(report.schema_version, "asset-reference-integrity-v1");
        assert_eq!(report.resolved_refs.len(), 0);
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "stale_asset_hash"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "missing_asset_ref"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "missing_asset_file"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "invalid_asset_type"));
        assert!(report
            .warnings
            .iter()
            .any(|warning| warning.kind == "invalid_asset_id"));
        assert!(!root.join("assets/remote.png").exists());

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn project_asset_manifest_v1_rejects_invalid_paths_roots_extensions_and_hashes() {
        let root = unique_temp_dir("project-asset-manifest-invalid");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::create_dir_all(root.join("runs/previews")).expect("runs dir");
        fs::write(root.join("assets/sprites/player.png"), b"png fixture").expect("sprite");
        fs::write(root.join("runs/previews/player.png"), b"generated fixture").expect("generated");
        let sprite_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("sprite hashes");
        let generated_hash = hash_project_asset_file(root.join("runs/previews/player.png"))
            .expect("generated hashes");

        let manifest_with_path =
            |path: &str,
             asset_type: ProjectAssetType,
             hash: ProjectAssetContentHash,
             classification: ProjectAssetClassification| {
                ProjectAssetManifest::from_json_str(
                    &json!({
                        "schemaVersion": "asset-manifest-v1",
                        "id": "invalid_asset_fixture",
                        "assets": [{
                            "id": "asset",
                            "type": asset_type,
                            "path": path,
                            "contentHash": hash,
                            "classification": classification
                        }]
                    })
                    .to_string(),
                )
                .expect("manifest parses")
            };

        let absolute = manifest_with_path(
            "/tmp/player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = absolute
            .validate_assets(&root)
            .expect_err("absolute path rejected");
        assert!(rejected.to_string().contains("must be relative"));

        let escape = manifest_with_path(
            "../player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = escape
            .validate_assets(&root)
            .expect_err("path escape rejected");
        assert!(rejected.to_string().contains("project root"));

        let hidden = manifest_with_path(
            ".omx/player.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = hidden
            .validate_assets(&root)
            .expect_err("hidden root rejected");
        assert!(rejected.to_string().contains("hidden"));

        let generated_source = manifest_with_path(
            "runs/previews/player.png",
            ProjectAssetType::Image,
            generated_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = generated_source
            .validate_assets(&root)
            .expect_err("source generated root rejected");
        assert!(rejected.to_string().contains("generated root runs"));

        let unsupported = manifest_with_path(
            "assets/sprites/player.txt",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = unsupported
            .validate_assets(&root)
            .expect_err("unsupported extension rejected");
        assert!(rejected.to_string().contains("unsupported extension"));

        let missing = manifest_with_path(
            "assets/sprites/missing.png",
            ProjectAssetType::Image,
            sprite_hash.clone(),
            ProjectAssetClassification::SourceLike,
        );
        let rejected = missing
            .validate_assets(&root)
            .expect_err("missing rejected");
        assert!(rejected.to_string().contains("missing file"));

        let mut stale_hash = sprite_hash.clone();
        stale_hash.value = "0000000000000000".to_string();
        let stale = manifest_with_path(
            "assets/sprites/player.png",
            ProjectAssetType::Image,
            stale_hash,
            ProjectAssetClassification::SourceLike,
        );
        let rejected = stale
            .validate_assets(&root)
            .expect_err("stale hash rejected");
        assert!(rejected.to_string().contains("contentHash mismatch"));

        let generated = manifest_with_path(
            "runs/previews/player.png",
            ProjectAssetType::Image,
            generated_hash,
            ProjectAssetClassification::Generated,
        );
        generated
            .validate_assets(&root)
            .expect("generated classified asset may live under generated root");

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn source_file_class_v1_classifies_fixture_matrix() {
        let fixture_path = Path::new(env!("CARGO_MANIFEST_DIR"))
            .join("../../examples/source-file-class-v1/classification-cases.json");
        let fixture: serde_json::Value = serde_json::from_str(
            &fs::read_to_string(fixture_path).expect("classification fixture reads"),
        )
        .expect("classification fixture parses");
        assert_eq!(
            fixture
                .get("schemaVersion")
                .and_then(|value| value.as_str()),
            Some("source-file-class-fixture-v1")
        );
        let cases = fixture
            .get("cases")
            .and_then(|value| value.as_array())
            .expect("cases array");
        assert!(cases.len() >= 10, "fixture covers the source class matrix");
        for case in cases {
            let path = case
                .get("path")
                .and_then(|value| value.as_str())
                .expect("case path");
            let expected_class = case
                .get("class")
                .and_then(|value| value.as_str())
                .expect("case class");
            let expected_decision = case
                .get("decision")
                .and_then(|value| value.as_str())
                .expect("case decision");
            let report = classify_source_file_path_str(path);
            assert_eq!(report.schema_version, "source-file-class-v1");
            assert_eq!(
                serde_json::to_value(&report.class).expect("class serializes"),
                json!(expected_class),
                "class for {path}"
            );
            assert_eq!(
                serde_json::to_value(&report.decision).expect("decision serializes"),
                json!(expected_decision),
                "decision for {path}"
            );
            assert!(
                report
                    .guardrails
                    .iter()
                    .any(|guardrail| guardrail.contains("no source patch apply")),
                "guardrail for {path}"
            );
            if report.is_blocked() {
                assert!(
                    !report.blocked_reasons.is_empty(),
                    "blocked class should explain why: {path}"
                );
            }
        }
    }

    #[test]
    fn source_file_class_v1_rejects_unsafe_hidden_generated_and_opaque_paths() {
        let unsafe_absolute = classify_source_file_path_str("/tmp/Ouroforge/README.md");
        assert_eq!(unsafe_absolute.class, SourceFileClassLabel::UnsafePath);
        assert!(unsafe_absolute.is_blocked());
        assert!(unsafe_absolute
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("absolute")));

        let generated = classify_source_file_path_str("target/debug/build.log");
        assert_eq!(generated.class, SourceFileClassLabel::GeneratedLocalState);
        assert!(generated.is_blocked());
        assert!(generated
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("generated")));

        let hidden_nested = classify_source_file_path_str("examples/demo/.cache/state.json");
        assert_eq!(hidden_nested.class, SourceFileClassLabel::UnsafePath);
        assert!(hidden_nested.is_blocked());

        let opaque = classify_source_file_path_str("examples/assets/player.png");
        assert_eq!(opaque.class, SourceFileClassLabel::BinaryOpaque);
        assert!(opaque.is_blocked());

        // Repeated separators must stay unsafe-path: `Path::components()` collapses
        // `//`, so the guard must inspect the raw separator-split segments.
        let repeated_separator =
            classify_source_file_path_str("examples//playable-demo-v2/scenes/foo.scene.json");
        assert_eq!(repeated_separator.class, SourceFileClassLabel::UnsafePath);
        assert!(repeated_separator.is_blocked());
        assert!(repeated_separator
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("empty path component")));

        // Backslash-normalized repeated separators are equally unsafe.
        let backslash_repeated = classify_source_file_path_str("examples\\\\demo\\scene.json");
        assert_eq!(backslash_repeated.class, SourceFileClassLabel::UnsafePath);
        assert!(backslash_repeated.is_blocked());

        // Trailing separator leaves an empty final segment and must be rejected.
        let trailing_separator = classify_source_file_path_str("examples/demo/scene.json/");
        assert_eq!(trailing_separator.class, SourceFileClassLabel::UnsafePath);
        assert!(trailing_separator.is_blocked());
    }

    #[test]
    fn source_patch_target_class_validation_blocks_dependency_ci_scripts_and_generated_roots() {
        let validation = classify_source_patch_preview_targets([
            "seeds/platformer.yaml",
            "Cargo.toml",
            ".github/workflows/ci.yml",
            "build.rs",
            "scripts/check.sh",
            "runs/run-1/run.json",
            "target/debug/output.txt",
            "examples/demo/.cache/state.json",
            "examples/assets/player.png",
        ]);
        assert_eq!(
            validation.schema_version,
            "source-patch-target-class-validation-v1"
        );
        assert_eq!(validation.status, "blocked");
        assert!(validation.has_blocked_targets());
        assert!(validation
            .guardrails
            .iter()
            .any(|guardrail| guardrail.contains("no diff evaluation")));
        for expected in [
            "Cargo.toml",
            ".github/workflows/ci.yml",
            "build.rs",
            "scripts/check.sh",
            "runs/run-1/run.json",
            "target/debug/output.txt",
            "examples/demo/.cache/state.json",
            "examples/assets/player.png",
        ] {
            assert!(
                validation
                    .blocked_reasons
                    .iter()
                    .any(|reason| reason.contains(expected)),
                "missing blocked reason for {expected}: {:?}",
                validation.blocked_reasons
            );
        }
        let error = validate_source_patch_preview_targets(["seeds/platformer.yaml", "Cargo.lock"])
            .expect_err("blocked target rejects preview preflight");
        assert!(error
            .to_string()
            .contains("source patch preview target class validation blocked"));
        assert!(error.to_string().contains("Cargo.lock"));
    }

    #[test]
    fn source_patch_target_class_validation_serializes_report_shape() {
        let validation = classify_source_patch_preview_targets([
            "seeds/platformer.yaml",
            "docs/source-file-class-validator-v1.md",
            "Cargo.lock",
        ]);
        let value = serde_json::to_value(&validation).expect("validation serializes");
        assert_eq!(
            value["schemaVersion"],
            json!("source-patch-target-class-validation-v1")
        );
        assert_eq!(value["status"], json!("blocked"));
        assert!(value["targets"]
            .as_array()
            .is_some_and(|targets| targets.len() == 3));
        assert_eq!(
            value["targets"][0]["schemaVersion"],
            json!("source-file-class-v1")
        );
        assert_eq!(value["targets"][0]["decision"], json!("allowed"));
        assert_eq!(value["targets"][1]["decision"], json!("needs-approval"));
        assert_eq!(value["targets"][2]["class"], json!("dependency-manifest"));
        assert!(value["blockedReasons"][0]
            .as_str()
            .is_some_and(|reason| reason.contains("Cargo.lock")));
        assert!(value["guardrails"]
            .as_array()
            .expect("guardrails")
            .iter()
            .any(|guardrail| guardrail
                .as_str()
                .is_some_and(|text| text.contains("no diff evaluation"))));
    }

