    #[test]
    fn source_apply_worktree_context_blocks_symlink_and_traversal_targets() {
        let root = unique_temp_dir("source-apply-context-symlink");
        fs::create_dir_all(root.join("seeds")).expect("seed dir");
        fs::write(root.join("seeds/platformer.yaml"), "id: platformer\n").expect("seed");
        let symlink_path = root.join("seeds/link.yaml");
        #[cfg(unix)]
        std::os::unix::fs::symlink(root.join("seeds/platformer.yaml"), &symlink_path)
            .expect("symlink created");
        #[cfg(windows)]
        std::os::windows::fs::symlink_file(root.join("seeds/platformer.yaml"), &symlink_path)
            .expect("symlink created");
        let input = clean_source_apply_worktree_context_input(
            &root,
            vec![
                SourceApplyWorktreeContextTargetInput {
                    path: "seeds/link.yaml".to_string(),
                    git_status: "clean".to_string(),
                    expected_file_class_decision: SourceFileClassDecision::Allowed,
                    authorized_creation: false,
                },
                SourceApplyWorktreeContextTargetInput {
                    path: "../outside.yaml".to_string(),
                    git_status: "clean".to_string(),
                    expected_file_class_decision: SourceFileClassDecision::Blocked,
                    authorized_creation: false,
                },
            ],
        );
        let report = inspect_source_apply_worktree_context(&input);
        assert!(report.is_blocked());
        let reasons = report.blocked_reasons.join(" | ");
        assert!(reasons.contains("symlink-target"), "{reasons}");
        assert!(
            reasons.contains("path-traversal") || reasons.contains("file-class blocked"),
            "{reasons}"
        );
        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn source_apply_worktree_context_blocks_symlinked_parent_directory_targets() {
        // A target whose LEAF is a regular file but whose PARENT directory is a
        // symlink must still fail closed: the parent symlink can redirect trusted
        // writes outside the worktree even though the leaf is not itself a symlink.
        let root = unique_temp_dir("source-apply-context-symlink-parent");
        fs::create_dir_all(root.join("real")).expect("real dir");
        fs::write(root.join("real/data.yaml"), "id: data\n").expect("data file");
        let linked_dir = root.join("linked");
        #[cfg(unix)]
        std::os::unix::fs::symlink(root.join("real"), &linked_dir).expect("dir symlink created");
        #[cfg(windows)]
        std::os::windows::fs::symlink_dir(root.join("real"), &linked_dir)
            .expect("dir symlink created");
        let input = clean_source_apply_worktree_context_input(
            &root,
            vec![SourceApplyWorktreeContextTargetInput {
                path: "linked/data.yaml".to_string(),
                git_status: "clean".to_string(),
                expected_file_class_decision: SourceFileClassDecision::Allowed,
                authorized_creation: false,
            }],
        );
        let report = inspect_source_apply_worktree_context(&input);
        assert!(
            report.is_blocked(),
            "symlinked parent target must fail closed"
        );
        let reasons = report.blocked_reasons.join(" | ");
        assert!(reasons.contains("symlink-target"), "{reasons}");
        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn source_apply_worktree_context_blocks_non_git_worktree() {
        let root = unique_temp_dir("source-apply-context-non-git");
        fs::create_dir_all(root.join("seeds")).expect("seed dir");
        fs::write(root.join("seeds/platformer.yaml"), "id: platformer\n").expect("seed");
        let input = SourceApplyWorktreeContextInput {
            policy_id: "source-apply-worktree-boundary-v1".to_string(),
            repository_root: root.to_string_lossy().to_string(),
            worktree_root: root.to_string_lossy().to_string(),
            branch: "issue-701-fixture".to_string(),
            expected_head_commit: "head123".to_string(),
            current_head_commit: "head123".to_string(),
            lock_status: SourceApplyWorktreeLockStatus {
                active: false,
                attempt_id: "attempt-1".to_string(),
            },
            targets: vec![SourceApplyWorktreeContextTargetInput {
                path: "seeds/platformer.yaml".to_string(),
                git_status: "clean".to_string(),
                expected_file_class_decision: SourceFileClassDecision::Allowed,
                authorized_creation: false,
            }],
        };
        let report = inspect_source_apply_worktree_context(&input);
        assert!(report.is_blocked());
        let reasons = report.blocked_reasons.join(" | ");
        assert!(reasons.contains("missing-git-context"), "{reasons}");
        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn source_apply_worktree_context_blocks_missing_git_head_and_active_lock() {
        let root = unique_temp_dir("source-apply-context-missing-git");
        fs::create_dir_all(root.join("seeds")).expect("seed dir");
        fs::write(root.join("seeds/platformer.yaml"), "id: platformer\n").expect("seed");
        let mut input = clean_source_apply_worktree_context_input(
            &root,
            vec![SourceApplyWorktreeContextTargetInput {
                path: "seeds/platformer.yaml".to_string(),
                git_status: "clean".to_string(),
                expected_file_class_decision: SourceFileClassDecision::Allowed,
                authorized_creation: false,
            }],
        );
        input.branch.clear();
        input.current_head_commit = "different".to_string();
        input.lock_status.active = true;
        let report = inspect_source_apply_worktree_context(&input);
        assert!(report.is_blocked());
        let reasons = report.blocked_reasons.join(" | ");
        assert!(reasons.contains("branch must not be empty"), "{reasons}");
        assert!(reasons.contains("branch-head-mismatch"), "{reasons}");
        assert!(reasons.contains("active-apply-lock"), "{reasons}");
        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn source_apply_worktree_context_evidence_exports_dashboard_read_model() {
        let root = unique_temp_dir("source-apply-context-dashboard");
        fs::create_dir_all(root.join("seeds")).expect("seed dir");
        fs::write(root.join("seeds/platformer.yaml"), "id: platformer\n").expect("seed");
        let (run_root, artifacts) = create_test_run("source-apply-context-dashboard-run");
        let input = clean_source_apply_worktree_context_input(
            &root,
            vec![
                SourceApplyWorktreeContextTargetInput {
                    path: "seeds/platformer.yaml".to_string(),
                    git_status: "modified".to_string(),
                    expected_file_class_decision: SourceFileClassDecision::Allowed,
                    authorized_creation: false,
                },
                SourceApplyWorktreeContextTargetInput {
                    path: "examples/demo/new.scene.json".to_string(),
                    git_status: "untracked-collision".to_string(),
                    expected_file_class_decision: SourceFileClassDecision::Allowed,
                    authorized_creation: true,
                },
            ],
        );
        let report = write_source_apply_worktree_context_evidence(&artifacts.run_dir, &input)
            .expect("context evidence written");
        assert_eq!(report.status, "blocked");

        let model = read_dashboard_run(&artifacts.run_dir).expect("dashboard run reads");
        let context = &model.source_apply_worktree_context;
        assert!(context.present);
        assert_eq!(context.status, "blocked");
        assert_eq!(context.target_count, 2);
        assert!(context.blocked_count >= 2);
        assert!(context
            .evidence_refs
            .contains(&"evidence/source-apply/worktree-context.json".to_string()));
        assert_eq!(
            context.reports[0].schema_version,
            "source-apply-worktree-context-v1"
        );
        assert!(context.reports[0]
            .blocked_reasons
            .iter()
            .any(|reason| reason.contains("dirty-target")));
        assert!(context.boundary.contains("must not apply patches"));

        fs::remove_dir_all(root).expect("fixture removed");
        fs::remove_dir_all(run_root).expect("run fixture removed");
    }

    #[test]
    fn project_asset_manifest_v1_rejects_duplicate_ids_and_paths() {
        let root = unique_temp_dir("project-asset-manifest-duplicates");
        fs::create_dir_all(root.join("assets/sprites")).expect("sprites dir");
        fs::write(root.join("assets/sprites/player.png"), b"png fixture").expect("sprite");
        fs::write(root.join("assets/sprites/player-copy.png"), b"png fixture").expect("copy");
        let player_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("player hashes");
        let copy_hash = hash_project_asset_file(root.join("assets/sprites/player-copy.png"))
            .expect("copy hashes");

        let duplicate_id = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "duplicate_id_fixture",
                "assets": [
                    { "id": "player", "type": "image", "path": "assets/sprites/player.png", "contentHash": player_hash, "classification": "source_like" },
                    { "id": "player", "type": "image", "path": "assets/sprites/player-copy.png", "contentHash": copy_hash, "classification": "source_like" }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let rejected = duplicate_id
            .validate_assets(&root)
            .expect_err("duplicate id rejected");
        assert!(rejected
            .to_string()
            .contains("duplicate project asset manifest asset id"));

        let path_hash =
            hash_project_asset_file(root.join("assets/sprites/player.png")).expect("path hashes");
        let duplicate_path = ProjectAssetManifest::from_json_str(
            &json!({
                "schemaVersion": "asset-manifest-v1",
                "id": "duplicate_path_fixture",
                "assets": [
                    { "id": "player", "type": "image", "path": "assets/sprites/player.png", "contentHash": path_hash, "classification": "source_like" },
                    { "id": "player_copy", "type": "image", "path": "assets/sprites/player.png", "contentHash": path_hash, "classification": "source_like" }
                ]
            })
            .to_string(),
        )
        .expect("manifest parses");
        let rejected = duplicate_path
            .validate_assets(&root)
            .expect_err("duplicate path rejected");
        assert!(rejected
            .to_string()
            .contains("duplicate project asset manifest asset path"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn asset_pipeline_v1_regression_fixtures_validate_feature_matrix() {
        let root = repo_fixture_path("examples/asset-pipeline-v1-regression");
        let project = ProjectManifest::from_path(root.join(PROJECT_MANIFEST_FILE_NAME))
            .expect("asset pipeline regression project manifest validates");
        assert_eq!(project.project.id, "asset_pipeline_v1_regression");
        assert_eq!(project.scenario_packs.len(), 1);
        assert_eq!(project.asset_roots, vec!["assets".to_string()]);
        assert_eq!(
            project.generated.roots,
            vec![
                "runs".to_string(),
                "target".to_string(),
                "dashboard-data".to_string(),
            ]
        );

        let seed = Seed::from_path(root.join("seeds/asset-pipeline-regression.yaml"))
            .expect("asset pipeline regression seed validates");
        assert_eq!(seed.id, "asset-pipeline.v1-regression");
        assert!(seed
            .acceptance
            .iter()
            .any(|item| item.contains("hash mismatch")));

        let pack =
            ScenarioPack::from_path(root.join("scenarios/asset-pipeline-v1-regression.json"))
                .expect("asset pipeline regression scenario pack validates");
        assert_eq!(pack.id, "asset-pipeline-v1-regression");
        assert_eq!(
            pack.ordered_scenario_ids(),
            vec![
                "manifest-validation".to_string(),
                "hash-mismatch-regression".to_string(),
                "missing-asset-regression".to_string(),
                "atlas-frame-validation".to_string(),
                "tile-collision-extraction".to_string(),
                "runtime-asset-load-evidence".to_string(),
                "studio-read-model-compatibility".to_string(),
            ]
        );

        let manifest = ProjectAssetManifest::from_path(root.join("asset-manifest.json"))
            .expect("asset pipeline regression asset manifest validates");
        let report = manifest
            .validate_assets(&root)
            .expect("asset regression fixture assets validate");
        assert_eq!(report.manifest_id, "asset_pipeline_v1_regression_assets");
        assert_eq!(report.assets, 5);
        assert_eq!(report.source_like_assets, 5);
        assert_eq!(report.generated_assets, 0);
        assert_eq!(report.sprite_atlases, 1);
        assert_eq!(report.sprite_atlas_frames, 6);
        assert_eq!(
            report.asset_types.get(&ProjectAssetType::Image).copied(),
            Some(1)
        );
        assert_eq!(
            report
                .asset_types
                .get(&ProjectAssetType::SpriteAtlas)
                .copied(),
            Some(1)
        );
        assert_eq!(
            report.asset_types.get(&ProjectAssetType::Tileset).copied(),
            Some(1)
        );
        assert_eq!(
            report.asset_types.get(&ProjectAssetType::Tilemap).copied(),
            Some(1)
        );
        assert_eq!(
            report.asset_types.get(&ProjectAssetType::Audio).copied(),
            Some(1)
        );

        let tilemaps = manifest
            .extract_tilemap_authoring()
            .expect("tilemap authoring extraction validates");
        let tilemap = tilemaps
            .tilemaps
            .first()
            .expect("regression tilemap extracted");
        assert_eq!(tilemap.tilemap_asset_id, "asset_regression_tilemap");
        assert!(tilemap
            .collision_cells
            .iter()
            .any(|cell| cell.tile_id == "ground"));
        assert!(tilemap
            .trigger_cells
            .iter()
            .any(|cell| cell.trigger.as_deref() == Some("missing_asset_observed")));
        assert!(tilemap
            .goal_cells
            .iter()
            .any(|cell| cell.tile_id == "exit_marker"));
        assert!(tilemap
            .hazard_cells
            .iter()
            .any(|cell| cell.tile_id == "hazard"));
    }

