    #[test]
    fn parses_valid_scenario_dsl() {
        let valid = r#"
id: platformer.v0
title: Platformer Harness Seed
goal: Prove the initial Ouroforge run artifact contract.
constraints:
  target: file-harness
acceptance:
  - Validate the seed schema.
scenarios:
  - id: probe-smoke
    description: Exercise the minimal probe DSL.
    steps:
      - wait:
          frames: 2
      - input:
          right: true
      - transition:
          id: to_level_2
    assertions:
      - world_state:
          path: tick
          equals: 2
      - frame_stats:
          path: fixedDeltaMs
          equals: 16
      - transition_evidence:
          path: 0.status
          equals: succeeded
"#;

        let seed = Seed::from_yaml_str(valid).expect("scenario dsl parses");

        assert_eq!(seed.scenarios[0].steps.len(), 3);
        assert_eq!(seed.scenarios[0].assertions.len(), 3);
        assert!(matches!(
            seed.scenarios[0].steps[2],
            ScenarioStep::Transition { .. }
        ));
    }

    #[test]
    fn parses_scenario_input_action_step_without_breaking_legacy_directions() {
        let valid = r#"
id: action-input.seed
title: Action Input Seed
goal: Validate action input steps.
constraints:
  target: game-runtime
acceptance:
  - Action input parses.
scenarios:
  - id: action-input-smoke
    description: Exercise additive action ids beside legacy directions.
    steps:
      - input:
          right: true
          actions:
            jump: true
            interact: false
"#;

        let seed = Seed::from_yaml_str(valid).expect("action input step parses");
        let ScenarioStep::Input { input } = &seed.scenarios[0].steps[0] else {
            panic!("expected input step");
        };
        assert_eq!(input.right, Some(true));
        assert_eq!(input.actions.get("jump"), Some(&true));
        assert_eq!(input.actions.get("interact"), Some(&false));
    }

    #[test]
    fn scenario_replay_reference_validates_referenced_file() {
        let root = unique_temp_dir("scenario-replay-ref-valid");
        fs::create_dir_all(root.join("replays")).expect("replay fixture dir exists");
        fs::write(
            root.join("replays/move-right.yaml"),
            r#"
schemaVersion: "1"
id: move-right
events:
  - frame: 0
    key: right
    pressed: true
  - frame: 4
    key: right
    pressed: false
"#,
        )
        .expect("replay fixture written");
        let seed_path = root.join("seed.yaml");
        fs::write(
            &seed_path,
            r#"
id: replay-ref.seed
title: Replay Ref Seed
goal: Validate replay references.
constraints:
  target: game-runtime
acceptance:
  - Replay reference validates.
scenarios:
  - id: replay-ref-smoke
    description: Bind replay from a fixture file.
    steps:
      - replayRef:
          id: move-right
          path: replays/move-right.yaml
    assertions:
      - world_state:
          path: object.x
          equals: 40
"#,
        )
        .expect("seed written");

        let seed = Seed::from_path(&seed_path).expect("replay reference validates");
        assert!(matches!(
            seed.scenarios[0].steps[0],
            ScenarioStep::ReplayRef { .. }
        ));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn scenario_replay_reference_rejects_missing_and_malformed_files() {
        let root = unique_temp_dir("scenario-replay-ref-invalid");
        fs::create_dir_all(root.join("replays")).expect("replay fixture dir exists");
        let seed_path = root.join("missing-seed.yaml");
        fs::write(
            &seed_path,
            r#"
id: replay-ref.seed
title: Replay Ref Seed
goal: Validate replay references.
constraints:
  target: game-runtime
acceptance:
  - Replay reference validates.
scenarios:
  - id: replay-ref-smoke
    description: Bind replay from a fixture file.
    steps:
      - replayRef:
          id: move-right
          path: replays/missing.yaml
"#,
        )
        .expect("missing seed written");
        let rejected = Seed::from_path(&seed_path).expect_err("missing replay reference rejected");
        assert!(rejected
            .to_string()
            .contains("replayRef could not be loaded"));

        fs::write(root.join("replays/bad.yaml"), "id: bad\n").expect("bad replay written");
        let malformed_seed_path = root.join("malformed-seed.yaml");
        fs::write(
            &malformed_seed_path,
            r#"
id: replay-ref.seed
title: Replay Ref Seed
goal: Validate replay references.
constraints:
  target: game-runtime
acceptance:
  - Replay reference validates.
scenarios:
  - id: replay-ref-smoke
    description: Bind replay from a fixture file.
    steps:
      - replayRef:
          id: bad
          path: replays/bad.yaml
"#,
        )
        .expect("malformed seed written");
        let rejected =
            Seed::from_path(&malformed_seed_path).expect_err("malformed replay rejected");
        assert!(rejected
            .to_string()
            .contains("replayRef could not be loaded"));

        let escaping = Seed::from_yaml_str(
            r#"
id: replay-ref.seed
title: Replay Ref Seed
goal: Validate replay references.
constraints:
  target: game-runtime
acceptance:
  - Replay reference validates.
scenarios:
  - id: replay-ref-smoke
    description: Bind replay from a fixture file.
    steps:
      - replayRef:
          id: move-right
          path: replays/../move-right.yaml
"#,
        )
        .expect_err("escaping replay reference rejected");
        assert!(escaping.to_string().contains("replayRef is invalid"));

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn input_replay_artifact_schema_accepts_valid_correlation_fields() {
        let artifact = ScenarioInputReplayArtifact {
            schema_version: SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION.to_string(),
            scenario_id: "replay-smoke".to_string(),
            worker_id: Some("worker-1".to_string()),
            step_index: 2,
            action: ScenarioInputReplayAction {
                kind: "input".to_string(),
                key: Some(ReplayKey::Right),
                pressed: Some(true),
            },
            frame: 4,
            tick: Some(4),
            input: InputStep {
                right: Some(true),
                ..InputStep::default()
            },
            probe: Some(ScenarioInputReplayProbeCorrelation {
                contract_version: RUNTIME_PROBE_CONTRACT_VERSION.to_string(),
                world_state_path: Some(
                    "evidence/scenarios/replay-smoke/world-state-1.json".to_string(),
                ),
                frame_stats_path: Some(
                    "evidence/scenarios/replay-smoke/frame-stats-1.json".to_string(),
                ),
            }),
            result: Some(ScenarioInputReplayResultCorrelation {
                scenario_result_path: "evidence/scenarios/replay-smoke/scenario-result-1.json"
                    .to_string(),
                verdict_path: Some("verdict.json".to_string()),
            }),
        };

        artifact.validate().expect("valid replay artifact");
        let value = serde_json::to_value(&artifact).expect("serializes");
        assert_eq!(
            value["schemaVersion"],
            SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION
        );
        assert_eq!(value["scenarioId"], "replay-smoke");
        assert_eq!(value["workerId"], "worker-1");
        assert_eq!(
            value["probe"]["contractVersion"],
            RUNTIME_PROBE_CONTRACT_VERSION
        );
        let parsed: ScenarioInputReplayArtifact =
            serde_json::from_value(value).expect("round-trips");
        assert_eq!(parsed, artifact);
    }

    #[test]
    fn input_replay_artifact_schema_rejects_invalid_contract_fields() {
        let mut artifact = ScenarioInputReplayArtifact {
            schema_version: SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION.to_string(),
            scenario_id: "replay-smoke".to_string(),
            worker_id: Some("worker-1".to_string()),
            step_index: 0,
            action: ScenarioInputReplayAction {
                kind: "input".to_string(),
                key: None,
                pressed: None,
            },
            frame: 0,
            tick: None,
            input: InputStep {
                left: Some(true),
                ..InputStep::default()
            },
            probe: None,
            result: None,
        };

        artifact.schema_version = "wrong".to_string();
        assert!(artifact
            .validate()
            .expect_err("schema version rejected")
            .to_string()
            .contains("schemaVersion"));
        artifact.schema_version = SCENARIO_INPUT_REPLAY_ARTIFACT_SCHEMA_VERSION.to_string();
        artifact.worker_id = Some("../worker".to_string());
        assert!(artifact
            .validate()
            .expect_err("unsafe worker rejected")
            .to_string()
            .contains("workerId"));
        artifact.worker_id = Some("worker-1".to_string());
        artifact.frame = MAX_INPUT_REPLAY_FRAME + 1;
        assert!(artifact
            .validate()
            .expect_err("frame bound rejected")
            .to_string()
            .contains("frame"));
        artifact.frame = 0;
        artifact.probe = Some(ScenarioInputReplayProbeCorrelation {
            contract_version: "v1".to_string(),
            world_state_path: None,
            frame_stats_path: None,
        });
        assert!(artifact
            .validate()
            .expect_err("probe contract rejected")
            .to_string()
            .contains("contractVersion"));
        artifact.probe = Some(ScenarioInputReplayProbeCorrelation {
            contract_version: RUNTIME_PROBE_CONTRACT_VERSION.to_string(),
            world_state_path: Some("../world.json".to_string()),
            frame_stats_path: None,
        });
        assert!(artifact
            .validate()
            .expect_err("unsafe evidence path rejected")
            .to_string()
            .contains("worldStatePath"));
    }

