    #[test]
    fn journal_authoring_governance_lifecycle_exposes_partial_and_malformed_data() {
        let partial_proposal = MutationProposal {
            id: "proposal-without-rationale".to_string(),
            reason: "partial lifecycle fixture".to_string(),
            evidence_id: "evidence-partial".to_string(),
            target: "seeds/platformer.yaml".to_string(),
            path: "scenarios.smoke.assertions".to_string(),
            from: "old".to_string(),
            to: "new".to_string(),
            confidence: "low".to_string(),
            status: "proposed".to_string(),
            verdict_status: "failed".to_string(),
            created_at_unix_ms: 1,
            rationale: None,
        };
        let comparison = RunDashboardComparison {
            present: true,
            empty_state: String::new(),
            artifacts: vec![RunDashboardComparisonArtifact {
                id: "run-comparison-malformed".to_string(),
                path: "mutation/run-comparison-malformed.json".to_string(),
                exists: true,
                read_error: Some("expected value at line 1 column 1".to_string()),
                before_run_id: None,
                after_run_id: None,
                classification: None,
                deltas: serde_json::Value::Null,
                semantic: serde_json::Value::Null,
                evidence_refs: Vec::new(),
                unsupported: vec!["malformed_json".to_string()],
                value: None,
            }],
        };

        let journal = render_authoring_governance_journal_section(
            &[partial_proposal],
            &[],
            &[],
            Some("failed to parse scene applications mutation/scene-applications.json"),
            (
                &[],
                Some("failed to parse visual edit applications mutation/visual-edit-applications.json"),
            ),
            &comparison,
            &[],
        );

        assert!(journal.contains("proposal-without-rationale"));
        assert!(journal.contains("Rationale: missing"));
        assert!(journal.contains("Scene application artifact is present but malformed"));
        assert!(journal.contains("failed to parse scene applications"));
        assert!(journal.contains("run-comparison-malformed"));
        assert!(journal.contains("Read error: expected value"));
        assert!(journal.contains("unsupported: malformed_json"));
        assert!(journal.contains("No review decisions recorded"));
        assert!(journal.contains("No regression promotions recorded"));
    }

    #[test]
    fn journal_renders_project_context_without_inference() {
        let seed = Seed::from_yaml_str(VALID_SEED).expect("seed parses");
        let evidence = EvidenceIndex { artifacts: vec![] };
        let ledger = vec![];
        let project = json!({
            "id": "minimal_2d",
            "name": "Minimal 2D Ouroforge Project",
            "projectRoot": ".",
            "manifestPath": "ouroforge.project.json",
            "manifestHash": { "algorithm": "fnv1a64-file-v1", "value": "manifesthash" },
            "seedPath": "seeds/platformer.yaml",
            "scenes": [{
                "id": "main",
                "path": "scenes/main.scene.json",
                "hash": { "algorithm": "fnv1a64-canonical-json-v1", "value": "scenehash" }
            }],
            "scenarioPack": {
                "id": "smoke",
                "path": "scenarios/smoke.scenario-pack.json",
                "scenarioIds": ["scaffold-smoke"]
            },
            "transactionId": "scene-edit-fixture"
        });

        let journal = render_journal(
            Path::new("."),
            &seed,
            &evidence,
            &ledger,
            &json!({ "status": "pending", "summary": "pending summary", "failures": [] }),
            &[],
            &json!({ "project": project }),
        );

        assert!(journal.contains("## Project Context"));
        assert!(journal.contains("Project: `minimal_2d`"));
        assert!(journal.contains("Manifest hash: `fnv1a64-file-v1:manifesthash`"));
        assert!(journal.contains("Scenario pack: `smoke`"));
        assert!(journal.contains("Linked transaction: `scene-edit-fixture`"));
        assert!(
            journal.contains("`scenes/main.scene.json` (`fnv1a64-canonical-json-v1:scenehash`)")
        );

        let malformed = render_journal(
            Path::new("."),
            &seed,
            &evidence,
            &ledger,
            &json!({ "status": "pending", "summary": "pending summary", "failures": [] }),
            &[],
            &json!({ "project": { "id": 7 } }),
        );
        assert!(malformed.contains("Project metadata is present but malformed"));
    }

