    #[test]
    fn scenario_steps_call_runtime_probe_api() {
        let mut client = CdpClient::new(RecordingRuntimeTransport { calls: Vec::new() });

        execute_scenario_step(
            &mut client,
            &ScenarioStep::Wait {
                wait: WaitStep { frames: 3 },
            },
        )
        .expect("wait executes");
        execute_scenario_step(
            &mut client,
            &ScenarioStep::Input {
                input: InputStep {
                    right: Some(true),
                    ..InputStep::default()
                },
            },
        )
        .expect("input executes");
        execute_scenario_step(
            &mut client,
            &ScenarioStep::Transition {
                transition: TransitionStep {
                    id: "to_level_2".to_string(),
                },
            },
        )
        .expect("transition executes");
        execute_scenario_step(
            &mut client,
            &ScenarioStep::Replay {
                replay: InputReplay {
                    schema_version: "1".to_string(),
                    id: "move-right".to_string(),
                    events: vec![
                        InputReplayEvent {
                            frame: 0,
                            key: ReplayKey::Right,
                            pressed: true,
                        },
                        InputReplayEvent {
                            frame: 4,
                            key: ReplayKey::Right,
                            pressed: false,
                        },
                    ],
                },
            },
        )
        .expect("replay executes");

        let transport = client.into_transport();
        let readiness = "Boolean(window.__OUROFORGE__ && typeof window.__OUROFORGE__.step === 'function' && typeof window.__OUROFORGE__.setInput === 'function')";
        assert_eq!(transport.calls[0], readiness);
        assert_eq!(transport.calls[1], "window.__OUROFORGE__.step(3)");
        assert_eq!(transport.calls[2], readiness);
        assert_eq!(
            transport.calls[3],
            "window.__OUROFORGE__.setInput({\"right\":true})"
        );
        let transition_readiness =
            "Boolean(window.__OUROFORGE__ && typeof window.__OUROFORGE__.transition === 'function')";
        assert_eq!(transport.calls[4], transition_readiness);
        assert_eq!(
            transport.calls[5],
            "window.__OUROFORGE__.transition(\"to_level_2\")"
        );
        assert_eq!(transport.calls[6], readiness);
        assert_eq!(
            transport.calls[7],
            "window.__OUROFORGE__.setInput({\"right\":true})"
        );
        assert_eq!(transport.calls[8], readiness);
        assert_eq!(transport.calls[9], "window.__OUROFORGE__.step(4)");
        assert_eq!(transport.calls[10], readiness);
        assert_eq!(
            transport.calls[11],
            "window.__OUROFORGE__.setInput({\"right\":false})"
        );
    }

    #[test]
    fn browser_smoke_records_worker_run_failure_evidence() {
        let (root, artifacts) = create_test_run("ouroforge-browser-worker-run-failure-test");
        let mut config = BrowserSmokeConfig::new(&artifacts.run_dir, "http://127.0.0.1:8765")
            .expect("config builds");
        config.debugging_http_url = "http://127.0.0.1:9".to_string();

        let error = run_browser_smoke(&config).expect_err("worker run fails without chrome");
        assert!(!error.to_string().is_empty());

        let index = read_evidence_index(&artifacts.run_dir).expect("evidence index reads");
        let failure = index
            .artifacts
            .iter()
            .find(|artifact| {
                artifact
                    .metadata
                    .get("artifact")
                    .and_then(|value| value.as_str())
                    == Some("browser_worker_failure")
            })
            .expect("failure artifact indexed");
        assert_eq!(failure.metadata["phase"], "worker_run");
        assert_eq!(failure.metadata["worker_id"], "worker-1");
        assert!(artifacts.run_dir.join(&failure.path).is_file());
        let failure_value =
            read_json_value(artifacts.run_dir.join(&failure.path)).expect("failure artifact reads");
        assert_eq!(failure_value["artifact"], "browser_worker_failure");
        assert_eq!(failure_value["phase"], "worker_run");
        assert_eq!(failure_value["execution_boundary"], "openchrome_cdp");

        let events = read_ledger_events(&artifacts.run_dir).expect("ledger reads");
        assert!(events.iter().any(|event| {
            event["event"] == "browser.worker.failed"
                && event["payload"]["worker_id"] == "worker-1"
                && event["payload"]["phase"] == "worker_run"
                && event["payload"]["failure_path"] == failure.path
        }));
        fs::remove_dir_all(root).ok();
    }

