    #[test]
    fn scene_3d_schema_v1_rejects_invalid_or_malformed_fixtures() {
        let missing_graph: SceneDocument = serde_json::from_str(&read_json_fixture(
            "examples/3d-capability-gate-v1/scene-3d-invalid-missing-graph.scene.json",
        ))
        .expect("invalid 3D fixture still parses before semantic validation");
        let error = validate_scene(&missing_graph).expect_err("3D scene without graph is rejected");
        assert!(error
            .to_string()
            .contains("sceneKind 3d requires scene3d graph"));

        let malformed = serde_json::from_str::<SceneDocument>(&read_json_fixture(
            "examples/3d-capability-gate-v1/scene-3d-malformed-transform.scene.json",
        ))
        .expect_err("malformed 3D transform is rejected by schema parsing");
        assert!(malformed.to_string().contains("missing field `z`"));

        // i64::MIN must be rejected as out of range, not overflow on abs().
        let extreme = validate_scene_3d_vector(
            "test vector",
            &Scene3dVector {
                x: i64::MIN,
                y: 0,
                z: 0,
            },
        )
        .expect_err("i64::MIN component is rejected without overflow");
        assert!(extreme.to_string().contains("exceeds bounded 3d range"));
        // A within-bound vector still validates.
        validate_scene_3d_vector(
            "test vector",
            &Scene3dVector {
                x: 1_000_000_000,
                y: -1_000_000_000,
                z: 0,
            },
        )
        .expect("vector at the bound is accepted");
    }

    #[test]
    fn scene_3d_hierarchy_v1_rejects_invalid_parent_graphs_and_components() {
        for (fixture, expected) in [
            (
                "examples/3d-capability-gate-v1/scene-3d-invalid-missing-parent.scene.json",
                "references missing parent",
            ),
            (
                "examples/3d-capability-gate-v1/scene-3d-invalid-duplicate-id.scene.json",
                "duplicate scene3d node id",
            ),
            (
                "examples/3d-capability-gate-v1/scene-3d-invalid-cycle.scene.json",
                "scene3d hierarchy cycle detected",
            ),
            (
                "examples/3d-capability-gate-v1/scene-3d-invalid-zero-scale.scene.json",
                "scale axes must be non-zero",
            ),
            (
                "examples/3d-capability-gate-v1/scene-3d-invalid-unsupported-component.scene.json",
                "unsupported component kind",
            ),
        ] {
            let scene: SceneDocument = serde_json::from_str(&read_json_fixture(fixture))
                .unwrap_or_else(|error| panic!("{fixture} parses before validation: {error:#}"));
            let error = match validate_scene(&scene) {
                Ok(()) => panic!("{fixture} rejected by 3D validation"),
                Err(error) => error,
            };
            assert!(
                error.to_string().contains(expected),
                "{fixture} error {error:#} contains {expected}"
            );
        }

        // A node whose component array exceeds the bounded count is rejected even
        // though each individual component is valid.
        let mut oversized: serde_json::Value = serde_json::from_str(&read_json_fixture(
            "examples/3d-capability-gate-v1/scene-3d-valid.scene.json",
        ))
        .expect("valid 3D fixture json");
        let components = (0..17)
            .map(|_| json!({ "kind": "marker" }))
            .collect::<Vec<_>>();
        oversized["scene3d"]["nodes"][0]["components"] = json!(components);
        let oversized_scene: SceneDocument =
            serde_json::from_str(&oversized.to_string()).expect("oversized 3D scene parses");
        let oversized_error = validate_scene(&oversized_scene)
            .expect_err("oversized 3D node components are rejected");
        assert!(oversized_error
            .to_string()
            .contains("components must not exceed"));
    }

