    #[test]
    fn dashboard_read_model_handles_command_context_missing_and_malformed() {
        let (root, artifacts) = create_test_run("dashboard-command-context");
        let model = read_dashboard_run(&artifacts.run_dir).expect("dashboard run reads");
        assert!(model.command_context.is_some());
        assert!(model.summary.command_context.is_some());
        assert_eq!(
            model.command_context.as_ref().unwrap().schema_version,
            "run-command-context-v1"
        );

        let run_path = artifacts.run_dir.join("run.json");
        let mut run_json = read_json_value(&run_path).expect("run json reads");
        run_json
            .as_object_mut()
            .expect("run json object")
            .remove("run_command_context");
        fs::write(
            &run_path,
            serde_json::to_string_pretty(&run_json).expect("run serializes"),
        )
        .expect("run json updated");
        let legacy = read_dashboard_run(&artifacts.run_dir).expect("legacy dashboard run reads");
        assert!(legacy.command_context.is_none());
        assert!(legacy.summary.command_context.is_none());

        run_json["run_command_context"] = json!({ "schemaVersion": 7, "command": false });
        fs::write(
            &run_path,
            serde_json::to_string_pretty(&run_json).expect("run serializes"),
        )
        .expect("run json updated");
        let malformed = read_dashboard_run(&artifacts.run_dir).expect("malformed context ignored");
        assert!(malformed.command_context.is_none());
        assert!(malformed.summary.command_context.is_none());

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn journal_renders_reproducible_command_context_without_inference() {
        let seed = Seed::from_yaml_str(VALID_SEED).expect("seed parses");
        let evidence = EvidenceIndex {
            artifacts: Vec::new(),
        };
        let run = json!({
            "run_command_context": {
                "schemaVersion": "run-command-context-v1",
                "command": "cargo run -p ouroforge-cli -- run seeds/platformer.yaml --workers 2",
                "argv": ["cargo", "run", "-p", "ouroforge-cli", "--", "run", "seeds/platformer.yaml", "--workers", "2"],
                "seedPath": "seeds/platformer.yaml",
                "workers": 2,
                "runsRoot": "runs",
                "runtimeTarget": "local-static-browser",
                "browserBoundary": "openchrome_cdp",
                "cdpTransport": "chrome_devtools_protocol",
                "environmentHints": []
            }
        });
        let journal = render_journal(
            Path::new("."),
            &seed,
            &evidence,
            &[],
            &json!({ "status": "pending" }),
            &[],
            &run,
        );
        assert!(journal.contains("## Reproducible Command Context"));
        assert!(journal.contains("Display-only"));
        assert!(journal.contains("run seeds/platformer.yaml"));
        assert!(journal.contains("Target assumption: `local-static-browser`"));
        assert!(journal.contains("Browser boundary: `openchrome_cdp` / `chrome_devtools_protocol`"));

        let malformed = render_journal(
            Path::new("."),
            &seed,
            &evidence,
            &[],
            &json!({ "status": "pending" }),
            &[],
            &json!({ "run_command_context": { "schemaVersion": 7 } }),
        );
        assert!(malformed.contains("present but malformed"));
    }

    #[test]
    fn dashboard_and_journal_surface_asset_reference_integrity_warnings() {
        let (root, artifacts) = create_test_run("dashboard-asset-reference-integrity");
        let warning = ProjectAssetReferenceIntegrityWarning {
            field: "scene entity player sprite asset".to_string(),
            asset_id: "player_sprite".to_string(),
            kind: "stale_asset_hash".to_string(),
            message: "project asset manifest asset player_sprite contentHash mismatch".to_string(),
            expected_types: Vec::new(),
            observed_type: Some(ProjectAssetType::Image),
            path: Some("assets/sprites/player.png".to_string()),
        };
        let report = ProjectAssetReferenceIntegrityReport {
            schema_version: "asset-reference-integrity-v1".to_string(),
            manifest_id: "warning_manifest".to_string(),
            scene_id: "main".to_string(),
            resolved_refs: Vec::new(),
            warnings: vec![warning],
        };
        fs::create_dir_all(artifacts.run_dir.join("evidence/assets")).expect("asset evidence dir");
        fs::write(
            artifacts
                .run_dir
                .join("evidence/assets/asset-reference-integrity.json"),
            serde_json::to_string_pretty(&report).expect("report serializes"),
        )
        .expect("integrity report written");
        add_evidence_artifact(
            &artifacts.run_dir,
            "asset-reference-integrity",
            "application/json",
            "evidence/assets/asset-reference-integrity.json",
            json!({
                "artifact": "asset_reference_integrity",
                "boundary": "local Rust validation only; no remote asset fetches"
            }),
        )
        .expect("asset integrity evidence indexed");

        let journal = update_journal(&artifacts.run_dir).expect("journal updates");
        assert!(journal.contains("## Asset Reference Integrity"));
        assert!(journal.contains("stale_asset_hash"));
        assert!(journal.contains("asset-reference-integrity.json"));

        let model = read_dashboard_run(&artifacts.run_dir).expect("dashboard reads");
        assert!(model.asset_integrity.present);
        assert_eq!(model.asset_integrity.warning_count, 1);
        assert_eq!(model.asset_integrity.stale_hash_count, 1);
        assert_eq!(
            model.asset_integrity.evidence_refs,
            vec!["evidence/assets/asset-reference-integrity.json".to_string()]
        );

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn dashboard_read_model_ignores_missing_and_malformed_project_context() {
        let (root, artifacts) = create_test_run("dashboard-project-context-malformed");
        let legacy = read_dashboard_run(&artifacts.run_dir).expect("legacy run reads");
        assert!(legacy.project.is_none());
        assert!(legacy.summary.project.is_none());

        let mut run_json: serde_json::Value = serde_json::from_str(
            &fs::read_to_string(artifacts.run_dir.join("run.json")).expect("run json reads"),
        )
        .expect("run json parses");
        run_json["project"] = json!({ "id": 7, "name": false });
        fs::write(
            artifacts.run_dir.join("run.json"),
            serde_json::to_string_pretty(&run_json).expect("run json serializes"),
        )
        .expect("run json updated");

        let malformed = read_dashboard_run(&artifacts.run_dir).expect("malformed project ignored");
        assert!(malformed.project.is_none());
        assert!(malformed.summary.project.is_none());

        fs::remove_dir_all(root).expect("fixture removed");
    }

    #[test]
    fn dashboard_runtime_state_summary_surfaces_save_load_replay_digest_fields() {
        let world_state = json!({
            "sceneId": "foundation-scene",
            "tick": 5,
            "runtimeState": {
                "schemaVersion": "runtime-state-read-model-v1",
                "stateId": "tick-5-tick-5",
                "sceneId": "foundation-scene",
                "tick": 5,
                "digest": { "algorithm": "fnv1a64-canonical-json-v1", "value": "0123456789abcdef" },
                "authority": "browser_runtime_evidence_input_not_trusted_persistence",
                "readOnlyInspection": { "disallowedActions": ["trusted writes", "command bridge", "live mutation"] }
            },
            "runtimeEvents": [
                { "tick": 4, "type": "runtime.save.created", "payload": { "saveId": "slot-1-tick-4", "slotId": "slot-1", "stateDigest": { "algorithm": "fnv1a64-canonical-json-v1", "value": "0123456789abcdef" } } },
                { "tick": 5, "type": "runtime.save.loaded", "payload": { "saveId": "slot-1-tick-4", "slotId": "slot-1", "stateDigest": { "algorithm": "fnv1a64-canonical-json-v1", "value": "0123456789abcdef" } } },
                { "tick": 5, "type": "runtime.replay.digest_compared", "payload": { "frameId": "frame-5", "status": "matched", "expected": { "algorithm": "fnv1a64-canonical-json-v1", "value": "0123456789abcdef" }, "actual": { "algorithm": "fnv1a64-canonical-json-v1", "value": "0123456789abcdef" } } }
            ],
            "snapshots": [{ "snapshotId": "snapshot-4", "tick": 4 }]
        });
        let summary = dashboard_runtime_state_summary(&world_state);
        assert_eq!(summary["present"], json!(true));
        assert_eq!(summary["stateId"], json!("tick-5-tick-5"));
        assert_eq!(summary["digest"]["value"], json!("0123456789abcdef"));
        assert_eq!(summary["snapshotCount"], json!(1));
        assert_eq!(summary["saveCreatedCount"], json!(1));
        assert_eq!(summary["saveLoadedCount"], json!(1));
        assert_eq!(summary["replayDigestComparedCount"], json!(1));
        assert_eq!(
            summary["latestReplayDigestComparison"]["payload"]["status"],
            json!("matched")
        );
        assert_eq!(
            summary["readOnlyInspection"]["disallowedActions"],
            json!(["trusted writes", "command bridge", "live mutation"])
        );
    }

    #[test]
    fn dashboard_runtime_state_summary_handles_missing_and_malformed_input() {
        // Absent runtime-state evidence renders the absence state, not defaults.
        let empty = dashboard_runtime_state_summary(&json!({}));
        assert_eq!(empty["present"], json!(false));
        assert_eq!(
            empty["emptyState"],
            json!("No runtime save/load/replay state read model is available.")
        );
        assert_eq!(empty["saveEventCount"], json!(0));
        assert_eq!(empty["snapshotCount"], json!(0));
        assert_eq!(empty["replayDigestComparedCount"], json!(0));
        assert_eq!(empty["stateId"], json!(null));

        // Wrong-typed runtimeState/runtimeEvents/snapshots are ignored, not crashed on.
        let malformed = dashboard_runtime_state_summary(&json!({
            "runtimeState": "not-an-object",
            "runtimeEvents": { "type": "runtime.save.created" },
            "snapshots": "not-an-array"
        }));
        assert_eq!(malformed["present"], json!(false));
        assert_eq!(malformed["stateId"], json!(null));
        assert_eq!(malformed["saveEventCount"], json!(0));
        assert_eq!(malformed["snapshotCount"], json!(0));

        // Event entries without a usable type string are not miscounted.
        let untyped_events = dashboard_runtime_state_summary(&json!({
            "runtimeEvents": [{ "tick": 1 }, { "type": 42 }, "not-an-object"]
        }));
        assert_eq!(untyped_events["present"], json!(false));
        assert_eq!(untyped_events["saveCreatedCount"], json!(0));
        assert_eq!(untyped_events["saveLoadedCount"], json!(0));
        assert_eq!(untyped_events["replayDigestComparedCount"], json!(0));
    }

    #[test]
    fn dashboard_camera_summary_surfaces_camera_scoped_layers() {
        // Layers emitted under worldState.camera (no renderer.layers) must still
        // be surfaced, mirroring how cameras resolves camera.cameras.
        let world_state = json!({
            "camera": {
                "activeCameraId": "follow-player",
                "layers": [
                    { "id": "sky", "order": -10, "visible": true, "parallaxFactor": 50, "cameraParticipation": true },
                    { "id": "hud", "order": 10, "visible": true, "parallaxFactor": 100, "cameraParticipation": false }
                ]
            }
        });
        let summary = dashboard_camera_summary(&world_state);
        assert_eq!(summary["present"], json!(true));
        assert_eq!(summary["layerCount"], json!(2));
        assert_eq!(summary["parallaxLayerCount"], json!(1));
        assert_eq!(summary["cameraExcludedLayerCount"], json!(1));
        assert_eq!(summary["layers"][0]["id"], json!("sky"));

        // Top-level layers are also surfaced when neither renderer nor camera carry them.
        let top_level =
            json!({ "layers": [{ "id": "ground", "order": 0, "parallaxFactor": 100 }] });
        assert_eq!(dashboard_camera_summary(&top_level)["layerCount"], json!(1));

        // renderer.layers still takes precedence (no regression).
        let renderer_scoped = json!({
            "renderer": { "layers": [{ "id": "a" }, { "id": "b" }] },
            "camera": { "layers": [{ "id": "ignored" }] }
        });
        assert_eq!(
            dashboard_camera_summary(&renderer_scoped)["layerCount"],
            json!(2)
        );
    }

